"""
runtime.py — Python ctypes wrapper around the Tessera runtime C ABI (Phase 6)

Provides ``TesseraRuntime``, a high-level Python interface over the C ABI
defined in ``tessera_runtime.h``.  When the compiled shared library is not
found the module transparently falls back to a pure-Python mock so tests and
development workflows always succeed.

Usage::

    from tessera.runtime import TesseraRuntime, DeviceKind

    rt = TesseraRuntime()
    rt.init()
    dev = rt.get_device(0)             # CPU device (always present)
    props = rt.get_device_props(dev)
    buf = rt.malloc(dev, 1024)
    rt.memset(buf, 0, 1024)
    rt.free(buf)
    rt.shutdown()
"""

from __future__ import annotations

import collections
import ctypes
import ctypes.util
import functools
import hashlib
import json
import os
import shutil
import subprocess
import sys
import time
from dataclasses import dataclass
from enum import IntEnum
from pathlib import Path
from typing import Any, Dict, List, Mapping, Optional

from .telemetry import TELEMETRY_SCHEMA_VERSION, make_event, telemetry_report
from .compiler.capabilities import get_target_capability, normalize_target, runtime_status as compiler_runtime_status
from .compiler.execution_matrix import executor_for_metadata as _exec_row_for_metadata


# ---------------------------------------------------------------------------
# Status codes (mirror TsrStatus)
# ---------------------------------------------------------------------------

class TsrStatus(IntEnum):
    SUCCESS          = 0
    INVALID_ARGUMENT = 1
    NOT_FOUND        = 2
    ALREADY_EXISTS   = 3
    OUT_OF_MEMORY    = 4
    UNIMPLEMENTED    = 5
    INTERNAL         = 6
    DEVICE_ERROR     = 7


class DeviceKind(IntEnum):
    CPU  = 0
    CUDA = 1
    HIP  = 2


class MemcpyKind(IntEnum):
    HOST_TO_DEVICE   = 0
    DEVICE_TO_HOST   = 1
    DEVICE_TO_DEVICE = 2
    HOST_TO_HOST     = 3


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TesseraRuntimeError(RuntimeError):
    """Raised when a C ABI call returns a non-SUCCESS status."""

    def __init__(self, fn_name: str, status: TsrStatus, detail: str = ""):
        msg = f"{fn_name} failed: {status.name}"
        if detail:
            msg += f" — {detail}"
        super().__init__(msg)
        self.status = status
        self.fn_name = fn_name


# ---------------------------------------------------------------------------
# Device properties
# ---------------------------------------------------------------------------

@dataclass
class DeviceProps:
    kind: DeviceKind
    name: str
    logical_tile_threads_max: int
    concurrent_tiles_hint: int

    def __repr__(self) -> str:
        return (
            f"DeviceProps(kind={self.kind.name}, name={self.name!r}, "
            f"tile_threads={self.logical_tile_threads_max}, "
            f"concurrent={self.concurrent_tiles_hint})"
        )


@dataclass(frozen=True)
class RuntimeProfile:
    cpu_wall_ms: float | None = None
    kernel_elapsed_ms: float | None = None
    memory_bytes: int | None = None
    launch_overhead_ms: float | None = None


@dataclass(frozen=True)
class BackendCapability:
    name: str
    available: bool
    executable: bool
    reason: str = ""
    dtypes: tuple[str, ...] = ()
    features: tuple[str, ...] = ()


@dataclass(frozen=True)
class RuntimeArtifact:
    graph_ir: str = ""
    schedule_ir: str = ""
    tile_ir: str = ""
    target_ir: str = ""
    metadata: dict[str, Any] | None = None
    abi_signature: str = ""

    @property
    def artifact_hash(self) -> str:
        payload = self.to_json(include_hash=False)
        return hashlib.sha256(payload.encode("utf-8")).hexdigest()

    def to_dict(self) -> dict[str, Any]:
        return {
            "graph_ir": self.graph_ir,
            "schedule_ir": self.schedule_ir,
            "tile_ir": self.tile_ir,
            "target_ir": self.target_ir,
            "metadata": self.metadata or {},
            "abi_signature": self.abi_signature,
            "artifact_hash": self.artifact_hash,
        }

    def to_json(self, *, include_hash: bool = True) -> str:
        data = {
            "graph_ir": self.graph_ir,
            "schedule_ir": self.schedule_ir,
            "tile_ir": self.tile_ir,
            "target_ir": self.target_ir,
            "metadata": self.metadata or {},
            "abi_signature": self.abi_signature,
        }
        if include_hash:
            data["artifact_hash"] = hashlib.sha256(
                json.dumps(data, sort_keys=True).encode("utf-8")
            ).hexdigest()
        return json.dumps(data, sort_keys=True)

    @classmethod
    def from_json(cls, payload: str | bytes) -> "RuntimeArtifact":
        if isinstance(payload, bytes):
            payload = payload.decode("utf-8")
        data = json.loads(payload)
        return cls(
            graph_ir=data.get("graph_ir", ""),
            schedule_ir=data.get("schedule_ir", ""),
            tile_ir=data.get("tile_ir", ""),
            target_ir=data.get("target_ir", ""),
            metadata=data.get("metadata") or {},
            abi_signature=data.get("abi_signature", ""),
        )


_last_profile = RuntimeProfile()
_apple_cpu_runtime: ctypes.CDLL | None = None
_apple_gpu_runtime: ctypes.CDLL | None = None


# bfloat16 dtype is exposed by the optional ml_dtypes package. We import lazily
# and tolerate it missing so the rest of the runtime works for users who do
# not need the bf16 fast path. ml_dtypes is the de-facto standard now (JAX,
# TensorFlow Probability, PyTorch's experimental numpy bridge all use it).
def _bfloat16_dtype() -> Any:
    try:
        import ml_dtypes
        return ml_dtypes.bfloat16
    except Exception:
        return None


# ---------------------------------------------------------------------------
# Mock implementation (no shared library required)
# ---------------------------------------------------------------------------

class _MockHandle:
    """Opaque handle returned by mock operations."""

    _counter = 0

    def __init__(self, kind: str, data: Any = None):
        _MockHandle._counter += 1
        self._id = _MockHandle._counter
        self.kind = kind
        self.data = data  # e.g. bytearray for Buffer
        self._destroyed = False

    def __repr__(self) -> str:
        return f"<MockHandle id={self._id} kind={self.kind}>"


class _MockBackend:
    """
    Pure-Python mock of the Tessera runtime C ABI.
    All operations succeed silently; memory is simulated with bytearray.
    """

    def __init__(self):
        self._initialized = False
        self._devices: List[_MockHandle] = []
        self._last_error = ""

    def init(self) -> TsrStatus:
        if not self._initialized:
            self._devices = [
                _MockHandle("device",
                            DeviceProps(DeviceKind.CPU,
                                        "Tessera CPU Backend (mock)",
                                        2048, 8))
            ]
            self._initialized = True
        return TsrStatus.SUCCESS

    def shutdown(self) -> TsrStatus:
        self._devices.clear()
        self._initialized = False
        return TsrStatus.SUCCESS

    def get_device_count(self) -> int:
        return len(self._devices)

    def get_device(self, index: int) -> _MockHandle:
        if index < 0 or index >= len(self._devices):
            raise TesseraRuntimeError("tsrGetDevice", TsrStatus.NOT_FOUND,
                                       f"no device at index {index}")
        return self._devices[index]

    def get_device_props(self, dev: _MockHandle) -> DeviceProps:
        return dev.data

    def malloc(self, dev: _MockHandle, size: int) -> _MockHandle:
        if size < 0:
            raise TesseraRuntimeError("tsrMalloc", TsrStatus.INVALID_ARGUMENT,
                                       "size must be >= 0")
        return _MockHandle("buffer", bytearray(size))

    def free(self, buf: _MockHandle) -> TsrStatus:
        if buf.kind != "buffer":
            return TsrStatus.INVALID_ARGUMENT
        buf._destroyed = True
        buf.data = None
        return TsrStatus.SUCCESS

    def memset(self, buf: _MockHandle, value: int, size: int) -> TsrStatus:
        if buf.data is None:
            return TsrStatus.INVALID_ARGUMENT
        n = min(size, len(buf.data))
        for i in range(n):
            buf.data[i] = value & 0xFF
        return TsrStatus.SUCCESS

    def memcpy(self, dst: _MockHandle, src: _MockHandle,
               size: int, kind: MemcpyKind) -> TsrStatus:
        if dst.data is None or src.data is None:
            return TsrStatus.INVALID_ARGUMENT
        n = min(size, len(dst.data), len(src.data))
        dst.data[:n] = src.data[:n]
        return TsrStatus.SUCCESS

    def map(self, buf: _MockHandle) -> bytes:
        if buf.data is None:
            return b""
        return bytes(buf.data)

    def unmap(self, buf: _MockHandle) -> TsrStatus:
        return TsrStatus.SUCCESS

    def create_stream(self, dev: _MockHandle) -> _MockHandle:
        return _MockHandle("stream", dev)

    def destroy_stream(self, stream: _MockHandle) -> TsrStatus:
        stream._destroyed = True
        return TsrStatus.SUCCESS

    def stream_sync(self, stream: _MockHandle) -> TsrStatus:
        return TsrStatus.SUCCESS

    def create_event(self, dev: _MockHandle) -> _MockHandle:
        return _MockHandle("event", {"timestamp_ns": 0, "signaled": False})

    def record_event(self, event: _MockHandle, stream: _MockHandle) -> TsrStatus:
        import time
        event.data["timestamp_ns"] = int(time.perf_counter_ns())
        event.data["signaled"] = True
        return TsrStatus.SUCCESS

    def wait_event(self, event: _MockHandle, stream: _MockHandle) -> TsrStatus:
        return TsrStatus.SUCCESS

    def event_sync(self, event: _MockHandle) -> TsrStatus:
        return TsrStatus.SUCCESS

    def destroy_event(self, event: _MockHandle) -> TsrStatus:
        event._destroyed = True
        return TsrStatus.SUCCESS

    def event_get_timestamp(self, event: _MockHandle) -> int:
        return event.data.get("timestamp_ns", 0)

    def get_version(self) -> tuple:
        return (0, 1, 0)

    def get_last_error(self) -> str:
        return self._last_error


# ---------------------------------------------------------------------------
# ctypes-based backend (real shared library)
# ---------------------------------------------------------------------------

def _find_library() -> Optional[str]:
    """Search for libtessera_runtime in common locations."""
    candidates = [
        "libtessera_runtime.dylib",
        "libtessera_runtime.so",
        "tessera_runtime.dll",
    ]
    search_dirs = [
        Path(__file__).parent.parent.parent.parent / "build" / "lib",
        Path(__file__).parent.parent.parent.parent / "build",
        Path("/usr/local/lib"),
        Path("/usr/lib"),
    ]
    # Environment override
    if env := os.environ.get("TESSERA_RUNTIME_LIB"):
        return env

    for d in search_dirs:
        for name in candidates:
            p = d / name
            if p.exists():
                return str(p)

    found = ctypes.util.find_library("tessera_runtime")
    return found


def _elapsed_ms(start_ns: int) -> float:
    return (time.perf_counter_ns() - start_ns) / 1_000_000.0


# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

class TesseraRuntime:
    """
    High-level Python wrapper over the Tessera runtime C ABI.

    Automatically falls back to a pure-Python mock when the compiled
    ``libtessera_runtime`` shared library is not found on the system.

    Parameters
    ----------
    lib_path : str, optional
        Explicit path to the shared library.  If not provided, the runtime
        searches standard locations and the ``TESSERA_RUNTIME_LIB`` env var.
    mock : bool
        Force mock mode regardless of library availability.
    """

    def __init__(
        self,
        lib_path: Optional[str] = None,
        *,
        mock: bool = False,
    ) -> None:
        self._mock_mode: bool = mock
        self._lib: Any = None
        self._backend: Any = None
        self._initialized: bool = False
        # Bounded so a long-running process (server / training loop) can't grow
        # this without limit; the oldest events are dropped. Telemetry is advisory.
        self._telemetry_events: "collections.deque[dict[str, Any]]" = collections.deque(maxlen=100_000)

        if not mock:
            # A library requested *explicitly* (constructor arg or env var) must
            # not silently degrade to the mock backend on load failure — that
            # hides a real deployment error. Also catch symbol-binding failures
            # in _setup_ctypes (AttributeError), not just dlopen (OSError).
            explicit = lib_path is not None or bool(os.environ.get("TESSERA_RUNTIME_LIB"))
            path = lib_path or _find_library()
            if path:
                try:
                    self._lib = ctypes.CDLL(path)
                    self._setup_ctypes()
                except (OSError, AttributeError) as exc:
                    self._lib = None
                    if explicit:
                        raise TesseraRuntimeError(
                            "load_runtime_library",
                            TsrStatus.NOT_FOUND,
                            f"explicitly requested runtime library {path!r} failed to "
                            f"load ({exc}); refusing to fall back to mock mode silently. "
                            f"Pass mock=True to use the mock backend deliberately.",
                        ) from exc

        if self._lib is None:
            self._mock_mode = True
            self._backend = _MockBackend()

    # ------------------------------------------------------------------
    # ctypes function declarations
    # ------------------------------------------------------------------

    def _setup_ctypes(self) -> None:
        """Declare argtypes / restypes for every ABI entry point."""
        lib = self._lib
        vp = ctypes.c_void_p
        i32 = ctypes.c_int
        u32 = ctypes.c_uint32
        u64 = ctypes.c_uint64
        sz = ctypes.c_size_t

        lib.tsrInit.restype = i32
        lib.tsrShutdown.restype = i32

        lib.tsrGetDeviceCount.argtypes = [ctypes.POINTER(i32)]
        lib.tsrGetDeviceCount.restype = i32

        lib.tsrGetDevice.argtypes = [i32, ctypes.POINTER(vp)]
        lib.tsrGetDevice.restype = i32

        lib.tsrGetDeviceProps.argtypes = [vp, ctypes.c_void_p]
        lib.tsrGetDeviceProps.restype = i32

        lib.tsrMalloc.argtypes = [vp, sz, ctypes.POINTER(vp)]
        lib.tsrMalloc.restype = i32

        lib.tsrFree.argtypes = [vp]
        lib.tsrFree.restype = i32

        lib.tsrMemset.argtypes = [vp, i32, sz]
        lib.tsrMemset.restype = i32

        lib.tsrMemcpy.argtypes = [vp, vp, sz, i32]
        lib.tsrMemcpy.restype = i32

        lib.tsrMap.argtypes = [vp, ctypes.POINTER(vp), ctypes.POINTER(sz)]
        lib.tsrMap.restype = i32

        lib.tsrUnmap.argtypes = [vp]
        lib.tsrUnmap.restype = i32

        lib.tsrCreateStream.argtypes = [vp, ctypes.POINTER(vp)]
        lib.tsrCreateStream.restype = i32

        lib.tsrDestroyStream.argtypes = [vp]
        lib.tsrDestroyStream.restype = i32

        lib.tsrStreamSynchronize.argtypes = [vp]
        lib.tsrStreamSynchronize.restype = i32

        lib.tsrCreateEvent.argtypes = [vp, ctypes.POINTER(vp)]
        lib.tsrCreateEvent.restype = i32

        lib.tsrRecordEvent.argtypes = [vp, vp]
        lib.tsrRecordEvent.restype = i32

        lib.tsrWaitEvent.argtypes = [vp, vp]
        lib.tsrWaitEvent.restype = i32

        lib.tsrEventSynchronize.argtypes = [vp]
        lib.tsrEventSynchronize.restype = i32

        lib.tsrDestroyEvent.argtypes = [vp]
        lib.tsrDestroyEvent.restype = i32

        lib.tsrEventGetTimestamp.argtypes = [vp, ctypes.POINTER(u64)]
        lib.tsrEventGetTimestamp.restype = i32

        lib.tsrGetLastError.restype = ctypes.c_char_p
        lib.tsrClearLastError.restype = None

        lib.tsrGetVersion.argtypes = [ctypes.POINTER(i32),
                                       ctypes.POINTER(i32),
                                       ctypes.POINTER(i32)]
        lib.tsrGetVersion.restype = None

        if hasattr(lib, "tsrNativeGemmF32"):
            lib.tsrNativeGemmF32.argtypes = [
                vp,
                ctypes.POINTER(ctypes.c_float),
                ctypes.POINTER(ctypes.c_float),
                ctypes.POINTER(ctypes.c_float),
                i32,
                i32,
                i32,
            ]
            lib.tsrNativeGemmF32.restype = i32

        if hasattr(lib, "tsrGetWorkerThreadCount"):
            lib.tsrGetWorkerThreadCount.argtypes = [vp, ctypes.POINTER(u32)]
            lib.tsrGetWorkerThreadCount.restype = i32

    def _check(self, fn_name: str, status: int, extra: str = "") -> None:
        """Raise TesseraRuntimeError if status != SUCCESS."""
        s = TsrStatus(status)
        if s != TsrStatus.SUCCESS:
            detail = extra
            if self._lib:
                err = self._lib.tsrGetLastError()
                if err:
                    detail = err.decode() if isinstance(err, bytes) else err
            raise TesseraRuntimeError(fn_name, s, detail)

    def _record_event(
        self,
        name: str,
        *,
        op: str | None = None,
        latency_ms: float | None = None,
        memory_bytes: int | None = None,
        status: str = "ok",
        kernel_id: str | None = None,
        device: str | int | None = None,
        stream: str | int | None = None,
        metadata: Mapping[str, Any] | None = None,
    ) -> dict[str, Any]:
        event = make_event(
            name,
            source="runtime",
            op=op or name,
            arch="cpu" if self._mock_mode else "native",
            kernel_id=kernel_id,
            device=device,
            stream=stream,
            latency_ms=latency_ms,
            memory_bytes=memory_bytes,
            status=status,
            metadata={
                "mock": self._mock_mode,
                **dict(metadata or {}),
            },
        )
        self._telemetry_events.append(event)
        return event

    # ------------------------------------------------------------------
    # Lifecycle
    # ------------------------------------------------------------------

    def init(self) -> None:
        """Initialise the runtime and all available backends."""
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.init()
        else:
            self._check("tsrInit", self._lib.tsrInit())
        self._initialized = True
        self._record_event("runtime.init", latency_ms=_elapsed_ms(start_ns))

    def shutdown(self) -> None:
        """Release all runtime resources."""
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.shutdown()
        else:
            self._check("tsrShutdown", self._lib.tsrShutdown())
        self._initialized = False
        self._record_event("runtime.shutdown", latency_ms=_elapsed_ms(start_ns))

    # ------------------------------------------------------------------
    # Device enumeration
    # ------------------------------------------------------------------

    def get_device_count(self) -> int:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            count = self._backend.get_device_count()
            self._record_event(
                "runtime.device_count",
                latency_ms=_elapsed_ms(start_ns),
                metadata={"count": count},
            )
            return count
        count = ctypes.c_int(0)
        self._check("tsrGetDeviceCount",
                    self._lib.tsrGetDeviceCount(ctypes.byref(count)))
        self._record_event(
            "runtime.device_count",
            latency_ms=_elapsed_ms(start_ns),
            metadata={"count": count.value},
        )
        return count.value

    def get_device(self, index: int) -> Any:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            dev = self._backend.get_device(index)
            self._record_event(
                "runtime.get_device",
                latency_ms=_elapsed_ms(start_ns),
                device=index,
            )
            return dev
        handle = ctypes.c_void_p(0)
        self._check("tsrGetDevice",
                    self._lib.tsrGetDevice(index, ctypes.byref(handle)))
        self._record_event(
            "runtime.get_device",
            latency_ms=_elapsed_ms(start_ns),
            device=index,
        )
        return handle

    def get_device_props(self, dev: Any) -> DeviceProps:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            props = self._backend.get_device_props(dev)
            self._record_event(
                "runtime.device_props",
                latency_ms=_elapsed_ms(start_ns),
                device=getattr(dev, "_id", None),
                metadata={"kind": props.kind.name, "name": props.name},
            )
            return props
        # C struct layout for tsrDeviceProps
        class _Props(ctypes.Structure):
            _fields_ = [
                ("kind",                     ctypes.c_int),
                ("name",                     ctypes.c_char * 128),
                ("logical_tile_threads_max", ctypes.c_uint32),
                ("concurrent_tiles_hint",    ctypes.c_uint32),
            ]
        p = _Props()
        self._check("tsrGetDeviceProps",
                    self._lib.tsrGetDeviceProps(dev, ctypes.byref(p)))
        props = DeviceProps(
            kind=DeviceKind(p.kind),
            name=p.name.decode(),
            logical_tile_threads_max=p.logical_tile_threads_max,
            concurrent_tiles_hint=p.concurrent_tiles_hint,
        )
        self._record_event(
            "runtime.device_props",
            latency_ms=_elapsed_ms(start_ns),
            metadata={"kind": props.kind.name, "name": props.name},
        )
        return props

    # ------------------------------------------------------------------
    # Memory
    # ------------------------------------------------------------------

    def malloc(self, dev: Any, size: int) -> Any:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            buf = self._backend.malloc(dev, size)
            self._record_event(
                "runtime.malloc",
                latency_ms=_elapsed_ms(start_ns),
                memory_bytes=size,
                device=getattr(dev, "_id", None),
            )
            return buf
        handle = ctypes.c_void_p(0)
        self._check("tsrMalloc",
                    self._lib.tsrMalloc(dev, size, ctypes.byref(handle)))
        self._record_event("runtime.malloc", latency_ms=_elapsed_ms(start_ns), memory_bytes=size)
        return handle

    def free(self, buf: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.free(buf)
        else:
            self._check("tsrFree", self._lib.tsrFree(buf))
        self._record_event("runtime.free", latency_ms=_elapsed_ms(start_ns))

    def memset(self, buf: Any, value: int, size: int) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.memset(buf, value, size)
        else:
            self._check("tsrMemset", self._lib.tsrMemset(buf, value, size))
        self._record_event(
            "runtime.memset",
            latency_ms=_elapsed_ms(start_ns),
            memory_bytes=size,
            metadata={"value": value},
        )

    def memcpy(self, dst: Any, src: Any, size: int,
               kind: MemcpyKind = MemcpyKind.DEVICE_TO_DEVICE) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.memcpy(dst, src, size, kind)
        else:
            self._check("tsrMemcpy",
                        self._lib.tsrMemcpy(dst, src, size, int(kind)))
        self._record_event(
            "runtime.memcpy",
            latency_ms=_elapsed_ms(start_ns),
            memory_bytes=size,
            metadata={"kind": kind.name},
        )

    def map(self, buf: Any) -> bytes:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            data = self._backend.map(buf)
            self._record_event(
                "runtime.map",
                latency_ms=_elapsed_ms(start_ns),
                memory_bytes=len(data),
            )
            return data
        host_ptr = ctypes.c_void_p(0)
        size = ctypes.c_size_t(0)
        self._check("tsrMap",
                    self._lib.tsrMap(buf, ctypes.byref(host_ptr),
                                     ctypes.byref(size)))
        self._record_event("runtime.map", latency_ms=_elapsed_ms(start_ns), memory_bytes=size.value)
        if not host_ptr.value or not size.value:
            return b""
        return (ctypes.c_char * size.value).from_address(host_ptr.value).raw

    def unmap(self, buf: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.unmap(buf)
        else:
            self._check("tsrUnmap", self._lib.tsrUnmap(buf))
        self._record_event("runtime.unmap", latency_ms=_elapsed_ms(start_ns))

    # ------------------------------------------------------------------
    # Streams & events
    # ------------------------------------------------------------------

    def create_stream(self, dev: Any) -> Any:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            stream = self._backend.create_stream(dev)
            self._record_event(
                "runtime.create_stream",
                latency_ms=_elapsed_ms(start_ns),
                device=getattr(dev, "_id", None),
                stream=getattr(stream, "_id", None),
            )
            return stream
        h = ctypes.c_void_p(0)
        self._check("tsrCreateStream",
                    self._lib.tsrCreateStream(dev, ctypes.byref(h)))
        self._record_event("runtime.create_stream", latency_ms=_elapsed_ms(start_ns), stream=h.value)
        return h

    def destroy_stream(self, stream: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.destroy_stream(stream)
        else:
            self._check("tsrDestroyStream",
                        self._lib.tsrDestroyStream(stream))
        self._record_event(
            "runtime.destroy_stream",
            latency_ms=_elapsed_ms(start_ns),
            stream=getattr(stream, "_id", None),
        )

    def stream_sync(self, stream: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.stream_sync(stream)
        else:
            self._check("tsrStreamSynchronize",
                        self._lib.tsrStreamSynchronize(stream))
        self._record_event(
            "runtime.stream_sync",
            latency_ms=_elapsed_ms(start_ns),
            stream=getattr(stream, "_id", None),
        )

    def create_event(self, dev: Any) -> Any:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            event = self._backend.create_event(dev)
            self._record_event(
                "runtime.create_event",
                latency_ms=_elapsed_ms(start_ns),
                device=getattr(dev, "_id", None),
                metadata={"event": getattr(event, "_id", None)},
            )
            return event
        h = ctypes.c_void_p(0)
        self._check("tsrCreateEvent",
                    self._lib.tsrCreateEvent(dev, ctypes.byref(h)))
        self._record_event("runtime.create_event", latency_ms=_elapsed_ms(start_ns), metadata={"event": h.value})
        return h

    def record_event(self, event: Any, stream: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.record_event(event, stream)
        else:
            self._check("tsrRecordEvent",
                        self._lib.tsrRecordEvent(event, stream))
        self._record_event(
            "runtime.record_event",
            latency_ms=_elapsed_ms(start_ns),
            stream=getattr(stream, "_id", None),
            metadata={
                "event": getattr(event, "_id", None),
                "timestamp_ns": self.event_get_timestamp(event),
            },
        )

    def wait_event(self, event: Any, stream: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.wait_event(event, stream)
        else:
            self._check("tsrWaitEvent",
                        self._lib.tsrWaitEvent(event, stream))
        self._record_event(
            "runtime.wait_event",
            latency_ms=_elapsed_ms(start_ns),
            stream=getattr(stream, "_id", None),
            metadata={"event": getattr(event, "_id", None)},
        )

    def event_sync(self, event: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.event_sync(event)
        else:
            self._check("tsrEventSynchronize",
                        self._lib.tsrEventSynchronize(event))
        self._record_event(
            "runtime.event_sync",
            latency_ms=_elapsed_ms(start_ns),
            metadata={"event": getattr(event, "_id", None)},
        )

    def destroy_event(self, event: Any) -> None:
        start_ns = time.perf_counter_ns()
        if self._mock_mode:
            self._backend.destroy_event(event)
        else:
            self._check("tsrDestroyEvent",
                        self._lib.tsrDestroyEvent(event))
        self._record_event(
            "runtime.destroy_event",
            latency_ms=_elapsed_ms(start_ns),
            metadata={"event": getattr(event, "_id", None)},
        )

    def event_get_timestamp(self, event: Any) -> int:
        """Return event timestamp in nanoseconds."""
        if self._mock_mode:
            return self._backend.event_get_timestamp(event)
        ts = ctypes.c_uint64(0)
        self._check("tsrEventGetTimestamp",
                    self._lib.tsrEventGetTimestamp(event, ctypes.byref(ts)))
        return ts.value

    # ------------------------------------------------------------------
    # Version / diagnostics
    # ------------------------------------------------------------------

    def get_version(self) -> tuple:
        if self._mock_mode:
            return self._backend.get_version()
        major = ctypes.c_int(0)
        minor = ctypes.c_int(0)
        patch = ctypes.c_int(0)
        self._lib.tsrGetVersion(ctypes.byref(major),
                                ctypes.byref(minor),
                                ctypes.byref(patch))
        return (major.value, minor.value, patch.value)

    def native_gemm_f32(self, dev: Any, a: Any, b: Any, c: Any, m: int, n: int, k: int) -> None:
        if self._mock_mode:
            raise TesseraRuntimeError("tsrNativeGemmF32", TsrStatus.UNIMPLEMENTED, "native GEMM requires the C runtime")
        if not hasattr(self._lib, "tsrNativeGemmF32"):
            raise TesseraRuntimeError("tsrNativeGemmF32", TsrStatus.UNIMPLEMENTED, "runtime ABI lacks tsrNativeGemmF32")
        self._check(
            "tsrNativeGemmF32",
            self._lib.tsrNativeGemmF32(
                dev,
                a,
                b,
                c,
                ctypes.c_int(m),
                ctypes.c_int(n),
                ctypes.c_int(k),
            ),
        )

    def get_worker_thread_count(self, dev: Any) -> int:
        if self._mock_mode:
            return 0
        if not hasattr(self._lib, "tsrGetWorkerThreadCount"):
            raise TesseraRuntimeError("tsrGetWorkerThreadCount", TsrStatus.UNIMPLEMENTED, "runtime ABI lacks tsrGetWorkerThreadCount")
        count = ctypes.c_uint32(0)
        self._check("tsrGetWorkerThreadCount", self._lib.tsrGetWorkerThreadCount(dev, ctypes.byref(count)))
        return int(count.value)

    def get_last_error(self) -> str:
        if self._mock_mode:
            return self._backend.get_last_error()
        err = self._lib.tsrGetLastError()
        return err.decode() if isinstance(err, bytes) else (err or "")

    def telemetry_events(self) -> list[dict[str, Any]]:
        return [dict(event) for event in self._telemetry_events]

    def telemetry_report(self) -> dict[str, Any]:
        events = self.telemetry_events()
        return {
            "schema": TELEMETRY_SCHEMA_VERSION,
            "source": "runtime",
            "summary": telemetry_report(events),
            "events": events,
        }

    def clear_telemetry(self) -> None:
        self._telemetry_events.clear()

    # ------------------------------------------------------------------
    # Properties
    # ------------------------------------------------------------------

    @property
    def is_mock(self) -> bool:
        """True when operating in pure-Python mock mode."""
        return self._mock_mode

    @property
    def is_initialized(self) -> bool:
        return self._initialized

    def __repr__(self) -> str:
        mode = "mock" if self._mock_mode else "native"
        return f"TesseraRuntime(mode={mode!r}, initialized={self._initialized})"

    def __enter__(self) -> "TesseraRuntime":
        self.init()
        return self

    def __exit__(self, *_) -> None:
        if self._initialized:
            self.shutdown()


def _runtime_snapshot() -> tuple[TesseraRuntime | None, list[DeviceProps]]:
    rt = TesseraRuntime()
    try:
        rt.init()
        devices = [rt.get_device_props(rt.get_device(i)) for i in range(rt.get_device_count())]
        return rt, devices
    except Exception:
        return None, []
    finally:
        if rt.is_initialized:
            rt.shutdown()


def available_backends() -> list[str]:
    """Return runtime backends discoverable through the current C ABI/mock."""
    _, devices = _runtime_snapshot()
    names = []
    for props in devices:
        if props.kind == DeviceKind.CPU:
            names.append("cpu")
        elif props.kind == DeviceKind.CUDA:
            names.append("cuda")
        elif props.kind == DeviceKind.HIP:
            names.append("rocm")
    return names or ["cpu"]


def backend_capabilities(target: str = "cpu") -> BackendCapability:
    """Describe current backend support without guessing executable kernels."""
    target = normalize_target(target)
    compiler_cap = get_target_capability(target)
    backends = available_backends()
    runtime_backend = compiler_cap.runtime_backend
    backend_name = "cuda" if runtime_backend == "cuda" else "rocm" if runtime_backend == "hip" else target
    if backend_name not in backends and target not in {"apple_cpu", "apple_gpu"}:
        return BackendCapability(
            name=target,
            available=False,
            executable=False,
            reason=f"{target} backend is not available",
        )
    if target == "cpu":
        return BackendCapability(
            name="cpu",
            available=True,
            executable=True,
            reason="CPU host-tile runtime is available; generated artifact launch remains limited",
            dtypes=("fp32", "f32"),
            features=("host_tile_launch", "memory", "events"),
        )
    status = compiler_runtime_status(target)
    return BackendCapability(
        name=target,
        available=True,
        executable=status == "ready",
        reason=compiler_cap.reason or f"{target} runtime status is {status}",
        dtypes=compiler_cap.supported_dtypes,
        features=compiler_cap.features,
    )


def query_backend(target: str = "cpu") -> dict[str, Any]:
    cap = backend_capabilities(target)
    result: dict[str, Any] = {
        "name": cap.name,
        "available": cap.available,
        "executable": cap.executable,
        "reason": cap.reason,
        "dtypes": list(cap.dtypes),
        "features": list(cap.features),
    }
    # Phase 3: for apple_gpu, attach the *observed* runtime capability snapshot
    # (the canonical source — a real Metal-4 probe). It is always explicit:
    # runtime_available=false + empty capabilities when the runtime can't load,
    # so this never makes a silent "Metal 4 full" claim.
    if target == "apple_gpu":
        from ._apple_gpu_dispatch import apple_gpu_capabilities_snapshot

        result["observed_capabilities"] = apple_gpu_capabilities_snapshot()
    return result


def compile(module_ir: str | RuntimeArtifact, target: str | None = None, options: dict[str, Any] | None = None) -> RuntimeArtifact:
    """Create a lightweight artifact container for the current compiler output.

    This is intentionally a containerization API, not a claim that Target IR can
    execute through the runtime yet.
    """
    if isinstance(module_ir, RuntimeArtifact):
        metadata = dict(module_ir.metadata or {})
        metadata.update({
            "target": target or metadata.get("target", "cpu"),
            "options": options or metadata.get("options", {}) or {},
        })
        return RuntimeArtifact(
            graph_ir=module_ir.graph_ir,
            schedule_ir=module_ir.schedule_ir,
            tile_ir=module_ir.tile_ir,
            target_ir=module_ir.target_ir,
            metadata=metadata,
            abi_signature=module_ir.abi_signature,
        )
    meta: dict[str, Any] = {
        "target": target or "cpu",
        "options": options or {},
        "runtime_status": "artifact_only",
    }
    # Phase 3: pure containerization of an apple_gpu module is an ARTIFACT, not a
    # runtime claim — stamp the metal_artifact descriptor (never metal_runtime /
    # mtl4_runtime) and its required_capabilities. No observed_capabilities: no
    # runtime probe ran here.
    if (target or "") == "apple_gpu":
        from .compiler.apple_target_descriptor import (
            METAL_ARTIFACT,
            apple_target_descriptor,
        )

        desc = apple_target_descriptor(METAL_ARTIFACT)
        meta["target_descriptor"] = desc
        meta["required_capabilities"] = desc["required_capabilities"]
    return RuntimeArtifact(
        graph_ir=str(module_ir),
        metadata=meta,
        abi_signature=f"tessera.runtime.v1.{target or 'cpu'}",
    )


def load_artifact(path_or_bytes: str | bytes | os.PathLike[str] | RuntimeArtifact) -> RuntimeArtifact:
    if isinstance(path_or_bytes, RuntimeArtifact):
        return path_or_bytes
    if isinstance(path_or_bytes, bytes):
        return RuntimeArtifact.from_json(path_or_bytes)
    if isinstance(path_or_bytes, str):
        payload = path_or_bytes.lstrip()
        if payload.startswith(("{", "[")):
            return RuntimeArtifact.from_json(path_or_bytes)
        candidate = Path(path_or_bytes)
        if candidate.exists():
            return RuntimeArtifact.from_json(candidate.read_text(encoding="utf-8"))
        return RuntimeArtifact.from_json(path_or_bytes)
    if isinstance(path_or_bytes, os.PathLike) and Path(path_or_bytes).exists():
        return RuntimeArtifact.from_json(Path(path_or_bytes).read_text(encoding="utf-8"))
    raise TypeError(f"unsupported artifact input: {type(path_or_bytes)!r}")


# G6 — executor functions, keyed by ExecutionRow.executor_id from the matrix.
# launch() consults the matrix to pick the executor; adding a new backend
# executor is now (1) add the function here, (2) add it to KNOWN_EXECUTORS in
# execution_matrix.py, (3) add the matrix row. No new branch in launch().
#
# Executors return either:
#   - the raw output (matrix row's execution_kind is reported as-is), or
#   - a (output, override_execution_kind) tuple — for executors with an internal
#     fallback chain (e.g. native_cpu -> reference_cpu) that need to report a
#     different execution_kind on success than the row's default.
def _execute_cpu_native_or_jit(artifact, args):
    """G6.1 — CPU executor that preserves the native_cpu -> reference_cpu
    fallback chain from the prior inline path. Tries the AMX/native CPU
    artifact first; if it raises, falls back to the JIT numpy reference path
    and reports execution_kind='reference_cpu' on success. Returns
    (output, execution_kind) so launch() can override the matrix row's
    default execution_kind on the fallback path."""
    try:
        return _execute_native_cpu_artifact(artifact, args), "native_cpu"
    except Exception:
        # Re-raise the JIT error if THAT fails too — preserves the existing
        # "invalid_artifact" reporting (the native exc is dropped because the
        # JIT path is the canonical CPU fallback and its error is more
        # informative than the AMX one).
        return _execute_jit_cpu_artifact(artifact, args), "reference_cpu"


_rocm_dspark_draft_block_hsaco_cache: dict[tuple[str], bytes] = {}


def _execute_rocm_dspark_draft_block_reference(artifact: RuntimeArtifact, args: Any) -> Any:
    """DS2 executor for ``rocm_dspark_draft_block_compiled``.

    Attempts the compiler-generated fused ROCm draft-block kernel first.  When
    ROCm is unavailable in the current environment, it falls back to the DS1
    NumPy oracle and reports ``reference_cpu`` so hardware-free tests still pin
    the ABI.
    """
    import numpy as np

    from .stdlib import dspark

    metadata = artifact.metadata or {}
    if isinstance(args, Mapping):
        values = dict(args)
    else:
        arg_names = list(metadata.get("arg_names") or [
            "target_hidden", "prev_tokens", "anchors", "weights",
        ])
        values = _bind_launch_args(args, arg_names)
    try:
        target_hidden = values["target_hidden"]
        prev_tokens = values["prev_tokens"]
        anchors = values["anchors"]
        weights = values["weights"]
    except KeyError as exc:
        raise ValueError(f"missing DSpark draft-block argument {exc.args[0]!r}") from exc

    if not isinstance(weights, dspark.DSparkWeights):
        if not isinstance(weights, Mapping):
            raise TypeError("weights must be DSparkWeights or a mapping of weight arrays")
        weights = dspark.DSparkWeights(**weights)

    cfg_meta = dict(metadata.get("dspark_config") or {})
    if "num_anchors" not in cfg_meta:
        cfg_meta["num_anchors"] = int(np.asarray(anchors).reshape(-1).shape[0])
    if "block_size" not in cfg_meta:
        cfg_meta["block_size"] = int(metadata.get("block_size", 0))
    if "vocab_size" not in cfg_meta:
        cfg_meta["vocab_size"] = int(np.asarray(weights.token_embedding).shape[0])
    if int(cfg_meta["block_size"]) <= 0:
        raise ValueError("dspark_config.block_size must be provided and positive")
    cfg = dspark.DSparkConfig(**cfg_meta)
    try:
        return (
            _rocm_dspark_draft_block_native(
                target_hidden, prev_tokens, anchors, weights, cfg, np),
            "native_gpu",
        )
    except _RocmCompiledUnavailable:
        pass

    out = dspark.draft_block_forward(target_hidden, prev_tokens, anchors, weights, cfg)
    return ({
        "logits": out.logits,
        "confidence_logits": out.confidence_logits,
        "tokens": out.tokens,
        "hidden": out.hidden,
    }, "reference_cpu")


def _rocm_dspark_draft_block_native(target_hidden: Any, prev_tokens: Any,
                                    anchors: Any, weights: Any, cfg: Any,
                                    np: Any) -> dict[str, Any]:
    """Run the generated DS2 fused draft-block kernel on ROCm. f32/i64 ABI."""
    chip = _rocm_chip()
    directive = (
        'module {\n'
        '  "tessera_rocm.dspark_draft_block"() {name = "ds"} : () -> ()\n'
        '}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-dspark-draft-block-kernel", directive,
        _rocm_dspark_draft_block_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm dspark draft-block: hipInit failed")

    th = np.ascontiguousarray(_as_numpy(target_hidden), dtype=np.float32)
    pt = np.ascontiguousarray(_as_numpy(prev_tokens).reshape(-1), dtype=np.int64)
    anc = np.ascontiguousarray(_as_numpy(anchors).reshape(-1), dtype=np.int64)
    emb = np.ascontiguousarray(_as_numpy(weights.token_embedding), dtype=np.float32)
    hp = np.ascontiguousarray(_as_numpy(weights.hidden_proj), dtype=np.float32)
    tp = np.ascontiguousarray(_as_numpy(weights.token_proj), dtype=np.float32)
    op = np.ascontiguousarray(_as_numpy(weights.out_proj), dtype=np.float32)
    cp = np.ascontiguousarray(_as_numpy(weights.confidence_proj), dtype=np.float32)
    has_markov = weights.markov is not None
    mk = np.ascontiguousarray(
        np.zeros((1, emb.shape[1]), dtype=np.float32)
        if weights.markov is None else _as_numpy(weights.markov),
        dtype=np.float32,
    )

    if th.ndim != 3:
        raise ValueError("target_hidden must be (B, S, H)")
    B, S, H = map(int, th.shape)
    A = int(cfg.num_anchors)
    D = int(cfg.block_size)
    V = int(cfg.vocab_size)
    if pt.shape != (B,):
        raise ValueError("prev_tokens must be (B,)")
    if anc.shape != (A,):
        raise ValueError("anchors must be (num_anchors,)")
    if emb.shape != (V, H):
        raise ValueError("token_embedding must be (V, H)")
    if hp.shape != (H, H) or tp.shape != (H, H):
        raise ValueError("hidden_proj/token_proj must be (H, H)")
    if op.shape != (H, V) or cp.shape != (H,):
        raise ValueError("out_proj/confidence_proj shapes do not match cfg")
    if has_markov and mk.shape != (V, H):
        raise ValueError("markov must be (V, H)")

    logits = np.zeros((B, A, D, V), dtype=np.float32)
    conf = np.zeros((B, A, D), dtype=np.float32)
    tokens = np.zeros((B, A, D), dtype=np.int64)
    hidden = np.zeros((B, A, D, H), dtype=np.float32)

    f32_arrays = [th.reshape(-1), emb.reshape(-1), hp.reshape(-1), tp.reshape(-1),
                  op.reshape(-1), cp.reshape(-1), mk.reshape(-1),
                  logits.reshape(-1), conf.reshape(-1), hidden.reshape(-1)]
    i64_arrays = [pt, anc, tokens.reshape(-1)]
    devs: list[Any] = []
    try:
        d_th = _rocm_dev_in(hip, f32_arrays[0], 4 * f32_arrays[0].size); devs.append(d_th)
        d_pt = _rocm_dev_in(hip, i64_arrays[0], 8 * i64_arrays[0].size); devs.append(d_pt)
        d_anc = _rocm_dev_in(hip, i64_arrays[1], 8 * i64_arrays[1].size); devs.append(d_anc)
        d_emb = _rocm_dev_in(hip, f32_arrays[1], 4 * f32_arrays[1].size); devs.append(d_emb)
        d_hp = _rocm_dev_in(hip, f32_arrays[2], 4 * f32_arrays[2].size); devs.append(d_hp)
        d_tp = _rocm_dev_in(hip, f32_arrays[3], 4 * f32_arrays[3].size); devs.append(d_tp)
        d_op = _rocm_dev_in(hip, f32_arrays[4], 4 * f32_arrays[4].size); devs.append(d_op)
        d_cp = _rocm_dev_in(hip, f32_arrays[5], 4 * f32_arrays[5].size); devs.append(d_cp)
        d_mk = _rocm_dev_in(hip, f32_arrays[6], 4 * f32_arrays[6].size); devs.append(d_mk)
        d_logits = _rocm_dev_in(hip, f32_arrays[7], 4 * f32_arrays[7].size); devs.append(d_logits)
        d_conf = _rocm_dev_in(hip, f32_arrays[8], 4 * f32_arrays[8].size); devs.append(d_conf)
        d_tokens = _rocm_dev_in(hip, i64_arrays[2], 8 * i64_arrays[2].size); devs.append(d_tokens)
        d_hidden = _rocm_dev_in(hip, f32_arrays[9], 4 * f32_arrays[9].size); devs.append(d_hidden)
        _rocm_sparse_launch(
            hsaco, b"ds",
            [(d_th, th.size), (d_pt, pt.size), (d_anc, anc.size),
             (d_emb, emb.size), (d_hp, hp.size), (d_tp, tp.size),
             (d_op, op.size), (d_cp, cp.size), (d_mk, mk.size),
             (d_logits, logits.size), (d_conf, conf.size),
             (d_tokens, tokens.size), (d_hidden, hidden.size)],
            [B, S, H, A, D, V, 1 if has_markov else 0],
            B * A)
        hip.hipMemcpy(logits.ctypes.data_as(ctypes.c_void_p), d_logits,
                      4 * logits.size, 2)
        hip.hipMemcpy(conf.ctypes.data_as(ctypes.c_void_p), d_conf,
                      4 * conf.size, 2)
        hip.hipMemcpy(tokens.ctypes.data_as(ctypes.c_void_p), d_tokens,
                      8 * tokens.size, 2)
        hip.hipMemcpy(hidden.ctypes.data_as(ctypes.c_void_p), d_hidden,
                      4 * hidden.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)

    return {
        "logits": logits,
        "confidence_logits": conf,
        "tokens": tokens,
        "hidden": hidden,
    }


def _execute_rocm_dequant_gemm_reference(artifact: RuntimeArtifact, args: Any) -> Any:
    """DK4 transition executor for ``rocm_dequant_gemm_compiled``.

    Runs the packed-weight NumPy oracle while preserving the runtime ABI and
    reporting ``reference_cpu``.  Native promotion replaces this body with the
    fused HIP dequant-into-GEMM kernel, not a different user contract.
    """
    import numpy as np

    from .stdlib import quant

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or ["x", "packed_w"])
    values = dict(args) if isinstance(args, Mapping) else _bind_launch_args(args, arg_names)
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else "tessera.dequant_matmul"
    if op_name == "tessera.dequant_matmul":
        try:
            return (
                _rocm_dequant_matmul_native(values["x"], values["packed_w"], np),
                "native_gpu",
            )
        except _RocmCompiledUnavailable:
            pass
        try:
            return (
                quant.dequant_matmul(values["x"], values["packed_w"], backend="reference"),
                "reference_cpu",
            )
        except KeyError as exc:
            raise ValueError(f"missing dequant_matmul argument {exc.args[0]!r}") from exc
    if op_name == "tessera.dequant_grouped_gemm":
        try:
            return (
                _rocm_dequant_grouped_gemm_native(
                    values["x"], values["packed_experts"], values["group_sizes"], np),
                "native_gpu",
            )
        except _RocmCompiledUnavailable:
            pass
        try:
            return (
                quant.dequant_grouped_gemm(
                    values["x"], values["packed_experts"], values["group_sizes"],
                    backend="reference"),
                "reference_cpu",
            )
        except KeyError as exc:
            raise ValueError(
                f"missing dequant_grouped_gemm argument {exc.args[0]!r}") from exc
    raise ValueError(
        "rocm_dequant_gemm_compiled executor handles tessera.dequant_matmul "
        f"or tessera.dequant_grouped_gemm; got {op_name!r}")


_rocm_dequant_gemm_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_dequant_gemm_hsaco() -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        '  "tessera_rocm.dequant_gemm"() {name = "dq"} : () -> ()\n'
        '}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-dequant-gemm-kernel", directive,
        _rocm_dequant_gemm_hsaco_cache, (chip,))


def _rocm_dequant_matmul_native(x: Any, packed_w: Any, np: Any) -> Any:
    """Run DK4 packed int4/int8 dequantize-into-GEMM on ROCm. f32 accumulate."""
    scheme = packed_w.scheme
    if scheme.dtype not in ("int4", "int8"):
        raise _RocmCompiledUnavailable(
            f"rocm dequant_gemm native handles int4/int8; got {scheme.dtype!r}")
    xa = np.ascontiguousarray(_as_numpy(x), dtype=np.float32)
    if xa.ndim != 2:
        raise _RocmCompiledUnavailable("rocm dequant_gemm native handles rank-2 x")
    K, N = map(int, packed_w.shape)
    M = int(xa.shape[0])
    if int(xa.shape[1]) != K:
        raise ValueError(f"dequant_matmul: x last dim {xa.shape[1]} != weight K {K}")
    g = int(scheme.group_size if scheme.group_size is not None else K)
    if K % g != 0:
        raise ValueError(f"dequant_matmul: K={K} must be divisible by group_size={g}")
    if scheme.dtype == "int4":
        codes = np.ascontiguousarray(np.asarray(packed_w.codes, dtype=np.uint8)).view(np.int8)
        mode = 4
    else:
        codes = np.ascontiguousarray(np.asarray(packed_w.codes, dtype=np.int8))
        mode = 8
    scales = np.ascontiguousarray(np.asarray(packed_w.scales, dtype=np.float32))
    if scales.shape != (K // g, N):
        raise ValueError(f"scales must be ({K // g}, {N}); got {scales.shape}")

    hsaco = _rocm_dequant_gemm_hsaco()
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm dequant_gemm: hipInit failed")
    out = np.zeros((M, N), dtype=np.float32)
    devs: list[Any] = []
    try:
        d_x = _rocm_dev_in(hip, xa.reshape(-1), 4 * xa.size); devs.append(d_x)
        d_c = _rocm_dev_in(hip, codes.reshape(-1), codes.size); devs.append(d_c)
        d_s = _rocm_dev_in(hip, scales.reshape(-1), 4 * scales.size); devs.append(d_s)
        d_o = _rocm_dev_in(hip, out.reshape(-1), 4 * out.size); devs.append(d_o)
        _rocm_sparse_launch(
            hsaco, b"dq",
            [(d_x, xa.size), (d_c, codes.size), (d_s, scales.size), (d_o, out.size)],
            [M, K, N, g, mode],
            M * N)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_o, 4 * out.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)
    return out


def _rocm_dequant_grouped_gemm_native(x: Any, packed_experts: Any,
                                      group_sizes: Any, np: Any) -> Any:
    xa = np.ascontiguousarray(_as_numpy(x), dtype=np.float32)
    experts = list(packed_experts)
    gs = np.asarray(group_sizes, dtype=np.int64).reshape(-1)
    if gs.shape[0] != len(experts):
        raise ValueError(f"group_sizes has {gs.shape[0]} groups but {len(experts)} experts")
    if not experts:
        raise ValueError("packed_experts must be non-empty")
    N = int(experts[0].shape[1])
    out = np.zeros((int(xa.shape[0]), N), dtype=np.float32)
    off = 0
    for e, packed in enumerate(experts):
        n = int(gs[e])
        if n:
            out[off:off + n] = _rocm_dequant_matmul_native(xa[off:off + n], packed, np)
        off += n
    return out


def _moe_dispatch_native(x: Any, plan: Any, np: Any) -> Any:
    """DK3 dispatch = gather the token row for each kept, expert-sorted slot
    (token_of_slot = sort_perm // top_k) on the gfx1151 device gather kernel.
    Exact vs the numpy gather (pure row movement, f32)."""
    xa = np.ascontiguousarray(_as_numpy(x), np.float32)
    if xa.ndim != 2:
        raise ValueError(f"moe_dispatch x must be 2-D (T,H); got {xa.shape}")
    tof = (np.asarray(plan.sort_perm, np.int64) // int(plan.top_k))
    if tof.shape[0] == 0:
        return np.zeros((0, int(xa.shape[1])), np.float32)
    return _rocm_gather_rows(xa, tof, np)


def _moe_combine_native(y_packed: Any, plan: Any, np: Any) -> Any:
    """DK3 combine = weighted scatter-add of the packed expert rows back to token
    order: out[t] += w[slot]*yp[i], t = slot // top_k. Host pre-scales each row
    by its route weight (exact f32), then the gfx1151 device scatter kernel
    (mode add) accumulates into the token rows. f32 accumulate."""
    yp = np.ascontiguousarray(_as_numpy(y_packed), np.float32)
    if yp.ndim != 2:
        raise ValueError(f"moe_combine partials must be 2-D (S,H); got {yp.shape}")
    S, H = int(yp.shape[0]), int(yp.shape[1])
    T = int(plan.num_tokens)
    out = np.zeros((T, H), np.float32)
    if S == 0:
        return out
    slots = np.asarray(plan.sort_perm, np.int64)
    w = np.asarray(plan.weights, np.float32).reshape(-1)[slots].reshape(S, 1)
    scaled = np.ascontiguousarray(yp * w, np.float32)
    tof = (slots // int(plan.top_k)).astype(np.int64)
    _rocm_scatter(out, scaled, tof, T, H, 1, np)   # mode 1 = atomic add
    return out


def _execute_rocm_moe_transport(artifact: RuntimeArtifact, args: Any) -> Any:
    """``rocm_moe_transport_compiled`` executor. The transport ops run natively
    on gfx1151 — ``moe_dispatch`` on the device gather kernel, ``moe_combine`` on
    the device scatter (add) kernel — and report ``native_gpu`` (falling back to
    the stdlib oracle + ``reference_cpu`` when tessera-opt / a GPU is absent).
    ``grouped_swiglu`` (the expert GEMM) stays on the stdlib oracle and reports
    ``reference_cpu`` — a native f32-exact grouped GEMM is a separate follow-up.
    Per-op ``execution_kind`` via the ``(output, kind)`` launch override."""
    import numpy as np
    from .stdlib import moe

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or ["x", "plan"])
    values = dict(args) if isinstance(args, Mapping) else _bind_launch_args(args, arg_names)
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""

    if op_name == "tessera.moe_dispatch":
        try:
            x, plan = values["x"], values["plan"]
        except KeyError as exc:
            raise ValueError(f"missing moe_dispatch argument {exc.args[0]!r}") from exc
        try:
            return (_moe_dispatch_native(x, plan, np), "native_gpu")
        except _RocmCompiledUnavailable:
            return (moe.dispatch(x, plan), "reference_cpu")
    if op_name == "tessera.moe_combine":
        try:
            partials, plan = values["partials"], values["plan"]
        except KeyError as exc:
            raise ValueError(f"missing moe_combine argument {exc.args[0]!r}") from exc
        try:
            return (_moe_combine_native(partials, plan, np), "native_gpu")
        except _RocmCompiledUnavailable:
            return (moe.combine(partials, plan), "reference_cpu")
    if op_name == "tessera.grouped_swiglu":
        try:
            gvals = (values["x_packed"], values["w_gate"], values["w_up"],
                     values["w_down"], values["group_sizes"])
        except KeyError as exc:
            raise ValueError(f"missing grouped_swiglu argument {exc.args[0]!r}") from exc
        # Expert GEMM runs natively on the f32 GEMM device kernel (three GEMMs +
        # host silu*mul per group); falls back to the f64 oracle off-box.
        try:
            return (_moe_grouped_swiglu_native(*gvals, np), "native_gpu")
        except _RocmCompiledUnavailable:
            return (moe.grouped_swiglu(*gvals), "reference_cpu")
    raise ValueError(
        "rocm_moe_transport_compiled executor handles tessera.moe_dispatch, "
        "tessera.moe_combine, or tessera.grouped_swiglu; "
        f"got {op_name!r}")


# ─────────────────────────────────────────────────────────────────────────────
# ROCm WMMA GEMM executor (Strix Halo bring-up, 2026-06-22).
#
# The shipped libtessera_rocm_gemm.so exports the C-ABI GEMM symbols
# ``tessera_rocm_wmma_gemm_f16`` / ``tessera_rocm_wmma_gemm_bf16``
# (signature ``(const void* A, const void* B, void* D, int M, int N, int K)``)
# that run a real RDNA WMMA matrix-core GEMM on the AMD GPU — the kernel is
# HIPRTC-compiled for the device arch (gfx1151 / gfx1100) at load. This executor
# is the ``runtime.launch()`` dispatch lane for ``target="rocm"`` artifacts whose
# ``compiler_path == "rocm_wmma"`` (one matmul/gemm op, half-precision storage,
# f32 accumulate).
#
# Host-gated exactly like the Apple GPU lane: the lib + a live HIP device exist
# only on a ROCm box, so the loader/probe return None / False elsewhere and the
# jit path never stamps ``executable=True`` (``launch()`` reports
# ``unimplemented`` via the matrix's _UNIMPLEMENTED reason instead). Nothing here
# is reachable — or claims to be — on a host without an AMD GPU.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_gemm_runtime: ctypes.CDLL | None = None
_rocm_gemm_probe_ok: bool | None = None
#: Cached probe for the compiler-generated ROCm WMMA flash_attn forward lane
#: (separate from the GEMM lane — it shells to ``tessera-opt`` + a live GPU).
_rocm_compiled_flash_attn_probe_ok: bool | None = None
#: Cached probe for the compiler-generated f32 GEMM lane
#: (generate-rocm-gemm-f32-kernel — a DIFFERENT pass from the flash lane).
_rocm_compiled_gemm_f32_probe_ok: bool | None = None

#: C-ABI GEMM symbols shipped by libtessera_rocm_gemm.so, keyed by storage dtype.
_ROCM_GEMM_SYMBOLS = {
    "float16": "tessera_rocm_wmma_gemm_f16",
    "bfloat16": "tessera_rocm_wmma_gemm_bf16",
}


def _rocm_gemm_lib_path() -> Optional[Path]:
    """Locate the shipped GEMM lib (env override → canonical CMake build dir)."""
    env = os.environ.get("TESSERA_ROCM_GEMM_LIB")
    candidates: list[Path] = []
    if env:
        candidates.append(Path(env))
    root = Path(__file__).resolve().parents[2]
    candidates.append(
        root / "build/src/compiler/codegen/Tessera_ROCM_Backend/runtime/hip"
        / "libtessera_rocm_gemm.so")
    for c in candidates:
        if c.is_file():
            return c
    return None


def _load_rocm_gemm_runtime() -> ctypes.CDLL | None:
    """Load libtessera_rocm_gemm.so once, binding the GEMM symbol signatures.
    Preloads the HIP runtime + HIPRTC globally so the lib resolves them. Returns
    None (never raises) when the lib / ROCm deps are absent — the caller treats
    that as "no ROCm execution lane on this host"."""
    global _rocm_gemm_runtime
    if _rocm_gemm_runtime is not None:
        return _rocm_gemm_runtime
    path = _rocm_gemm_lib_path()
    if path is None:
        return None
    rocm_lib = os.path.join(os.environ.get("ROCM_PATH", "/opt/rocm"), "lib")
    for dep in ("libamdhip64.so", "libhiprtc.so"):
        p = os.path.join(rocm_lib, dep)
        if os.path.isfile(p):
            try:
                ctypes.CDLL(p, mode=ctypes.RTLD_GLOBAL)
            except OSError:
                pass
    try:
        lib = ctypes.CDLL(str(path), mode=ctypes.RTLD_GLOBAL)
    except OSError:
        return None
    for sym in _ROCM_GEMM_SYMBOLS.values():
        fn = getattr(lib, sym, None)
        if fn is None:
            # Older build without the bf16 sibling — bind what exists; the
            # executor validates the specific symbol it needs per-dtype.
            continue
        fn.argtypes = [ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p,
                       ctypes.c_int, ctypes.c_int, ctypes.c_int]
        fn.restype = ctypes.c_int
    _rocm_gemm_runtime = lib
    return lib


def _rocm_wmma_runtime_available() -> bool:
    """Cached host probe: True iff the GEMM lib loads AND a real HIP device runs
    a tiny WMMA GEMM (rc == 0). This is the gate the jit path consults before
    stamping a rocm artifact ``executable`` — so ``native_gpu`` is never claimed
    on a host without an AMD GPU. The probe runs the f16 symbol on a 16×16×16
    zero GEMM; rc==2 (no device / no HIPRTC) ⇒ unavailable."""
    global _rocm_gemm_probe_ok
    if _rocm_gemm_probe_ok is not None:
        return _rocm_gemm_probe_ok
    _rocm_gemm_probe_ok = False
    lib = _load_rocm_gemm_runtime()
    if lib is None:
        return False
    fn = getattr(lib, _ROCM_GEMM_SYMBOLS["float16"], None)
    if fn is None:
        return False
    try:
        import numpy as np
    except Exception:
        return False
    a = np.zeros((16, 16), np.float16)
    b = np.zeros((16, 16), np.float16)
    d = np.zeros((16, 16), np.float32)
    try:
        rc = fn(a.ctypes.data_as(ctypes.c_void_p),
                b.ctypes.data_as(ctypes.c_void_p),
                d.ctypes.data_as(ctypes.c_void_p), 16, 16, 16)
    except Exception:
        return False
    _rocm_gemm_probe_ok = (rc == 0)
    return _rocm_gemm_probe_ok


def _rocm_compiled_flash_attn_available() -> bool:
    """Cached host probe: True iff the compiler-generated ROCm WMMA flash_attn
    forward can actually run — i.e. ``tessera-opt`` is built AND a live gfx1151
    executes the tiny probe attention without raising ``_RocmCompiledUnavailable``.
    Separate from ``_rocm_wmma_runtime_available`` because the flash lane shells
    out to the compiler rather than the shipped GEMM symbol. Never fabricates:
    on a host without the compiler/GPU it returns False, so the perf recorder
    skip-cleans the flash-attn row (repo Decision #26)."""
    global _rocm_compiled_flash_attn_probe_ok
    if _rocm_compiled_flash_attn_probe_ok is not None:
        return _rocm_compiled_flash_attn_probe_ok
    _rocm_compiled_flash_attn_probe_ok = False
    try:
        import numpy as np
    except Exception:
        return False
    q = np.zeros((1, 1, 16, 16), np.float16)
    try:
        _rocm_flash_attn(q, q, q, causal=True)
        _rocm_compiled_flash_attn_probe_ok = True
    except Exception:
        _rocm_compiled_flash_attn_probe_ok = False
    return _rocm_compiled_flash_attn_probe_ok


def _rocm_compiled_gemm_f32_available() -> bool:
    """Cached host probe: True iff the compiler-generated f32 GEMM lane can run —
    i.e. ``tessera-opt`` is built AND a live gfx1151 executes a tiny
    ``_rocm_f32_gemm`` without raising. Its own probe (NOT the flash-attn one):
    ``generate-rocm-gemm-f32-kernel`` is a DIFFERENT compiler pass, so a host
    where the f32 GEMM works but the flash lane is missing/broken still records
    (and re-times) its gemm_f32 ratchet rows. Never fabricates (Decision #26)."""
    global _rocm_compiled_gemm_f32_probe_ok
    if _rocm_compiled_gemm_f32_probe_ok is not None:
        return _rocm_compiled_gemm_f32_probe_ok
    _rocm_compiled_gemm_f32_probe_ok = False
    try:
        import numpy as np
        a = np.zeros((1, 1), np.float32)
        _rocm_f32_gemm(a, a, np)
        _rocm_compiled_gemm_f32_probe_ok = True
    except Exception:
        _rocm_compiled_gemm_f32_probe_ok = False
    return _rocm_compiled_gemm_f32_probe_ok


def _execute_rocm_wmma_artifact(artifact: RuntimeArtifact, args: Any) -> Any:
    """Execute a ``target="rocm"`` single-matmul artifact on the AMD GPU through
    the shipped ``tessera_rocm_wmma_gemm_{f16,bf16}`` C-ABI symbol (RDNA WMMA,
    f32 accumulate). Returns the f32 result matrix. Raises on a missing lib /
    device, an unsupported op set, or a kernel error — ``launch()`` maps the
    raise to ``invalid_artifact``."""
    import numpy as np

    lib = _load_rocm_gemm_runtime()
    if lib is None:
        raise RuntimeError(
            "libtessera_rocm_gemm.so not loadable — no ROCm execution lane "
            "on this host (build target: tessera_rocm_gemm)")

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) not in (
            "tessera.matmul", "tessera.gemm"):
        raise ValueError(
            "rocm_wmma executor handles exactly one matmul/gemm op; got "
            f"{[o.get('op_name') for o in ops]!r}")

    values = _bind_launch_args(args, arg_names)
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) != 2:
        raise ValueError("matmul requires exactly two operands")
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    if a.ndim != 2 or b.ndim != 2 or a.shape[1] != b.shape[0]:
        raise ValueError(
            f"rocm_wmma matmul needs rank-2 operands with matching K; got "
            f"{a.shape} @ {b.shape}")

    bf16 = _bfloat16_dtype()
    if a.dtype == np.float16 and b.dtype == np.float16:
        sym, store = _ROCM_GEMM_SYMBOLS["float16"], np.float16
    elif bf16 is not None and a.dtype == bf16 and b.dtype == bf16:
        sym, store = _ROCM_GEMM_SYMBOLS["bfloat16"], bf16
    else:
        raise ValueError(
            "rocm_wmma executor handles f16/bf16 storage (f32 accumulate); got "
            f"{a.dtype} @ {b.dtype}")
    fn = getattr(lib, sym, None)
    if fn is None:
        raise RuntimeError(
            f"libtessera_rocm_gemm.so lacks {sym} — rebuild the tessera_rocm_gemm "
            f"target for {store!r} support")

    m, k = a.shape
    n = b.shape[1]
    a_c = np.ascontiguousarray(a, dtype=store)
    b_c = np.ascontiguousarray(b, dtype=store)
    d = np.zeros((m, n), dtype=np.float32)
    rc = fn(a_c.ctypes.data_as(ctypes.c_void_p),
            b_c.ctypes.data_as(ctypes.c_void_p),
            d.ctypes.data_as(ctypes.c_void_p), int(m), int(n), int(k))
    if rc == 1:
        raise ValueError(
            f"rocm_wmma kernel rejected shape ({m}x{n}x{k}) — M/N/K must be "
            f"positive")
    if rc == 2:
        raise RuntimeError("rocm_wmma: no usable AMD GPU / HIPRTC at launch")
    if rc != 0:
        raise RuntimeError(f"rocm_wmma kernel returned rc={rc}")
    return d


# ─────────────────────────────────────────────────────────────────────────────
# NVIDIA mma.sync GEMM lane — the consumer-Blackwell analog of rocm_wmma.
# Dispatches a single matmul to the shipped libtessera_nvidia_gemm.so symbols
# (NVRTC-compiled warp-level mma.sync for the device arch). Mirror of the ROCm
# block above; same shipped-symbol contract, CUDA driver instead of HIP.
# ─────────────────────────────────────────────────────────────────────────────
_nvidia_gemm_runtime: ctypes.CDLL | None = None
_nvidia_gemm_probe_ok: bool | None = None

#: C-ABI GEMM symbols shipped by libtessera_nvidia_gemm.so, keyed by storage
#: dtype. fp32 storage runs tf32-math (mma.sync m16n8k8.tf32).
_NVIDIA_GEMM_SYMBOLS = {
    "float16": "tessera_nvidia_mma_gemm_f16",
    "bfloat16": "tessera_nvidia_mma_gemm_bf16",
    "float32": "tessera_nvidia_mma_gemm_tf32",
}


def _nvidia_gemm_lib_path() -> Optional[Path]:
    """Locate the shipped GEMM lib (env override → canonical CMake build dir)."""
    env = os.environ.get("TESSERA_NVIDIA_GEMM_LIB")
    candidates: list[Path] = []
    if env:
        candidates.append(Path(env))
    root = Path(__file__).resolve().parents[2]
    candidates.append(
        root / "build/src/compiler/codegen/tessera_gpu_backend_NVIDIA/runtime/cuda"
        / "libtessera_nvidia_gemm.so")
    for c in candidates:
        if c.is_file():
            return c
    return None


def _load_nvidia_gemm_runtime() -> ctypes.CDLL | None:
    """Load libtessera_nvidia_gemm.so once, binding the GEMM symbol signatures.
    Preloads the CUDA driver + NVRTC globally so the lib resolves them. Returns
    None (never raises) when the lib / CUDA deps are absent — the caller treats
    that as "no NVIDIA execution lane on this host"."""
    global _nvidia_gemm_runtime
    if _nvidia_gemm_runtime is not None:
        return _nvidia_gemm_runtime
    path = _nvidia_gemm_lib_path()
    if path is None:
        return None
    cuda_dirs = ["/usr/lib/wsl/lib",
                 os.path.join(os.environ.get("CUDA_PATH", "/usr/local/cuda"), "lib64")]
    for dep in ("libcuda.so.1", "libcuda.so", "libnvrtc.so"):
        for d in cuda_dirs:
            p = os.path.join(d, dep)
            if os.path.isfile(p):
                try:
                    ctypes.CDLL(p, mode=ctypes.RTLD_GLOBAL)
                except OSError:
                    pass
                break
    try:
        lib = ctypes.CDLL(str(path), mode=ctypes.RTLD_GLOBAL)
    except OSError:
        return None
    for sym in _NVIDIA_GEMM_SYMBOLS.values():
        fn = getattr(lib, sym, None)
        if fn is None:
            continue
        fn.argtypes = [ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p,
                       ctypes.c_int, ctypes.c_int, ctypes.c_int]
        fn.restype = ctypes.c_int
    _nvidia_gemm_runtime = lib
    return lib


def _nvidia_mma_runtime_available() -> bool:
    """Cached host probe: True iff the GEMM lib loads AND a real NVIDIA device
    runs a tiny mma.sync GEMM (rc == 0). The gate the jit path consults before
    stamping an nvidia artifact ``executable`` — so ``native_gpu`` is never
    claimed on a host without an NVIDIA GPU. rc==2 (no device / no NVRTC) ⇒
    unavailable."""
    global _nvidia_gemm_probe_ok
    if _nvidia_gemm_probe_ok is not None:
        return _nvidia_gemm_probe_ok
    _nvidia_gemm_probe_ok = False
    lib = _load_nvidia_gemm_runtime()
    if lib is None:
        return False
    fn = getattr(lib, _NVIDIA_GEMM_SYMBOLS["float16"], None)
    if fn is None:
        return False
    try:
        import numpy as np
    except Exception:
        return False
    a = np.zeros((16, 16), np.float16)
    b = np.zeros((16, 16), np.float16)
    d = np.zeros((16, 16), np.float32)
    try:
        rc = fn(a.ctypes.data_as(ctypes.c_void_p),
                b.ctypes.data_as(ctypes.c_void_p),
                d.ctypes.data_as(ctypes.c_void_p), 16, 16, 16)
    except Exception:
        return False
    _nvidia_gemm_probe_ok = (rc == 0)
    return _nvidia_gemm_probe_ok


def _execute_nvidia_mma_artifact(artifact: RuntimeArtifact, args: Any) -> Any:
    """Execute a ``target="nvidia_sm120"`` single-matmul artifact on the NVIDIA
    GPU through the shipped ``tessera_nvidia_mma_gemm_{f16,bf16,tf32}`` C-ABI
    symbol (warp-level mma.sync, f32 accumulate). Returns the f32 result matrix.
    Raises on a missing lib / device, an unsupported op set, or a kernel error —
    ``launch()`` maps the raise to ``invalid_artifact``."""
    import numpy as np

    lib = _load_nvidia_gemm_runtime()
    if lib is None:
        raise RuntimeError(
            "libtessera_nvidia_gemm.so not loadable — no NVIDIA execution lane "
            "on this host (build target: tessera_nvidia_gemm)")

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) not in (
            "tessera.matmul", "tessera.gemm"):
        raise ValueError(
            "nvidia_mma executor handles exactly one matmul/gemm op; got "
            f"{[o.get('op_name') for o in ops]!r}")

    values = _bind_launch_args(args, arg_names)
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) != 2:
        raise ValueError("matmul requires exactly two operands")
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    if a.ndim != 2 or b.ndim != 2 or a.shape[1] != b.shape[0]:
        raise ValueError(
            f"nvidia_mma matmul needs rank-2 operands with matching K; got "
            f"{a.shape} @ {b.shape}")

    bf16 = _bfloat16_dtype()
    store: Any
    if a.dtype == np.float16 and b.dtype == np.float16:
        sym, store = _NVIDIA_GEMM_SYMBOLS["float16"], np.float16
    elif bf16 is not None and a.dtype == bf16 and b.dtype == bf16:
        sym, store = _NVIDIA_GEMM_SYMBOLS["bfloat16"], bf16
    elif a.dtype == np.float32 and b.dtype == np.float32:
        # fp32 storage → tf32-math GEMM (Decision #15a).
        sym, store = _NVIDIA_GEMM_SYMBOLS["float32"], np.float32
    else:
        raise ValueError(
            "nvidia_mma executor handles f16/bf16/fp32(tf32-math) storage "
            f"(f32 accumulate); got {a.dtype} @ {b.dtype}")
    fn = getattr(lib, sym, None)
    if fn is None:
        raise RuntimeError(
            f"libtessera_nvidia_gemm.so lacks {sym} — rebuild the "
            f"tessera_nvidia_gemm target for {store!r} support")

    m, k = a.shape
    n = b.shape[1]
    a_c = np.ascontiguousarray(a, dtype=store)
    b_c = np.ascontiguousarray(b, dtype=store)
    d = np.zeros((m, n), dtype=np.float32)
    rc = fn(a_c.ctypes.data_as(ctypes.c_void_p),
            b_c.ctypes.data_as(ctypes.c_void_p),
            d.ctypes.data_as(ctypes.c_void_p), int(m), int(n), int(k))
    if rc == 1:
        raise ValueError(
            f"nvidia_mma kernel rejected shape ({m}x{n}x{k}) — M/N/K must be "
            f"positive")
    if rc == 2:
        raise RuntimeError("nvidia_mma: no usable NVIDIA GPU / NVRTC at launch")
    if rc != 0:
        raise RuntimeError(f"nvidia_mma kernel returned rc={rc}")
    return d


# ── 2D GEMM execution helpers for the D1 arbiter's NVIDIA matmul candidates ────
# Two lanes for a bare ``D = A @ B`` (f32 accumulate), both keyed by 16-bit
# storage dtype ("bfloat16"/"float16"): the shipped hand-tuned symbol (Tier 3)
# and the compiler-EMITTED ptx_emit kernel via the launch bridge (Tier 2). The
# arbiter (emit/candidate.py) F4-gates and selects between them.

def _nvidia_mma_gemm_2d(A: Any, B: Any, dtype: str = "bfloat16") -> Any:
    """Shipped ``libtessera_nvidia_gemm`` mma.sync GEMM on 2D ``A @ B`` -> f32.
    ``B`` is row-major (the shipped convention). Raises on shape mismatch / no lib
    / GPU / kernel error (the caller declines to the reference)."""
    import numpy as np
    # Validate the contraction dim BEFORE any side effect: the C ABI takes a
    # single K and copies K*N from B, so a mismatched K (A is MxK, B is K2xN)
    # would overread B or compute against the wrong slice. Raise like
    # MatmulRegion.reference / the JIT path instead (PR #294 review).
    Aa, Ba = np.asarray(A), np.asarray(B)
    if Aa.ndim != 2 or Ba.ndim != 2 or Aa.shape[1] != Ba.shape[0]:
        raise ValueError(
            f"nvidia GEMM needs rank-2 A @ B with matching K; got "
            f"{Aa.shape} @ {Ba.shape}")
    lib = _load_nvidia_gemm_runtime()
    if lib is None:
        raise RuntimeError("libtessera_nvidia_gemm.so not loadable")
    sym = _NVIDIA_GEMM_SYMBOLS.get(dtype)
    fn = getattr(lib, sym, None) if sym else None
    if fn is None:
        raise RuntimeError(f"shipped GEMM lacks a symbol for dtype {dtype!r}")
    store = np.float16 if dtype == "float16" else _bfloat16_dtype()
    if store is None:
        raise RuntimeError("bfloat16 dtype unavailable (ml_dtypes not installed)")
    Ac = np.ascontiguousarray(Aa, store)
    Bc = np.ascontiguousarray(Ba, store)
    M, K = Ac.shape
    _, N = Bc.shape
    D = np.zeros((M, N), np.float32)
    rc = fn(Ac.ctypes.data_as(ctypes.c_void_p), Bc.ctypes.data_as(ctypes.c_void_p),
            D.ctypes.data_as(ctypes.c_void_p), int(M), int(N), int(K))
    if rc != 0:
        raise RuntimeError(f"shipped nvidia GEMM returned rc={rc}")
    return D


_nvidia_ptx_launch_lib: ctypes.CDLL | None = None
_nvidia_ptx_registered: set[str] = set()


def _nvidia_ptx_launch_lib_path() -> Optional[Path]:
    """Locate the PTX launch-bridge lib (env override -> canonical CMake build)."""
    env = os.environ.get("TESSERA_NVIDIA_PTX_LAUNCH_LIB")
    candidates: list[Path] = []
    if env:
        candidates.append(Path(env))
    root = Path(__file__).resolve().parents[2]
    candidates.append(
        root / "build/src/compiler/codegen/tessera_gpu_backend_NVIDIA/runtime/cuda"
        / "libtessera_nvidia_ptx_launch.so")
    for c in candidates:
        if c.is_file():
            return c
    return None


def _load_nvidia_ptx_launch() -> ctypes.CDLL | None:
    """Load the PTX launch bridge once (preloading libcuda globally so its weak
    ``tsrRegisterGpuLauncher`` ref and cuda deps resolve). Returns None (never
    raises) when the lib / CUDA deps are absent."""
    global _nvidia_ptx_launch_lib
    if _nvidia_ptx_launch_lib is not None:
        return _nvidia_ptx_launch_lib
    path = _nvidia_ptx_launch_lib_path()
    if path is None:
        return None
    cuda_dirs = ["/usr/lib/wsl/lib",
                 os.path.join(os.environ.get("CUDA_PATH", "/usr/local/cuda"), "lib64")]
    for dep in ("libcuda.so.1", "libcuda.so"):
        for d in cuda_dirs:
            p = os.path.join(d, dep)
            if os.path.isfile(p):
                try:
                    ctypes.CDLL(p, mode=ctypes.RTLD_GLOBAL)
                except OSError:
                    pass
                break
    try:
        lib = ctypes.CDLL(str(path), mode=ctypes.RTLD_GLOBAL)
    except OSError:
        return None
    lib.tessera_nvidia_ptx_register.argtypes = [ctypes.c_char_p, ctypes.c_char_p]
    lib.tessera_nvidia_ptx_register.restype = ctypes.c_int
    lib.tessera_nvidia_ptx_invoke.argtypes = [
        ctypes.c_char_p, ctypes.POINTER(ctypes.c_void_p), ctypes.c_size_t,
        ctypes.POINTER(ctypes.c_int64), ctypes.c_size_t]
    lib.tessera_nvidia_ptx_invoke.restype = ctypes.c_int
    _nvidia_ptx_launch_lib = lib
    return lib


def _nvidia_ptx_gemm_2d(A: Any, B: Any, dtype: str = "bfloat16") -> Any:
    """Compiler-EMITTED mma.sync GEMM (ptx_emit) via the launch bridge on 2D
    ``A @ B`` -> f32. Registers the emitted general-GEMM PTX once per dtype, then
    invokes it. The emitted kernel wants ``B`` col-major (converted here) and
    aligned M%16 / N%8 / K%16. Raises on shape mismatch / no lib / GPU / launch
    error."""
    import numpy as np
    from tessera.compiler import ptx_emit as pe
    # Validate the contraction dim before any side effect (see _nvidia_mma_gemm_2d).
    Aa, Ba = np.asarray(A), np.asarray(B)
    if Aa.ndim != 2 or Ba.ndim != 2 or Aa.shape[1] != Ba.shape[0]:
        raise ValueError(
            f"nvidia GEMM needs rank-2 A @ B with matching K; got "
            f"{Aa.shape} @ {Ba.shape}")
    lib = _load_nvidia_ptx_launch()
    if lib is None:
        raise RuntimeError("libtessera_nvidia_ptx_launch.so not loadable")
    edt = "f16" if dtype == "float16" else "bf16"
    entry = pe.MMA_SYNC_GEMM_ENTRY[edt]
    if entry not in _nvidia_ptx_registered:
        ptx = pe.emit_mma_sync_gemm_ptx(dtype=edt)
        if lib.tessera_nvidia_ptx_register(entry.encode(), ptx.encode()) != 0:
            raise RuntimeError(f"ptx register failed for {entry}")
        _nvidia_ptx_registered.add(entry)
    store = np.float16 if dtype == "float16" else _bfloat16_dtype()
    if store is None:
        raise RuntimeError("bfloat16 dtype unavailable (ml_dtypes not installed)")
    Ac = np.ascontiguousarray(A, store)                       # row-major A
    Bc = np.asfortranarray(np.ascontiguousarray(B, store))    # col-major B storage
    M, K = Ac.shape
    _, N = Bc.shape
    D = np.zeros((M, N), np.float32)
    bufs = (ctypes.c_void_p * 3)(Ac.ctypes.data, Bc.ctypes.data, D.ctypes.data)
    dims = (ctypes.c_int64 * 3)(int(M), int(N), int(K))
    rc = lib.tessera_nvidia_ptx_invoke(entry.encode(), bufs, 3, dims, 3)
    if rc != 0:
        raise RuntimeError(f"emitted nvidia GEMM invoke rc={rc}")
    return D


_nvidia_device_name_probe: Any = False       # False = unprobed; None/str after


def _nvidia_device_name() -> str | None:
    """Best-effort stable per-device tag (``"sm_<cc>"``, e.g. ``"sm_120"``) for
    autotune-cache keying — so a config measured on one device is never reused on
    another. Cached; returns None (never raises) with no usable CUDA driver."""
    global _nvidia_device_name_probe
    if _nvidia_device_name_probe is not False:
        return _nvidia_device_name_probe
    _nvidia_device_name_probe = None
    try:
        cu = None
        for cand in ("libcuda.so.1", "libcuda.so"):
            try:
                cu = ctypes.CDLL(cand)
                break
            except OSError:
                continue
        if cu is None:
            return None
        if cu.cuInit(0) != 0:
            return None
        dev = ctypes.c_int(0)
        if cu.cuDeviceGet(ctypes.byref(dev), 0) != 0:
            return None
        major, minor = ctypes.c_int(), ctypes.c_int()
        # CU_DEVICE_ATTRIBUTE_COMPUTE_CAPABILITY_{MAJOR,MINOR} = 75, 76
        cu.cuDeviceGetAttribute(ctypes.byref(major), 75, dev)
        cu.cuDeviceGetAttribute(ctypes.byref(minor), 76, dev)
        _nvidia_device_name_probe = f"sm_{major.value}{minor.value}"
    except Exception:
        _nvidia_device_name_probe = None
    return _nvidia_device_name_probe


# ─────────────────────────────────────────────────────────────────────────────
# Stage L4 — the COMPILED GEMM lane (the default rocm matmul execution path).
#
# This lane executes the kernel the *Tessera compiler* generates: it drives the
# in-process Stage L pipeline through ``tessera-opt`` (Stage L3 — no mlir-opt
# shell-out) to produce an hsaco, then loads + launches it via HIP. The emitted
# kernel is problem-size-generic (L1), register-blocked (L2), and reaches
# parity-or-better vs the hand-written kernel across aligned/ragged/f16/bf16
# (L4). So `@jit(target="rocm")` matmul now executes through this lane by default
# on a capable host (jit.py stamps ``compiler_path = "rocm_compiled"``).
#
# WMMA dtypes (all verified on gfx1151): f16/bf16 -> f32 accumulate; int8 -> i32
# (rocdl iu8); int4 -> i32 (rocdl iu4, int4 values in int8 containers [-8,7],
# opt-in via metadata["wmma_dtype"]="int4"). f32/tf32/fp8 WMMA do not exist on
# RDNA 3.5.
#
# The hand-written ``rocm_wmma`` HIPRTC kernel is now the reference oracle + the
# availability fallback: if the compiled lane can't run here (no tessera-opt
# built, no in-process serialization spine, or no usable AMD GPU) the executor
# degrades to it, so flipping the default never regresses availability. ONE hsaco
# per (mt,nt,chip,dtype) serves every shape — cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_hip_launch_lib: ctypes.CDLL | None = None
#: hsaco bytes keyed by (mt, nt, chip, dtype) — the kernel is shape-generic.
_rocm_compiled_hsaco_cache: dict[
    tuple[int, int, str, str, bool, str], bytes] = {}


class _RocmCompiledUnavailable(RuntimeError):
    """The compiled ROCm lane can't run on this host (no tessera-opt, no
    in-process serialization, or no usable AMD GPU). The executor degrades to the
    hand-written ``rocm_wmma`` oracle on this — but NOT on a genuine kernel
    failure (those surface, so a real compiled-lane bug is never masked)."""


def _tessera_opt_path() -> Optional[Path]:
    """Locate the tessera-opt driver (env override → canonical build dir)."""
    env = os.environ.get("TESSERA_OPT")
    if env and Path(env).is_file():
        return Path(env)
    p = (Path(__file__).resolve().parents[2]
         / "build/tools/tessera-opt/tessera-opt")
    return p if p.is_file() else None


def _rocm_chip() -> str:
    return os.environ.get("TESSERA_ROCM_CHIP", "gfx1151")


def _rocm_live_arch() -> Optional[str]:
    """The *actual* live GPU gfx arch (``"gfx1151"`` / ``"gfx1100"`` / ``"gfx942"``)
    read from ``rocm_agent_enumerator`` / ``amdgpu-arch`` — the real device, not a
    compile default. Returns the first real GPU agent (``gfx000`` is the CPU agent),
    or ``None`` if no tool/agent is present. Never raises."""
    for exe in ("rocm_agent_enumerator", "/opt/rocm/bin/rocm_agent_enumerator",
                "amdgpu-arch", "/opt/rocm/llvm/bin/amdgpu-arch"):
        try:
            res = subprocess.run([exe], capture_output=True, text=True, timeout=10)
        except (OSError, subprocess.SubprocessError):
            continue
        for tok in res.stdout.split():
            tok = tok.strip()
            if tok.startswith("gfx") and tok != "gfx000":
                return tok
    return None


_rocm_device_name_probe: Any = False          # False = unprobed; None/str after


def _rocm_device_name() -> Optional[str]:
    """Stable per-device tag (the gfx arch, e.g. ``"gfx1151"``) for autotune-cache
    keying — the counterpart to :func:`_nvidia_device_name`. It identifies the
    **actual device the measurement ran on** so the fleet corpus's per-device
    isolation holds on a mixed ROCm fleet (a gfx1100/CDNA run must never consume or
    publish gfx1151 verdicts). Resolution, in order:

    1. Gate on the live-execution probe — ``None`` if no ROCm device can run here
       (a GPU-less host never pollutes the corpus with a gfx key).
    2. An explicit ``TESSERA_ROCM_CHIP`` pin is authoritative — it *is* the
       ``--offload-arch`` the kernels were built for, so it can't mismatch them.
    3. Otherwise read the **live device arch** (:func:`_rocm_live_arch`). We never
       fall back to the compile *default* (``_rocm_chip`` → ``gfx1151`` when unset):
       guessing would mislabel a gfx1100 host as gfx1151 and cross-contaminate the
       shared corpus (PR #308 review). Unknown arch → ``None``. Cached."""
    global _rocm_device_name_probe
    if _rocm_device_name_probe is not False:
        return _rocm_device_name_probe
    _rocm_device_name_probe = None
    try:
        if _rocm_wmma_runtime_available():
            env = os.environ.get("TESSERA_ROCM_CHIP")
            _rocm_device_name_probe = env if env else _rocm_live_arch()
    except Exception:
        _rocm_device_name_probe = None
    return _rocm_device_name_probe


def _rocm_prod_tile(m: int, n: int, k: int) -> tuple[int, int]:
    """Mirror the hand-written oracle's size-adaptive macro-tile (prodTile in
    tessera_rocm_gemm.cpp): 3x4 once min(M,N,K) >= 1024, else 2x4."""
    return (3, 4) if min(m, n, k) >= 1024 else (2, 4)


def _extract_hsaco_blob(text: str) -> bytes:
    """Decode the ELF bytes from a printed ``#gpu.object<..., bin = "...">``."""
    i = text.index('bin = "') + len('bin = "')
    out = bytearray()
    j = i
    hexd = "0123456789abcdefABCDEF"
    simple = {"\\": 0x5C, '"': 0x22, "n": 0x0A, "t": 0x09, "r": 0x0D}
    while j < len(text):
        c = text[j]
        if c == '"':
            break
        if c == "\\":
            nx = text[j + 1:j + 3]
            if len(nx) == 2 and nx[0] in hexd and nx[1] in hexd:
                out.append(int(nx, 16)); j += 3; continue
            if text[j + 1] in simple:
                out.append(simple[text[j + 1]]); j += 2; continue
        out.append(ord(c)); j += 1
    return bytes(out)


def _build_compiled_gemm_hsaco(mt: int, nt: int, dtype: str = "f16",
                               bias: bool = False,
                               activation: str = "none") -> bytes:
    """Generate + serialize the compiler's WMMA GEMM kernel to hsaco, fully
    in-process via tessera-opt (Stage L3). Cached per (mt, nt, chip, dtype,
    bias, activation). ``bias``/``activation`` select the fused epilogue — when
    set, the kernel adds a per-column bias and/or applies relu/gelu/silu on the
    f32 accumulator before the store (float dtypes only)."""
    chip = _rocm_chip()
    # The compiled GEMM emits the RDNA WMMA 16x16x16 f16/bf16 fragment layout,
    # which the backend selects only on the gfx11 family (RDNA3/RDNA3.5 —
    # hardware-verified on gfx1151). RDNA4 gfx12xx uses a 16x16x32 WMMA layout
    # and CDNA uses MFMA (32x32x8); neither selects this intrinsic, so raise a
    # stable diagnostic naming the arch gap (Decision #21) rather than letting
    # the ROCDL backend emit a raw "Cannot select" crash downstream.
    if not chip.startswith("gfx11"):
        raise _RocmCompiledUnavailable(
            f"compiled WMMA GEMM: the 16x16x16 f16/bf16 WMMA fragment layout is "
            f"a gfx11 (RDNA3/RDNA3.5) contract, hardware-verified on gfx1151; "
            f"target '{chip}' needs its own layout (RDNA4 gfx12xx: 16x16x32 WMMA; "
            f"CDNA: MFMA 32x32x8) which is arch-gated on that fragment ISA + silicon")
    key = (mt, nt, chip, dtype, bias, activation)
    cached = _rocm_compiled_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm lane (build: "
            "ninja -C build tessera-opt)")
    epi = ""
    if bias:
        epi += ", bias = true"
    if activation and activation != "none":
        epi += f', activation = "{activation}"'
    directive = (
        'module {\n'
        '  "tessera_rocm.wmma_gemm"() {name = "gemm", m = 16 : i64, '
        'n = 16 : i64, k = 16 : i64, '
        f'mt = {mt} : i64, nt = {nt} : i64, dtype = "{dtype}"{epi}}} : () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-wmma-gemm-kernel,"
        "lower-tessera-target-to-rocdl,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled GEMM in-process "
            f"(Stage L3 spine missing? rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm lane: gpu.binary was not an ELF hsaco")
    _rocm_compiled_hsaco_cache[key] = hsaco
    return hsaco


def _rocm_compiled_dtype(a, b):
    """Map the operand numpy dtype to the compiled-kernel (tag, store, out)
    triple, or (None, None, None) if unsupported. f16/bf16 (-> f32) and int8
    (-> i32) are real gfx1151 WMMA storage types; f32 is not."""
    import numpy as np
    if a.dtype == np.float16 and b.dtype == np.float16:
        return "f16", np.float16, np.float32
    bf16 = _bfloat16_dtype()
    if bf16 is not None and a.dtype == bf16 and b.dtype == bf16:
        return "bf16", bf16, np.float32
    if a.dtype == np.int8 and b.dtype == np.int8:
        return "int8", np.int8, np.int32
    return None, None, None


def _load_hip_for_launch() -> ctypes.CDLL | None:
    """Load libamdhip64 with the module-launch ABI bound (cached)."""
    global _rocm_hip_launch_lib
    if _rocm_hip_launch_lib is not None:
        return _rocm_hip_launch_lib
    rocm_lib = os.path.join(os.environ.get("ROCM_PATH", "/opt/rocm"), "lib")
    for dep in ("libamdhip64.so", "libhiprtc.so"):
        p = os.path.join(rocm_lib, dep)
        if os.path.isfile(p):
            try:
                ctypes.CDLL(p, mode=ctypes.RTLD_GLOBAL)
            except OSError:
                pass
    try:
        hip = ctypes.CDLL("libamdhip64.so", mode=ctypes.RTLD_GLOBAL)
    except OSError:
        return None
    hip.hipMalloc.argtypes = [ctypes.c_void_p, ctypes.c_size_t]
    hip.hipMemcpy.argtypes = [ctypes.c_void_p, ctypes.c_void_p,
                              ctypes.c_size_t, ctypes.c_int]
    hip.hipModuleLaunchKernel.argtypes = (
        [ctypes.c_void_p] + [ctypes.c_uint] * 6
        + [ctypes.c_uint, ctypes.c_void_p, ctypes.c_void_p, ctypes.c_void_p])
    _rocm_hip_launch_lib = hip
    return hip


def _execute_rocm_compiled_gemm(artifact: RuntimeArtifact, args: Any) -> Any:
    """The default ``target="rocm"`` matmul lane: run the COMPILER-GENERATED WMMA
    kernel, falling back to the hand-written ``rocm_wmma`` oracle only when the
    compiled lane is *unavailable* on this host (no tessera-opt / serialization /
    GPU). A genuine compiled-kernel failure (malloc/launch) is NOT masked — it
    surfaces, so a real bug is never hidden behind the fallback."""
    try:
        return _rocm_compiled_gemm_impl(artifact, args)
    except _RocmCompiledUnavailable:
        return _execute_rocm_wmma_artifact(artifact, args)


def _rocm_compiled_gemm_impl(artifact: RuntimeArtifact, args: Any) -> Any:
    """Generate + serialize the kernel in-process (tessera-opt, no mlir-opt), then
    load + launch the hsaco via HIP. f16/bf16 storage, f32 accumulate. Returns the
    MxN f32 result. Raises ``_RocmCompiledUnavailable`` when the lane can't run
    here, ``ValueError`` on a bad op/dtype/shape, ``RuntimeError`` on a real
    kernel failure — ``launch()`` maps a raise to ``invalid_artifact``."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    # `fused_epilogue` is matmul + a fused bias/activation epilogue — the same
    # rocm_compiled GEMM kernel with the bias operand / activation kwarg — so
    # accept that op name too (it's a `compiled` row in rocm_target_map).
    if len(ops) != 1 or str(ops[0].get("op_name", "")) not in (
            "tessera.matmul", "tessera.gemm", "tessera.fused_epilogue"):
        raise ValueError(
            "rocm_compiled executor handles exactly one matmul/gemm/"
            f"fused_epilogue op; got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    # A fused epilogue is opt-in via the op kwargs: an optional third operand is
    # the per-output-column bias (shape [N]), and `activation` selects an
    # in-kernel pointwise activation (relu/gelu/silu). 2 operands = plain GEMM.
    kwargs = op.get("kwargs") or {}
    activation = str(kwargs.get("activation") or "none")
    if activation not in ("none", "relu", "gelu", "silu"):
        raise ValueError(
            "rocm_compiled epilogue activation must be one of "
            f"none/relu/gelu/silu; got {activation!r}")
    if len(operand_names) not in (2, 3):
        raise ValueError(
            "rocm_compiled matmul takes two operands (a, b) plus an optional "
            f"third bias operand; got {len(operand_names)}")
    has_bias = len(operand_names) == 3
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    if a.ndim != 2 or b.ndim != 2 or a.shape[1] != b.shape[0]:
        raise ValueError(
            f"rocm_compiled matmul needs rank-2 operands with matching K; got "
            f"{a.shape} @ {b.shape}")
    dtype_tag, store, out_dt = _rocm_compiled_dtype(a, b)
    if dtype_tag is None:
        # gfx1151 WMMA storage is f16/bf16 (f32 acc) or int8 (i32 acc). f32 in is
        # not a WMMA storage dtype — be explicit, don't silently miscompute.
        raise ValueError(
            "rocm_compiled lane handles f16/bf16 (f32 acc) or int8 (i32 acc) "
            f"storage; got {a.dtype} @ {b.dtype}")
    # int4 shares the int8 container (np.int8, values in [-8,7]); it is opt-in via
    # an explicit metadata hint since the numpy dtype can't distinguish it.
    if str(metadata.get("wmma_dtype") or "") in ("int4", "i4"):
        if a.dtype != np.int8 or b.dtype != np.int8:
            raise ValueError(
                "rocm_compiled int4 lane needs int8 containers (int4 values in "
                f"[-8,7]); got {a.dtype} @ {b.dtype}")
        dtype_tag, store, out_dt = "int4", np.int8, np.int32

    # The fused epilogue is float-only (gelu/silu are transcendentals; bias is an
    # fadd) — surface a clean error rather than emit an int directive the kernel
    # generator will reject.
    if dtype_tag in ("int8", "int4") and (has_bias or activation != "none"):
        raise ValueError(
            "rocm_compiled fused epilogue (bias/activation) is float-only; "
            f"got integer dtype {dtype_tag}")

    m, k = a.shape
    n = b.shape[1]
    bias_arr = None
    if has_bias:
        bias_arr = np.ascontiguousarray(
            _as_numpy(values[operand_names[2]]), dtype=np.float32)
        if bias_arr.shape != (n,):
            raise ValueError(
                f"rocm_compiled bias must have shape ({n},) (one per output "
                f"column); got {bias_arr.shape}")
    mt, nt = _rocm_prod_tile(m, n, k)
    hsaco = _build_compiled_gemm_hsaco(
        mt, nt, dtype_tag, bias=has_bias, activation=activation)

    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm_compiled: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm_compiled: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"gemm") != 0:
        raise RuntimeError("rocm_compiled: kernel symbol 'gemm' not found")

    a_c = np.ascontiguousarray(a, dtype=store)
    b_c = np.ascontiguousarray(b, dtype=store)
    d = np.zeros((m, n), dtype=out_dt)
    da, db, dd = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    ab = a_c.itemsize  # 1 (int8) or 2 (f16/bf16); D element is always 4 bytes
    nb = (ab * m * k, ab * k * n, 4 * m * n)
    for dev, size in ((da, nb[0]), (db, nb[1]), (dd, nb[2])):
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm_compiled: hipMalloc failed")
    hip.hipMemcpy(da, a_c.ctypes.data_as(ctypes.c_void_p), nb[0], 1)
    hip.hipMemcpy(db, b_c.ctypes.data_as(ctypes.c_void_p), nb[1], 1)

    # Fused-epilogue bias: the trailing length-N memref the generated kernel
    # reads (accumulator dtype, f32). Tracked in `devs` so it is always freed.
    devs = [da, db, dd]
    dbias = None
    if has_bias:
        dbias = ctypes.c_void_p()
        if hip.hipMalloc(ctypes.byref(dbias), 4 * n) != 0:
            for dev in devs:
                hip.hipFree(dev)
            raise RuntimeError("rocm_compiled: hipMalloc (bias) failed")
        devs.append(dbias)
        assert bias_arr is not None  # set above whenever has_bias
        hip.hipMemcpy(dbias, bias_arr.ctypes.data_as(ctypes.c_void_p),
                      4 * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(da, m * k) + _mr(db, k * n) + _mr(dd, m * n)
                   + [ctypes.c_int64(m), ctypes.c_int64(n), ctypes.c_int64(k)])
    if has_bias:
        launch_args += _mr(dbias, n)
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + 16 * nt - 1) // (16 * nt)
    gy = (m + 16 * mt - 1) // (16 * mt)
    rc = hip.hipModuleLaunchKernel(fn, gx, gy, 1, 32, 1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in devs:
            hip.hipFree(dev)
        raise RuntimeError(f"rocm_compiled: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(d.ctypes.data_as(ctypes.c_void_p), dd, nb[2], 2)
    for dev in devs:
        hip.hipFree(dev)
    return d


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED matmul-family lane (2026-06-25) — batched_gemm / linear_general /
# qkv_projection / factorized_matmul / einsum, all built on the same
# COMPILER-GENERATED WMMA GEMM kernel (the rocm_compiled spine) via reshaping /
# batching / splitting in the runtime — the matmul analog of how flash_attn
# GQA/MQA reuse the FA kernel. ``compiler_path = "rocm_matmul_family_compiled"``.
# f16/bf16 storage, f32 accumulate. (factorized_matmul's rank-r SVD truncation
# is an exact host epilogue on the GPU matmul; einsum supports single-contraction
# specs that map to a (batched) matmul, else a stable "unsupported" diagnostic.)
# ─────────────────────────────────────────────────────────────────────────────
def _rocm_wmma_gemm_2d(a: Any, b: Any) -> Any:
    """Run ONE 2-D WMMA GEMM (a[M,K] @ b[K,N]) on the COMPILER-GENERATED kernel
    and return the [M,N] f32 (int8→i32) result. Reuses the rocm_compiled spine
    (_build_compiled_gemm_hsaco). Raises _RocmCompiledUnavailable when the lane
    can't run here, RuntimeError on a real kernel failure."""
    import numpy as np

    if a.ndim != 2 or b.ndim != 2 or a.shape[1] != b.shape[0]:
        raise ValueError(
            f"_rocm_wmma_gemm_2d needs rank-2 operands with matching K; got "
            f"{a.shape} @ {b.shape}")
    dtype_tag, store, out_dt = _rocm_compiled_dtype(a, b)
    if dtype_tag is None:
        raise ValueError(
            "rocm matmul-family lane handles f16/bf16 (f32 acc) or int8 (i32 "
            f"acc) storage; got {a.dtype} @ {b.dtype}")
    m, k = a.shape
    n = b.shape[1]
    mt, nt = _rocm_prod_tile(m, n, k)
    hsaco = _build_compiled_gemm_hsaco(mt, nt, dtype_tag)

    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm matmul-family: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm matmul-family: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"gemm") != 0:
        raise RuntimeError("rocm matmul-family: kernel symbol 'gemm' not found")

    a_c = np.ascontiguousarray(a, dtype=store)
    b_c = np.ascontiguousarray(b, dtype=store)
    d = np.zeros((m, n), dtype=out_dt)
    ab = a_c.itemsize
    nb = (ab * m * k, ab * k * n, 4 * m * n)
    da, db, dd = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    for dev, size in ((da, nb[0]), (db, nb[1]), (dd, nb[2])):
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm matmul-family: hipMalloc failed")
    hip.hipMemcpy(da, a_c.ctypes.data_as(ctypes.c_void_p), nb[0], 1)
    hip.hipMemcpy(db, b_c.ctypes.data_as(ctypes.c_void_p), nb[1], 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(da, m * k) + _mr(db, k * n) + _mr(dd, m * n)
                   + [ctypes.c_int64(m), ctypes.c_int64(n), ctypes.c_int64(k)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + 16 * nt - 1) // (16 * nt)
    gy = (m + 16 * mt - 1) // (16 * mt)
    rc = hip.hipModuleLaunchKernel(fn, gx, gy, 1, 32, 1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in (da, db, dd):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm matmul-family: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(d.ctypes.data_as(ctypes.c_void_p), dd, nb[2], 2)
    for dev in (da, db, dd):
        hip.hipFree(dev)
    return d


def _rocm_wmma_fused_2d(a: Any, b: Any, bias: Any = None,
                        activation: str = "none") -> Any:
    """Run ONE 2-D WMMA GEMM with a **fused epilogue** — a per-column bias add
    and/or a pointwise activation (``relu``/``gelu``/``silu``) applied on the f32
    accumulator *before the store*, all inside the one COMPILER-GENERATED kernel
    (the ``generate-wmma-gemm-kernel`` pass with ``bias``/``activation`` set). This
    is the fused-region analog of :func:`_rocm_wmma_gemm_2d`; it is the direct
    entry the D1 arbiter's Tier-3 WMMA candidate calls to serve a ``FusedRegion``
    whose epilogue is ``bias`` + one of relu/gelu/silu (float storage only). ``a``/
    ``b`` are f16/bf16 [M,K]@[K,N]; ``bias`` (if given) is f32 [N]. Returns the
    [M,N] f32 result. Raises ``_RocmCompiledUnavailable`` when the lane can't run
    here, ``ValueError`` on a bad dtype/shape, ``RuntimeError`` on a kernel error."""
    import numpy as np

    if a.ndim != 2 or b.ndim != 2 or a.shape[1] != b.shape[0]:
        raise ValueError(
            f"_rocm_wmma_fused_2d needs rank-2 operands with matching K; got "
            f"{a.shape} @ {b.shape}")
    if activation not in ("none", "relu", "gelu", "silu"):
        raise ValueError(
            "_rocm_wmma_fused_2d activation must be none/relu/gelu/silu; got "
            f"{activation!r}")
    dtype_tag, store, out_dt = _rocm_compiled_dtype(a, b)
    if dtype_tag is None or dtype_tag in ("int8", "int4"):
        # The fused epilogue is float-only (gelu/silu are transcendentals; bias is
        # an fadd) — be explicit rather than emit an int directive the generator
        # rejects. Plain int GEMM stays on :func:`_rocm_wmma_gemm_2d`.
        raise ValueError(
            "rocm WMMA fused epilogue is float-only (f16/bf16 storage, f32 acc); "
            f"got {a.dtype} @ {b.dtype}")
    m, k = a.shape
    n = b.shape[1]
    has_bias = bias is not None
    bias_arr = None
    if has_bias:
        bias_arr = np.ascontiguousarray(bias, dtype=np.float32)
        if bias_arr.shape != (n,):
            raise ValueError(
                f"rocm WMMA bias must have shape ({n},) (one per output column); "
                f"got {bias_arr.shape}")
    mt, nt = _rocm_prod_tile(m, n, k)
    hsaco = _build_compiled_gemm_hsaco(
        mt, nt, dtype_tag, bias=has_bias, activation=activation)

    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm WMMA fused: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm WMMA fused: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"gemm") != 0:
        raise RuntimeError("rocm WMMA fused: kernel symbol 'gemm' not found")

    a_c = np.ascontiguousarray(a, dtype=store)
    b_c = np.ascontiguousarray(b, dtype=store)
    d = np.zeros((m, n), dtype=out_dt)
    ab = a_c.itemsize
    nb = (ab * m * k, ab * k * n, 4 * m * n)
    da, db, dd = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    devs = [da, db, dd]
    for dev, size in ((da, nb[0]), (db, nb[1]), (dd, nb[2])):
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm WMMA fused: hipMalloc failed")
    hip.hipMemcpy(da, a_c.ctypes.data_as(ctypes.c_void_p), nb[0], 1)
    hip.hipMemcpy(db, b_c.ctypes.data_as(ctypes.c_void_p), nb[1], 1)
    dbias = None
    if has_bias:
        dbias = ctypes.c_void_p()
        if hip.hipMalloc(ctypes.byref(dbias), 4 * n) != 0:
            for dev in devs:
                hip.hipFree(dev)
            raise RuntimeError("rocm WMMA fused: hipMalloc (bias) failed")
        devs.append(dbias)
        assert bias_arr is not None
        hip.hipMemcpy(dbias, bias_arr.ctypes.data_as(ctypes.c_void_p), 4 * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(da, m * k) + _mr(db, k * n) + _mr(dd, m * n)
                   + [ctypes.c_int64(m), ctypes.c_int64(n), ctypes.c_int64(k)])
    if has_bias:
        launch_args += _mr(dbias, n)
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + 16 * nt - 1) // (16 * nt)
    gy = (m + 16 * mt - 1) // (16 * mt)
    rc = hip.hipModuleLaunchKernel(fn, gx, gy, 1, 32, 1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in devs:
            hip.hipFree(dev)
        raise RuntimeError(f"rocm WMMA fused: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(d.ctypes.data_as(ctypes.c_void_p), dd, nb[2], 2)
    for dev in devs:
        hip.hipFree(dev)
    return d


_rocm_wmma_fused_probe_ok: bool | None = None


def _rocm_wmma_fused_available() -> bool:
    """Cached host probe: True iff the COMPILER-GENERATED fused WMMA GEMM lane can
    actually run here — i.e. ``tessera-opt`` is built AND a live gfx1151 executes a
    tiny fused GEMM through :func:`_rocm_wmma_fused_2d` itself. This is stricter
    than :func:`_rocm_wmma_runtime_available` (which probes only the *shipped* GEMM
    symbol): the fused-epilogue path additionally needs ``tessera-opt`` + the
    generated kernel, so a host with the shipped lib but no compiler would pass the
    shipped probe yet fail here. The D1 WMMA candidate gates ``available()`` on this
    so it never wins arbitration and then silently declines to the reference,
    starving the generic lane (PR #289 review)."""
    global _rocm_wmma_fused_probe_ok
    if _rocm_wmma_fused_probe_ok is not None:
        return _rocm_wmma_fused_probe_ok
    _rocm_wmma_fused_probe_ok = False
    try:
        import numpy as np
        a = np.zeros((16, 16), np.float16)
        b = np.zeros((16, 16), np.float16)
        _rocm_wmma_fused_2d(a, b, None, "relu")
        _rocm_wmma_fused_probe_ok = True
    except Exception:
        _rocm_wmma_fused_probe_ok = False
    return _rocm_wmma_fused_probe_ok


def _rocm_batched_gemm(a: Any, b: Any) -> Any:
    """np.matmul semantics over leading batch dims, each [M,K]@[K,N] on the WMMA
    kernel. ``b`` may be rank-2 (shared across the batch) or batched to match."""
    import numpy as np
    if a.ndim < 2 or b.ndim < 2:
        raise ValueError("batched_gemm needs rank>=2 operands")
    m, k = a.shape[-2], a.shape[-1]
    if b.shape[-2] != k:
        raise ValueError(
            f"batched_gemm inner dims must match; got {a.shape} @ {b.shape}")
    n = b.shape[-1]
    a_batch = a.reshape(-1, m, k)
    nb_a = a_batch.shape[0]
    if b.ndim == 2:
        b_batch = np.broadcast_to(b, (nb_a, k, n))
    else:
        b_batch = b.reshape(-1, k, n)
        if b_batch.shape[0] != nb_a:
            raise ValueError(
                f"batched_gemm batch mismatch; got {a.shape} @ {b.shape}")
    out = np.stack([_rocm_wmma_gemm_2d(a_batch[i], b_batch[i])
                    for i in range(nb_a)], axis=0)
    return out.reshape(*a.shape[:-2], m, n)


def _rocm_einsum_via_gemm(spec: str, lhs: Any, rhs: Any) -> Any:
    """Single-contraction two-operand einsum mapped to a (batched) WMMA gemm.
    Canonicalizes to [batch..., M, K] @ [batch..., K, N] then transposes the
    result into the requested output order. Raises a stable diagnostic when the
    spec is not a single-contraction two-tensor matmul (Decision #21)."""
    import numpy as np
    if "->" not in spec:
        raise ValueError(f"rocm einsum needs an explicit '->' spec; got {spec!r}")
    ins, out = spec.split("->")
    terms = [t.strip() for t in ins.split(",")]
    if len(terms) != 2:
        raise ValueError(
            "rocm einsum lane handles exactly two operands; got "
            f"{len(terms)} in {spec!r}")
    lt, rt = terms
    out = out.strip()
    contracted = (set(lt) & set(rt)) - set(out)
    if len(contracted) != 1:
        raise ValueError(
            "rocm einsum lane handles a single contraction index that maps to a "
            f"(batched) matmul; spec {spec!r} has {len(contracted)} — unsupported")
    c = next(iter(contracted))
    batch = [x for x in lt if x in rt and x in out]
    free_l = [x for x in lt if x not in rt]
    free_r = [x for x in rt if x not in lt]
    if set(out) != set(batch) | set(free_l) | set(free_r):
        raise ValueError(f"rocm einsum: output indices in {spec!r} are unsupported")
    # Canonical layouts: lhs -> [batch, free_l, c]; rhs -> [batch, c, free_r].
    lhs_t = np.transpose(lhs, [lt.index(x) for x in batch + free_l + [c]])
    rhs_t = np.transpose(rhs, [rt.index(x) for x in batch + [c] + free_r])
    bsh = [lhs.shape[lt.index(x)] for x in batch]
    msh = [lhs.shape[lt.index(x)] for x in free_l]
    nsh = [rhs.shape[rt.index(x)] for x in free_r]
    kdim = lhs.shape[lt.index(c)]
    a2 = lhs_t.reshape(int(np.prod(bsh or [1])), int(np.prod(msh or [1])), kdim)
    b2 = rhs_t.reshape(int(np.prod(bsh or [1])), kdim, int(np.prod(nsh or [1])))
    prod = _rocm_batched_gemm(a2, b2)            # [B, M, N]
    canon = prod.reshape(*(bsh + msh + nsh))     # batch + free_l + free_r
    canon_order = batch + free_l + free_r
    return np.transpose(canon, [canon_order.index(x) for x in out])


def _execute_rocm_compiled_matmul_family(artifact: RuntimeArtifact,
                                         args: Any) -> Any:
    """The ``target="rocm"`` matmul-family lane: batched_gemm / linear_general /
    qkv_projection / factorized_matmul / einsum, all on the COMPILER-GENERATED
    WMMA GEMM kernel. f16/bf16 (f32 acc). Each op reshapes/batches/splits around
    the gemm; einsum maps single-contraction specs to a (batched) matmul."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    handled = ("tessera.batched_gemm", "tessera.linear_general",
               "tessera.qkv_projection", "tessera.factorized_matmul",
               "tessera.einsum")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"rocm_matmul_family_compiled executor handles one of {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]

    if op_name == "tessera.einsum":
        spec = kwargs.get("spec") or kwargs.get("equation")
        if spec is None or len(operands) != 2:
            raise ValueError(
                "rocm einsum lane needs a 'spec' kwarg and exactly two tensors")
        return _rocm_einsum_via_gemm(str(spec), operands[0], operands[1])

    if op_name == "tessera.batched_gemm":
        if len(operands) != 2:
            raise ValueError("batched_gemm takes two operands (A, B)")
        return _rocm_batched_gemm(operands[0], operands[1])

    if op_name == "tessera.qkv_projection":
        if len(operands) != 2:
            raise ValueError("qkv_projection takes two operands (x, W_qkv)")
        x, w = operands
        if w.ndim != 2:
            raise ValueError(f"qkv_projection W_qkv must be rank-2; got {w.shape}")
        k, n3 = w.shape
        x2 = x.reshape(-1, k)
        y = _rocm_wmma_gemm_2d(x2, w).reshape(*x.shape[:-1], n3)
        # The op returns (Q, K, V); the runtime returns the packed projection and
        # the 3-way last-axis split is a trivial host view.
        return y

    if op_name == "tessera.factorized_matmul":
        if len(operands) != 2:
            raise ValueError("factorized_matmul takes two operands (A, B)")
        a, b = operands
        if a.ndim != 2 or b.ndim != 2:
            raise ValueError("rocm factorized_matmul handles rank-2 A, B")
        rank = int(kwargs.get("rank", min(a.shape[0], b.shape[1])))
        out = _rocm_wmma_gemm_2d(a, b).astype(np.float32)  # GPU matmul
        # rank-r SVD truncation — an exact host epilogue on the GPU product.
        u, s, vh = np.linalg.svd(out, full_matrices=False)
        r = max(1, min(rank, s.shape[-1]))
        return (u[..., :r] * s[..., :r]) @ vh[..., :r, :]

    # tessera.linear_general — default axis=-1, rank-2 weight [K, N] (+ bias).
    if len(operands) not in (2, 3):
        raise ValueError("linear_general takes (x, W) plus an optional bias")
    axis = kwargs.get("axis", -1)
    if axis not in (-1, None):
        raise ValueError(
            f"rocm linear_general lane handles axis=-1 only; got axis={axis}")
    x, w = operands[0], operands[1]
    if w.ndim != 2:
        raise ValueError(
            f"rocm linear_general lane handles a rank-2 weight [K, N]; got "
            f"{w.shape}")
    k, n = w.shape
    if x.shape[-1] != k:
        raise ValueError(
            f"linear_general contracted dim mismatch: x{x.shape} @ W{w.shape}")
    y = _rocm_wmma_gemm_2d(x.reshape(-1, k), w).reshape(*x.shape[:-1], n)
    if len(operands) == 3:
        y = y + _as_numpy(values[operand_names[2]]).astype(np.float32)
    return y


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED flash_attn lane (2026-06-24) — the matmul-L4 analog for
# attention. ``runtime.launch()`` of an artifact stamped
# ``compiler_path = "rocm_flash_attn_compiled"`` builds the COMPILER-GENERATED
# FA-2 forward kernel in-process (the ``generate-wmma-flash-attn-kernel``
# pipeline → hsaco, same Stage-L3 spine as the GEMM) and launches it via HIP.
# f16/bf16 storage, f32 softmax + accumulate. ONE hsaco per (head_dim, chip,
# dtype) — the kernel is (B,H,Sq,Sk)-generic — cached.
# ─────────────────────────────────────────────────────────────────────────────
#: hsaco bytes keyed by (head_dim, chip, dtype, gqa, window, softcap, bias).
_rocm_fa_hsaco_cache: dict[tuple[int, str, str, bool, bool, bool, bool], bytes] = {}


def _build_compiled_flash_attn_hsaco(head_dim: int, dtype: str = "f16",
                                     gqa: bool = False,
                                     sliding_window: bool = False,
                                     logit_softcap: bool = False,
                                     attn_bias: bool = False) -> bytes:
    """Generate + serialize the compiler's WMMA FA-2 forward kernel to hsaco,
    fully in-process via tessera-opt. Cached per (head_dim, chip, dtype, gqa,
    sliding_window, logit_softcap, attn_bias). gqa=True emits the grouped-query
    variant (kernel gains heads + kv_ratio runtime args, reads K/V from the
    grouped head); sliding_window=True emits the windowed variant (trailing W
    arg, a causal band of width W); logit_softcap=True emits the Gemma-2 soft-cap
    variant (trailing f32 `cap` arg, scores → cap·tanh(S/cap) before softmax);
    attn_bias=True emits the additive-bias variant (a trailing f32 `[bh,Sq,Sk]`
    memref arg, `softmax(scale·Q@K^T + bias)·V`)."""
    chip = _rocm_chip()
    key = (head_dim, chip, dtype, gqa, sliding_window, logit_softcap, attn_bias)
    cached = _rocm_fa_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm flash_attn lane")
    gqa_attr = ", gqa = true" if gqa else ""
    win_attr = ", sliding_window = true" if sliding_window else ""
    cap_attr = ", logit_softcap = true" if logit_softcap else ""
    bias_attr = ", attn_bias = true" if attn_bias else ""
    directive = (
        'module {\n'
        '  "tessera_rocm.flash_attn"() {name = "fa", '
        f'head_dim = {head_dim} : i64, dtype = "{dtype}"'
        f'{gqa_attr}{win_attr}{cap_attr}{bias_attr}}} '
        ': () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-wmma-flash-attn-kernel,"
        "lower-tessera-target-to-rocdl,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled flash_attn in-process "
            f"(rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm flash_attn lane: gpu.binary was not an ELF hsaco")
    _rocm_fa_hsaco_cache[key] = hsaco
    return hsaco


def _execute_rocm_compiled_flash_attn(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` flash_attn lane: run the COMPILER-GENERATED FA-2
    forward WMMA kernel. Raises ``_RocmCompiledUnavailable`` when the lane can't
    run here (no tessera-opt / serialization / GPU) — ``launch()`` maps that to
    ``invalid_artifact``; ``ValueError`` on a bad op/dtype/shape; ``RuntimeError``
    on a real kernel failure. Q/K/V are ``[..., S, D]`` (leading dims = B*H)."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    # The flash-attn WMMA kernel realizes the whole multi-head family; accept the
    # registry op names that map onto it (so a caller stamping e.g.
    # tessera.gqa_attention actually launches, matching the `compiled` rows in
    # rocm_target_map). GQA/MQA come from the operand shapes; the window/softcap
    # come from kwargs. `attn_sliding_window` additionally requires a window.
    _FA_OPS = ("tessera.flash_attn", "tessera.multi_head_attention",
               "tessera.gqa_attention", "tessera.mqa_attention",
               "tessera.attn_sliding_window")
    fa_op = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or fa_op not in _FA_OPS:
        raise ValueError(
            "rocm_flash_attn_compiled executor handles exactly one of "
            f"{_FA_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("flash_attn requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    q = _as_numpy(values[operand_names[0]])
    k = _as_numpy(values[operand_names[1]])
    v = _as_numpy(values[operand_names[2]])
    # Additive attention bias: Graph IR / the Apple + x86 paths normalize
    # flash_attn(..., attn_bias=…) into a 4th operand (matches runtime.py:3095).
    # O = softmax(scale·Q@K^T + attn_bias)·V; None → the plain kernel.
    bias_arr = (_as_numpy(values[operand_names[3]])
                if len(operand_names) >= 4 else None)
    if q.ndim < 2 or k.ndim < 2 or v.ndim < 2:
        raise ValueError("flash_attn Q/K/V must be at least rank 2 ([..., S, D])")
    head_dim = int(q.shape[-1])
    if head_dim <= 0 or head_dim % 16 != 0:
        raise ValueError(
            f"rocm flash_attn lane needs head_dim a positive multiple of 16; "
            f"got {head_dim}")
    sq = int(q.shape[-2])
    sk = int(k.shape[-2])
    bh = int(np.prod(q.shape[:-2])) if q.ndim > 2 else 1
    bh_kv = int(np.prod(k.shape[:-2])) if k.ndim > 2 else 1
    # V is paired with K: it must match K's batch/head, sequence length, and
    # head dim. `sk` / `bh_kv` (from K) drive the V device allocation + copy
    # (nkv), so a smaller V would read past the host buffer — reject, not read
    # OOB. (Q's head dim must also equal V's, since O is shaped like Q.)
    if (v.shape[:-2] != k.shape[:-2] or int(v.shape[-2]) != sk
            or int(v.shape[-1]) != head_dim):
        raise ValueError(
            "rocm flash_attn lane requires V to match K's batch/head + sequence "
            f"length and Q's head dim; got Q{q.shape} K{k.shape} V{v.shape}")
    # GQA/MQA: H query heads vs G<H key/value heads (the head axis is -3:
    # [...,H,S,D] / [...,G,S,D]). G != H -> grouped lane (heads + kv_ratio args);
    # G == H is plain MHA (the original 8-arg kernel).
    n_qh = int(q.shape[-3]) if q.ndim >= 3 else 1
    n_kvh = int(k.shape[-3]) if k.ndim >= 3 else 1
    gqa = n_kvh != n_qh
    if gqa and (n_kvh <= 0 or n_qh % n_kvh != 0):
        raise ValueError(
            f"rocm GQA lane needs query-heads ({n_qh}) divisible by kv-heads "
            f"({n_kvh})")
    kv_ratio = n_qh // n_kvh if gqa else 1

    if q.dtype == np.float16:
        dtype_tag, store = "f16", np.float16
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and q.dtype == bf16:
            dtype_tag, store = "bf16", bf16
        else:
            raise ValueError(
                "rocm flash_attn lane handles f16/bf16 storage (f32 softmax + "
                f"accumulate); got {q.dtype}")

    kwargs = op.get("kwargs") or {}
    causal = 1 if bool(kwargs.get("causal", False)) else 0
    scale = kwargs.get("scale")
    scale = float(scale) if scale is not None else 1.0 / float(np.sqrt(head_dim))
    # Sliding-window attention: a positive `window` selects a causal band of
    # width W (query p attends to keys in (p-W, p]). The windowed kernel is
    # implicitly causal and takes W as a trailing runtime arg.
    window = int(kwargs.get("window") or 0)
    if window < 0:
        raise ValueError(
            f"rocm flash_attn window must be a non-negative width; got {window}")
    if fa_op == "tessera.attn_sliding_window" and window <= 0:
        raise ValueError(
            "tessera.attn_sliding_window requires a positive `window` width "
            f"kwarg; got {window}")
    sliding = window > 0
    # Gemma-2 logit soft-capping: a positive `logit_softcap` is the cap value
    # (scores → cap·tanh(S/cap) before softmax). 0/None disables it.
    softcap = kwargs.get("logit_softcap")
    softcap = float(softcap) if softcap else 0.0
    if softcap < 0:
        raise ValueError(
            f"rocm flash_attn logit_softcap must be non-negative; got {softcap}")
    has_softcap = softcap > 0

    # Additive bias → host-broadcast to the folded-batch leading dim + (Sq,Sk),
    # i.e. Q.lead + (Sq,Sk), flattened to [bh,Sq,Sk] f32 (the kernel indexes
    # bias[(bh*Sq+qpos)*Sk+gk]). Mirrors the x86 ext lane's broadcast.
    has_bias = bias_arr is not None
    bias_c = None
    if has_bias:
        try:
            bias_b = np.broadcast_to(
                np.asarray(bias_arr, dtype=np.float32),
                tuple(q.shape[:-2]) + (sq, sk))
        except ValueError as exc:
            raise ValueError(
                f"rocm flash_attn attn_bias {np.asarray(bias_arr).shape} is not "
                f"broadcastable to Q.lead+(Sq,Sk) = {tuple(q.shape[:-2]) + (sq, sk)}"
            ) from exc
        bias_c = np.ascontiguousarray(bias_b, dtype=np.float32).reshape(-1)

    hsaco = _build_compiled_flash_attn_hsaco(
        head_dim, dtype_tag, gqa, sliding_window=sliding,
        logit_softcap=has_softcap, attn_bias=has_bias)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm flash_attn: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm flash_attn: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"fa") != 0:
        raise RuntimeError("rocm flash_attn: kernel symbol 'fa' not found")

    qc = np.ascontiguousarray(q, dtype=store)
    kc = np.ascontiguousarray(k, dtype=store)
    vc = np.ascontiguousarray(v, dtype=store)
    o = np.zeros((bh, sq, head_dim), dtype=np.float32)
    # K/V are sized by the KV-head count (bh_kv), which differs from bh under GQA.
    nq, nkv = bh * sq * head_dim, bh_kv * sk * head_dim
    dq, dk, dv, do = (ctypes.c_void_p(), ctypes.c_void_p(),
                      ctypes.c_void_p(), ctypes.c_void_p())
    for dev, size in ((dq, 2 * nq), (dk, 2 * nkv), (dv, 2 * nkv), (do, 4 * nq)):
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm flash_attn: hipMalloc failed")
    hip.hipMemcpy(dq, qc.ctypes.data_as(ctypes.c_void_p), 2 * nq, 1)
    hip.hipMemcpy(dk, kc.ctypes.data_as(ctypes.c_void_p), 2 * nkv, 1)
    hip.hipMemcpy(dv, vc.ctypes.data_as(ctypes.c_void_p), 2 * nkv, 1)
    dbias = ctypes.c_void_p()
    if has_bias:  # [bh,Sq,Sk] f32 broadcast bias — the kernel's last runtime arg
        assert bias_c is not None  # set above whenever has_bias
        nb = bh * sq * sk
        if hip.hipMalloc(ctypes.byref(dbias), 4 * nb) != 0:
            for dev in (dq, dk, dv, do):
                hip.hipFree(dev)
            raise RuntimeError("rocm flash_attn: hipMalloc (attn_bias) failed")
        hip.hipMemcpy(dbias, bias_c.ctypes.data_as(ctypes.c_void_p), 4 * nb, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dq, nq) + _mr(dk, nkv) + _mr(dv, nkv) + _mr(do, nq)
                   + [ctypes.c_int64(sq), ctypes.c_int64(sk),
                      ctypes.c_float(scale), ctypes.c_int64(causal)])
    if gqa:  # grouped kernel's two trailing runtime args
        launch_args += [ctypes.c_int64(n_qh), ctypes.c_int64(kv_ratio)]
    if sliding:  # windowed kernel's trailing W arg (after the gqa args)
        launch_args += [ctypes.c_int64(window)]
    if has_softcap:  # soft-cap kernel's trailing f32 cap arg
        launch_args += [ctypes.c_float(softcap)]
    if has_bias:  # additive-bias kernel's trailing [bh,Sq,Sk] f32 memref (last)
        launch_args += _mr(dbias, bh * sq * sk)
    dev_bufs = (dq, dk, dv, do, dbias) if has_bias else (dq, dk, dv, do)
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx, gy = (sq + 15) // 16, bh
    rc = hip.hipModuleLaunchKernel(fn, gx, gy, 1, 32, 1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in dev_bufs:
            hip.hipFree(dev)
        raise RuntimeError(f"rocm flash_attn: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, 4 * nq, 2)
    for dev in dev_bufs:
        hip.hipFree(dev)
    return o.reshape(q.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED flash_attn BACKWARD lane (2026-07-10) — the reverse-mode analog
# of the forward lane above. ``runtime.launch()`` of an artifact stamped
# ``compiler_path = "rocm_flash_attn_bwd_compiled"`` builds the COMPILER-
# GENERATED FA-2 backward via ``generate-wmma-flash-attn-bwd-kernel`` (one
# tessera_rocm.flash_attn_bwd directive → THREE fragment-materialized WMMA
# kernels fa_pre / fa_dkdv / fa_dq → hsaco) and launches them in sequence to
# produce (dQ, dK, dV). The forward output O the pre-pass needs is recomputed
# on-device by REUSING the forward lane above (no state saved from forward), so
# the backward is a self-contained VJP over (dO, Q, K, V). f16/bf16 storage, f32
# accumulate. Matches the numpy attention-backward reference / autodiff
# ``vjp_flash_attn``. Core MHA (scale + causal) — GQA / sliding-window /
# logit-softcap / attn_bias backward are a follow-up (the C++ kernel already
# carries the GQA variant; the runtime lane forwards only the core here).
# ─────────────────────────────────────────────────────────────────────────────
#: hsaco bytes keyed by (head_dim, chip, dtype, gqa, bias).
_rocm_fa_bwd_hsaco_cache: dict[
    tuple[int, str, str, bool, bool, bool, bool], bytes] = {}


def _build_compiled_flash_attn_bwd_hsaco(head_dim: int,
                                         dtype: str = "f16",
                                         gqa: bool = False,
                                         bias: bool = False,
                                         window: bool = False,
                                         softcap: bool = False) -> bytes:
    """Generate + serialize the compiler's WMMA FA-2 backward kernels to hsaco
    (fa_pre / fa_dkdv / fa_dq in one module), fully in-process via tessera-opt.
    Cached per (head_dim, chip, dtype, gqa, bias, window, softcap). Trailing
    runtime args appended in a FIXED order — gqa(heads,kv_ratio) | window(W) |
    softcap(cap) | bias([bh,Sq,Sk], LAST): gqa=True adds the grouped-query
    variant (fa_dkdv atomically accumulates dK/dV, host pre-zeros); window=True
    the sliding-window variant (implicitly causal, masks keys older than W);
    softcap=True the Gemma-2 soft-cap (S=cap*tanh(scale*QK/cap), backward scales
    dS by 1-tanh^2); bias=True the additive-bias variant."""
    chip = _rocm_chip()
    key = (head_dim, chip, dtype, gqa, bias, window, softcap)
    cached = _rocm_fa_bwd_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm flash_attn backward lane")
    attrs = "".join([
        ", gqa = true" if gqa else "",
        ", sliding_window = true" if window else "",
        ", logit_softcap = true" if softcap else "",
        ", attn_bias = true" if bias else "",
    ])
    directive = (
        'module {\n'
        '  "tessera_rocm.flash_attn_bwd"() {name = "fa", '
        f'head_dim = {head_dim} : i64, dtype = "{dtype}"{attrs}}} '
        ': () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-wmma-flash-attn-bwd-kernel,"
        "lower-tessera-target-to-rocdl,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled flash_attn backward "
            f"in-process (rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm flash_attn backward lane: gpu.binary was not an ELF "
            "hsaco")
    _rocm_fa_bwd_hsaco_cache[key] = hsaco
    return hsaco


def _rocm_flash_attn_forward_o(q: Any, k: Any, v: Any, scale: float,
                               causal: int, bias: Any = None,
                               window: int = 0,
                               logit_softcap: float = 0.0) -> Any:
    """Recompute the forward output O (f32, shape [bh, sq, D]) by REUSING the
    forward compiled lane — the backward saves nothing from forward. The forward
    lane takes attn_bias as a 4th operand and window / logit_softcap as kwargs,
    so O matches the backward's windowed / soft-capped / biased score recompute."""
    names = ["q", "k", "v"] + (["bias"] if bias is not None else [])
    kw: dict[str, Any] = {"scale": scale, "causal": bool(causal)}
    if window:
        kw["window"] = int(window)
    if logit_softcap:
        kw["logit_softcap"] = float(logit_softcap)
    fwd_art = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_flash_attn_compiled",
        "executable": True, "execution_kind": "native_gpu",
        "arg_names": names, "output_name": "o",
        "ops": [{"op_name": "tessera.flash_attn", "result": "o",
                 "operands": names, "kwargs": kw}]})
    call = (q, k, v) if bias is None else (q, k, v, bias)
    return _execute_rocm_compiled_flash_attn(fwd_art, call)


_FA_BWD_OPS = ("tessera.flash_attn_bwd", "tessera.flash_attn_vjp")


def _execute_rocm_compiled_flash_attn_bwd(artifact: RuntimeArtifact,
                                          args: Any) -> Any:
    """The ``target="rocm"`` flash_attn BACKWARD lane. Operands are
    ``(dO, Q, K, V)`` — ``Q``/``dO`` are ``[..., H, Sq, D]`` and ``K``/``V`` are
    ``[..., G, Sk, D]`` (``G <= H``; ``G == H`` is plain MHA, ``G < H`` selects
    the grouped-query backward). Returns the tuple ``(dQ, dK, dV)`` shaped like
    ``(Q, K, V)``. Raises ``_RocmCompiledUnavailable`` when the lane can't run
    (no tessera-opt / serialization / GPU); ``ValueError`` on a bad op / dtype /
    shape / unsupported variant; ``RuntimeError`` on a real kernel failure."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _FA_BWD_OPS:
        raise ValueError(
            "rocm_flash_attn_bwd_compiled executor handles exactly one of "
            f"{_FA_BWD_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) not in (4, 5):
        raise ValueError(
            "flash_attn backward requires (dO, Q, K, V) operands, optionally "
            "plus a 5th additive attn_bias")
    values = _bind_launch_args(args, arg_names)
    do = _as_numpy(values[operand_names[0]])
    q = _as_numpy(values[operand_names[1]])
    k = _as_numpy(values[operand_names[2]])
    v = _as_numpy(values[operand_names[3]])
    bias_arr = (_as_numpy(values[operand_names[4]])
                if len(operand_names) == 5 else None)
    for name, arr in (("dO", do), ("Q", q), ("K", k), ("V", v)):
        if arr.ndim < 2:
            raise ValueError(
                f"flash_attn backward {name} must be rank >= 2 ([..., S, D]); "
                f"got {arr.shape}")
    head_dim = int(q.shape[-1])
    if head_dim <= 0 or head_dim % 16 != 0:
        raise ValueError(
            f"rocm flash_attn backward needs head_dim a positive multiple of "
            f"16; got {head_dim}")
    sq, sk = int(q.shape[-2]), int(k.shape[-2])
    bh = int(np.prod(q.shape[:-2])) if q.ndim > 2 else 1
    bh_kv = int(np.prod(k.shape[:-2])) if k.ndim > 2 else 1
    # GQA/MQA: H query heads vs G<=H key/value heads (head axis -3). The grouped
    # backward variant atomically accumulates dK/dV across the kv_ratio query
    # heads sharing each KV head. V must match K, dO must match Q, the batch dims
    # (everything before the head axis) must agree, and head_dim is shared.
    n_qh = int(q.shape[-3]) if q.ndim >= 3 else 1
    n_kvh = int(k.shape[-3]) if k.ndim >= 3 else 1
    gqa = n_kvh != n_qh
    if gqa and (n_kvh <= 0 or n_qh % n_kvh != 0):
        raise ValueError(
            f"rocm flash_attn backward GQA needs query-heads ({n_qh}) divisible "
            f"by kv-heads ({n_kvh})")
    kv_ratio = n_qh // n_kvh if gqa else 1
    if (v.shape != k.shape or do.shape != q.shape
            or int(v.shape[-1]) != head_dim
            or q.shape[:-3] != k.shape[:-3]):
        raise ValueError(
            "rocm flash_attn backward requires V==K, dO==Q, matching batch dims "
            f"and a shared head_dim; got Q{q.shape} K{k.shape} V{v.shape} "
            f"dO{do.shape}.")

    if q.dtype == np.float16:
        dtype_tag, store = "f16", np.float16
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and q.dtype == bf16:
            dtype_tag, store = "bf16", bf16
        else:
            raise ValueError(
                "rocm flash_attn backward handles f16/bf16 storage (f32 "
                f"accumulate); got {q.dtype}")

    kwargs = op.get("kwargs") or {}
    causal = 1 if bool(kwargs.get("causal", False)) else 0
    scale = kwargs.get("scale")
    scale = float(scale) if scale is not None else 1.0 / float(np.sqrt(head_dim))
    # Sliding-window: a positive `window` selects a causal band of width W
    # (query q attends to keys in (q-W, q]); the windowed kernel is implicitly
    # causal. Gemma-2 soft-cap: a positive `logit_softcap` caps the pre-softmax
    # score to cap*tanh(S/cap); the backward scales dS by 1-tanh^2(S_raw/cap).
    window = int(kwargs.get("window") or 0)
    if window < 0:
        raise ValueError(
            f"rocm flash_attn backward window must be non-negative; got {window}")
    sliding = window > 0
    softcap = kwargs.get("logit_softcap")
    softcap = float(softcap) if softcap else 0.0
    if softcap < 0:
        raise ValueError(
            f"rocm flash_attn backward logit_softcap must be non-negative; got "
            f"{softcap}")
    has_softcap = softcap > 0

    # Additive bias: S = softmax(scale*Q@K^T + bias). Host-broadcast to
    # Q.lead+(Sq,Sk) → [bh,Sq,Sk] f32 (kernel indexes bias[(bh*Sq+q)*Sk+k]),
    # matching the forward attn_bias lane. bias enters both O (via the forward
    # recompute) and the backward P/L/dS — dbias is not produced (constant-bias
    # VJP: dbias is only needed when bias is a positional differentiable input).
    has_bias = bias_arr is not None
    bias_c = None
    if has_bias:
        try:
            bias_b = np.broadcast_to(
                np.asarray(bias_arr, dtype=np.float32),
                tuple(q.shape[:-2]) + (sq, sk))
        except ValueError as exc:
            raise ValueError(
                f"rocm flash_attn backward attn_bias {np.asarray(bias_arr).shape}"
                f" is not broadcastable to Q.lead+(Sq,Sk) = "
                f"{tuple(q.shape[:-2]) + (sq, sk)}") from exc
        bias_c = np.ascontiguousarray(bias_b, dtype=np.float32).reshape(-1)

    # O the pre-pass needs — recompute on-device via the forward lane with the
    # SAME window/softcap/bias, so O matches the backward's score recompute.
    o_f32 = np.ascontiguousarray(
        _rocm_flash_attn_forward_o(q, k, v, scale, causal,
                                   bias=bias_arr if has_bias else None,
                                   window=window, logit_softcap=softcap),
        dtype=np.float32).reshape(bh, sq, head_dim)

    hsaco = _build_compiled_flash_attn_bwd_hsaco(
        head_dim, dtype_tag, gqa=gqa, bias=has_bias, window=sliding,
        softcap=has_softcap)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm flash_attn bwd: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm flash_attn bwd: no usable AMD GPU (module load failed)")
    fns = {}
    for nm in (b"fa_pre", b"fa_dkdv", b"fa_dq"):
        fn = ctypes.c_void_p()
        if hip.hipModuleGetFunction(ctypes.byref(fn), mod, nm) != 0:
            raise RuntimeError(
                f"rocm flash_attn bwd: kernel symbol {nm!r} not found")
        fns[nm] = fn

    qc = np.ascontiguousarray(q, dtype=store)
    kc = np.ascontiguousarray(k, dtype=store)
    vc = np.ascontiguousarray(v, dtype=store)
    doc = np.ascontiguousarray(do, dtype=store)
    nq, nkv, nl = bh * sq * head_dim, bh_kv * sk * head_dim, bh * sq
    cv = ctypes.c_void_p
    bufs: dict[str, Any] = {}
    for name, nb in (("Q", 2 * nq), ("K", 2 * nkv), ("V", 2 * nkv),
                     ("dO", 2 * nq), ("O", 4 * nq), ("L", 4 * nl), ("Dd", 4 * nl),
                     ("dQ", 4 * nq), ("dK", 4 * nkv), ("dV", 4 * nkv)):
        d = cv()
        if hip.hipMalloc(ctypes.byref(d), max(nb, 4)) != 0:
            for dd in bufs.values():
                hip.hipFree(dd)
            raise RuntimeError("rocm flash_attn bwd: hipMalloc failed")
        bufs[name] = d
    hip.hipMemcpy(bufs["Q"], qc.ctypes.data_as(cv), 2 * nq, 1)
    hip.hipMemcpy(bufs["K"], kc.ctypes.data_as(cv), 2 * nkv, 1)
    hip.hipMemcpy(bufs["V"], vc.ctypes.data_as(cv), 2 * nkv, 1)
    hip.hipMemcpy(bufs["dO"], doc.ctypes.data_as(cv), 2 * nq, 1)
    hip.hipMemcpy(bufs["O"], o_f32.ctypes.data_as(cv), 4 * nq, 1)
    n_bias = bh * sq * sk
    if has_bias:
        assert bias_c is not None  # set above whenever has_bias
        d = cv()
        if hip.hipMalloc(ctypes.byref(d), max(4 * n_bias, 4)) != 0:
            for dd in bufs.values():
                hip.hipFree(dd)
            raise RuntimeError("rocm flash_attn bwd: hipMalloc (attn_bias) failed")
        bufs["bias"] = d
        hip.hipMemcpy(d, bias_c.ctypes.data_as(cv), 4 * n_bias, 1)
    if gqa:
        # kv_ratio query heads atomic-accumulate into each KV head's dK/dV rows
        # (the sharing blocks add into the same rows) — pre-zero before fa_dkdv.
        hip.hipMemset(bufs["dK"], 0, 4 * nkv)
        hip.hipMemset(bufs["dV"], 0, 4 * nkv)

    def _mr(p, size):
        return [cv(p.value), cv(p.value), ctypes.c_int64(0),
                ctypes.c_int64(size), ctypes.c_int64(1)]

    sqc, skc = ctypes.c_int64(sq), ctypes.c_int64(sk)
    sc, cau = ctypes.c_float(scale), ctypes.c_int64(causal)
    # Grouped kernels take (heads, kv_ratio) as two trailing runtime args after
    # (Sq, Sk, scale, causal); the plain kernels have neither. Grid.y is always
    # the query-head count B*H (fa_dkdv accumulates into KV heads atomically).
    tail: list[Any] = (
        [ctypes.c_int64(n_qh), ctypes.c_int64(kv_ratio)] if gqa else [])
    # Trailing args in the C++ withGqa order: gqa pair | window W | softcap cap |
    # bias memref (LAST). Each present only when its flag is set.
    if sliding:
        tail.append(ctypes.c_int64(window))
    if has_softcap:
        tail.append(ctypes.c_float(softcap))
    bias_tail = _mr(bufs["bias"], n_bias) if has_bias else []
    gqt, gkt, gyt = (sq + 15) // 16, (sk + 15) // 16, bh

    def _launch(fn, gx, argv):
        arr = (cv * len(argv))()
        for i, val in enumerate(argv):
            arr[i] = ctypes.cast(ctypes.byref(val), cv)
        rc = hip.hipModuleLaunchKernel(fn, gx, gyt, 1, 32, 1, 1, 0, None,
                                       arr, None)
        if rc != 0:
            for dd in bufs.values():
                hip.hipFree(dd)
            raise RuntimeError(
                f"rocm flash_attn bwd: kernel launch failed rc={rc}")

    # fa_pre : (Q,K,dO, O,L,Dd, Sq,Sk, scale, causal[, heads, kv_ratio][, bias])
    _launch(fns[b"fa_pre"], gqt,
            _mr(bufs["Q"], nq) + _mr(bufs["K"], nkv) + _mr(bufs["dO"], nq)
            + _mr(bufs["O"], nq) + _mr(bufs["L"], nl) + _mr(bufs["Dd"], nl)
            + [sqc, skc, sc, cau] + tail + bias_tail)
    # fa_dkdv : (Q,K,V,dO, L,Dd, dK,dV, Sq,Sk, scale, causal[,heads,kv_ratio][,bias])
    _launch(fns[b"fa_dkdv"], gkt,
            _mr(bufs["Q"], nq) + _mr(bufs["K"], nkv) + _mr(bufs["V"], nkv)
            + _mr(bufs["dO"], nq) + _mr(bufs["L"], nl) + _mr(bufs["Dd"], nl)
            + _mr(bufs["dK"], nkv) + _mr(bufs["dV"], nkv)
            + [sqc, skc, sc, cau] + tail + bias_tail)
    # fa_dq : (Q,K,V,dO, L,Dd, dQ, Sq,Sk, scale, causal[, heads, kv_ratio][, bias])
    _launch(fns[b"fa_dq"], gqt,
            _mr(bufs["Q"], nq) + _mr(bufs["K"], nkv) + _mr(bufs["V"], nkv)
            + _mr(bufs["dO"], nq) + _mr(bufs["L"], nl) + _mr(bufs["Dd"], nl)
            + _mr(bufs["dQ"], nq) + [sqc, skc, sc, cau] + tail + bias_tail)
    hip.hipDeviceSynchronize()

    dq = np.zeros((bh, sq, head_dim), np.float32)
    dk = np.zeros((bh_kv, sk, head_dim), np.float32)
    dv = np.zeros((bh_kv, sk, head_dim), np.float32)
    hip.hipMemcpy(dq.ctypes.data_as(cv), bufs["dQ"], 4 * nq, 2)
    hip.hipMemcpy(dk.ctypes.data_as(cv), bufs["dK"], 4 * nkv, 2)
    hip.hipMemcpy(dv.ctypes.data_as(cv), bufs["dV"], 4 * nkv, 2)
    for dd in bufs.values():
        hip.hipFree(dd)
    return (dq.reshape(q.shape), dk.reshape(k.shape), dv.reshape(v.shape))


# ─────────────────────────────────────────────────────────────────────────────
# x86 flash_attn lane (P10) — the AVX-512 PARTNER to the ROCm WMMA flash_attn.
# FA-style streaming/online softmax (running max/denominator + rescaled
# accumulator; the S×S score matrix is never materialized). f32 (softmax is f32
# on every backend). Core MHA path: scale + causal. GQA / sliding-window /
# P10 extras (now supported, the AVX-512 partner to the ROCm WMMA flash_attn):
# GQA/MQA (host kv-head expansion), sliding window, logit-softcap, and additive
# attn_bias all run on the kernel (the basic kernel for plain MHA, the ext kernel
# for the extras). dropout (an RNG step) is still rejected.
# compiler_path="x86_flash_attn_compiled".
#
# tessera.multi_head_attention is a DIFFERENT contract — rank-3 [B, S, H*D] +
# num_heads, needing a split to [B, H, S, D] this kernel does not do — so it is
# rejected (mis-running it as single-head over H*D would corrupt the output).
# ─────────────────────────────────────────────────────────────────────────────
_X86_FA_OPS = ("tessera.flash_attn", "tessera.gqa_attention",
               "tessera.mqa_attention", "tessera.attn_sliding_window")


def _execute_x86_compiled_flash_attn(artifact: RuntimeArtifact,
                                     args: Any) -> Any:
    """The ``target="x86"`` flash_attn lane (AVX-512 online-softmax FA forward).
    Q/K/V are ``[..., S, D]`` (leading dims = B*H). f32, scale + causal."""
    import numpy as np
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    fn = getattr(lib, "tessera_x86_flash_attn_f32", None)
    if fn is None:
        raise _RocmCompiledUnavailable("tessera_x86_flash_attn_f32 missing")
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_FA_OPS:
        raise ValueError(
            f"x86_flash_attn_compiled executor handles one of {_X86_FA_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("flash_attn requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    q = np.ascontiguousarray(_as_numpy(values[operand_names[0]]), np.float32)
    k = np.ascontiguousarray(_as_numpy(values[operand_names[1]]), np.float32)
    v = np.ascontiguousarray(_as_numpy(values[operand_names[2]]), np.float32)
    # A 4th operand is the additive attn_bias / mask (the Graph IR + Apple path
    # normalize flash_attn(..., attn_bias=…) into a 4th operand).
    bias = (np.ascontiguousarray(_as_numpy(values[operand_names[3]]), np.float32)
            if len(operand_names) > 3 else None)
    if q.ndim < 2 or k.ndim < 2 or v.ndim < 2:
        raise ValueError("flash_attn Q/K/V must be at least rank 2 ([..., S, D])")
    d = int(q.shape[-1])
    sq, sk = int(q.shape[-2]), int(k.shape[-2])
    # K must share Q's head dim (the QK score dot); V's last dim is the value
    # width and MAY differ (v_head_dim != qk_head_dim). K/V share key length +
    # their own batch/head dims (which differ from Q under GQA).
    if (int(k.shape[-1]) != d or int(v.shape[-2]) != sk
            or v.shape[:-2] != k.shape[:-2]):
        raise ValueError(
            "x86 flash_attn requires K to share Q's head dim and K/V to share "
            f"batch/head + key length; got Q{q.shape} K{k.shape} V{v.shape}")
    # GQA / MQA — Hq query heads share Hkv < Hq key/value heads (head axis -3).
    # Expand K/V kv-heads to match Q's head count on the host, then the kernel
    # runs ordinary MHA. G == H is plain MHA (no expansion).
    if q.shape[:-2] != k.shape[:-2]:
        n_qh = int(q.shape[-3]) if q.ndim >= 3 else 1
        n_kvh = int(k.shape[-3]) if k.ndim >= 3 else 1
        if q.shape[:-3] != k.shape[:-3] or n_kvh <= 0 or n_qh % n_kvh:
            raise ValueError(
                f"x86 flash_attn GQA needs Q/K to share batch dims and "
                f"q-heads ({n_qh}) divisible by kv-heads ({n_kvh}); got "
                f"Q{q.shape} K{k.shape}")
        ratio = n_qh // n_kvh
        if ratio != 1:
            k = np.ascontiguousarray(np.repeat(k, ratio, axis=-3), np.float32)
            v = np.ascontiguousarray(np.repeat(v, ratio, axis=-3), np.float32)
    kwargs = op.get("kwargs") or {}
    if kwargs.get("dropout_p"):
        raise ValueError(
            "x86 flash_attn lane does not apply dropout (an RNG step); got "
            f"dropout_p={kwargs.get('dropout_p')!r}")
    causal = bool(kwargs.get("causal", False))
    scale = kwargs.get("scale")
    scale = float(scale) if scale is not None else 1.0 / float(np.sqrt(d))
    window = int(kwargs.get("window") or 0)
    if window < 0:
        raise ValueError(f"x86 flash_attn window must be >= 0; got {window}")
    if op_name == "tessera.attn_sliding_window" and window <= 0:
        raise ValueError(
            "tessera.attn_sliding_window requires a positive `window` kwarg")
    softcap = float(kwargs.get("logit_softcap") or 0.0)
    if softcap < 0:
        raise ValueError(f"x86 flash_attn logit_softcap must be >= 0; got {softcap}")
    if window > 0 or softcap > 0 or bias is not None:
        return _x86_flash_attn_run(q, k, v, scale, causal, window, softcap,
                                   bias, np)
    return _x86_flash_attn_kernel(q, k, v, scale, causal, np)


def _x86_flash_attn(q: Any, k: Any, v: Any, *, scale: Any = None,
                    causal: bool = True, attn_bias: Any = None) -> Any:
    """Run the native AVX-512 flash_attn forward on Q/K/V via the x86 flash
    executor (constructs a minimal sub-artifact) — the CPU analog of
    :func:`_rocm_flash_attn`. Returns the f32 attention output shaped like Q. An
    optional ``attn_bias`` (additive, broadcastable to Q.lead+(Sq,Sk)) routes
    through the extended kernel: ``O = softmax(scale·Q@K^T + attn_bias)·V``."""
    kw: dict[str, Any] = {"causal": bool(causal)}
    if scale is not None:
        kw["scale"] = float(scale)
    arg_names = ["q", "k", "v"]
    operands = ["q", "k", "v"]
    call_args: tuple[Any, ...] = (q, k, v)
    if attn_bias is not None:
        arg_names = ["q", "k", "v", "attn_bias"]
        operands = ["q", "k", "v", "attn_bias"]
        call_args = (q, k, v, attn_bias)
    sub = RuntimeArtifact(metadata={
        "target": "x86", "compiler_path": "x86_flash_attn_compiled",
        "executable": True, "execution_kind": "native_cpu",
        "arg_names": arg_names, "output_name": "o",
        "ops": [{"op_name": "tessera.flash_attn", "result": "o",
                 "operands": operands, "kwargs": kw}],
    })
    return _execute_x86_compiled_flash_attn(sub, call_args)


def _x86_flash_attn_run(q: Any, k: Any, v: Any, scale: float, causal: bool,
                        window: int, softcap: float, bias: Any, np: Any) -> Any:
    """The extended AVX-512 FA forward (sliding window / logit-softcap / additive
    bias). Operands are already MHA-matched (GQA expanded). bias is None or
    broadcastable to [bh, Sq, Sk]. Returns O shaped q.shape[:-1] + (dv,)."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    fn = getattr(lib, "tessera_x86_flash_attn_ext_f32", None)
    if fn is None:
        raise _RocmCompiledUnavailable("tessera_x86_flash_attn_ext_f32 missing")
    d, sq, sk = int(q.shape[-1]), int(q.shape[-2]), int(k.shape[-2])
    dv = int(v.shape[-1])
    bh = int(np.prod(q.shape[:-2])) if q.ndim > 2 else 1
    qc = q.reshape(bh, sq, d)
    kc = k.reshape(bh, sk, d)
    vc = v.reshape(bh, sk, dv)
    o = np.zeros((bh, sq, dv), np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    if bias is not None:
        # Broadcast the bias to Q's leading (batch/head) dims + (Sq, Sk), then
        # flatten those leading dims to bh — consistent with the Q/K/V reshape.
        # Accepts [Sq,Sk] (shared), [B,H,Sq,Sk] (per bh), [B,1,Sq,Sk], etc.
        lead = q.shape[:-2]
        try:
            bc = np.ascontiguousarray(
                np.broadcast_to(bias, lead + (sq, sk)), np.float32).reshape(
                bh, sq, sk)
        except ValueError as exc:
            raise ValueError(
                f"x86 flash_attn attn_bias shape {bias.shape} does not "
                f"broadcast to Q's batch/head + (Sq, Sk) = {lead + (sq, sk)}"
            ) from exc
        bptr = bc.ctypes.data_as(cf)
        bstride = sq * sk
    else:
        bptr = cf()                       # NULL
        bstride = 0
    fn(qc.ctypes.data_as(cf), kc.ctypes.data_as(cf), vc.ctypes.data_as(cf),
       bptr, ctypes.c_int64(bstride), ctypes.c_int64(bh), ctypes.c_int64(sq),
       ctypes.c_int64(sk), ctypes.c_int64(d), ctypes.c_int64(dv),
       ctypes.c_float(scale), ctypes.c_int(1 if causal else 0),
       ctypes.c_int64(window), ctypes.c_float(softcap), o.ctypes.data_as(cf))
    return o.reshape(q.shape[:-1] + (dv,))


def _x86_flash_attn_kernel(q: Any, k: Any, v: Any, scale: float, causal: bool,
                           np: Any) -> Any:
    """Run the AVX-512 online-softmax FA forward on already-validated MHA
    operands. Q ``[..., Sq, D]``, K/V ``[..., Sk, D]`` (matching leading dims);
    returns O shaped like Q. f32."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    fn = getattr(lib, "tessera_x86_flash_attn_f32", None)
    if fn is None:
        raise _RocmCompiledUnavailable("tessera_x86_flash_attn_f32 missing")
    q = np.ascontiguousarray(q, np.float32)
    k = np.ascontiguousarray(k, np.float32)
    v = np.ascontiguousarray(v, np.float32)
    # `d` is the QK head dim (the score dot); `dv` is the value width (output
    # width). They differ for MLA configs with v_head_dim != qk_head_dim.
    d, sq, sk = int(q.shape[-1]), int(q.shape[-2]), int(k.shape[-2])
    dv = int(v.shape[-1])
    bh = int(np.prod(q.shape[:-2])) if q.ndim > 2 else 1
    qc = q.reshape(bh, sq, d)
    kc = k.reshape(bh, sk, d)
    vc = v.reshape(bh, sk, dv)
    o = np.zeros((bh, sq, dv), np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    fn(qc.ctypes.data_as(cf), kc.ctypes.data_as(cf), vc.ctypes.data_as(cf),
       ctypes.c_int64(bh), ctypes.c_int64(sq), ctypes.c_int64(sk),
       ctypes.c_int64(d), ctypes.c_int64(dv), ctypes.c_float(scale),
       ctypes.c_int(1 if causal else 0), o.ctypes.data_as(cf))
    return o.reshape(q.shape[:-1] + (dv,))


# ─────────────────────────────────────────────────────────────────────────────
# x86 MLA latent-KV lane (P11) — DeepSeek Multi-head Latent Attention building
# blocks, COMPOSED on the shipped AVX-512 GEMM + the P10 flash_attn lane (no new
# kernel). latent_kv_compress c = x @ W_dkv; latent_kv_expand_k/v K/V = c @ W_uk
# /W_uv (all batched GEMMs); mla_decode_fused chains compress → expand → flash_
# attn. Device does the FLOP-heavy matmuls + attention; host orchestrates the
# chain. compiler_path="x86_mla_compiled". f32. Matches the numpy MLA reference.
# ─────────────────────────────────────────────────────────────────────────────
_X86_MLA_OPS = ("tessera.latent_kv_compress", "tessera.latent_kv_expand_k",
                "tessera.latent_kv_expand_v", "tessera.mla_decode_fused")


def _execute_x86_compiled_mla(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` MLA latent-KV lane (compress / expand_k / expand_v /
    mla_decode_fused), composed on the AVX-512 GEMM + flash_attn lanes."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_MLA_OPS:
        raise ValueError(
            f"x86_mla_compiled executor handles one of {_X86_MLA_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    ops_in = [np.ascontiguousarray(_as_numpy(values[n]), np.float32)
              for n in operand_names]

    if op_name in ("tessera.latent_kv_compress", "tessera.latent_kv_expand_k",
                   "tessera.latent_kv_expand_v"):
        if len(ops_in) != 2:
            raise ValueError(f"{op_name} needs (x, W) operands; got {len(ops_in)}")
        return _x86_batched_gemm(ops_in[0], ops_in[1])

    # mla_decode_fused(x, W_dkv, W_uk, W_uv, q)
    if len(ops_in) != 5:
        raise ValueError(
            "mla_decode_fused needs (x, W_dkv, W_uk, W_uv, q) operands; "
            f"got {len(ops_in)}")
    x, w_dkv, w_uk, w_uv, q = ops_in
    c = _x86_batched_gemm(x, w_dkv)           # compress to latent
    kk = _x86_batched_gemm(c, w_uk)           # expand to K
    vv = _x86_batched_gemm(c, w_uv)           # expand to V (value width may
    #                                           differ from the QK head dim)
    if q.shape[:-2] != kk.shape[:-2] or int(q.shape[-1]) != int(kk.shape[-1]):
        raise ValueError(
            "x86 mla_decode_fused: expanded K must match q's batch + head dim "
            f"(the QK score dot; single-head MLA); got q{q.shape} K{kk.shape}")
    scale = kwargs.get("scale")
    scale = float(scale) if scale is not None else 1.0 / float(np.sqrt(q.shape[-1]))
    causal = bool(kwargs.get("causal", False))
    return _x86_flash_attn_kernel(q, kk, vv, scale, causal, np)


# ─────────────────────────────────────────────────────────────────────────────
# NSA — DeepSeek native sparse attention (P11) — blends three branches through a
# learned gate: a sliding-window branch (the P10 window kernel), a
# compressed-block branch (dense attention over per-block mean summaries), and a
# top-k block branch (per-query top-k block SELECTION on the host + dense
# attention over the gathered tokens on the device). The FLOP-heavy attention in
# every branch runs on the AVX-512 flash_attn kernels; the block compression /
# top-k selection / gather / gate blend are the cheap host structure. f32,
# matches tessera.ops.deepseek_sparse_attention. compiler_path=
# "x86_nsa_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_NSA_OPS = ("tessera.deepseek_sparse_attention",)


def _x86_attn_dense(q: Any, k: Any, v: Any, causal: bool, window: int,
                    np: Any) -> Any:
    """A dense / windowed attention via the AVX-512 flash_attn kernels."""
    scale = 1.0 / float(np.sqrt(int(q.shape[-1])))
    if window and window > 0:
        return _x86_flash_attn_run(q, k, v, scale, causal, int(window), 0.0,
                                   None, np)
    return _x86_flash_attn_kernel(q, k, v, scale, causal, np)


def _x86_nsa_topk_block_attn(Q: Any, K: Any, V: Any, top_k: int,
                             block_size: int, causal: bool, np: Any) -> Any:
    """NSA top-k branch: per query select the top_k highest-scoring KV blocks
    (vs the compressed summaries), gather their full tokens, run dense attention
    over the gathered set. Q/K/V are [B, H, S, D]."""
    B, H, Sq, D = Q.shape
    Sk, Dv = int(K.shape[2]), int(V.shape[-1])
    nb = Sk // block_size
    Kr = K.reshape(B, H, nb, block_size, D)
    Vr = V.reshape(B, H, nb, block_size, Dv)
    Kc = Kr.mean(axis=3)                                   # [B,H,nb,D] summaries
    scores = np.matmul(Q, np.swapaxes(Kc, -1, -2))         # [B,H,Sq,nb]
    if causal:
        q_block = (np.arange(Sq) // block_size)[None, None, :, None]
        future = np.arange(nb)[None, None, None, :] > q_block
        scores = np.where(future, -np.inf, scores)
    k_sel = min(top_k, nb)
    idx = np.argpartition(-scores, k_sel - 1, axis=-1)[..., :k_sel]
    idx = np.sort(idx, axis=-1)                            # [B,H,Sq,k_sel]
    bi = np.arange(B)[:, None, None, None]
    hi = np.arange(H)[None, :, None, None]
    Ksel = Kr[bi, hi, idx]            # [B,H,Sq,k_sel,block_size,D]
    Vsel = Vr[bi, hi, idx]            # [B,H,Sq,k_sel,block_size,Dv]
    g = k_sel * block_size
    Qf = np.ascontiguousarray(Q.reshape(B * H * Sq, 1, D), np.float32)
    Kf = np.ascontiguousarray(Ksel.reshape(B * H * Sq, g, D), np.float32)
    Vf = np.ascontiguousarray(Vsel.reshape(B * H * Sq, g, Dv), np.float32)
    Of = _x86_attn_dense(Qf, Kf, Vf, causal=False, window=0, np=np)
    return Of.reshape(B, H, Sq, Dv)


def _x86_nsa_compute(operands: list, kwargs: dict, np: Any) -> Any:
    Q = np.ascontiguousarray(operands[0], np.float32)
    K = np.ascontiguousarray(operands[1], np.float32)
    V = np.ascontiguousarray(operands[2], np.float32)
    gate = (np.ascontiguousarray(operands[3], np.float32)
            if len(operands) > 3 and operands[3] is not None else None)
    if Q.ndim != 4 or K.ndim != 4 or V.ndim != 4:
        raise ValueError("nsa expects rank-4 (B, H, S, D) Q/K/V")
    window_size = int(kwargs["window_size"])
    block_size = int(kwargs["block_size"])
    top_k = int(kwargs["top_k"])
    causal = bool(kwargs.get("causal", True))
    if int(K.shape[2]) % block_size:
        raise ValueError(
            f"nsa: key length {K.shape[2]} not divisible by block_size "
            f"{block_size}")
    nb = int(K.shape[2]) // block_size
    Kc = K.reshape(K.shape[0], K.shape[1], nb, block_size, K.shape[-1]).mean(3)
    Vc = V.reshape(V.shape[0], V.shape[1], nb, block_size, V.shape[-1]).mean(3)
    sliding = _x86_attn_dense(Q, K, V, causal, window_size, np)
    compressed = _x86_attn_dense(Q, Kc, Vc, False, 0, np)
    topk = _x86_nsa_topk_block_attn(Q, K, V, top_k, block_size, causal, np)
    if gate is None:
        w = np.full(sliding.shape[:-1] + (3,), 1.0 / 3.0, np.float32)
    else:
        g = gate.astype(np.float64)
        e = np.exp(g - g.max(axis=-1, keepdims=True))
        w = (e / e.sum(axis=-1, keepdims=True)).astype(np.float32)
    out = (sliding * w[..., 0:1] + compressed * w[..., 1:2]
           + topk * w[..., 2:3])
    return np.ascontiguousarray(out, np.float32)


def _execute_x86_compiled_nsa(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` NSA (deepseek_sparse_attention) lane."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _NSA_OPS:
        raise ValueError(
            f"x86_nsa_compiled executor handles one of {_NSA_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    operand_names = [str(n) for n in ops[0].get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("nsa requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    return _x86_nsa_compute(operands, ops[0].get("kwargs") or {}, np)


# ─────────────────────────────────────────────────────────────────────────────
# MSA (MiniMax Sparse Attention) main-branch lane — the AVX-512 partner to the
# ROCm block-sparse WMMA lane and Apple's host-select MSL lane. MSA is exact
# attention over a per-GQA-group Top-k of KV blocks: the exp-free index scoring +
# block selection are data-dependent host code (reuse the reference ops so the
# selection is bit-identical), and the exact attend runs on the AVX-512
# flash_attn kernel as DENSE attention with the non-selected / causal-invalid keys
# folded into an additive -inf bias (the same host-select + device-attend shape
# Apple/ROCm use; the fused exp-free-Top-k + KV-outer kernel is future). Exact
# match to the reference; dense-equivalence (top_k == num_blocks) reduces the mask
# to causal-only → dense GQA. compiler_path="x86_msa_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_X86_MSA_OPS = ("tessera.msa_sparse_attention",)


def _x86_msa_compute(operands: list, kwargs: dict, np: Any) -> Any:
    from tessera.stdlib import attention as _attn
    Q = np.ascontiguousarray(operands[0], np.float32)
    K = np.ascontiguousarray(operands[1], np.float32)
    V = np.ascontiguousarray(operands[2], np.float32)
    if Q.ndim != 4 or K.ndim != 4 or V.ndim != 4:
        raise ValueError("msa_sparse_attention expects rank-4 (B, H, S, D)")
    B, Hq, Sq, D = Q.shape
    Hkv, Sk = int(K.shape[1]), int(K.shape[2])
    if Hkv == 0 or Hq % Hkv:
        raise ValueError(f"MSA GQA requires Hq % Hkv == 0; got Hq={Hq}, Hkv={Hkv}")
    block_size = int(kwargs["block_size"])
    top_k = int(kwargs["top_k"])
    if block_size <= 0:
        raise ValueError("MSA block_size must be > 0")
    causal = bool(kwargs.get("causal", True))
    force_local = bool(kwargs.get("force_local_block", True))
    scale_kw = kwargs.get("scale")
    scale = float(scale_kw) if scale_kw is not None else 1.0 / float(np.sqrt(D))
    qpos = kwargs.get("q_positions")
    qpos = np.arange(Sq) if qpos is None else np.asarray(qpos).reshape(-1)
    if qpos.shape[0] != Sq:
        raise ValueError(f"q_positions length {qpos.shape[0]} must equal Sq={Sq}")
    num_blocks = (Sk + block_size - 1) // block_size
    if not (1 <= top_k <= num_blocks):
        raise ValueError(
            f"MSA top_k={top_k} must be in [1, num_blocks={num_blocks}]")
    # Selection — host, bit-identical to the reference (accept an explicit
    # selected_block_ids worklist, else score + top-k select).
    sel = kwargs.get("selected_block_ids")
    if sel is None:
        scores = _attn.msa_index_scores(Q, K, block_size=block_size,
                                        scale=scale_kw)
        sel = _attn.msa_select_blocks(
            scores, top_k=top_k, block_size=block_size,
            force_local_block=force_local, causal=causal, q_positions=qpos)
    sel = np.asarray(sel, np.int64)
    if sel.shape != (B, Hkv, Sq, top_k):
        raise ValueError(
            f"selected_block_ids must be {(B, Hkv, Sq, top_k)}; got {sel.shape}")
    # Additive mask [B, Hkv, Sq, Sk]: a key is allowed iff its block is selected
    # AND (non-causal or key <= qpos). Non-allowed keys get -inf → 0 weight, so
    # the dense flash_attn over all keys equals exact attention over the selected
    # blocks. (padded keys past Sk never appear — Sk is the real key length.)
    onehot = np.zeros((B, Hkv, Sq, num_blocks), dtype=bool)
    np.put_along_axis(onehot, np.clip(sel, 0, num_blocks - 1), True, axis=-1)
    kb = np.arange(Sk) // block_size                       # block id per key
    key_sel = onehot[..., kb]                              # [B,Hkv,Sq,Sk]
    if causal:
        key_sel = key_sel & (np.arange(Sk)[None, None, None, :]
                             <= qpos[None, None, :, None])
    g = Hq // Hkv
    mask = np.where(key_sel, np.float32(0.0), np.float32(-1e30))
    mask_hq = np.repeat(mask, g, axis=1)                   # [B,Hq,Sq,Sk]
    out = np.asarray(_x86_flash_attn(Q, K, V, scale=scale, causal=False,
                                     attn_bias=mask_hq), np.float32)
    # Rows with no allowed key (only reachable when force_local_block=False and
    # every selected block is in the future) are 0 in the reference; the dense
    # softmax over an all-(-inf) row would instead be uniform, so zero them.
    row_has_key = np.repeat(key_sel.any(axis=-1), g, axis=1)   # [B,Hq,Sq]
    return np.ascontiguousarray(np.where(row_has_key[..., None], out, 0.0),
                                np.float32)


def _execute_x86_compiled_msa(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` MSA (msa_sparse_attention) lane: host index-select +
    AVX-512 dense-over-selected-blocks attend (additive -inf mask)."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_MSA_OPS:
        raise ValueError(
            f"x86_msa_compiled executor handles one of {_X86_MSA_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    operand_names = [str(n) for n in ops[0].get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("msa_sparse_attention requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    return _x86_msa_compute(operands, ops[0].get("kwargs") or {}, np)


# ─────────────────────────────────────────────────────────────────────────────
# Linear-attention backbone (P10 scan-family x86 partners) — the AVX-512 partner
# to the ROCm linear_attn lane. linear_attn / power_attn / retention all share
# the `_linear_attn_impl` recurrence, which is mathematically the
# QUADRATIC-PARALLEL form  O = (φ(Q)·φ(K)ᵀ ⊙ causal ⊙ decay) @ V : two batched
# GEMMs on the AVX-512 f32 GEMM with the causal mask + per-token decay matrix on
# the host. The feature map (elu / relu / identity / polynomial_2) and the
# power/decay parametrics are host structure; power_attn = φ=x^deg,
# retention = φ=x^deg + multiplicative decay = exp(log_g). f32, matches the numpy
# reference. compiler_path="x86_linear_attn_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_X86_LINATTN_OPS = ("tessera.linear_attn", "tessera.power_attn",
                    "tessera.retention")
_LINATTN_FEATURE_MAPS = ("elu", "relu", "identity", "polynomial_2")


def _linattn_feature_map(x: Any, name: str, np: Any) -> Any:
    if name == "elu":
        return np.where(x > 0, x + 1.0, np.exp(x)).astype(np.float32)
    if name == "relu":
        return np.maximum(x, 0.0).astype(np.float32)
    if name == "identity":
        return np.ascontiguousarray(x, np.float32)
    if name == "polynomial_2":
        return (x * x).astype(np.float32)
    raise ValueError(
        f"linear_attn feature_map must be one of {_LINATTN_FEATURE_MAPS}; "
        f"got {name!r}")


def _x86_linear_attn_quad(phi_q: Any, phi_k: Any, v: Any, causal: bool,
                          decay: Any, np: Any) -> Any:
    """O = (φQ·φKᵀ ⊙ causal ⊙ decay) @ V on the AVX-512 batched GEMM.
    phi_q/phi_k [B,H,S,Dqk]; v [B,H,S,Dv]; decay [B,H,S] or None.

    decay is honored ONLY in the causal path — the reference
    ``_linear_attn_impl`` non-causal branch folds to a single global
    ``φQ @ Σ(φKᵀV)`` and ignores decay, so this lane must too.
    """
    scores = _x86_batched_gemm(phi_q, np.swapaxes(phi_k, -1, -2))  # [B,H,S,S]
    s = int(scores.shape[-1])
    if not causal:
        return _x86_batched_gemm(np.ascontiguousarray(scores, np.float32),
                                 np.ascontiguousarray(v, np.float32))
    tri = np.tril(np.ones((s, s), bool))
    if decay is None:
        scores = scores * tri.astype(np.float32)
    else:
        # Decay matrix D[t,r] = prod_{u=r+1..t} decay[u], built in LOG space:
        # cumprod(decay) underflows to 0 over a long run of small factors, and
        # the c[t]/c[r] ratio then yields inf/NaN that the tril-multiply turns
        # into inf*0 = NaN, contaminating even valid earlier rows. cumsum of
        # logs never underflows; masking the upper triangle to -inf BEFORE exp
        # makes those entries exp(-inf)=0 cleanly (no overflow, no inf*0).
        d = np.asarray(decay, np.float64)                       # [B,H,S]
        ell = np.cumsum(np.log(np.maximum(d, 1e-30)), axis=-1)  # L[t]
        diff = ell[..., :, None] - ell[..., None, :]            # L[t]-L[r]
        diff = np.where(tri, diff, -np.inf)
        scores = scores * np.exp(diff).astype(np.float32)
    return _x86_batched_gemm(np.ascontiguousarray(scores, np.float32),
                             np.ascontiguousarray(v, np.float32))


def _x86_linattn_compute(op_name: str, operands: list, kwargs: dict,
                         np: Any) -> Any:
    Q = np.ascontiguousarray(operands[0], np.float32)
    K = np.ascontiguousarray(operands[1], np.float32)
    V = np.ascontiguousarray(operands[2], np.float32)
    if Q.ndim != 4 or K.ndim != 4 or V.ndim != 4:
        raise ValueError("linear_attn family expects rank-4 (B, H, S, D)")
    causal = bool(kwargs.get("causal", True))
    decay = None

    if op_name == "tessera.linear_attn":
        feature_map = str(kwargs.get("feature_map", "elu"))
        if kwargs.get("decay") is not None:
            decay = np.asarray(kwargs["decay"], np.float64)
        phi_q = _linattn_feature_map(Q, feature_map, np)
        phi_k = _linattn_feature_map(K, feature_map, np)
    elif op_name == "tessera.power_attn":
        deg = int(kwargs.get("deg", 2))
        if deg < 1:
            raise ValueError(f"power_attn deg must be >= 1; got {deg}")
        if deg == 2:
            phi_q = _linattn_feature_map(Q, "polynomial_2", np)
            phi_k = _linattn_feature_map(K, "polynomial_2", np)
        else:
            phi_q = (Q.astype(np.float64) ** deg).astype(np.float32)
            phi_k = (K.astype(np.float64) ** deg).astype(np.float32)
    else:  # tessera.retention — φ = x^deg + multiplicative decay = exp(log_g)
        deg = int(kwargs.get("deg", 2))
        phi_q = (Q.astype(np.float64) ** deg).astype(np.float32)
        phi_k = (K.astype(np.float64) ** deg).astype(np.float32)
        log_g = kwargs.get("log_g")
        if log_g is not None:
            decay = np.exp(np.asarray(log_g, np.float64))

    return np.ascontiguousarray(
        _x86_linear_attn_quad(phi_q, phi_k, V, causal, decay, np), np.float32)


def _execute_x86_compiled_linear_attn(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="x86"`` linear-attention backbone (linear_attn / power_attn
    / retention) on the AVX-512 GEMM quadratic-parallel form."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_LINATTN_OPS:
        raise ValueError(
            f"x86_linear_attn_compiled executor handles one of "
            f"{_X86_LINATTN_OPS}; got {[o.get('op_name') for o in ops]!r}")
    operand_names = [str(n) for n in ops[0].get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("linear_attn family requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    return _x86_linattn_compute(op_name, operands, ops[0].get("kwargs") or {},
                                np)



# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED linear_attn lane (2026-06-25) — the quadratic-parallel form
# O = (φ(Q)φ(K)ᵀ ⊙ causal) @ V, NO softmax (a distinct algorithm from
# flash_attn). ``runtime.launch()`` of an artifact stamped
# ``compiler_path = "rocm_linear_attn_compiled"`` builds the COMPILER-GENERATED
# kernel via the ``generate-wmma-linear-attn-kernel`` pipeline → hsaco (same
# Stage-L3 spine) and launches it via HIP. f16/bf16 storage, f32 accumulate;
# square head dim. ONE hsaco per (head_dim, chip, dtype, feature_map) — cached.
# ─────────────────────────────────────────────────────────────────────────────
#: hsaco bytes keyed by (head_dim, chip, dtype, feature_map, decay).
_rocm_la_hsaco_cache: dict[tuple[int, str, str, str, bool], bytes] = {}


def _build_compiled_linear_attn_hsaco(head_dim: int, dtype: str = "f16",
                                      feature_map: str = "identity",
                                      decay: bool = False) -> bytes:
    """Generate + serialize the compiler's WMMA linear-attention forward kernel
    to hsaco, in-process via tessera-opt. Cached per (head_dim, chip, dtype,
    feature_map, decay). decay=True emits the decay-masked variant (trailing
    f32 log λ arg; lightning_attention / retention)."""
    chip = _rocm_chip()
    key = (head_dim, chip, dtype, feature_map, decay)
    cached = _rocm_la_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm linear_attn lane")
    fm_attr = (f', feature_map = "{feature_map}"'
               if feature_map != "identity" else "")
    decay_attr = ", decay = true" if decay else ""
    directive = (
        'module {\n'
        '  "tessera_rocm.linear_attn"() {name = "la", '
        f'head_dim = {head_dim} : i64, dtype = "{dtype}"{fm_attr}{decay_attr}}} '
        ': () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-wmma-linear-attn-kernel,"
        "lower-tessera-target-to-rocdl,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled linear_attn in-process "
            f"(rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm linear_attn lane: gpu.binary was not an ELF hsaco")
    _rocm_la_hsaco_cache[key] = hsaco
    return hsaco


def _execute_rocm_compiled_linear_attn(artifact: RuntimeArtifact,
                                       args: Any) -> Any:
    """The ``target="rocm"`` linear-attention family lane: run the COMPILER-
    GENERATED WMMA kernel for the quadratic-parallel form
    O = (φ(Q)φ(K)ᵀ ⊙ causal [⊙ λ^(i-j)]) @ V — no softmax, no normalization (a
    distinct algorithm from flash_attn). Handles ``tessera.linear_attn`` plus its
    decay-masked siblings ``tessera.lightning_attention`` (φ = identity + decay)
    and ``tessera.retention`` (φ = x², degree-2, + decay), dispatched by op name
    to a (feature_map, decay) config — all three run the same kernel. Q/K/V are
    ``[..., S, D]`` (leading dims = B*H), square head dim. ``causal`` defaults
    True; ``feature_map`` ∈ {identity, relu, polynomial_2}; decay via
    ``log_decay`` / ``log_g`` (log λ) or ``decay`` (λ)."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    # The lane handles linear_attn plus its decay-masked siblings, which the
    # canonical reference (`_apple_gpu_dispatch_linear_attn`) dispatches by op
    # name to a (feature_map, decay) config: lightning_attention = identity +
    # decay; retention (deg 2) = polynomial_2 + decay. linear_attn takes its
    # feature_map from the kwargs. All three run the SAME WMMA kernel.
    _LA_OPS = ("tessera.linear_attn", "tessera.lightning_attention",
               "tessera.retention")
    op_short = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_short not in _LA_OPS:
        raise ValueError(
            "rocm_linear_attn_compiled executor handles exactly one of "
            f"{_LA_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 3:
        raise ValueError("linear_attn requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    q = _as_numpy(values[operand_names[0]])
    k = _as_numpy(values[operand_names[1]])
    v = _as_numpy(values[operand_names[2]])
    if q.ndim < 2 or k.ndim < 2 or v.ndim < 2:
        raise ValueError("linear_attn Q/K/V must be at least rank 2 ([...,S,D])")
    head_dim = int(q.shape[-1])
    if head_dim <= 0 or head_dim % 16 != 0:
        raise ValueError(
            "rocm linear_attn lane needs head_dim a positive multiple of 16; "
            f"got {head_dim}")
    # v1: square head dim (Dq == Dv) and equal Q/K/V head counts (no grouping).
    if int(k.shape[-1]) != head_dim or int(v.shape[-1]) != head_dim:
        raise ValueError(
            "rocm linear_attn lane requires square head dim (Dq == Dv); got "
            f"Q{q.shape} K{k.shape} V{v.shape}")
    if q.shape[:-2] != k.shape[:-2] or q.shape[:-2] != v.shape[:-2]:
        raise ValueError(
            "rocm linear_attn lane requires equal Q/K/V batch/head dims; got "
            f"Q{q.shape} K{k.shape} V{v.shape}")
    # K and V are a paired key/value sequence — they MUST share the key length.
    # `sk` (from K) drives the V device allocation + copy size (nkv), so a
    # shorter V would otherwise read past the host buffer; reject, never read OOB.
    if int(k.shape[-2]) != int(v.shape[-2]):
        raise ValueError(
            "rocm linear_attn lane requires K and V to share the sequence "
            f"length; got K{k.shape} V{v.shape}")
    sq = int(q.shape[-2])
    sk = int(k.shape[-2])
    bh = int(np.prod(q.shape[:-2])) if q.ndim > 2 else 1

    if q.dtype == np.float16:
        dtype_tag, store = "f16", np.float16
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and q.dtype == bf16:
            dtype_tag, store = "bf16", bf16
        else:
            raise ValueError(
                "rocm linear_attn lane handles f16/bf16 storage (f32 accumulate)"
                f"; got {q.dtype}")

    kwargs = op.get("kwargs") or {}
    causal = 1 if bool(kwargs.get("causal", True)) else 0
    # Feature map: the decay-masked siblings pin it (matching the reference);
    # plain linear_attn takes it from the kwargs.
    if op_short == "tessera.lightning_attention":
        feature_map = "identity"
    elif op_short == "tessera.retention":
        # The kernel realizes degree-2 retention (φ = x²). The reference's
        # deg != 2 path pre-powers Q/K, which this kernel does not do — reject
        # rather than silently compute the wrong thing.
        deg = int(kwargs.get("deg", 2))
        if deg != 2:
            raise ValueError(
                "rocm retention lane supports degree 2 only (φ = x²); got "
                f"deg={deg}")
        feature_map = "polynomial_2"
    else:  # tessera.linear_attn
        feature_map = str(kwargs.get("feature_map") or "identity")
    if feature_map not in ("identity", "relu", "polynomial_2"):
        raise ValueError(
            "rocm linear_attn feature_map must be identity, relu, or "
            f"polynomial_2; got {feature_map!r}")
    # Decay: per-head λ as `log_decay` / `log_g` (log λ) or `decay` (λ). The
    # kernel applies A[i,j] *= λ^(i-j) over the causal band. Optional for all
    # three ops (the reference applies the decay mask only when supplied).
    log_g = kwargs.get("log_decay")
    if log_g is None:
        log_g = kwargs.get("log_g")          # retention's canonical decay kwarg
    if log_g is None and kwargs.get("decay") is not None:
        lam = float(kwargs["decay"])
        if lam <= 0.0:
            raise ValueError(
                f"rocm linear_attn decay (λ) must be > 0; got {lam}")
        log_g = float(np.log(lam))
    has_decay = log_g is not None
    log_decay = float(log_g) if log_g is not None else 0.0

    hsaco = _build_compiled_linear_attn_hsaco(
        head_dim, dtype_tag, feature_map, decay=has_decay)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm linear_attn: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm linear_attn: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"la") != 0:
        raise RuntimeError("rocm linear_attn: kernel symbol 'la' not found")

    qc = np.ascontiguousarray(q, dtype=store)
    kc = np.ascontiguousarray(k, dtype=store)
    vc = np.ascontiguousarray(v, dtype=store)
    o = np.zeros((bh, sq, head_dim), dtype=np.float32)
    nq, nkv = bh * sq * head_dim, bh * sk * head_dim
    dq, dk, dv, do = (ctypes.c_void_p(), ctypes.c_void_p(),
                      ctypes.c_void_p(), ctypes.c_void_p())
    for dev, size in ((dq, 2 * nq), (dk, 2 * nkv), (dv, 2 * nkv), (do, 4 * nq)):
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm linear_attn: hipMalloc failed")
    hip.hipMemcpy(dq, qc.ctypes.data_as(ctypes.c_void_p), 2 * nq, 1)
    hip.hipMemcpy(dk, kc.ctypes.data_as(ctypes.c_void_p), 2 * nkv, 1)
    hip.hipMemcpy(dv, vc.ctypes.data_as(ctypes.c_void_p), 2 * nkv, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dq, nq) + _mr(dk, nkv) + _mr(dv, nkv) + _mr(do, nq)
                   + [ctypes.c_int64(sq), ctypes.c_int64(sk),
                      ctypes.c_int64(causal)])
    if has_decay:  # decay kernel's trailing f32 log λ arg
        launch_args += [ctypes.c_float(log_decay)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx, gy = (sq + 15) // 16, bh
    rc = hip.hipModuleLaunchKernel(fn, gx, gy, 1, 32, 1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in (dq, dk, dv, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm linear_attn: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, 4 * nq, 2)
    for dev in (dq, dk, dv, do):
        hip.hipFree(dev)
    return o.reshape(q.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED softmax lane (2026-06-25) — the first non-matmul/non-WMMA
# compiler-generated ROCm kernel. ``runtime.launch()`` of an artifact stamped
# ``compiler_path = "rocm_softmax_compiled"`` builds the COMPILER-GENERATED
# row-reduction kernel (the ``generate-rocm-softmax-kernel`` pipeline → hsaco;
# no WMMA / no lower-tessera-target-to-rocdl) and launches it via HIP. Stable
# softmax over the last axis; f32/f16/bf16 storage, f32-reduce. ONE hsaco per
# (chip, dtype) — the kernel is (M,K)-generic — cached.
# ─────────────────────────────────────────────────────────────────────────────
_SOFTMAX_BLOCKDIM = 256  # must match BD in GenerateROCMSoftmaxKernel.cpp
#: hsaco bytes keyed by (chip, dtype).
_rocm_softmax_hsaco_cache: dict[tuple[str, str], bytes] = {}


def _build_compiled_softmax_hsaco(dtype: str = "f32") -> bytes:
    """Generate + serialize the compiler's row-reduction softmax kernel to
    hsaco, in-process via tessera-opt. Cached per (chip, dtype). No WMMA → the
    pipeline is the plain gpu→ROCDL chain (no lower-tessera-target-to-rocdl)."""
    chip = _rocm_chip()
    key = (chip, dtype)
    cached = _rocm_softmax_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm softmax lane")
    directive = (
        'module {\n'
        f'  "tessera_rocm.softmax"() {{name = "sm", dtype = "{dtype}"}} '
        ': () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-rocm-softmax-kernel,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled softmax in-process "
            f"(rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm softmax lane: gpu.binary was not an ELF hsaco")
    _rocm_softmax_hsaco_cache[key] = hsaco
    return hsaco


def _execute_rocm_compiled_softmax(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` softmax lane: run the COMPILER-GENERATED row-
    reduction kernel — stable softmax over the last axis (one workgroup per
    row). Handles ``tessera.softmax`` / ``tessera.softmax_safe`` (both the
    numerically-stable formula). f32/f16/bf16 storage, f32 reduce. Raises
    ``_RocmCompiledUnavailable`` when the lane can't run here; ``ValueError`` on
    a bad op/dtype."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    _SM_OPS = ("tessera.softmax", "tessera.softmax_safe")
    if len(ops) != 1 or str(ops[0].get("op_name", "")) not in _SM_OPS:
        raise ValueError(
            "rocm_softmax_compiled executor handles exactly one of "
            f"{_SM_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("softmax requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = int(kwargs.get("axis", -1))
    if axis not in (-1,):
        raise ValueError(
            f"rocm softmax lane only supports axis=-1 (last); got {axis}")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.ndim < 1:
        raise ValueError("softmax operand must have rank >= 1")
    k = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1
    if k <= 0:
        raise ValueError(f"softmax last dim must be positive; got {k}")

    store: Any  # numpy dtype varies per branch (f32 / f16 / bf16)
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(
                "rocm softmax lane handles f32/f16/bf16 storage; got "
                f"{x.dtype}")

    hsaco = _build_compiled_softmax_hsaco(dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm softmax: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm softmax: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"sm") != 0:
        raise RuntimeError("rocm softmax: kernel symbol 'sm' not found")

    xc = np.ascontiguousarray(x, dtype=store)
    o = np.zeros((m, k), dtype=store)
    n = m * k
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (dx, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm softmax: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, n) + _mr(do, n)
                   + [ctypes.c_int64(m), ctypes.c_int64(k)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, m, 1, 1, _SOFTMAX_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm softmax: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (dx, do):
        hip.hipFree(dev)
    return o.reshape(x.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED norm lane (2026-06-25) — rmsnorm / layer_norm as row-reduction
# kernels (siblings of the softmax kernel). ``compiler_path = "rocm_norm_compiled"``
# builds the COMPILER-GENERATED kernel (the ``generate-rocm-norm-kernel`` pipeline
# → hsaco; no WMMA) and launches it via HIP. Unweighted row normalize over the
# last axis; f32/f16/bf16 storage, f32 reduce. ONE hsaco per (chip, kind, dtype),
# cached. (Re-added after a main-merge conflict dropped it; see PR#123.)
# ─────────────────────────────────────────────────────────────────────────────
_NORM_BLOCKDIM = 256  # must match BD in GenerateROCMNormKernel.cpp
#: hsaco bytes keyed by (chip, kind, dtype).
_rocm_norm_hsaco_cache: dict[tuple[str, str, str], bytes] = {}


def _build_compiled_norm_hsaco(kind: str, dtype: str = "f32") -> bytes:
    """Generate + serialize the compiler's row-reduction norm kernel to hsaco,
    in-process via tessera-opt. Cached per (chip, kind, dtype). No WMMA → plain
    gpu→ROCDL pipeline."""
    chip = _rocm_chip()
    key = (chip, kind, dtype)
    cached = _rocm_norm_hsaco_cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable(
            "tessera-opt not built — no compiled ROCm norm lane")
    directive = (
        'module {\n'
        f'  "tessera_rocm.norm"() {{name = "nm", kind = "{kind}", '
        f'dtype = "{dtype}"}} : () -> ()\n'
        '}\n'
    )
    pipeline = (
        "builtin.module("
        "generate-rocm-norm-kernel,"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            "tessera-opt did not serialize the compiled norm in-process "
            f"(rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(
            "compiled ROCm norm lane: gpu.binary was not an ELF hsaco")
    _rocm_norm_hsaco_cache[key] = hsaco
    return hsaco


#: op_name → (norm kind, default eps). rmsnorm_safe uses a tighter eps default.
_ROCM_NORM_OPS: dict[str, tuple[str, float]] = {
    "tessera.rmsnorm": ("rmsnorm", 1e-5),
    "tessera.rmsnorm_safe": ("rmsnorm", 1e-6),
    "tessera.layer_norm": ("layer_norm", 1e-5),
}


def _execute_rocm_compiled_norm(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` norm lane: run the COMPILER-GENERATED row-reduction
    kernel — unweighted rmsnorm / layer_norm over the last axis (one workgroup
    per row). Handles ``tessera.rmsnorm`` / ``tessera.rmsnorm_safe`` /
    ``tessera.layer_norm``; ``eps`` from kwargs (per-op default). f32/f16/bf16
    storage, f32 reduce."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_NORM_OPS:
        raise ValueError(
            "rocm_norm_compiled executor handles exactly one of "
            f"{tuple(_ROCM_NORM_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind, eps_default = _ROCM_NORM_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("norm requires one operand")
    kwargs = op.get("kwargs") or {}
    eps = float(kwargs.get("eps", eps_default))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.ndim < 1:
        raise ValueError("norm operand must have rank >= 1")
    k = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1
    if k <= 0:
        raise ValueError(f"norm last dim must be positive; got {k}")

    store: Any  # numpy dtype varies per branch (f32 / f16 / bf16)
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(
                f"rocm norm lane handles f32/f16/bf16 storage; got {x.dtype}")

    hsaco = _build_compiled_norm_hsaco(kind, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable(
            "libamdhip64.so not loadable — no ROCm execution lane on this host")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm norm: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(
            "rocm norm: no usable AMD GPU (module load failed)")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"nm") != 0:
        raise RuntimeError("rocm norm: kernel symbol 'nm' not found")

    xc = np.ascontiguousarray(x, dtype=store)
    o = np.zeros((m, k), dtype=store)
    n = m * k
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (dx, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm norm: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, n) + _mr(do, n)
                   + [ctypes.c_int64(m), ctypes.c_int64(k), ctypes.c_float(eps)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, m, 1, 1, _NORM_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm norm: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (dx, do):
        hip.hipFree(dev)
    return o.reshape(x.shape)


# ─────────────────────────────────────────────────────────────────────────────
# x86 ELEMENTWISE compiled lane (2026-06-26) — runtime-loadable AVX-512 kernels.
# libtessera_x86_elementwise.so exports the hand-written AVX-512 C-ABI kernels
# (reduce/unary/binary/compare/logical/bitwise); the Python runtime ctypes-loads
# it and calls them from runtime.launch() (``compiler_path = "x86_*_compiled"``)
# — the CPU analog of the ROCm compiled lanes. Host-gated: the lib only builds /
# loads on an AVX-512 box, so the loader returns None elsewhere and the lane
# skips. The kernels are f32 (reduce/unary/binary/compare) / i8 (logical) / i32
# (bitwise); reductions fold an arbitrary axis to [outer, inner] like the ROCm
# reduce lane.
# ─────────────────────────────────────────────────────────────────────────────
_x86_elementwise_runtime: ctypes.CDLL | None = None
_x86_elementwise_loaded = False


def _x86_elementwise_lib_path() -> Optional[Path]:
    """Locate libtessera_x86_elementwise.so (env override → CMake build dir)."""
    env = os.environ.get("TESSERA_X86_ELEMENTWISE_LIB")
    candidates: list[Path] = []
    if env:
        candidates.append(Path(env))
    root = Path(__file__).resolve().parents[2]
    candidates.append(
        root / "build/src/compiler/codegen/tessera_x86_backend"
        / "libtessera_x86_elementwise.so")
    for c in candidates:
        if c.is_file():
            return c
    return None


def _load_x86_elementwise() -> ctypes.CDLL | None:
    """Load libtessera_x86_elementwise.so once, binding the C-ABI signatures.
    Returns None (never raises) when the lib is absent — the caller treats that
    as "no x86 compiled lane on this host" and the executor skips clean."""
    global _x86_elementwise_runtime, _x86_elementwise_loaded
    if _x86_elementwise_loaded:
        return _x86_elementwise_runtime
    _x86_elementwise_loaded = True
    path = _x86_elementwise_lib_path()
    if path is None:
        return None
    try:
        lib = ctypes.CDLL(str(path))
    except OSError:
        return None
    c_f32 = ctypes.POINTER(ctypes.c_float)
    c_i8 = ctypes.c_void_p
    c_i32 = ctypes.c_void_p
    i64 = ctypes.c_int64
    sigs = {
        "tessera_x86_avx512_reduce_f32":
            [c_f32, i64, i64, c_f32, ctypes.c_int],
        "tessera_x86_avx512_unary_f32":
            [c_f32, i64, c_f32, ctypes.c_int],
        "tessera_x86_avx512_binary_f32":
            [c_f32, c_f32, i64, c_f32, ctypes.c_int],
        "tessera_x86_avx512_compare_f32":
            [c_f32, c_f32, i64, c_i8, ctypes.c_int],
        "tessera_x86_avx512_predicate_f32":
            [c_f32, i64, c_i8, ctypes.c_int],
        "tessera_x86_avx512_logical_i8":
            [c_i8, c_i8, i64, c_i8, ctypes.c_int],
        "tessera_x86_avx512_bitwise_i32":
            [c_i32, c_i32, i64, c_i32, ctypes.c_int],
        "tessera_x86_avx512_scan_f32":
            [c_f32, i64, i64, c_f32, ctypes.c_int],
        "tessera_x86_avx512_argreduce_f32":
            [c_f32, i64, i64, c_i32, ctypes.c_int],
        "tessera_x86_avx512_where_f32":
            [c_i8, c_f32, c_f32, i64, c_f32],
        "tessera_x86_avx512_transcendental_f32":
            [c_f32, i64, c_f32, ctypes.c_int],
        "tessera_x86_avx512_pow_f32":
            [c_f32, c_f32, i64, c_f32],
        "tessera_x86_avx512_silu_mul_f32":
            [c_f32, c_f32, i64, c_f32],
        "tessera_x86_avx512_rmsnorm_f32":
            [c_f32, i64, i64, ctypes.c_float, c_f32],
        "tessera_x86_avx512_layernorm_f32":
            [c_f32, i64, i64, ctypes.c_float, c_f32],
        "tessera_x86_avx512_softmax_f32":
            [c_f32, i64, i64, c_f32],
        "tessera_x86_avx512_gemm_f32":
            [c_f32, c_f32, i64, i64, i64, c_f32],
        "tessera_x86_avx512_rope_f32":
            [c_f32, c_f32, i64, i64, c_f32],
        "tessera_x86_avx512_alibi_f32":
            [c_f32, i64, i64, c_f32],
        "tessera_x86_avx512_pointwise_loss_f32":
            [c_f32, c_f32, i64, ctypes.c_int, ctypes.c_float, c_f32],
        "tessera_x86_avx512_binary_loss_f32":
            [c_f32, c_f32, i64, ctypes.c_int, ctypes.c_float, ctypes.c_float,
             c_f32],
        "tessera_x86_avx512_policy_loss_f32":
            [c_f32, c_f32, c_f32, i64, ctypes.c_int, ctypes.c_float, c_f32],
        "tessera_x86_avx512_fpquant_f32":
            [c_f32, i64, ctypes.c_float, ctypes.c_int, ctypes.c_int, c_f32],
        "tessera_x86_fft_c2c_f32":
            [c_f32, i64, i64, ctypes.c_int],
        "tessera_x86_avx512_spmm_csr_f32":
            [c_i32, c_i32, c_f32, c_f32, i64, i64, c_f32],
        "tessera_x86_avx512_sddmm_f32":
            [c_f32, c_f32, c_f32, i64, i64, i64, c_f32],
        "tessera_x86_avx512_selective_ssm_f32":
            [c_f32, c_f32, c_f32, c_f32, c_f32, i64, i64, i64, i64, c_f32, c_f32],
        # backward: (x,A2d,B,C,delta,dy, Bsz,S,D,N, h_traj, dx,dA2d,dB,dC,ddelta)
        "tessera_x86_selective_ssm_bwd_f32":
            [c_f32] * 6 + [i64, i64, i64, i64] + [c_f32] * 6,
        # Half-I/O SSM: x/A/B/C/delta + y are u16 (f16/bf16 storage); h is f32.
        "tessera_x86_avx512_selective_ssm_f16":
            [ctypes.POINTER(ctypes.c_uint16)] * 5 + [i64, i64, i64, i64, c_f32,
                                                     ctypes.POINTER(ctypes.c_uint16)],
        "tessera_x86_avx512_selective_ssm_bf16":
            [ctypes.POINTER(ctypes.c_uint16)] * 5 + [i64, i64, i64, i64, c_f32,
                                                     ctypes.POINTER(ctypes.c_uint16)],
        "tessera_x86_cholesky_f32":
            [c_f32, i64, i64, c_f32],
        "tessera_x86_tri_solve_f32":
            [c_f32, c_f32, i64, i64, i64, ctypes.c_int, c_f32],
        "tessera_x86_lu_f32":
            [c_f32, i64, i64, c_f32, c_i32],
        "tessera_x86_qr_f32":
            [c_f32, i64, i64, i64, c_f32, c_f32],
        "tessera_x86_svd_f32":
            [c_f32, i64, i64, i64, c_f32, c_f32, c_f32],
        "tessera_x86_moe_f32":
            [c_f32, c_f32, c_i32, i64, i64, i64, c_f32],
        "tessera_x86_optimizer_f32":
            [c_f32, c_f32, c_f32, c_f32, i64, ctypes.c_int,
             ctypes.c_float, ctypes.c_float, ctypes.c_float, ctypes.c_float,
             ctypes.c_float, ctypes.c_float, ctypes.c_float,
             c_f32, c_f32, c_f32],
    }
    for sym, argtypes in sigs.items():
        fn = getattr(lib, sym, None)
        if fn is not None:
            fn.argtypes = argtypes
            fn.restype = None
    _x86_elementwise_runtime = lib
    return lib


def _x86_elementwise_available() -> bool:
    """True iff the AVX-512 elementwise lib loads on this host."""
    return _load_x86_elementwise() is not None


#: op_name -> reduce kind index (must match avx512_reduce_f32.cpp).
_X86_REDUCE_OPS = {
    "tessera.sum": 0, "tessera.mean": 2,
    "tessera.max": 1, "tessera.amax": 1,
    "tessera.min": 3, "tessera.amin": 3,
    "tessera.prod": 4,
}


def _execute_x86_compiled_reduce(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` reduce lane: run the hand-written AVX-512 row-reduction
    kernel (sum/mean/max/min) loaded from libtessera_x86_elementwise.so. An
    arbitrary ``axis`` (default: reduce all) is folded to a [outer, inner]
    last-axis reduction by transposing the reduced axes to the end; ``keepdims``
    supported. f32 only (the kernel's dtype)."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_REDUCE_OPS:
        raise ValueError(
            "x86_reduce_compiled executor handles exactly one of "
            f"{tuple(_X86_REDUCE_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _X86_REDUCE_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    keepdims = bool(kwargs.get("keepdims", False))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"x86 reduce lane handles f32 only; got {x.dtype}")
    n = x.ndim
    if n == 0:
        return np.array(x, copy=True)

    axis = kwargs.get("axis", None)
    if axis is None:
        axes = tuple(range(n))
    elif isinstance(axis, int):
        axes = (axis if axis >= 0 else n + axis,)
    else:
        axes = tuple(a if a >= 0 else n + a for a in axis)
    kept = [i for i in range(n) if i not in axes]
    perm = kept + list(axes)
    xt = np.ascontiguousarray(np.transpose(x, perm), dtype=np.float32)
    inner = 1
    for a in axes:
        inner *= int(x.shape[a])
    outer = int(xt.size // inner) if inner else 0
    if inner <= 0:
        raise ValueError("x86 reduce: empty reduction axis")
    kept_shape = tuple(int(x.shape[i]) for i in kept)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(xt, dtype=np.float32).reshape(-1)
    out = np.zeros(outer, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_reduce_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(outer), ctypes.c_int64(inner),
        out.ctypes.data_as(cf), ctypes.c_int(kind))

    res = out.reshape(kept_shape) if kept_shape else out.reshape(())
    if keepdims:
        shape = [1 if i in axes else int(x.shape[i]) for i in range(n)]
        res = res.reshape(shape)
    return res


#: op_name -> scan kind index (must match avx512_scan_f32.cpp).
_X86_SCAN_OPS = {
    "tessera.cumsum": 0, "tessera.cumprod": 1,
    "tessera.cummax": 2, "tessera.cummin": 3,
}


def _execute_x86_compiled_scan(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` scan lane: run the AVX-512 inclusive prefix scan
    (cumsum/cumprod/cummax/cummin) from libtessera_x86_elementwise.so along one
    axis; same-shape output (axis=None flattens, numpy semantics). f32 only."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_SCAN_OPS:
        raise ValueError(
            "x86_scan_compiled executor handles exactly one of "
            f"{tuple(_X86_SCAN_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _X86_SCAN_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("scan requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"x86 scan lane handles f32 only; got {x.dtype}")
    n = x.ndim

    axis = kwargs.get("axis", None)
    flatten = axis is None or n <= 1
    if flatten:
        flat = np.ascontiguousarray(x, dtype=np.float32).reshape(1, -1)
        inner = int(flat.shape[1])
        outer = 1
        kept_then_axis: tuple[int, ...] = ()
        inv: list[int] = []
    else:
        assert axis is not None
        a = int(axis) if axis >= 0 else n + int(axis)
        perm = [i for i in range(n) if i != a] + [a]
        inv = [int(perm.index(i)) for i in range(n)]
        flat = np.ascontiguousarray(np.transpose(x, perm), dtype=np.float32)
        inner = int(x.shape[a])
        outer = int(flat.size // inner)
        kept_then_axis = tuple(int(x.shape[i]) for i in perm)
    if inner <= 0:
        return np.array(x, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(flat, dtype=np.float32).reshape(-1)
    out = np.zeros(outer * inner, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_scan_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(outer), ctypes.c_int64(inner),
        out.ctypes.data_as(cf), ctypes.c_int(kind))
    if flatten:
        return out.reshape(-1)
    return np.transpose(out.reshape(kept_then_axis), inv)


#: op_name -> argreduce kind index (must match avx512_argreduce_f32.cpp).
_X86_ARGREDUCE_OPS = {"tessera.argmax": 0, "tessera.argmin": 1}


def _execute_x86_compiled_argreduce(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` arg-reduce lane: run the AVX-512 argmax/argmin from
    libtessera_x86_elementwise.so along one axis (numpy first-occurrence
    tie-break). f32 input, i32 index output."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_ARGREDUCE_OPS:
        raise ValueError(
            "x86_argreduce_compiled executor handles exactly one of "
            f"{tuple(_X86_ARGREDUCE_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _X86_ARGREDUCE_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("argreduce requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"x86 argreduce lane handles f32 only; got {x.dtype}")
    n = x.ndim
    if n == 0:
        return np.array(0, dtype=np.int32)

    axis = kwargs.get("axis", None)
    if axis is None:
        axes = tuple(range(n))
    elif isinstance(axis, int):
        axes = (axis if axis >= 0 else n + axis,)
    else:
        raise ValueError("argreduce supports a single int axis or None")
    kept = [i for i in range(n) if i not in axes]
    perm = kept + list(axes)
    xt = np.ascontiguousarray(np.transpose(x, perm), dtype=np.float32)
    inner = 1
    for a in axes:
        inner *= int(x.shape[a])
    outer = int(xt.size // inner) if inner else 0
    if inner <= 0:
        raise ValueError("x86 argreduce: empty reduction axis")
    kept_shape = tuple(int(x.shape[i]) for i in kept)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(xt, dtype=np.float32).reshape(-1)
    out = np.zeros(max(outer, 1), dtype=np.int32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_argreduce_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(outer), ctypes.c_int64(inner),
        out.ctypes.data_as(ctypes.c_void_p), ctypes.c_int(kind))
    return out.reshape(kept_shape)


#: op_name -> unary kind index (must match avx512_unary_f32.cpp). The x86 lane
#: covers the DIRECT-intrinsic algebraic + rounding subset; transcendentals
#: (exp/log/erf/trig/…) stay numpy-reference on CPU.
_X86_UNARY_OPS = {
    "tessera.sqrt": 0, "tessera.rsqrt": 1, "tessera.reciprocal": 2,
    "tessera.absolute": 3, "tessera.abs": 3, "tessera.sign": 5,
    "tessera.floor": 6, "tessera.ceil": 7, "tessera.trunc": 8,
    "tessera.round": 9,
}


def _execute_x86_compiled_unary(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` unary lane: run the hand-written AVX-512 elementwise
    kernel (sqrt/rsqrt/reciprocal/abs/sign/floor/ceil/trunc/round) loaded from
    libtessera_x86_elementwise.so over any-shape f32 input."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_UNARY_OPS:
        raise ValueError(
            "x86_unary_compiled executor handles exactly one of "
            f"{tuple(_X86_UNARY_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _X86_UNARY_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("unary requires one operand")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"x86 unary lane handles f32 only; got {x.dtype}")
    n = int(np.prod(x.shape)) if x.ndim else 1
    if n <= 0:
        return np.array(x, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    out = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_unary_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(n), out.ctypes.data_as(cf),
        ctypes.c_int(kind))
    return out.reshape(x.shape)


#: op_name -> transcendental kind index (must match avx512_transcendental_f32.cpp).
#: The AVX-512 vectorized transcendental / activation lane (Cephes exp/log cores +
#: Abramowitz-Stegun erf; activations compose), reaching ROCm math->ROCDL parity.
#: gelu uses the tanh approximation, matching the ROCm activation reference.
_X86_TRANSCENDENTAL_OPS = {
    "tessera.exp": 0,
    "tessera.log": 1,
    "tessera.tanh": 2,
    "tessera.sigmoid": 3,
    "tessera.silu": 4, "tessera.swish": 4,
    "tessera.gelu": 5,
    "tessera.erf": 6,
    "tessera.softplus": 7,
    "tessera.expm1": 8,
    "tessera.log1p": 9,
    "tessera.cos": 10,
    "tessera.tan": 11,
    "tessera.sinh": 12,
    "tessera.cosh": 13,
    "tessera.asin": 14,
    "tessera.acos": 15,
    "tessera.atan": 16,
    "tessera.erfc": 17,
    "tessera.sin": 18,
    "tessera.lgamma": 19,  # ln Γ(x) — NR Lanczos g=5 SIMD core
    "tessera.digamma": 20,  # ψ(x) — recurrence + asymptotic series
}


def _execute_x86_compiled_transcendental(artifact: RuntimeArtifact,
                                         args: Any) -> Any:
    """The ``target="x86"`` transcendental lane: run the hand-written AVX-512
    vectorized transcendental / activation kernel (exp/log/tanh/sigmoid/silu/
    gelu/erf/softplus/expm1/log1p) loaded from libtessera_x86_elementwise.so
    over any-shape f32 input. Cephes exp/log cores (~1 ulp) + A&S erf; matches
    numpy to atol/rtol 2e-5."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_TRANSCENDENTAL_OPS:
        raise ValueError(
            "x86_transcendental_compiled executor handles exactly one of "
            f"{tuple(_X86_TRANSCENDENTAL_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    kind = _X86_TRANSCENDENTAL_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("transcendental requires one operand")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"x86 transcendental lane handles f32 only; got {x.dtype}")
    n = int(np.prod(x.shape)) if x.ndim else 1
    if n <= 0:
        return np.array(x, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    out = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_transcendental_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(n), out.ctypes.data_as(cf),
        ctypes.c_int(kind))
    return out.reshape(x.shape)


#: op_name -> .so symbol for the transcendental-backed BINARY lane. pow(a,b) and
#: silu_mul(a,b)=silu(a)*b share the exp/log/sigmoid cores of the transcendental
#: kernel. pow assumes a POSITIVE base (a^b via exp(b*log(a))).
_X86_BINARY_MATH_OPS = {
    "tessera.pow": "tessera_x86_avx512_pow_f32",
    "tessera.power": "tessera_x86_avx512_pow_f32",
    "tessera.silu_mul": "tessera_x86_avx512_silu_mul_f32",
    "tessera.swiglu": "tessera_x86_avx512_silu_mul_f32",
}


def _execute_x86_compiled_binary_math(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="x86"`` transcendental-backed binary lane: pow(a,b) (positive
    base) and silu_mul(a,b)=silu(a)*b, from libtessera_x86_elementwise.so over
    any-shape f32 inputs. Matches numpy to atol/rtol 2e-5."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_BINARY_MATH_OPS:
        raise ValueError(
            "x86_binary_math_compiled executor handles exactly one of "
            f"{tuple(_X86_BINARY_MATH_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    sym = _X86_BINARY_MATH_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("binary math requires two operands (a, b)")
    values = _bind_launch_args(args, arg_names)
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    if a.shape != b.shape:
        raise ValueError(
            f"x86 binary-math lane requires matching operand shapes; got "
            f"a{a.shape} b{b.shape}")
    if a.dtype != np.float32:
        raise ValueError(f"x86 binary-math lane handles f32 only; got {a.dtype}")
    n = int(np.prod(a.shape)) if a.ndim else 1
    if n <= 0:
        return np.array(a, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    ac = np.ascontiguousarray(a, dtype=np.float32).reshape(-1)
    bc = np.ascontiguousarray(b, dtype=np.float32).reshape(-1)
    out = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    getattr(lib, sym)(
        ac.ctypes.data_as(cf), bc.ctypes.data_as(cf), ctypes.c_int64(n),
        out.ctypes.data_as(cf))
    return out.reshape(a.shape)


#: op_name -> (.so symbol, default eps) for the x86 norm lane. UNWEIGHTED
#: rmsnorm / layer_norm over the last axis (matching the ROCm norm lane's op
#: signature — no γ/β operands).
_X86_NORM_OPS = {
    "tessera.rmsnorm": ("tessera_x86_avx512_rmsnorm_f32", 1e-5),
    "tessera.rmsnorm_safe": ("tessera_x86_avx512_rmsnorm_f32", 1e-6),
    "tessera.layer_norm": ("tessera_x86_avx512_layernorm_f32", 1e-5),
}


def _execute_x86_compiled_norm(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` norm lane: run the hand-written AVX-512 row-reduction
    kernel — unweighted rmsnorm / layer_norm over the last axis, from
    libtessera_x86_elementwise.so. ``eps`` from kwargs (per-op default). f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_NORM_OPS:
        raise ValueError(
            "x86_norm_compiled executor handles exactly one of "
            f"{tuple(_X86_NORM_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    sym, eps_default = _X86_NORM_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("norm requires one operand")
    kwargs = op.get("kwargs") or {}
    eps = float(kwargs.get("eps", eps_default))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.ndim < 1:
        raise ValueError("norm operand must have rank >= 1")
    if x.dtype != np.float32:
        raise ValueError(f"x86 norm lane handles f32 only; got {x.dtype}")
    k = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1
    if k <= 0:
        raise ValueError(f"norm last dim must be positive; got {k}")

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    out = np.zeros(m * k, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    getattr(lib, sym)(
        xc.ctypes.data_as(cf), ctypes.c_int64(m), ctypes.c_int64(k),
        ctypes.c_float(eps), out.ctypes.data_as(cf))
    return out.reshape(x.shape)


# ─────────────────────────────────────────────────────────────────────────────
# Composed normalization (P5) — group_norm / instance_norm / weight_norm built
# on the existing device lanes (no new kernels): group/instance normalize is a
# row-wise mean/var normalize, which IS the layer_norm kernel applied to a
# reshaped [rows, cols] view (device); weight_norm is a row sum-of-squares on
# the device reduce lane + a host divide. The reshape/affine structure runs on
# host — the same device-heavy / host-light split LAMB/Muon use. These device
# ops are UNWEIGHTED (like rmsnorm/layer_norm); the affine composes separately
# through ops.mul/ops.add. compiler_path="x86_normcompose_compiled" /
# "rocm_normcompose_compiled". f32. Matches nn.functional.{group,instance,
# weight}_norm (weight=bias=None).
# ─────────────────────────────────────────────────────────────────────────────
_NORM_COMPOSE_OPS = ("tessera.group_norm", "tessera.instance_norm",
                     "tessera.weight_norm")


def _device_layernorm_rows(x2d: Any, eps: float, target: str, np: Any) -> Any:
    fn = (_execute_x86_compiled_norm if target == "x86"
          else _execute_rocm_compiled_norm)
    art = RuntimeArtifact(metadata={
        "target": target, "compiler_path": f"{target}_norm_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": "tessera.layer_norm", "result": "o",
                 "operands": ["x"], "kwargs": {"eps": eps}}]})
    return np.asarray(fn(art, (np.ascontiguousarray(x2d, np.float32),)),
                      np.float32)


def _device_reduce_sum_rows(x2d: Any, target: str, np: Any) -> Any:
    fn = (_execute_x86_compiled_reduce if target == "x86"
          else _execute_rocm_compiled_reduce)
    art = RuntimeArtifact(metadata={
        "target": target, "compiler_path": f"{target}_reduce_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": "tessera.sum", "result": "o", "operands": ["x"],
                 "kwargs": {"axis": -1}}]})
    return np.asarray(fn(art, (np.ascontiguousarray(x2d, np.float32),)),
                      np.float32)


def _norm_compose_compute(op_name: str, x: Any, kwargs: dict, target: str,
                          np: Any) -> Any:
    x = np.ascontiguousarray(x, np.float32)
    if op_name == "tessera.instance_norm":
        if x.ndim < 3:
            raise ValueError(f"instance_norm expects rank>=3; got {x.shape}")
        eps = float(kwargs.get("eps", 1e-5))
        n, c = int(x.shape[0]), int(x.shape[1])
        rows = x.reshape(n * c, -1)
        return _device_layernorm_rows(rows, eps, target, np).reshape(x.shape)
    if op_name == "tessera.group_norm":
        if x.ndim < 2:
            raise ValueError(f"group_norm expects rank>=2; got {x.shape}")
        ng = int(kwargs["num_groups"])
        eps = float(kwargs.get("eps", 1e-5))
        n, c = int(x.shape[0]), int(x.shape[1])
        if c % ng != 0:
            raise ValueError(f"channels {c} not divisible by num_groups {ng}")
        rows = x.reshape(n * ng, -1)
        return _device_layernorm_rows(rows, eps, target, np).reshape(x.shape)
    if op_name == "tessera.weight_norm":
        axis = int(kwargs.get("axis", 0))
        axis = axis if axis >= 0 else x.ndim + axis
        eps = float(kwargs.get("eps", 1e-12))
        wt = np.moveaxis(x, axis, 0)
        flat = np.ascontiguousarray(wt.reshape(int(wt.shape[0]), -1), np.float32)
        sumsq = _device_reduce_sum_rows(flat * flat, target, np).reshape(-1)
        norm = np.sqrt(sumsq + np.float32(eps)).astype(np.float32)
        out = (flat / norm[:, None]).reshape(wt.shape)
        return np.ascontiguousarray(np.moveaxis(out, 0, axis), np.float32)
    raise ValueError(f"norm-compose executor handles {_NORM_COMPOSE_OPS}; "
                     f"got {op_name!r}")


def _execute_norm_compose(artifact: RuntimeArtifact, args: Any, target: str,
                          path: str) -> Any:
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _NORM_COMPOSE_OPS:
        raise ValueError(
            f"{path} executor handles one of {_NORM_COMPOSE_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    operand_names = [str(n) for n in ops[0].get("operands", [])]
    # group_norm/instance_norm accept optional weight/bias operands in the
    # catalog, but this device lane (like the rmsnorm/layer_norm device ops) is
    # UNWEIGHTED — the affine composes separately through ops.mul/ops.add. Reject
    # an artifact that carries affine operands rather than silently returning the
    # unweighted result (Decision #21: stable diagnostic, never silently wrong).
    if len(operand_names) > 1:
        raise ValueError(
            f"{path} is an UNWEIGHTED normalize lane for {op_name}; it takes a "
            f"single input operand but got {len(operand_names)} "
            f"({operand_names!r}). Compose the per-channel weight/bias affine "
            f"separately via ops.mul / ops.add.")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    return _norm_compose_compute(op_name, x, ops[0].get("kwargs") or {},
                                 target, np)


def _execute_x86_compiled_normcompose(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="x86"`` group/instance/weight-norm lane (composed)."""
    return _execute_norm_compose(artifact, args, "x86",
                                 "x86_normcompose_compiled")


def _execute_rocm_compiled_normcompose(artifact: RuntimeArtifact,
                                       args: Any) -> Any:
    """The ``target="rocm"`` group/instance/weight-norm lane (composed)."""
    return _execute_norm_compose(artifact, args, "rocm",
                                 "rocm_normcompose_compiled")


# ─────────────────────────────────────────────────────────────────────────────
# grad_clip_norm lane (§5.5) — global gradient-norm clipping g*min(1,max_norm/‖g‖)
# composed on the device reduce kernel: the L2 norm's global sum-of-squares runs
# on the row-reduction kernel (the FLOP-heavy O(n) part), host does sqrt + the
# clip scale + the elementwise scale. Single-tensor form (the atomic unit of the
# pytree clip_grad_norm; total = ‖g‖). norm_type=inf uses max|g| (host). Matches
# optim.clip_grad_norm within f32 tolerance (the reference accumulates in f64).
# compiler_path="{x86,rocm}_grad_clip_compiled".
# ─────────────────────────────────────────────────────────────────────────────
def _execute_grad_clip(artifact: RuntimeArtifact, args: Any, target: str,
                       path: str) -> Any:
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name != "tessera.grad_clip_norm":
        raise ValueError(
            f"{path} executor handles tessera.grad_clip_norm; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("grad_clip_norm requires one operand (the gradient)")
    kwargs = op.get("kwargs") or {}
    if kwargs.get("max_norm") is None:
        raise ValueError("grad_clip_norm requires a max_norm kwarg")
    max_norm = float(kwargs["max_norm"])
    norm_type = float(kwargs.get("norm_type", 2.0))
    # Only L2 (norm_type == 2) and inf are implemented — the same norms
    # optim.clip_grad_norm actually distinguishes (it computes tree_l2_norm for
    # every finite norm_type). Reject other finite p-norms rather than silently
    # clipping by the L2 norm the caller did not ask for (Decision #21).
    if norm_type != float("inf") and norm_type != 2.0:
        raise ValueError(
            f"grad_clip_norm supports norm_type 2.0 (L2) or inf; got "
            f"{norm_type}. Other finite p-norms are not implemented — pass "
            f"2.0/inf, or clip that norm on the host.")
    values = _bind_launch_args(args, arg_names)
    g = np.ascontiguousarray(_as_numpy(values[operand_names[0]]), np.float32)
    if g.size == 0:
        return g
    if norm_type == float("inf"):
        total = float(np.max(np.abs(g)))
    else:
        # L2 global norm: sum-of-squares on the device reduce kernel (row sum of
        # the flattened g², one row), host sqrt. Matches optim.tree_l2_norm.
        sumsq = float(_device_reduce_sum_rows(
            (g * g).reshape(1, -1), target, np).reshape(-1)[0])
        total = float(np.sqrt(sumsq))
    scale = min(1.0, max_norm / (total + 1e-12))
    return np.ascontiguousarray(g * np.float32(scale), np.float32)


def _execute_x86_compiled_grad_clip(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` grad_clip_norm lane (composed)."""
    return _execute_grad_clip(artifact, args, "x86", "x86_grad_clip_compiled")


def _execute_rocm_compiled_grad_clip(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` grad_clip_norm lane (composed)."""
    return _execute_grad_clip(artifact, args, "rocm", "rocm_grad_clip_compiled")


def _execute_x86_compiled_softmax(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` softmax lane: run the hand-written AVX-512 row-
    reduction kernel — numerically-stable softmax over the last axis, from
    libtessera_x86_elementwise.so. f32. axis=-1 only."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    _SM_OPS = ("tessera.softmax", "tessera.softmax_safe")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _SM_OPS:
        raise ValueError(
            "x86_softmax_compiled executor handles exactly one of "
            f"{_SM_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("softmax requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = int(kwargs.get("axis", -1))
    if axis not in (-1,):
        raise ValueError(
            f"x86 softmax lane only supports axis=-1 (last); got {axis}")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.ndim < 1:
        raise ValueError("softmax operand must have rank >= 1")
    if x.dtype != np.float32:
        raise ValueError(f"x86 softmax lane handles f32 only; got {x.dtype}")
    k = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1
    if k <= 0:
        raise ValueError(f"softmax last dim must be positive; got {k}")

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    out = np.zeros(m * k, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_softmax_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(m), ctypes.c_int64(k),
        out.ctypes.data_as(cf))
    return out.reshape(x.shape)


# ─────────────────────────────────────────────────────────────────────────────
# x86 GEMM-family lane — batched_gemm / linear_general / qkv_projection /
# factorized_matmul / einsum, all built on the AVX-512 f32 GEMM microkernel
# (tessera_x86_avx512_gemm_f32). The CPU analog of the ROCm WMMA matmul-family
# lane; each op reshapes/batches/splits around the 2D GEMM in Python.
# ``compiler_path = "x86_matmul_family_compiled"``. f32.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_gemm_2d(a: Any, b: Any) -> Any:
    """C[M,N] = A[M,K] @ B[K,N] on the AVX-512 f32 GEMM microkernel. f32 only —
    rejects other dtypes rather than silently coercing (the lane advertises
    f32, matching the other x86 compiled lanes)."""
    import numpy as np
    if a.dtype != np.float32 or b.dtype != np.float32:
        raise ValueError(
            f"x86 gemm lane handles f32 only; got {a.dtype} @ {b.dtype}")
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    a2 = np.ascontiguousarray(a, dtype=np.float32)
    b2 = np.ascontiguousarray(b, dtype=np.float32)
    m, k = int(a2.shape[0]), int(a2.shape[1])
    if b2.shape[0] != k:
        raise ValueError(f"x86 gemm inner dims must match; got {a2.shape} @ "
                         f"{b2.shape}")
    n = int(b2.shape[1])
    out = np.zeros((m, n), dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_gemm_f32(
        a2.ctypes.data_as(cf), b2.ctypes.data_as(cf),
        ctypes.c_int64(m), ctypes.c_int64(n), ctypes.c_int64(k),
        out.ctypes.data_as(cf))
    return out


def _x86_batched_gemm(a: Any, b: Any) -> Any:
    """Full np.matmul semantics over leading batch dims, each [M,K]@[K,N] on the
    AVX-512 GEMM. The batch dims of ``a`` and ``b`` BROADCAST against each other
    (NumPy rules), so a rank-2 shared operand and shapes like (2,1,M,K) @
    (1,3,K,N) -> (2,3,M,N) are all valid."""
    import numpy as np
    if a.ndim < 2 or b.ndim < 2:
        raise ValueError("batched_gemm needs rank>=2 operands")
    m, k = a.shape[-2], a.shape[-1]
    if b.shape[-2] != k:
        raise ValueError(
            f"batched_gemm inner dims must match; got {a.shape} @ {b.shape}")
    n = b.shape[-1]
    try:
        batch = np.broadcast_shapes(a.shape[:-2], b.shape[:-2])
    except ValueError as exc:
        raise ValueError(
            f"batched_gemm batch dims do not broadcast; got {a.shape} @ "
            f"{b.shape}") from exc
    a_b = np.broadcast_to(a, batch + (m, k)).reshape(-1, m, k)
    b_b = np.broadcast_to(b, batch + (k, n)).reshape(-1, k, n)
    nb = a_b.shape[0]
    out = np.stack([_x86_gemm_2d(a_b[i], b_b[i]) for i in range(nb)], axis=0)
    return out.reshape(*batch, m, n)


def _x86_einsum_via_gemm(spec: str, lhs: Any, rhs: Any) -> Any:
    """Single-contraction two-operand einsum mapped to a (batched) AVX-512 gemm.
    Raises a stable diagnostic when the spec is not a single-contraction
    two-tensor matmul (Decision #21)."""
    import numpy as np
    if "->" not in spec:
        raise ValueError(f"x86 einsum needs an explicit '->' spec; got {spec!r}")
    ins, out = spec.split("->")
    terms = [t.strip() for t in ins.split(",")]
    if len(terms) != 2:
        raise ValueError(
            "x86 einsum lane handles exactly two operands; got "
            f"{len(terms)} in {spec!r}")
    lt, rt = terms
    out = out.strip()
    contracted = (set(lt) & set(rt)) - set(out)
    if len(contracted) != 1:
        raise ValueError(
            "x86 einsum lane handles a single contraction index that maps to a "
            f"(batched) matmul; spec {spec!r} has {len(contracted)} — unsupported")
    c = next(iter(contracted))
    batch = [x for x in lt if x in rt and x in out]
    free_l = [x for x in lt if x not in rt]
    free_r = [x for x in rt if x not in lt]
    if set(out) != set(batch) | set(free_l) | set(free_r):
        raise ValueError(f"x86 einsum: output indices in {spec!r} are unsupported")
    lhs_t = np.transpose(lhs, [lt.index(x) for x in batch + free_l + [c]])
    rhs_t = np.transpose(rhs, [rt.index(x) for x in batch + [c] + free_r])
    bsh = [lhs.shape[lt.index(x)] for x in batch]
    msh = [lhs.shape[lt.index(x)] for x in free_l]
    nsh = [rhs.shape[rt.index(x)] for x in free_r]
    kdim = lhs.shape[lt.index(c)]
    a2 = lhs_t.reshape(int(np.prod(bsh or [1])), int(np.prod(msh or [1])), kdim)
    b2 = rhs_t.reshape(int(np.prod(bsh or [1])), kdim, int(np.prod(nsh or [1])))
    prod = _x86_batched_gemm(a2, b2)
    canon = prod.reshape(*(bsh + msh + nsh))
    canon_order = batch + free_l + free_r
    return np.transpose(canon, [canon_order.index(x) for x in out])


def _execute_x86_compiled_matmul_family(artifact: RuntimeArtifact,
                                        args: Any) -> Any:
    """The ``target="x86"`` matmul-family lane: batched_gemm / linear_general /
    qkv_projection / factorized_matmul / einsum, all on the AVX-512 f32 GEMM
    microkernel. Each op reshapes/batches/splits around the gemm; einsum maps
    single-contraction specs to a (batched) matmul. Matches numpy to a
    K-scaled f32 tolerance."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    handled = ("tessera.batched_gemm", "tessera.linear_general",
               "tessera.qkv_projection", "tessera.factorized_matmul",
               "tessera.einsum")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"x86_matmul_family_compiled executor handles one of {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]

    if op_name == "tessera.einsum":
        spec = kwargs.get("spec") or kwargs.get("equation")
        if spec is None or len(operands) != 2:
            raise ValueError(
                "x86 einsum lane needs a 'spec' kwarg and exactly two tensors")
        return _x86_einsum_via_gemm(str(spec), operands[0], operands[1])

    if op_name == "tessera.batched_gemm":
        if len(operands) != 2:
            raise ValueError("batched_gemm takes two operands (A, B)")
        return _x86_batched_gemm(operands[0], operands[1])

    if op_name == "tessera.qkv_projection":
        if len(operands) != 2:
            raise ValueError("qkv_projection takes two operands (x, W_qkv)")
        x, w = operands
        if w.ndim != 2:
            raise ValueError(f"qkv_projection W_qkv must be rank-2; got {w.shape}")
        k, n3 = w.shape
        return _x86_gemm_2d(x.reshape(-1, k), w).reshape(*x.shape[:-1], n3)

    if op_name == "tessera.factorized_matmul":
        if len(operands) != 2:
            raise ValueError("factorized_matmul takes two operands (A, B)")
        a, b = operands
        if a.ndim != 2 or b.ndim != 2:
            raise ValueError("x86 factorized_matmul handles rank-2 A, B")
        rank = int(kwargs.get("rank", min(a.shape[0], b.shape[1])))
        out = _x86_gemm_2d(a, b).astype(np.float32)
        u, s, vh = np.linalg.svd(out, full_matrices=False)
        r = max(1, min(rank, s.shape[-1]))
        return (u[..., :r] * s[..., :r]) @ vh[..., :r, :]

    # tessera.linear_general — default axis=-1, rank-2 weight [K, N] (+ bias).
    if len(operands) not in (2, 3):
        raise ValueError("linear_general takes (x, W) plus an optional bias")
    axis = kwargs.get("axis", -1)
    if axis not in (-1, None):
        raise ValueError(
            f"x86 linear_general lane handles axis=-1 only; got axis={axis}")
    x, w = operands[0], operands[1]
    if w.ndim != 2:
        raise ValueError(
            f"x86 linear_general lane handles a rank-2 weight [K, N]; got "
            f"{w.shape}")
    k, n = w.shape
    if x.shape[-1] != k:
        raise ValueError(
            f"linear_general contracted dim mismatch: x{x.shape} @ W{w.shape}")
    y = _x86_gemm_2d(x.reshape(-1, k), w).reshape(*x.shape[:-1], n)
    if len(operands) == 3:
        y = y + _as_numpy(values[operand_names[2]]).astype(np.float32)
    return y


def _execute_x86_compiled_rope(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` rope lane: run the hand-written AVX-512 interleaved-
    pair rotary-position-embedding kernel from libtessera_x86_elementwise.so.
    Operands X, Theta are both ``[.., D]`` (D even, same shape); the angle for
    pair p is theta[.., 2p]. f32. ``compiler_path = "x86_rope_compiled"``."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) != "tessera.rope":
        raise ValueError(
            "x86_rope_compiled executor handles exactly one tessera.rope op; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("rope requires two operands (x, theta)")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    theta = _as_numpy(values[operand_names[1]])
    if x.ndim < 1 or int(x.shape[-1]) % 2 != 0:
        raise ValueError(f"rope needs an even innermost dim; got x{x.shape}")
    if theta.shape != x.shape:
        raise ValueError(
            f"rope requires theta to match x shape; got x{x.shape} "
            f"theta{theta.shape}")
    if x.dtype != np.float32:
        raise ValueError(f"x86 rope lane handles f32 only; got {x.dtype}")
    d = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    tc = np.ascontiguousarray(theta, dtype=np.float32).reshape(-1)
    out = np.zeros(m * d, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_rope_f32(
        xc.ctypes.data_as(cf), tc.ctypes.data_as(cf),
        ctypes.c_int64(m), ctypes.c_int64(d), out.ctypes.data_as(cf))
    return out.reshape(x.shape)


def _execute_x86_compiled_alibi(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` alibi lane: run the hand-written AVX-512 ALiBi
    positional-bias generator from libtessera_x86_elementwise.so —
    bias[h,i,j] = slope[h]·(j−i), shape [H, S, S]. ``num_heads`` / ``seq_len``
    from kwargs; the optional ``slopes`` operand overrides the default
    2^(-8k/H) ramp. f32. ``compiler_path = "x86_alibi_compiled"``."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) != "tessera.alibi":
        raise ValueError(
            "x86_alibi_compiled executor handles exactly one tessera.alibi op; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    operand_names = [str(n) for n in op.get("operands", [])]
    values = _bind_launch_args(args, arg_names) if arg_names else {}

    h_val = kwargs.get("num_heads")
    s_val = kwargs.get("seq_len")
    if h_val is None or s_val is None:
        raise ValueError("alibi requires num_heads and seq_len")
    hh = int(h_val)
    ss = int(s_val)
    if hh <= 0 or ss <= 0:
        raise ValueError(f"alibi needs positive num_heads/seq_len; got {hh}/{ss}")

    if operand_names:
        slopes = np.ascontiguousarray(
            _as_numpy(values[operand_names[0]]), dtype=np.float32).reshape(-1)
        if slopes.size != hh:
            raise ValueError(
                f"alibi slopes must have length num_heads={hh}; got {slopes.size}")
    else:
        k = np.arange(1, hh + 1, dtype=np.float32)
        slopes = (2.0 ** (-8.0 * k / hh)).astype(np.float32)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    sc = np.ascontiguousarray(slopes, dtype=np.float32)
    out = np.zeros(hh * ss * ss, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_alibi_f32(
        sc.ctypes.data_as(cf), ctypes.c_int64(hh), ctypes.c_int64(ss),
        out.ctypes.data_as(cf))
    return out.reshape(hh, ss, ss)


# ─────────────────────────────────────────────────────────────────────────────
# x86 softmax-attention lane — multi_head / gqa / mqa / mla_decode, all composed
# from the AVX-512 f32 GEMM (QKᵀ and probs·V) + the AVX-512 row-softmax kernel.
# The CPU analog of the ROCm WMMA flash-attention family; reshapes / scaling /
# causal masking / KV-group expansion happen in Python around the two kernels.
# ``compiler_path = "x86_attention_compiled"``. f32.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_softmax_rows(x: Any, np: Any) -> Any:
    """Numerically-stable softmax over the last axis on the AVX-512 kernel."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    k = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    out = np.zeros(m * k, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_softmax_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(m), ctypes.c_int64(k),
        out.ctypes.data_as(cf))
    return out.reshape(x.shape)


def _x86_sdpa(Q: Any, K: Any, V: Any, nq: int, nkv: int, np: Any,
              scale: Any = None, causal: bool = False) -> Any:
    """Scaled dot-product attention with GQA head grouping, on the x86 kernels:
    O = softmax(Q·Kᵀ·scale [+ causal mask]) · V. Q is [.., nq, Sq, D]; K/V are
    [.., nkv, Sk, D]; query head h reads KV group h // (nq/nkv). f32."""
    import math
    Q = np.ascontiguousarray(Q, np.float32)
    K = np.ascontiguousarray(K, np.float32)
    V = np.ascontiguousarray(V, np.float32)
    if Q.ndim < 3 or K.ndim < 3 or V.ndim < 3:
        raise ValueError("sdpa needs rank>=3 Q/K/V")
    if nkv <= 0 or nq % nkv != 0:
        raise ValueError(f"sdpa needs nq divisible by nkv; got {nq}/{nkv}")
    d = int(Q.shape[-1])
    sq, sk = int(Q.shape[-2]), int(K.shape[-2])
    if int(K.shape[-1]) != d or int(V.shape[-1]) != d:
        raise ValueError("sdpa head dim D must match across Q/K/V")
    sc = float(scale) if scale is not None else 1.0 / math.sqrt(d)
    g = nq // nkv
    kx = np.repeat(K, g, axis=-3) if g > 1 else K   # query head h -> kv h//g
    vx = np.repeat(V, g, axis=-3) if g > 1 else V
    kxt = np.ascontiguousarray(np.swapaxes(kx, -1, -2))
    scores = _x86_batched_gemm(Q, kxt) * np.float32(sc)
    if causal:
        i = np.arange(sq).reshape(sq, 1)
        j = np.arange(sk).reshape(1, sk)
        scores = np.where(j > i + (sk - sq), np.float32(-1e30), scores)
    probs = _x86_softmax_rows(scores, np)
    return _x86_batched_gemm(probs, vx)


_X86_ATTN_OPS = ("tessera.multi_head_attention", "tessera.gqa_attention",
                 "tessera.mqa_attention", "tessera.mla_decode")


def _execute_x86_compiled_attention(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` softmax-attention lane: multi_head / gqa / mqa /
    mla_decode, all composed from the AVX-512 GEMM + row-softmax kernels.
    multi_head_attention reshapes [B,S,H·D]→[B,H,S,D]; gqa/mqa pick the KV-group
    counts; mla_decode optionally projects K/V. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_ATTN_OPS:
        raise ValueError(
            f"x86_attention_compiled executor handles one of {_X86_ATTN_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    if len(operands) < 3:
        raise ValueError("attention needs at least three operands (Q, K, V)")
    scale = kwargs.get("scale")
    causal = bool(kwargs.get("causal", False))
    q, k, v = operands[0], operands[1], operands[2]
    if any(o.dtype != np.float32 for o in (q, k, v)):
        raise ValueError("x86 attention lane handles f32 only")

    if op_name == "tessera.multi_head_attention":
        nh = int(kwargs["num_heads"])
        if q.ndim != 3:
            raise ValueError("multi_head_attention expects rank-3 [B, S, H*D]")
        b, sq, hd = q.shape
        if hd % nh != 0:
            raise ValueError(f"H*D={hd} not divisible by num_heads={nh}")
        dd = hd // nh

        def split(t: Any) -> Any:
            st = int(t.shape[1])
            return np.ascontiguousarray(
                t.reshape(b, st, nh, dd).transpose(0, 2, 1, 3))

        out = _x86_sdpa(split(q), split(k), split(v), nh, nh, np,
                        scale=scale, causal=causal)
        return np.ascontiguousarray(out.transpose(0, 2, 1, 3).reshape(b, sq, hd))

    if op_name in ("tessera.gqa_attention", "tessera.mqa_attention"):
        if q.ndim != 4:
            raise ValueError("gqa/mqa attention expects rank-4 [B, H, S, D]")
        if op_name == "tessera.mqa_attention":
            nq, nkv = int(q.shape[1]), 1
        else:
            nq = int(kwargs["num_query_heads"])
            nkv = int(kwargs["num_kv_heads"])
        return _x86_sdpa(q, k, v, nq, nkv, np, scale=scale, causal=causal)

    # tessera.mla_decode — optional latent K/V projection, then GQA attention.
    w_k = operands[3] if len(operands) > 3 else kwargs.get("W_k")
    w_v = operands[4] if len(operands) > 4 else kwargs.get("W_v")
    if w_k is not None:
        k = _x86_batched_gemm(k, np.ascontiguousarray(np.asarray(w_k), np.float32))
    if w_v is not None:
        v = _x86_batched_gemm(v, np.ascontiguousarray(np.asarray(w_v), np.float32))
    if q.ndim != 4 or k.ndim != 4:
        raise ValueError("mla_decode expects rank-4 Q and projected K")
    return _x86_sdpa(q, k, v, int(q.shape[1]), int(k.shape[1]), np,
                     scale=scale, causal=causal)


# ─────────────────────────────────────────────────────────────────────────────
# x86 pointwise-loss lane — mse / mae / huber / smooth_l1 / log_cosh. The
# per-element loss runs on the AVX-512 loss kernel; the reduction (none / mean /
# sum) runs on the AVX-512 reduce kernel. ``compiler_path = "x86_loss_compiled"``.
# ─────────────────────────────────────────────────────────────────────────────
#: op_name -> (loss kind, param-kwarg name or None). Matches avx512_loss_f32.cpp.
_X86_LOSS_OPS = {
    "tessera.mse_loss": (0, None),
    "tessera.mae_loss": (1, None),
    "tessera.huber_loss": (2, "delta"),
    "tessera.smooth_l1_loss": (3, "beta"),
    "tessera.log_cosh_loss": (4, None),
}


def _x86_reduce_scalar(flat: Any, kind: int, np: Any) -> Any:
    """Full reduction of a flat f32 array on the AVX-512 reduce kernel
    (kind 0 = sum, 2 = mean)."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    n = int(flat.size)
    out = np.zeros(1, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_reduce_f32(
        np.ascontiguousarray(flat, np.float32).ctypes.data_as(cf),
        ctypes.c_int64(1), ctypes.c_int64(n), out.ctypes.data_as(cf),
        ctypes.c_int(kind))
    return np.float32(out[0])


def _execute_x86_compiled_loss(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` pointwise-loss lane: mse / mae / huber / smooth_l1 /
    log_cosh over (pred, target). The per-element loss runs on the AVX-512 loss
    kernel; reduction none/mean/sum on the AVX-512 reduce kernel. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_LOSS_OPS:
        raise ValueError(
            "x86_loss_compiled executor handles exactly one of "
            f"{tuple(_X86_LOSS_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind, param_kw = _X86_LOSS_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("loss requires two operands (pred, target)")
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    param = float(kwargs.get(param_kw, 1.0)) if param_kw else 0.0
    values = _bind_launch_args(args, arg_names)
    pred = _as_numpy(values[operand_names[0]])
    target = _as_numpy(values[operand_names[1]])
    if pred.dtype != np.float32:
        raise ValueError(f"x86 loss lane handles f32 only; got {pred.dtype}")
    # pred/target broadcast against each other (the reference uses NumPy
    # broadcasting), so e.g. a (N, C) pred with a (N, 1) / scalar target works.
    try:
        bshape = np.broadcast_shapes(pred.shape, target.shape)
    except ValueError as exc:
        raise ValueError(
            f"loss pred{pred.shape} and target{target.shape} do not "
            f"broadcast") from exc
    pred = np.broadcast_to(pred, bshape)
    target = np.broadcast_to(target, bshape)
    n = int(np.prod(bshape)) if bshape else 1
    if n <= 0:
        return np.array(pred, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    pc = np.ascontiguousarray(pred, dtype=np.float32).reshape(-1)
    tc = np.ascontiguousarray(target, dtype=np.float32).reshape(-1)
    per = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_pointwise_loss_f32(
        pc.ctypes.data_as(cf), tc.ctypes.data_as(cf), ctypes.c_int64(n),
        ctypes.c_int(kind), ctypes.c_float(param), per.ctypes.data_as(cf))
    if reduction == "none":
        return per.reshape(pred.shape)
    return _x86_reduce_scalar(per, 0 if reduction == "sum" else 2, np)


#: op_name -> (binary-loss kind, (pos_weight kw, neg_weight kw) or None). Matches
#: avx512_loss_f32.cpp. bce has no weights; asymmetric_bce has pos/neg weights.
_X86_BINARY_LOSS_OPS = {
    "tessera.binary_cross_entropy_loss": (0, None),
    "tessera.asymmetric_bce": (1, ("pos_weight", "neg_weight")),
}


def _execute_x86_compiled_binary_loss(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="x86"`` binary-cross-entropy loss lane: bce / asymmetric_bce
    over (logits, targets). Per-element loss on the AVX-512 binary-loss kernel
    (stable softplus form); reduction none/mean/sum on the reduce kernel. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_BINARY_LOSS_OPS:
        raise ValueError(
            "x86_binary_loss_compiled executor handles exactly one of "
            f"{tuple(_X86_BINARY_LOSS_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    kind, weight_kws = _X86_BINARY_LOSS_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("binary loss requires two operands (logits, targets)")
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    pos_w = float(kwargs.get(weight_kws[0], 1.0)) if weight_kws else 1.0
    neg_w = float(kwargs.get(weight_kws[1], 1.0)) if weight_kws else 1.0
    values = _bind_launch_args(args, arg_names)
    z = _as_numpy(values[operand_names[0]])
    t = _as_numpy(values[operand_names[1]])
    if z.dtype != np.float32:
        raise ValueError(f"x86 binary-loss lane handles f32 only; got {z.dtype}")
    # targets are broadcastable to logits (the reference uses NumPy broadcasting;
    # asymmetric_bce documents targets as broadcastable). Broadcast both to the
    # common shape so e.g. logits (N, C) + targets (N, 1) / scalar work.
    try:
        bshape = np.broadcast_shapes(z.shape, t.shape)
    except ValueError as exc:
        raise ValueError(
            f"binary loss targets {t.shape} not broadcastable to logits "
            f"{z.shape}") from exc
    z = np.broadcast_to(z, bshape)
    t = np.broadcast_to(t, bshape)
    n = int(np.prod(bshape)) if bshape else 1
    if n <= 0:
        return np.array(z, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    zc = np.ascontiguousarray(z, dtype=np.float32).reshape(-1)
    tc = np.ascontiguousarray(t, dtype=np.float32).reshape(-1)
    per = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_binary_loss_f32(
        zc.ctypes.data_as(cf), tc.ctypes.data_as(cf), ctypes.c_int64(n),
        ctypes.c_int(kind), ctypes.c_float(pos_w), ctypes.c_float(neg_w),
        per.ctypes.data_as(cf))
    if reduction == "none":
        return per.reshape(z.shape)
    return _x86_reduce_scalar(per, 0 if reduction == "sum" else 2, np)


# ─────────────────────────────────────────────────────────────────────────────
# x86 RL policy-loss lane — ppo / cispo / grpo (core surrogate on the AVX-512
# policy-loss kernel) + normalize_group_advantages (the AVX-512 layer_norm
# kernel over the group axis). ``compiler_path = "x86_rl_loss_compiled"``. f32.
# The optional KL-penalty / entropy-bonus / masked-reduce add-ons are NOT in the
# fused lane — the runtime emits a stable diagnostic if they are requested.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_group_normalize(r: Any, group_axis: int, eps: float, np: Any) -> Any:
    """(r − mean) / sqrt(var + eps) over ``group_axis`` — the unweighted
    layer_norm kernel applied over an arbitrary axis (transpose-to-last → kernel
    → transpose-back)."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    r = np.ascontiguousarray(r, np.float32)
    nd = r.ndim
    ax = int(group_axis) if group_axis >= 0 else nd + int(group_axis)
    if ax < 0 or ax >= nd:
        raise ValueError(f"normalize_group_advantages: group_axis out of range "
                         f"for shape {r.shape}")
    perm = [i for i in range(nd) if i != ax] + [ax]
    rt = np.ascontiguousarray(np.transpose(r, perm))
    k = int(rt.shape[-1])
    m = int(np.prod(rt.shape[:-1])) if rt.ndim > 1 else 1
    out = np.zeros(m * k, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_layernorm_f32(
        rt.reshape(-1).ctypes.data_as(cf), ctypes.c_int64(m), ctypes.c_int64(k),
        ctypes.c_float(eps), out.ctypes.data_as(cf))
    out = out.reshape(rt.shape)
    inv = [perm.index(i) for i in range(nd)]
    return np.ascontiguousarray(np.transpose(out, inv))


#: op_name -> (policy-loss kind, clip-kwarg name, clip default). Matches
#: avx512_policy_loss_f32.cpp.
_X86_POLICY_OPS = {
    "tessera.ppo_policy_loss": (0, "clip_epsilon", 0.2),
    "tessera.grpo_policy_loss": (0, "clip_epsilon", 0.2),
    "tessera.cispo_policy_loss": (1, "epsilon_high", 5.0),
}


def _execute_x86_compiled_rl_loss(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` RL policy-loss lane: ppo / cispo / grpo core
    surrogate (on the AVX-512 policy-loss kernel over logp_new/logp_old/
    advantages) + normalize_group_advantages (layer_norm over the group axis).
    The KL/entropy/mask add-ons get a stable diagnostic. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    handled = ("tessera.ppo_policy_loss", "tessera.cispo_policy_loss",
               "tessera.grpo_policy_loss", "tessera.normalize_group_advantages")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"x86_rl_loss_compiled executor handles one of {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    if any(o.dtype != np.float32 for o in operands):
        raise ValueError("x86 rl-loss lane handles f32 only")

    if op_name == "tessera.normalize_group_advantages":
        if len(operands) != 1:
            raise ValueError(
                "x86 normalize_group_advantages lane takes one operand "
                "(rewards); masked normalization is not in the fused lane")
        return _x86_group_normalize(
            operands[0], int(kwargs.get("group_axis", 1)),
            float(kwargs.get("eps", 1e-8)), np)

    # ppo / cispo / grpo — core surrogate. The KL/entropy/masked-reduce add-ons
    # are not in the fused lane (Decision #21: stable diagnostic, never silent).
    if float(kwargs.get("kl_coef", 0.0)) or float(kwargs.get("entropy_coef", 0.0)):
        raise ValueError(
            f"x86 rl-loss lane handles the core {op_name} surrogate only; the "
            "KL-penalty / entropy-bonus terms are unsupported (set "
            "kl_coef=entropy_coef=0)")
    if len(operands) < 3:
        raise ValueError(f"{op_name} needs (logp_new, logp_old, advantages)")
    kind, clip_kw, clip_default = _X86_POLICY_OPS[op_name]
    clip = float(kwargs.get(clip_kw, clip_default))
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"rl-loss reduction must be none/mean/sum; got {reduction}")
    ln = np.ascontiguousarray(operands[0], np.float32)
    lo = np.ascontiguousarray(operands[1], np.float32)
    adv = np.ascontiguousarray(operands[2], np.float32)
    if not (ln.shape == lo.shape == adv.shape):
        raise ValueError(
            f"rl-loss requires matching shapes; got logp_new{ln.shape} "
            f"logp_old{lo.shape} advantages{adv.shape}")
    n = int(np.prod(ln.shape)) if ln.ndim else 1
    if n <= 0:
        return np.array(ln, copy=True)

    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    per = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_policy_loss_f32(
        ln.reshape(-1).ctypes.data_as(cf), lo.reshape(-1).ctypes.data_as(cf),
        adv.reshape(-1).ctypes.data_as(cf), ctypes.c_int64(n),
        ctypes.c_int(kind), ctypes.c_float(clip), per.ctypes.data_as(cf))
    if reduction == "none":
        return per.reshape(ln.shape)
    return _x86_reduce_scalar(per, 0 if reduction == "sum" else 2, np)


# ─────────────────────────────────────────────────────────────────────────────
# x86 class-axis loss lane — cross_entropy / kl / js / focal /
# label_smoothed_cross_entropy / z_loss. The transcendentals (exp / log) run on
# the AVX-512 transcendental kernel; the class-axis max / sum and gather / one-hot
# are host structure (the same compose-kernels pattern as attention). Reduction
# over the leading axes on the reduce kernel. ``compiler_path =
# "x86_class_loss_compiled"``. f32.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_unary_t(x: Any, kind: int, np: Any) -> Any:
    """Elementwise exp (kind 0) / log (kind 1) on the AVX-512 transcendental
    kernel."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(x, dtype=np.float32).reshape(-1)
    n = int(xc.size)
    out = np.zeros(n, dtype=np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_transcendental_f32(
        xc.ctypes.data_as(cf), ctypes.c_int64(n), out.ctypes.data_as(cf),
        ctypes.c_int(kind))
    return out.reshape(np.shape(x))


def _x86_log_softmax(z: Any, np: Any) -> Any:
    """Numerically-stable log_softmax over the last axis: shifted − log(Σ exp),
    exp/log on the AVX-512 kernel."""
    m = np.max(z, axis=-1, keepdims=True)
    shifted = (z - m).astype(np.float32)
    e = _x86_unary_t(shifted, 0, np)
    s = e.sum(axis=-1, keepdims=True).astype(np.float32)
    return (shifted - _x86_log_arr(s, np)).astype(np.float32)


def _x86_log_arr(x: Any, np: Any) -> Any:
    return _x86_unary_t(x, 1, np)


def _x86_reduce_leading(loss: Any, reduction: str, np: Any) -> Any:
    """Apply none/mean/sum over all axes of the class-axis-reduced loss array."""
    if reduction == "none":
        return loss.astype(np.float32)
    flat = np.ascontiguousarray(loss, np.float32).reshape(-1)
    return _x86_reduce_scalar(flat, 0 if reduction == "sum" else 2, np)


# ─────────────────────────────────────────────────────────────────────────────
# x86 reduce/stable-reduce FOUNDATION — var/std/count_nonzero (stat) and
# logsumexp/log_softmax/softmax_safe/sigmoid_safe (stable), the x86 mirror of the
# ROCm reduce-foundation lane. prod routes through x86_reduce_compiled (new
# kernel kind). var/std/count_nonzero and logsumexp/log_softmax compose the
# AVX-512 reduce kernel + the transcendental exp/log lane.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_reduce(x: Any, op_name: str, axis: Any, keepdims: bool, np: Any) -> Any:
    """Row-reduction (sum/mean/max/min/prod) over ``axis`` on the AVX-512 reduce
    kernel, via the x86_reduce_compiled lane."""
    art = RuntimeArtifact(metadata={
        "target": "x86", "compiler_path": "x86_reduce_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": op_name, "result": "o", "operands": ["x"],
                 "kwargs": {"axis": axis, "keepdims": keepdims}}]})
    return np.asarray(_execute_x86_compiled_reduce(
        art, (np.ascontiguousarray(x, np.float32),)), np.float32)


_X86_STAT_REDUCE_OPS = ("tessera.var", "tessera.std", "tessera.count_nonzero")


def _execute_x86_compiled_stat_reduce(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="x86"`` statistical-reduction lane: var / std /
    count_nonzero over an axis, composed from the AVX-512 reduce kernel."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_STAT_REDUCE_OPS:
        raise ValueError(
            f"x86_stat_reduce_compiled executor handles one of "
            f"{_X86_STAT_REDUCE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("stat reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = kwargs.get("axis", None)
    keepdims = bool(kwargs.get("keepdims", False))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]]).astype(np.float32)

    if op_name == "tessera.count_nonzero":
        out = _x86_reduce((x != 0.0).astype(np.float32), "tessera.sum", axis,
                          keepdims, np)
        return np.rint(out).astype(np.int64)

    mean = _x86_reduce(x, "tessera.mean", axis, True, np)
    m2 = _x86_reduce(x * x, "tessera.mean", axis, True, np)
    var = np.maximum(m2 - mean * mean, np.float32(0.0))
    if op_name == "tessera.std":
        var = np.sqrt(var).astype(np.float32)
    if not keepdims:
        if axis is None:
            var = var.reshape(())
        else:
            axes = (axis,) if isinstance(axis, int) else tuple(axis)
            var = np.squeeze(var, axis=tuple(a if a >= 0 else x.ndim + a
                                             for a in axes))
    return var.astype(np.float32)


_X86_STABLE_REDUCE_OPS = ("tessera.logsumexp", "tessera.log_softmax",
                          "tessera.softmax_safe", "tessera.sigmoid_safe")


def _execute_x86_compiled_stable_reduce(artifact: RuntimeArtifact,
                                        args: Any) -> Any:
    """The ``target="x86"`` stable-reduction lane: logsumexp / log_softmax /
    softmax_safe / sigmoid_safe. logsumexp/log_softmax compose the AVX-512 reduce
    (max/sum) + the transcendental exp/log lane (max-shifted, overflow-safe);
    softmax_safe routes to the stable softmax lane, sigmoid_safe to sigmoid."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_STABLE_REDUCE_OPS:
        raise ValueError(
            f"x86_stable_reduce_compiled executor handles one of "
            f"{_X86_STABLE_REDUCE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("stable reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]]).astype(np.float32)

    if op_name == "tessera.softmax_safe":
        return _execute_x86_compiled_softmax(
            RuntimeArtifact(metadata={
                "target": "x86", "compiler_path": "x86_softmax_compiled",
                "arg_names": ["x"], "output_name": "o",
                "ops": [{"op_name": "tessera.softmax", "result": "o",
                         "operands": ["x"], "kwargs": kwargs}]}), (x,))
    if op_name == "tessera.sigmoid_safe":
        return _x86_unary_t(x, 3, np)              # sigmoid kind in transcendental

    axis = kwargs.get("axis", -1)
    keepdims = bool(kwargs.get("keepdims", False))
    m = _x86_reduce(x, "tessera.max", axis, True, np)
    e = _x86_unary_t((x - m).astype(np.float32), 0, np)
    s = _x86_reduce(e, "tessera.sum", axis, True, np)
    lse_keep = (m + _x86_log_arr(s, np)).astype(np.float32)
    if op_name == "tessera.log_softmax":
        return (x - lse_keep).astype(np.float32)
    if keepdims:
        return lse_keep
    if axis is None:
        return lse_keep.reshape(())
    axes = (axis,) if isinstance(axis, int) else tuple(axis)
    return np.squeeze(lse_keep, axis=tuple(a if a >= 0 else x.ndim + a
                                           for a in axes)).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# x86 spectral (FFT) lane — fft / ifft / rfft / irfft over power-of-two lengths
# (Spectral PR2). The radix-2 C2C kernel (tessera_x86_fft_c2c_f32) does the
# transform; r2c/c2r pack/unpack around it; the SpectralPlan (compiler/
# spectral_plan.py) owns strategy + normalization. Non-power-of-two lengths emit
# a stable diagnostic until the Bluestein/DFT path (PR3). f32/complex64.
# ─────────────────────────────────────────────────────────────────────────────
def _x86_fft_c2c_rows(xc: Any, inverse: bool, np: Any) -> Any:
    """Unnormalized radix-2 C2C FFT of complex64 rows [batch, n] (n a power of
    two) on the AVX-512 kernel. Returns a new complex64 [batch, n]."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable(
            "libtessera_x86_elementwise.so not loadable")
    xc = np.ascontiguousarray(xc, np.complex64)
    batch, n = int(xc.shape[0]), int(xc.shape[1])
    buf = np.ascontiguousarray(xc.view(np.float32).reshape(-1))
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_fft_c2c_f32(
        buf.ctypes.data_as(cf), ctypes.c_int64(batch), ctypes.c_int64(n),
        ctypes.c_int(1 if inverse else 0))
    return buf.view(np.complex64).reshape(batch, n)


def _x86_dft_rows(rows: Any, inverse: bool, np: Any) -> Any:
    """Unnormalized naive DFT of complex64 rows [batch, n] via the DFT matrix
    on the AVX-512 GEMM (complex = 4 real matmuls). For tiny non-power-of-two n
    (Spectral PR3, strategy='dft'). X = rows @ W, W[j,k]=exp(sign·2πi·jk/n)."""
    n = int(rows.shape[1])
    sign = 1.0 if inverse else -1.0
    j = np.arange(n)
    w = np.exp(sign * 2j * np.pi * np.outer(j, j) / n).astype(np.complex64)
    ar = np.ascontiguousarray(rows.real, np.float32)
    ai = np.ascontiguousarray(rows.imag, np.float32)
    wr = np.ascontiguousarray(w.real, np.float32)
    wi = np.ascontiguousarray(w.imag, np.float32)
    rr = _x86_gemm_2d(ar, wr) - _x86_gemm_2d(ai, wi)
    ri = _x86_gemm_2d(ar, wi) + _x86_gemm_2d(ai, wr)
    return (rr + 1j * ri).astype(np.complex64)


def _x86_bluestein_rows(rows: Any, inverse: bool, np: Any) -> Any:
    """Unnormalized Bluestein (chirp-z) DFT of complex64 rows [batch, n] for an
    arbitrary n, as a power-of-two convolution on the radix-2 C2C kernel
    (Spectral PR3, strategy='bluestein'). m = next_pow2(2n-1)."""
    from .compiler.spectral_plan import next_power_of_two
    n = int(rows.shape[1])
    batch = int(rows.shape[0])
    m = next_power_of_two(2 * n - 1)
    sign = 1.0 if inverse else -1.0
    j = np.arange(n)
    chirp = np.exp(sign * 1j * np.pi * (j.astype(np.float64) ** 2) / n).astype(
        np.complex64)
    a = np.zeros((batch, m), np.complex64)
    a[:, :n] = rows * chirp[None, :]
    b = np.zeros(m, np.complex64)
    bconj = np.conj(chirp)
    b[:n] = bconj
    if n > 1:
        b[m - n + 1:] = bconj[1:][::-1]      # circular filter == linear conv
    fa = _x86_fft_c2c_rows(a, False, np)
    fb = _x86_fft_c2c_rows(b[None, :].copy(), False, np)[0]
    c = _x86_fft_c2c_rows(fa * fb[None, :], True, np) / np.float32(m)
    return (c[:, :n] * chirp[None, :]).astype(np.complex64)


def _x86_transform_rows(rows: Any, inverse: bool, np: Any) -> Any:
    """Unnormalized DFT of complex64 rows [batch, n] for ANY n — dispatches the
    plan's strategy: radix-2 (power-of-two), naive DFT (tiny), or Bluestein."""
    from .compiler.spectral_plan import plan_fft
    n = int(rows.shape[1])
    strat = plan_fft(n, inverse=inverse).strategy
    if strat == "radix2":
        return _x86_fft_c2c_rows(rows, inverse, np)
    if strat == "dft":
        return _x86_dft_rows(rows, inverse, np)
    return _x86_bluestein_rows(rows, inverse, np)


_X86_FFT_OPS = ("tessera.fft", "tessera.ifft", "tessera.rfft", "tessera.irfft")


def _execute_x86_compiled_fft(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` spectral lane: fft / ifft / rfft / irfft over a
    power-of-two axis. Consumes the SpectralPlan for strategy + normalization;
    radix-2 C2C kernel + r2c/c2r pack-unpack. Non-power-of-two → stable
    diagnostic (Spectral PR3)."""
    import numpy as np

    from .compiler.spectral_plan import plan_fft

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_FFT_OPS:
        raise ValueError(
            f"x86_fft_compiled executor handles one of {_X86_FFT_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("fft requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = int(kwargs.get("axis", -1))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    nd = x.ndim
    if nd < 1:
        raise ValueError("fft operand must have rank >= 1")
    ax = axis if axis >= 0 else nd + axis

    inverse = op_name == "tessera.ifft"
    if op_name == "tessera.irfft":
        m = int(x.shape[ax])
        n = int(kwargs.get("n") or 2 * (m - 1))
    else:
        n = int(x.shape[ax])
    mode = {"tessera.rfft": "r2c", "tessera.irfft": "c2r"}.get(op_name, "c2c")
    plan = plan_fft(n, axis=ax, mode=mode,
                    inverse=inverse or op_name == "tessera.irfft")
    # strategy (radix-2 / dft / bluestein) is dispatched per-row by
    # _x86_transform_rows; any positive length is supported (Spectral PR3).

    xm = np.moveaxis(x, ax, -1)
    lead = xm.shape[:-1]

    if op_name in ("tessera.fft", "tessera.ifft"):
        rows = xm.reshape(-1, n).astype(np.complex64)
        out = _x86_transform_rows(rows, plan.inverse, np)
        if plan.scale != 1.0:
            out = out * np.complex64(plan.scale)
        return np.moveaxis(out.reshape(*lead, n), -1, ax).astype(np.complex64)

    if op_name == "tessera.rfft":
        rows = xm.reshape(-1, n).astype(np.complex64)   # im = 0
        full = _x86_transform_rows(rows, False, np)
        half = full[:, : n // 2 + 1]
        return np.moveaxis(half.reshape(*lead, n // 2 + 1), -1, ax).astype(
            np.complex64)

    # tessera.irfft — Hermitian-reconstruct the full spectrum, ifft, take real.
    rows = xm.reshape(-1, m).astype(np.complex64)
    batch = rows.shape[0]
    full = np.zeros((batch, n), np.complex64)
    full[:, :m] = rows[:, :m]
    if n - m > 0:                                       # mirror conj tail
        full[:, m:n] = np.conj(rows[:, 1:n - n // 2])[:, ::-1]
    out = _x86_transform_rows(full, True, np).real * np.float32(1.0 / n)
    return np.moveaxis(out.reshape(*lead, n), -1, ax).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# Spectral composite ops (Spectral PR5) — dct / stft / istft / spectral_conv /
# spectral_filter. Device-agnostic: each composes the device FFT lane (passed as
# ``fftexec``) for the transform + host framing / windowing / overlap-add /
# pointwise. One implementation, two thin per-device wrappers (x86 / ROCm).
# ─────────────────────────────────────────────────────────────────────────────
_SPECTRAL_COMPOSITE_OPS = ("tessera.dct", "tessera.stft", "tessera.istft",
                           "tessera.spectral_conv", "tessera.spectral_filter")


def _spectral_composite(op_name: str, operands: list, kwargs: dict,
                        fftexec: Any, np: Any) -> Any:
    """Composite spectral op over the device FFT lane. ``fftexec(sub_op, x,
    sub_kwargs)`` runs fft/ifft/rfft/irfft on the device."""
    if op_name == "tessera.spectral_filter":               # pointwise cmul
        return (np.asarray(operands[0]) * np.asarray(operands[1])).astype(
            np.complex64)

    if op_name == "tessera.dct":                            # type-2 via FFT
        x = np.asarray(operands[0])
        axis = int(kwargs.get("axis", -1))
        ax = axis if axis >= 0 else x.ndim + axis
        n = int(x.shape[ax])
        y = np.concatenate([x, np.flip(x, axis=ax)], axis=ax).astype(np.complex64)
        spec = np.asarray(fftexec("tessera.fft", y, {"axis": ax}))
        sl = [slice(None)] * spec.ndim
        sl[ax] = slice(0, n)
        return np.real(spec[tuple(sl)]).astype(np.float32)

    if op_name == "tessera.spectral_conv":                  # FFT convolution
        x = np.asarray(operands[0], np.float32)
        w = np.asarray(operands[1], np.float32)
        n = int(x.shape[-1] + w.shape[-1] - 1)
        nfft = 1 << int(np.ceil(np.log2(max(n, 1))))
        xp = np.zeros(x.shape[:-1] + (nfft,), np.float32)
        xp[..., :x.shape[-1]] = x
        wp = np.zeros(w.shape[:-1] + (nfft,), np.float32)
        wp[..., :w.shape[-1]] = w
        xf = np.asarray(fftexec("tessera.rfft", xp, {"axis": -1}))
        wf = np.asarray(fftexec("tessera.rfft", wp, {"axis": -1}))
        y = fftexec("tessera.irfft", (xf * wf).astype(np.complex64),
                    {"axis": -1, "n": nfft})
        return np.asarray(y, np.float32)[..., :n]

    if op_name == "tessera.stft":                           # framed windowed rfft
        x = np.asarray(operands[0])
        win = np.asarray(operands[1])
        hop = int(kwargs["hop"])
        wl = int(win.shape[-1])
        starts = list(range(0, max(1, int(x.shape[-1]) - wl + 1), hop))
        frames = np.stack([x[..., s:s + wl] * win for s in starts], axis=-2)
        return np.asarray(fftexec("tessera.rfft", frames.astype(np.float32),
                                  {"axis": -1})).astype(np.complex64)

    # tessera.istft — overlap-add of windowed irfft frames
    xf = np.asarray(operands[0])
    win = np.asarray(operands[1])
    hop = int(kwargs["hop"])
    fl = int(win.shape[-1])
    nf = int(xf.shape[-2])
    frames = np.asarray(fftexec("tessera.irfft", xf.astype(np.complex64),
                                {"axis": -1, "n": fl}))
    out = np.zeros(xf.shape[:-2] + ((nf - 1) * hop + fl,), np.float64)
    weight = np.zeros_like(out)
    for idx in range(nf):
        fr = frames[..., idx, :] * win
        s = idx * hop
        out[..., s:s + fl] += fr
        weight[..., s:s + fl] += win * win
    return (out / np.maximum(weight, 1e-12)).astype(np.float32)


def _x86_fftexec(sub_op: str, x: Any, sub_kwargs: dict) -> Any:
    art = RuntimeArtifact(metadata={
        "target": "x86", "compiler_path": "x86_fft_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": sub_op, "result": "o", "operands": ["x"],
                 "kwargs": sub_kwargs}]})
    return _execute_x86_compiled_fft(art, (x,))


def _execute_x86_compiled_spectral(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` composite spectral lane: dct / stft / istft /
    spectral_conv / spectral_filter, composing the x86 FFT lane."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _SPECTRAL_COMPOSITE_OPS:
        raise ValueError(
            f"x86_spectral_compiled executor handles one of "
            f"{_SPECTRAL_COMPOSITE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[str(n)]) for n in op.get("operands", [])]
    return _spectral_composite(op_name, operands, op.get("kwargs") or {},
                               _x86_fftexec, np)


# ─────────────────────────────────────────────────────────────────────────────
# Sparse linear algebra (S-series `sparse`) — GENUINELY sparse kernels (iterate
# the nonzero structure, not densify-then-GEMM). spmm_csr/coo = row-wise SpMM;
# sddmm = sampled dense-dense; bsmm = block-sparse → GEMM. compiler_path=
# "x86_sparse_compiled" / "rocm_sparse_compiled". f32.
# ─────────────────────────────────────────────────────────────────────────────
_SPARSE_OPS = ("tessera.spmm_csr", "tessera.spmm_coo", "tessera.sddmm",
               "tessera.bsmm")


def _coo_to_csr(coords: Any, nrows: int, np: Any) -> Any:
    """COO coords [nnz,2] (row,col) → (sort_order, indptr[nrows+1] i32). The
    caller reorders values/cols by ``sort_order`` to get CSR layout."""
    coords = np.asarray(coords)
    order = np.lexsort((coords[:, 1], coords[:, 0]))
    counts = np.zeros(nrows + 1, np.int64)
    np.add.at(counts, coords[order, 0].astype(np.int64) + 1, 1)
    indptr = np.cumsum(counts).astype(np.int32)
    return order, indptr


def _x86_spmm_csr(indptr: Any, indices: Any, values: Any, B: Any,
                  m: int, n: int, np: Any) -> Any:
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    ip = np.ascontiguousarray(indptr, np.int32)
    ix = np.ascontiguousarray(indices, np.int32)
    vv = np.ascontiguousarray(values, np.float32)
    bc = np.ascontiguousarray(B, np.float32)
    out = np.zeros((m, n), np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    vp = ctypes.c_void_p
    lib.tessera_x86_avx512_spmm_csr_f32(
        ip.ctypes.data_as(vp), ix.ctypes.data_as(vp), vv.ctypes.data_as(cf),
        bc.ctypes.data_as(cf), ctypes.c_int64(m), ctypes.c_int64(n),
        out.ctypes.data_as(cf))
    return out


def _x86_sddmm(A: Any, B: Any, mask: Any, np: Any) -> Any:
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    bt = np.ascontiguousarray(np.asarray(B, np.float32).T)   # Bt[N,K]
    mk = np.ascontiguousarray(mask, np.float32)
    m, k = int(a.shape[0]), int(a.shape[1])
    n = int(bt.shape[0])
    out = np.zeros((m, n), np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_avx512_sddmm_f32(
        a.ctypes.data_as(cf), bt.ctypes.data_as(cf), mk.ctypes.data_as(cf),
        ctypes.c_int64(m), ctypes.c_int64(n), ctypes.c_int64(k),
        out.ctypes.data_as(cf))
    return out


def _sparse_compute(op_name: str, operands: list, spmm_fn: Any, sddmm_fn: Any,
                    gemm_fn: Any, np: Any) -> Any:
    """Dispatch a sparse op over device spmm/sddmm/gemm kernels. ``spmm_fn(indptr,
    indices, values, B, M, N)`` runs CSR SpMM on the device; COO is converted to
    CSR on host first; bsmm routes through the dense GEMM."""
    if op_name in ("tessera.spmm_csr", "tessera.spmm_coo"):
        a, b = operands[0], operands[1]
        b = np.asarray(b, np.float32)
        if op_name == "tessera.spmm_csr":
            indptr, indices, values, shape = a
            m, _ = int(shape[0]), int(shape[1])
            return spmm_fn(np.asarray(indptr), np.asarray(indices),
                           np.asarray(values, np.float32), b, m, int(b.shape[1]))
        coords, values, shape = a
        m = int(shape[0])
        order, indptr = _coo_to_csr(coords, m, np)
        indices = np.asarray(coords)[order, 1].astype(np.int32)
        values = np.asarray(values, np.float32)[order]
        return spmm_fn(indptr, indices, values, b, m, int(b.shape[1]))
    if op_name == "tessera.sddmm":
        return sddmm_fn(np.asarray(operands[0], np.float32),
                        np.asarray(operands[1], np.float32),
                        np.asarray(operands[2], np.float32))
    # tessera.bsmm — block-sparse matmul collapses to dense GEMM (meta=None)
    return gemm_fn(np.asarray(operands[0], np.float32),
                   np.asarray(operands[1], np.float32))


def _execute_x86_compiled_sparse(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` sparse lane: spmm_csr / spmm_coo / sddmm / bsmm on
    the AVX-512 sparse kernels (spmm_csr row-AXPY, sddmm sampled-dot) + the GEMM
    microkernel for bsmm. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _SPARSE_OPS:
        raise ValueError(
            f"x86_sparse_compiled executor handles one of {_SPARSE_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands = [values[str(n)] for n in op.get("operands", [])]

    def _spmm(indptr, indices, vals, b, m, n):
        return _x86_spmm_csr(indptr, indices, vals, b, m, n, np)

    return _sparse_compute(
        op_name, operands, _spmm,
        lambda a, b, mk: _x86_sddmm(a, b, mk, np), _x86_gemm_2d, np)


# ─────────────────────────────────────────────────────────────────────────────
# Mixture-of-experts COMPUTE (S-series `moe`) — the routed per-token expert
# matmuls (top-1). Routing (argmax/round-robin) is resolved on host; the device
# kernel runs the FLOP-heavy expert GEMVs. compiler_path="x86_moe_compiled" /
# "rocm_moe_compiled". f32. (moe_dispatch/moe_combine = transport, mesh-gated.)
# ─────────────────────────────────────────────────────────────────────────────
def _moe_prepare(x: Any, experts: Any, route: Any, scores: Any, np: Any) -> tuple:
    """Reshape to (tokens, in_dim) + stacked experts (E,in,out) + resolved int32
    route[tokens] (route → scores-argmax → round-robin). Returns (tokens, experts,
    route_i32, lead_shape, in_dim, out_dim)."""
    x = np.ascontiguousarray(x, np.float32)
    experts = np.asarray(experts, np.float32)
    if experts.ndim == 2:
        experts = experts[None, :, :]
    if experts.ndim != 3:
        raise ValueError("moe experts must be (num_experts, in_dim, out_dim)")
    e, in_dim, out_dim = (int(v) for v in experts.shape)
    if int(x.shape[-1]) != in_dim:
        raise ValueError(f"moe input dim {x.shape[-1]} != expert dim {in_dim}")
    tokens = x.reshape(-1, in_dim)
    t = int(tokens.shape[0])
    if route is not None:
        r = np.asarray(route, np.int64).reshape(-1)
    elif scores is not None:
        r = np.argmax(np.asarray(scores).reshape(t, e), axis=-1)
    else:
        r = np.arange(t, dtype=np.int64) % e
    if r.shape[0] != t:
        raise ValueError("moe route length must match token count")
    r = np.mod(r, e).astype(np.int32)
    return (np.ascontiguousarray(tokens, np.float32),
            np.ascontiguousarray(experts, np.float32), r,
            x.shape[:-1], in_dim, out_dim)


def _x86_moe(x: Any, experts: Any, route: Any, scores: Any, np: Any) -> Any:
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    tk, ex, r, lead, in_dim, out_dim = _moe_prepare(x, experts, route, scores, np)
    t = int(tk.shape[0])
    out = np.zeros((t, out_dim), np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_moe_f32(
        tk.ctypes.data_as(cf), ex.ctypes.data_as(cf),
        r.ctypes.data_as(ctypes.c_void_p), ctypes.c_int64(t),
        ctypes.c_int64(in_dim), ctypes.c_int64(out_dim), out.ctypes.data_as(cf))
    return out.reshape(lead + (out_dim,))


def _moe_bind(op: dict, values: dict) -> tuple:
    """Unpack moe operands: [x, experts] + trailing extras named by
    kwargs["extras"] (e.g. ["route"], ["scores"])."""
    names = [str(nm) for nm in op.get("operands", [])]
    extras = list((op.get("kwargs") or {}).get("extras", []))
    ev = {kk: values[names[2 + i]] for i, kk in enumerate(extras)}
    return values[names[0]], values[names[1]], ev.get("route"), ev.get("scores")


def _execute_x86_compiled_moe(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` moe-compute lane: routed per-token expert GEMVs (top-1)
    on the AVX-512 kernel. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name != "tessera.moe":
        raise ValueError(
            "x86_moe_compiled executor handles tessera.moe; "
            f"got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    x, experts, route, scores = _moe_bind(ops[0], values)
    return _x86_moe(x, experts, route, scores, np)


# ─────────────────────────────────────────────────────────────────────────────
# Fused optimizer steps (S-series `functional_optimizer_step`, P3) — a single
# flat per-parameter update kernel parameterized by optimizer `kind`. The pytree
# orchestration + the bias-correction scalars (1-β^t) are host-side; the kernel
# is pure elementwise. State (m,v) is in/out. compiler_path="x86_optimizer_
# compiled" / "rocm_optimizer_compiled". f32.
# ─────────────────────────────────────────────────────────────────────────────
# op_name -> (kind_str, kind_int, state-buffer names in return order)
_OPTIMIZER_OPS: dict[str, tuple[str, int, tuple[str, ...]]] = {
    "tessera.sgd": ("sgd", 0, ()),
    "tessera.momentum": ("momentum", 1, ("v",)),
    "tessera.adam": ("adam", 2, ("m", "v")),
    "tessera.adamw": ("adamw", 3, ("m", "v")),
    "tessera.lion": ("lion", 4, ("m",)),
    "tessera.nesterov": ("nesterov", 5, ("v",)),  # look-ahead momentum
}


def _optimizer_bind(op: dict, values: dict) -> tuple:
    """Unpack [p, g] + state extras (m/v) named by kwargs["extras"]."""
    names = [str(nm) for nm in op.get("operands", [])]
    extras = list((op.get("kwargs") or {}).get("extras", []))
    ev = {kk: values[names[2 + i]] for i, kk in enumerate(extras)}
    return values[names[0]], values[names[1]], ev.get("m"), ev.get("v")


def _optimizer_compute(op_name: str, p: Any, g: Any, m: Any, v: Any,
                       kwargs: dict, run_kernel: Any, np: Any) -> Any:
    """Run one optimizer step over a single parameter tensor. ``run_kernel(kind,
    p, g, m, v, n, lr, b1, b2, eps, wd, b1c, b2c)`` does the device update and
    returns (p_out, m_out, v_out). Returns (p_new, *state) per the op's kind."""
    _, kind, state_names = _OPTIMIZER_OPS[op_name]
    p = np.ascontiguousarray(p, np.float32)
    g = np.ascontiguousarray(g, np.float32)
    shape = p.shape
    pf = p.reshape(-1)
    gf = g.reshape(-1)
    n = int(pf.size)
    mf = (np.ascontiguousarray(m, np.float32).reshape(-1) if m is not None
          else np.zeros(n, np.float32))
    vf = (np.ascontiguousarray(v, np.float32).reshape(-1) if v is not None
          else np.zeros(n, np.float32))
    lr = float(kwargs.get("lr", 1e-3))
    beta1 = float(kwargs.get("beta1", kwargs.get("momentum", 0.9)))
    beta2 = float(kwargs.get("beta2", 0.999))
    eps = float(kwargs.get("eps", 1e-8))
    wd = float(kwargs.get("weight_decay", 0.0))
    step = int(kwargs.get("step", 1))
    b1c = 1.0 - beta1 ** step if kind in (2, 3) else 1.0
    b2c = 1.0 - beta2 ** step if kind in (2, 3) else 1.0
    p_out, m_out, v_out = run_kernel(kind, pf, gf, mf, vf, n, lr, beta1, beta2,
                                     eps, wd, b1c, b2c)
    out = [p_out.reshape(shape)]
    for sn in state_names:
        out.append((m_out if sn == "m" else v_out).reshape(shape))
    return tuple(out) if len(out) > 1 else out[0]


def _x86_optimizer_kernel(kind: int, p: Any, g: Any, m: Any, v: Any, n: int,
                          lr: float, b1: float, b2: float, eps: float, wd: float,
                          b1c: float, b2c: float) -> tuple:
    import numpy as np
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    p_out = np.zeros(n, np.float32)
    m_out = np.zeros(n, np.float32)
    v_out = np.zeros(n, np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_optimizer_f32(
        p.ctypes.data_as(cf), g.ctypes.data_as(cf), m.ctypes.data_as(cf),
        v.ctypes.data_as(cf), ctypes.c_int64(n), ctypes.c_int(kind),
        ctypes.c_float(lr), ctypes.c_float(b1), ctypes.c_float(b2),
        ctypes.c_float(eps), ctypes.c_float(wd), ctypes.c_float(b1c),
        ctypes.c_float(b2c), p_out.ctypes.data_as(cf), m_out.ctypes.data_as(cf),
        v_out.ctypes.data_as(cf))
    return p_out, m_out, v_out


def _execute_x86_compiled_optimizer(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` optimizer lane: sgd / momentum / adam / adamw / lion
    per-parameter update on the AVX-512 fused kernel. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _OPTIMIZER_OPS:
        raise ValueError(
            f"x86_optimizer_compiled executor handles one of "
            f"{tuple(_OPTIMIZER_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    p, g, m, v = _optimizer_bind(ops[0], values)
    return _optimizer_compute(op_name, p, g, m, v, ops[0].get("kwargs") or {},
                              _x86_optimizer_kernel, np)


def _apple_optimizer_kernel(kind: int, p: Any, g: Any, m: Any, v: Any, n: int,
                            lr: float, b1: float, b2: float, eps: float,
                            wd: float, b1c: float, b2c: float) -> tuple:
    """Numpy per-parameter optimizer update — Apple ships no device optimizer
    kernel, so the lane runs the same elementwise rules the x86/ROCm device
    kernels are matched against (scalar reference in avx512_optimizer_f32.cpp;
    matches tessera.optim). f32. (kind: 0 sgd, 1 momentum, 2 adam, 3 adamw,
    4 lion, 5 nesterov.)"""
    import numpy as np
    p = np.asarray(p, np.float32)
    g = np.asarray(g, np.float32)
    m = np.asarray(m, np.float32)
    v = np.asarray(v, np.float32)
    m_out, v_out = m, v
    if kind == 0:                                   # sgd
        p_out = p - lr * g
    elif kind == 1:                                 # momentum
        v_out = b1 * v + g
        p_out = p - lr * v_out
    elif kind == 5:                                 # nesterov (look-ahead)
        v_out = b1 * v + g
        p_out = p - lr * (g + b1 * v_out)
    elif kind == 4:                                 # lion
        u = b1 * m + (1.0 - b1) * g
        m_out = b2 * m + (1.0 - b2) * g
        pp = p * np.float32(1.0 - lr * wd) if wd != 0.0 else p
        p_out = pp - lr * np.sign(u).astype(np.float32)
    else:                                           # adam (2) / adamw (3)
        m_out = b1 * m + (1.0 - b1) * g
        v_out = b2 * v + (1.0 - b2) * g * g
        pp = p * np.float32(1.0 - lr * wd) if (kind == 3 and wd != 0.0) else p
        upd = (m_out / b1c) / (np.sqrt(v_out / b2c) + eps)
        p_out = pp - lr * upd
    return (p_out.astype(np.float32), np.asarray(m_out, np.float32),
            np.asarray(v_out, np.float32))


def _execute_apple_gpu_compiled_optimizer(artifact: RuntimeArtifact,
                                          args: Any) -> Any:
    """The ``target="apple_gpu"`` optimizer lane: sgd / momentum / adam / adamw /
    lion per-parameter update via the numpy reference (Apple ships no device
    optimizer kernel — runs on the CPU reference path). f32; matches
    tessera.optim — parity with x86/rocm_optimizer_compiled."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _OPTIMIZER_OPS:
        raise ValueError(
            f"apple_gpu_optimizer_compiled executor handles one of "
            f"{tuple(_OPTIMIZER_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    p, g, m, v = _optimizer_bind(ops[0], values)
    return _optimizer_compute(op_name, p, g, m, v, ops[0].get("kwargs") or {},
                              _apple_optimizer_kernel, np)


# ─────────────────────────────────────────────────────────────────────────────
# LAMB — layer-wise adaptive moments (P3 optimizer tail). LAMB is the device
# adam update (the FLOP-heavy elementwise m/v step, run with lr=1 / wd=0 on the
# fused optimizer kernel) followed by a PER-TENSOR trust ratio ‖p‖/‖update‖ that
# the elementwise lane cannot compute — that reduction + the final scaling run on
# host. compiler_path="x86_lamb_compiled" / "rocm_lamb_compiled". f32. Matches
# tessera.optim.lamb.
# ─────────────────────────────────────────────────────────────────────────────
_LAMB_OPS = ("tessera.lamb",)


def _lamb_compute(p: Any, g: Any, m: Any, v: Any, kwargs: dict,
                  run_kernel: Any, np: Any) -> tuple:
    """One LAMB step over a single parameter tensor. ``run_kernel`` is the fused
    optimizer device kernel; kind 2 (adam) with lr=1/wd=0 yields the adam update,
    then the host applies the layer-wise trust ratio. Returns (p_new, m, v)."""
    p = np.ascontiguousarray(p, np.float32)
    g = np.ascontiguousarray(g, np.float32)
    shape = p.shape
    pf = p.reshape(-1)
    gf = g.reshape(-1)
    n = int(pf.size)
    mf = (np.ascontiguousarray(m, np.float32).reshape(-1) if m is not None
          else np.zeros(n, np.float32))
    vf = (np.ascontiguousarray(v, np.float32).reshape(-1) if v is not None
          else np.zeros(n, np.float32))
    lr = float(kwargs.get("lr", 1e-3))
    beta1 = float(kwargs.get("beta1", 0.9))
    beta2 = float(kwargs.get("beta2", 0.999))
    eps = float(kwargs.get("eps", 1e-6))
    wd = float(kwargs.get("weight_decay", 0.0))
    step = int(kwargs.get("step", 1))
    b1c = 1.0 - beta1 ** step
    b2c = 1.0 - beta2 ** step
    # device adam update (lr=1, wd=0): next_p = p - adam_update; m/v advanced.
    next_p, m_out, v_out = run_kernel(2, pf, gf, mf, vf, n, 1.0, beta1, beta2,
                                      eps, 0.0, b1c, b2c)
    update = (pf - next_p) + wd * pf
    p_norm = float(np.linalg.norm(pf))
    u_norm = float(np.linalg.norm(update))
    trust = 1.0 if (p_norm == 0.0 or u_norm == 0.0) else p_norm / u_norm
    p_new = pf - np.float32(lr * trust) * update
    return (p_new.reshape(shape), m_out.reshape(shape), v_out.reshape(shape))


def _execute_lamb(artifact: RuntimeArtifact, args: Any, run_kernel: Any,
                  path: str) -> Any:
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _LAMB_OPS:
        raise ValueError(
            f"{path} executor handles one of {_LAMB_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    p, g, m, v = _optimizer_bind(ops[0], values)
    return _lamb_compute(p, g, m, v, ops[0].get("kwargs") or {}, run_kernel, np)


def _execute_x86_compiled_lamb(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` LAMB lane: AVX-512 adam kernel + host trust ratio."""
    return _execute_lamb(artifact, args, _x86_optimizer_kernel,
                         "x86_lamb_compiled")


# ─────────────────────────────────────────────────────────────────────────────
# Muon — momentum + orthogonalized update (P3 optimizer tail). The orthogonal
# polar factor U·Vh of the momentum matrix is computed from a DEVICE SVD (the
# FLOP-heavy linalg op, on the x86/gfx1151 one-sided-Jacobi kernel); the small
# U@Vh product + the momentum / sgd elementwise steps run on host — the same
# device-heavy / host-light split LAMB uses. <2-D params normalize instead.
# compiler_path="x86_muon_compiled" / "rocm_muon_compiled". f32. Matches
# tessera.optim.muon.
# ─────────────────────────────────────────────────────────────────────────────
_MUON_OPS = ("tessera.muon",)


def _muon_compute(p: Any, g: Any, v: Any, kwargs: dict, svd_mn_fn: Any,
                  np: Any) -> tuple:
    """One Muon step over a single parameter. ``svd_mn_fn(A)→(U,S,Vh)`` is the
    m≥n device SVD kernel. Returns (p_new, new_velocity)."""
    p = np.ascontiguousarray(p, np.float32)
    g = np.ascontiguousarray(g, np.float32)
    momentum = float(kwargs.get("momentum", 0.95))
    lr = float(kwargs.get("lr", 1e-3))
    v_arr = (np.ascontiguousarray(v, np.float32) if v is not None
             else np.zeros_like(p))
    new_v = (momentum * v_arr + g).astype(np.float32)
    if new_v.ndim < 2:
        update = new_v / (float(np.linalg.norm(new_v)) + 1e-12)
    else:
        mat = new_v.reshape(int(new_v.shape[0]), -1)
        u, _s, vh = _svd_via(mat, lambda A: svd_mn_fn(A, np), np)  # device SVD
        update = (np.asarray(u) @ np.asarray(vh)).reshape(new_v.shape)
    p_new = (p - np.float32(lr) * update.astype(np.float32)).astype(np.float32)
    return (p_new, new_v)


def _execute_muon(artifact: RuntimeArtifact, args: Any, svd_mn_fn: Any,
                  path: str) -> Any:
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _MUON_OPS:
        raise ValueError(
            f"{path} executor handles one of {_MUON_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    names = [str(nm) for nm in op.get("operands", [])]
    values = _bind_launch_args(args, arg_names)
    p = values[names[0]]
    g = values[names[1]]
    v = values[names[2]] if len(names) > 2 else None
    return _muon_compute(p, g, v, op.get("kwargs") or {}, svd_mn_fn, np)


def _execute_x86_compiled_muon(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` Muon lane: AVX-512 SVD orthogonalization + host."""
    return _execute_muon(artifact, args, _x86_svd_mn, "x86_muon_compiled")


# ─────────────────────────────────────────────────────────────────────────────
# State-space model (S-series `state_space`) — Mamba2 selective scan. A single
# fused sequential scan over S, vectorized over the state dim N, maintaining the
# (B,D,N) state in place. compiler_path="x86_selective_ssm_compiled" /
# "rocm_selective_ssm_compiled". f32.
# ─────────────────────────────────────────────────────────────────────────────
def _ssm_store_dtype(x: Any, np: Any) -> Any:
    """The SSM I/O storage dtype from the input: f16 / bf16 stay half; everything
    else runs f32. (The state + exp + accumulate are always f32 in-kernel.)"""
    dt = np.asarray(x).dtype
    bf16 = _bfloat16_dtype()
    if dt == np.float16 or (bf16 is not None and dt == bf16):
        return dt
    return np.float32


def _ssm_prepare(x: Any, A: Any, B: Any, C: Any, delta: Any, state: Any,
                 np: Any, store: Any = None) -> tuple:
    """Validate shapes + broadcast A→(D,N) + init working state h→(B,D,N).
    Returns (x, A2d, B, C, delta, h, Bsz, S, D, N): x/A2d/B/C/delta in the
    ``store`` dtype (default f32), the working state ``h`` ALWAYS f32."""
    if store is None:
        store = np.float32
    x = np.ascontiguousarray(x, store)
    Bc = np.ascontiguousarray(B, store)
    Cc = np.ascontiguousarray(C, store)
    delta = np.ascontiguousarray(delta, store)
    if x.ndim != 3:
        raise ValueError(f"selective_ssm: x must be (B,S,D); got {x.shape}")
    bsz, s, d = (int(v) for v in x.shape)
    n = int(Bc.shape[2])
    A = np.asarray(A)
    if A.ndim == 1:
        a2d = np.ascontiguousarray(np.broadcast_to(A[:, None], (d, n)), store)
    else:
        a2d = np.ascontiguousarray(A, store)
    if state is not None:
        h = np.ascontiguousarray(state, np.float32).copy()
    else:
        h = np.zeros((bsz, d, n), np.float32)
    return x, a2d, Bc, Cc, delta, h, bsz, s, d, n


def _x86_selective_ssm_chunked(x, A, B, C, delta, gate, state, np,
                               chunk_size: int = 128):
    """Chunked-parallel (SSD) selective_ssm for scalar-state A — the three batched
    contractions run on the AVX-512 GEMM (f32), the per-chunk state recurrence on
    host. The standard Mamba-2 algorithm; matches the sequential scan. Scalar-A
    ``(D,)`` only (the caller routes ``(D, N)`` A to the sequential lane)."""
    from . import _mamba_ssd as _ssd
    if _load_x86_elementwise() is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")

    def bmm(a, b):
        return _x86_batched_gemm(np.ascontiguousarray(a, np.float32),
                                 np.ascontiguousarray(b, np.float32))

    return _ssd.selective_ssm_parallel(
        x, A, B, C, delta, gate=gate, state=state,
        chunk_size=int(chunk_size), matmul3d=bmm)


def _x86_selective_ssm(x: Any, A: Any, B: Any, C: Any, delta: Any,
                       gate: Any, state: Any, np: Any) -> Any:
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    store = _ssm_store_dtype(x, np)
    # Scalar-state A (D,) in f32 → the chunked-parallel SSD form (AVX-512 GEMM
    # bmms). Same result as the sequential scan (~1e-8), the standard Mamba-2
    # decomposition; (D, N) A + f16/bf16 keep the sequential kernel below.
    if store == np.float32 and np.asarray(A).ndim == 1:
        return _x86_selective_ssm_chunked(x, A, B, C, delta, gate, state, np)
    iptr: Any
    if store == np.float16:
        sym, iptr = "tessera_x86_avx512_selective_ssm_f16", ctypes.c_uint16
    elif store == np.float32:
        sym, iptr = "tessera_x86_avx512_selective_ssm_f32", ctypes.c_float
    else:  # bf16
        sym, iptr = "tessera_x86_avx512_selective_ssm_bf16", ctypes.c_uint16
    x, a2d, Bc, Cc, dl, h, bsz, s, d, n = _ssm_prepare(
        x, A, B, C, delta, state, np, store=store)
    y = np.zeros((bsz, s, d), store)
    ip = ctypes.POINTER(iptr)
    cf = ctypes.POINTER(ctypes.c_float)
    getattr(lib, sym)(
        x.ctypes.data_as(ip), a2d.ctypes.data_as(ip), Bc.ctypes.data_as(ip),
        Cc.ctypes.data_as(ip), dl.ctypes.data_as(ip),
        ctypes.c_int64(bsz), ctypes.c_int64(s), ctypes.c_int64(d),
        ctypes.c_int64(n), h.ctypes.data_as(cf), y.ctypes.data_as(ip))
    if gate is not None:
        y = y * np.ascontiguousarray(gate, store)
    return y


def _ssm_bwd_prepare(x, A, B, C, delta, dout, gate, state, np):
    """Common host prep for the selective_ssm backward: contiguous f32, A→(D,N),
    dy = dout·gate, zeroed outputs, and h_traj scratch with h_traj[0]=state.
    Returns (x,a2d,B,C,delta,dy, bsz,s,d,n, a_was_1d, h_traj, dx,dA2d,dB,dC,dd)."""
    x = np.ascontiguousarray(x, np.float32)
    Bc = np.ascontiguousarray(B, np.float32)
    Cc = np.ascontiguousarray(C, np.float32)
    dl = np.ascontiguousarray(delta, np.float32)
    bsz, s, d = (int(v) for v in x.shape)
    n = int(Bc.shape[2])
    A = np.asarray(A, np.float32)
    a_was_1d = A.ndim == 1
    a2d = np.ascontiguousarray(
        np.broadcast_to(A[:, None], (d, n)) if a_was_1d else A, np.float32)
    dy = np.ascontiguousarray(dout, np.float32)
    if gate is not None:
        dy = np.ascontiguousarray(dy * np.asarray(gate, np.float32), np.float32)
    h_traj = np.zeros((s + 1, bsz, d, n), np.float32)
    if state is not None:
        h_traj[0] = np.ascontiguousarray(state, np.float32)
    dx = np.zeros((bsz, s, d), np.float32)
    dA2d = np.zeros((d, n), np.float32)
    dBg = np.zeros((bsz, s, n), np.float32)
    dCg = np.zeros((bsz, s, n), np.float32)
    dd = np.zeros((bsz, s, d), np.float32)
    return (x, a2d, Bc, Cc, dl, dy, bsz, s, d, n, a_was_1d, h_traj,
            dx, dA2d, dBg, dCg, dd)


def _x86_selective_ssm_bwd(x, A, B, C, delta, dout, gate, state, np):
    """Reverse-mode adjoint of selective_ssm on the AVX-512 backward kernel.
    Returns (dx, dA, dB, dC, ddelta) — matches autodiff.vjp.vjp_selective_ssm."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    (xa, a2d, Bc, Cc, dl, dy, bsz, s, d, n, a1d, h_traj,
     dx, dA2d, dBg, dCg, dd) = _ssm_bwd_prepare(
        x, A, B, C, delta, dout, gate, state, np)
    cf = ctypes.POINTER(ctypes.c_float)
    P = lambda a: a.ctypes.data_as(cf)
    lib.tessera_x86_selective_ssm_bwd_f32(
        P(xa), P(a2d), P(Bc), P(Cc), P(dl), P(dy),
        ctypes.c_int64(bsz), ctypes.c_int64(s), ctypes.c_int64(d),
        ctypes.c_int64(n), P(h_traj), P(dx), P(dA2d), P(dBg), P(dCg), P(dd))
    dA = dA2d.sum(axis=1) if a1d else dA2d
    return dx, dA, dBg, dCg, dd


def _ssm_bind_operands(op: dict, values: dict) -> tuple:
    """Unpack the selective_ssm operands. Positional [x,A,B,C,delta] then any
    trailing operands named by ``kwargs["extras"]`` (e.g. ["gate"], ["state"],
    ["gate","state"])."""
    names = [str(nm) for nm in op.get("operands", [])]
    base = [values[nm] for nm in names[:5]]
    extras = list((op.get("kwargs") or {}).get("extras", []))
    extra_vals = {k: values[names[5 + i]] for i, k in enumerate(extras)}
    return (base[0], base[1], base[2], base[3], base[4],
            extra_vals.get("gate"), extra_vals.get("state"))


def _execute_x86_compiled_state_space(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` state-space lane: selective_ssm (Mamba2) on the
    AVX-512 fused selective-scan kernel. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name != "tessera.selective_ssm":
        raise ValueError(
            "x86_selective_ssm_compiled executor handles tessera.selective_ssm; "
            f"got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    x, A, B, C, delta, gate, state = _ssm_bind_operands(ops[0], values)
    return _x86_selective_ssm(x, A, B, C, delta, gate, state, np)


# ─────────────────────────────────────────────────────────────────────────────
# Dense linear algebra (S-series `linalg`) — Cholesky / triangular solve family.
# Genuinely computes the factorization / substitution (does not wrap LAPACK).
# compiler_path="x86_linalg_compiled" / "rocm_linalg_compiled". f32.
# ─────────────────────────────────────────────────────────────────────────────
_LINALG_OPS = ("tessera.cholesky", "tessera.tri_solve", "tessera.cholesky_solve",
               "tessera.lu", "tessera.qr", "tessera.svd")


def _x86_cholesky(A: Any, np: Any) -> Any:
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    n = int(a.shape[-1])
    batch = int(a.size // (n * n))
    out = np.zeros_like(a)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_cholesky_f32(a.ctypes.data_as(cf), ctypes.c_int64(batch),
                                 ctypes.c_int64(n), out.ctypes.data_as(cf))
    return out


def _x86_tri_solve_raw(A: Any, B: Any, lower: bool, np: Any) -> Any:
    """A[..,n,n] · X = B[..,n,m] (triangular part of A used). f32."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    b = np.ascontiguousarray(B, np.float32)
    n = int(a.shape[-1])
    m = int(b.shape[-1])
    batch = int(a.size // (n * n))
    out = np.zeros_like(b)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_tri_solve_f32(
        a.ctypes.data_as(cf), b.ctypes.data_as(cf), ctypes.c_int64(batch),
        ctypes.c_int64(n), ctypes.c_int64(m), ctypes.c_int(1 if lower else 0),
        out.ctypes.data_as(cf))
    return out


def _x86_lu(A: Any, np: Any) -> tuple:
    """getrf — A[..,n,n] → (packed LU[..,n,n], pivots[..,n] int32). f32."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    n = int(a.shape[-1])
    batch = int(a.size // (n * n))
    lu = np.zeros_like(a)
    piv = np.zeros(batch * n, np.int32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_lu_f32(a.ctypes.data_as(cf), ctypes.c_int64(batch),
                           ctypes.c_int64(n), lu.ctypes.data_as(cf),
                           piv.ctypes.data_as(ctypes.c_void_p))
    return lu, piv.reshape(a.shape[:-1])


def _x86_qr(A: Any, np: Any) -> tuple:
    """Householder QR — A[..,m,n] → reduced (Q[..,m,k], R[..,k,n]), k=min(m,n)."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    m, n = int(a.shape[-2]), int(a.shape[-1])
    k = min(m, n)
    batch = int(a.size // (m * n))
    q = np.zeros(batch * m * m, np.float32)
    r = np.zeros(batch * m * n, np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_qr_f32(a.ctypes.data_as(cf), ctypes.c_int64(batch),
                           ctypes.c_int64(m), ctypes.c_int64(n),
                           q.ctypes.data_as(cf), r.ctypes.data_as(cf))
    qf = q.reshape(a.shape[:-2] + (m, m))[..., :, :k]
    rf = r.reshape(a.shape[:-2] + (m, n))[..., :k, :]
    return np.ascontiguousarray(qf), np.ascontiguousarray(rf)


def _x86_svd_mn(A: Any, np: Any) -> tuple:
    """One-sided Jacobi SVD for the m≥n case — A[..,m,n] → (U[..,m,n], S[..,n],
    Vh[..,n,n]) on the AVX-512 kernel. f32."""
    lib = _load_x86_elementwise()
    if lib is None:
        raise _RocmCompiledUnavailable("libtessera_x86_elementwise.so not loadable")
    a = np.ascontiguousarray(A, np.float32)
    m, n = int(a.shape[-2]), int(a.shape[-1])
    batch = int(a.size // (m * n))
    u = np.zeros(batch * m * n, np.float32)
    s = np.zeros(batch * n, np.float32)
    vt = np.zeros(batch * n * n, np.float32)
    cf = ctypes.POINTER(ctypes.c_float)
    lib.tessera_x86_svd_f32(a.ctypes.data_as(cf), ctypes.c_int64(batch),
                            ctypes.c_int64(m), ctypes.c_int64(n),
                            u.ctypes.data_as(cf), s.ctypes.data_as(cf),
                            vt.ctypes.data_as(cf))
    return (u.reshape(a.shape[:-2] + (m, n)), s.reshape(a.shape[:-2] + (n,)),
            vt.reshape(a.shape[:-2] + (n, n)))


def _svd_via(A: Any, svd_mn_fn: Any, np: Any) -> tuple:
    """SVD with the m≥n device kernel ``svd_mn_fn(A)→(U[..,m,n], S[..,n],
    Vh[..,n,n])``. For the wide case (m<n) compute on Aᵀ and swap: A=Uᵀ... i.e.
    (U,S,Vh) of A = (Vh'ᵀ, S', U'ᵀ) of Aᵀ. Returns the reduced numpy convention."""
    a = np.ascontiguousarray(A, np.float32)
    m, n = int(a.shape[-2]), int(a.shape[-1])
    if m >= n:
        return svd_mn_fn(a)
    at = np.ascontiguousarray(np.swapaxes(a, -1, -2))
    u2, s2, vh2 = svd_mn_fn(at)            # Aᵀ = U2·diag(S2)·Vh2
    u = np.ascontiguousarray(np.swapaxes(vh2, -1, -2))
    vh = np.ascontiguousarray(np.swapaxes(u2, -1, -2))
    return u, s2, vh


def _linalg_compute(op_name: str, operands: list, chol_fn: Any, tri_fn: Any,
                    lu_fn: Any, qr_fn: Any, svd_fn: Any, np: Any) -> Any:
    """Dispatch a linalg op over the device kernels. ``tri_fn(A, B, lower)`` solves
    A·X=B; cholesky_solve = two triangular solves (L then Lᵀ). RHS may be a vector
    [..,n] (→ m=1, squeezed) or matrix [..,n,m]. lu→(packed, piv); qr→(Q, R);
    svd→(U, S, Vh) reduced."""
    if op_name == "tessera.cholesky":
        return chol_fn(np.asarray(operands[0], np.float32))
    if op_name == "tessera.lu":
        return lu_fn(np.asarray(operands[0], np.float32))
    if op_name == "tessera.qr":
        return qr_fn(np.asarray(operands[0], np.float32))
    if op_name == "tessera.svd":
        return _svd_via(np.asarray(operands[0], np.float32), svd_fn, np)

    A = np.asarray(operands[0], np.float32)
    b = np.asarray(operands[1], np.float32)
    vec = b.ndim == A.ndim - 1
    B = b[..., None] if vec else b

    if op_name == "tessera.tri_solve":
        kwargs = operands[2] if len(operands) > 2 else {}
        lower = bool(kwargs.get("lower", True)) if isinstance(kwargs, dict) else True
        x = tri_fn(A, B, lower)
    else:  # tessera.cholesky_solve — solve (L Lᵀ) x = b
        y = tri_fn(A, B, True)
        lt = np.ascontiguousarray(np.swapaxes(A, -1, -2))
        x = tri_fn(lt, y, False)
    return x[..., 0] if vec else x


def _execute_x86_compiled_linalg(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="x86"`` linalg lane: cholesky / tri_solve / cholesky_solve on
    the AVX-512 Cholesky + triangular-solve kernels. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _LINALG_OPS:
        raise ValueError(
            f"x86_linalg_compiled executor handles one of {_LINALG_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands: list = [values[str(n)] for n in op.get("operands", [])]
    if op_name == "tessera.tri_solve":
        operands = operands[:2] + [op.get("kwargs") or {}]
    return _linalg_compute(op_name, operands,
                           lambda a: _x86_cholesky(a, np),
                           lambda a, b, lo: _x86_tri_solve_raw(a, b, lo, np),
                           lambda a: _x86_lu(a, np),
                           lambda a: _x86_qr(a, np),
                           lambda a: _x86_svd_mn(a, np), np)


# ── Apple GPU linalg lane (2026-07-10) — Apple ships no MPS lu/qr/svd primitive,
#    so the decomposition ops resolve on the numpy reference the x86/ROCm device
#    kernels match (qr/svd/cholesky via np.linalg; a standalone partial-pivot LU;
#    triangular solves via the extracted triangle). Direct execute/compare, not a
#    bespoke fused Metal kernel — parity with x86/rocm_linalg_compiled.
def _apple_cholesky(A: Any, np: Any) -> Any:
    return np.linalg.cholesky(np.ascontiguousarray(A, np.float32)).astype(np.float32)


def _apple_tri_solve_raw(A: Any, B: Any, lower: bool, np: Any) -> Any:
    """Solve A·X=B using the triangular part of A (batched). f32."""
    a = np.ascontiguousarray(A, np.float32)
    tri = np.tril(a) if lower else np.triu(a)
    return np.linalg.solve(tri, np.ascontiguousarray(B, np.float32)).astype(np.float32)


def _apple_lu(A: Any, np: Any) -> tuple:
    """Batched partial-pivot LU — A[..,n,n] → (packed LU[..,n,n], piv[..,n] int32)
    with the row-permutation convention ``A[piv] = L·U`` (L unit-lower below the
    diagonal, U on/above). Standalone numpy (no scipy)."""
    a = np.array(A, np.float32)
    batch = a.shape[:-2]
    n = int(a.shape[-1])
    flat = a.reshape(-1, n, n).copy()
    piv = np.zeros((flat.shape[0], n), np.int32)
    for bi in range(flat.shape[0]):
        M = flat[bi]
        perm = np.arange(n)
        for col in range(n):
            p = col + int(np.argmax(np.abs(M[col:, col])))
            if p != col:
                M[[col, p]] = M[[p, col]]
                perm[[col, p]] = perm[[p, col]]
            d = M[col, col]
            if d != 0.0:
                M[col + 1:, col] /= d
                M[col + 1:, col + 1:] -= np.outer(M[col + 1:, col], M[col, col + 1:])
        piv[bi] = perm
    return flat.reshape(*batch, n, n).astype(np.float32), piv.reshape(*batch, n)


def _apple_qr(A: Any, np: Any) -> tuple:
    """Reduced QR — A[..,m,n] → (Q[..,m,k], R[..,k,n]), k=min(m,n)."""
    q, r = np.linalg.qr(np.ascontiguousarray(A, np.float32), mode="reduced")
    return (np.ascontiguousarray(q, np.float32), np.ascontiguousarray(r, np.float32))


def _apple_svd_mn(A: Any, np: Any) -> tuple:
    """Reduced SVD (m≥n) — A[..,m,n] → (U[..,m,n], S[..,n], Vh[..,n,n])."""
    u, s, vh = np.linalg.svd(np.ascontiguousarray(A, np.float32),
                             full_matrices=False)
    return (np.ascontiguousarray(u, np.float32), np.ascontiguousarray(s, np.float32),
            np.ascontiguousarray(vh, np.float32))


def _execute_apple_gpu_compiled_linalg(artifact: RuntimeArtifact,
                                       args: Any) -> Any:
    """The ``target="apple_gpu"`` linalg lane: cholesky / tri_solve /
    cholesky_solve / lu / qr / svd via the numpy reference (Apple has no MPS
    lu/qr/svd primitive). f32; matches np.linalg — parity with
    x86/rocm_linalg_compiled."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _LINALG_OPS:
        raise ValueError(
            f"apple_gpu_linalg_compiled executor handles one of {_LINALG_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands: list = [values[str(n)] for n in op.get("operands", [])]
    if op_name == "tessera.tri_solve":
        operands = operands[:2] + [op.get("kwargs") or {}]
    return _linalg_compute(op_name, operands,
                           lambda a: _apple_cholesky(a, np),
                           lambda a, b, lo: _apple_tri_solve_raw(a, b, lo, np),
                           lambda a: _apple_lu(a, np),
                           lambda a: _apple_qr(a, np),
                           lambda a: _apple_svd_mn(a, np), np)


# ── Apple GPU matmul-family lane (2026-07-10) — einsum (single-contraction) and
#    factorized_matmul via the numpy reference the x86/ROCm GEMM lanes match.
_APPLE_MATMUL_FAMILY_OPS = ("tessera.einsum", "tessera.factorized_matmul")


def _execute_apple_gpu_compiled_matmul_family(artifact: RuntimeArtifact,
                                              args: Any) -> Any:
    """The ``target="apple_gpu"`` matmul-family lane: einsum (single-contraction
    spec) and factorized_matmul (GEMM + rank-r SVD truncation) via the numpy
    reference. f32; matches numpy — parity with x86/rocm_matmul_family_compiled."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _APPLE_MATMUL_FAMILY_OPS:
        raise ValueError(
            f"apple_gpu_matmul_family_compiled executor handles one of "
            f"{_APPLE_MATMUL_FAMILY_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[str(n)]) for n in op.get("operands", [])]
    if op_name == "tessera.einsum":
        spec = kwargs.get("spec") or kwargs.get("equation")
        if spec is None or len(operands) != 2:
            raise ValueError(
                "apple einsum lane needs a 'spec' kwarg and exactly two tensors")
        return np.einsum(str(spec),
                         np.ascontiguousarray(operands[0], np.float32),
                         np.ascontiguousarray(operands[1], np.float32)).astype(
            np.float32)
    # tessera.factorized_matmul — (A·B) truncated to rank r via SVD (rank-2).
    if len(operands) != 2:
        raise ValueError("factorized_matmul takes two operands (A, B)")
    a = np.ascontiguousarray(operands[0], np.float32)
    b = np.ascontiguousarray(operands[1], np.float32)
    if a.ndim != 2 or b.ndim != 2:
        raise ValueError("apple factorized_matmul handles rank-2 A, B")
    rank = int(kwargs.get("rank", min(a.shape[0], b.shape[1])))
    out = (a @ b).astype(np.float32)
    u, s, vh = np.linalg.svd(out, full_matrices=False)
    r = max(1, min(rank, s.shape[-1]))
    return ((u[..., :r] * s[..., :r]) @ vh[..., :r, :]).astype(np.float32)


_X86_CLASS_LOSS_OPS = (
    "tessera.cross_entropy_loss", "tessera.kl_divergence",
    "tessera.js_divergence", "tessera.focal_loss",
    "tessera.label_smoothed_cross_entropy", "tessera.z_loss",
)


def _execute_x86_compiled_class_loss(artifact: RuntimeArtifact,
                                     args: Any) -> Any:
    """The ``target="x86"`` class-axis loss lane: cross_entropy / kl / js / focal
    / label_smoothed_cross_entropy / z_loss. exp/log on the AVX-512 kernel;
    class-axis structure (max/sum/gather/one-hot) on the host. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _X86_CLASS_LOSS_OPS:
        raise ValueError(
            f"x86_class_loss_compiled executor handles one of "
            f"{_X86_CLASS_LOSS_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]

    def _gather(logp: Any, targets: Any) -> Any:
        flat = logp.reshape(-1, logp.shape[-1])
        idx = targets.reshape(-1).astype(np.int64)
        return flat[np.arange(idx.size), idx].reshape(targets.shape)

    if op_name == "tessera.cross_entropy_loss":
        logits = operands[0].astype(np.float32)
        targets = operands[1]
        logp = _x86_log_softmax(logits, np)
        if targets.dtype.kind in "iu":
            loss = -_gather(logp, targets)
        else:
            loss = -np.sum(targets.astype(np.float32) * logp, axis=-1)
        return _x86_reduce_leading(loss, reduction, np)

    if op_name == "tessera.label_smoothed_cross_entropy":
        logits = operands[0].astype(np.float32)
        targets = operands[1].astype(np.int64)
        c = int(logits.shape[-1])
        smooth = float(kwargs.get("smoothing", 0.1))
        soft = np.full(targets.shape + (c,), smooth / max(1, c - 1),
                       dtype=np.float32)
        np.put_along_axis(soft, targets[..., None], 1.0 - smooth, axis=-1)
        logp = _x86_log_softmax(logits, np)
        loss = -np.sum(soft * logp, axis=-1)
        return _x86_reduce_leading(loss, reduction, np)

    if op_name == "tessera.focal_loss":
        logits = operands[0].astype(np.float32)
        targets = operands[1]
        gamma = float(kwargs.get("gamma", 2.0))
        alpha = kwargs.get("alpha")
        logp = _x86_log_softmax(logits, np)
        probs = _x86_unary_t(logp, 0, np)              # exp(log_softmax)
        pt = _gather(probs, targets)
        logpt = _x86_log_arr(np.maximum(pt, 1e-12).astype(np.float32), np)
        loss = -((1.0 - pt) ** gamma) * logpt
        if alpha is not None:
            loss = float(alpha) * loss
        return _x86_reduce_leading(loss, reduction, np)

    if op_name == "tessera.z_loss":
        z = operands[0].astype(np.float32)
        m = np.max(z, axis=-1, keepdims=True)
        e = _x86_unary_t((z - m).astype(np.float32), 0, np)
        s = e.sum(axis=-1, keepdims=True).astype(np.float32)
        lse = (m + _x86_log_arr(s, np)).squeeze(axis=-1)
        return _x86_reduce_leading(lse * lse, reduction, np)

    if op_name == "tessera.kl_divergence":
        p_log = operands[0].astype(np.float32)
        q = operands[1].astype(np.float32)
        p = _x86_unary_t(p_log, 0, np)                 # exp(p_log)
        logq = _x86_log_arr(np.maximum(q, 1e-12).astype(np.float32), np)
        loss = np.sum(p * (p_log - logq), axis=-1)
        return _x86_reduce_leading(loss, reduction, np)

    # tessera.js_divergence
    p = operands[0].astype(np.float32)
    q = operands[1].astype(np.float32)
    mid = (0.5 * (p + q)).astype(np.float32)
    logp = _x86_log_arr(np.maximum(p, 1e-12).astype(np.float32), np)
    logq = _x86_log_arr(np.maximum(q, 1e-12).astype(np.float32), np)
    logm = _x86_log_arr(np.maximum(mid, 1e-12).astype(np.float32), np)
    kl_pm = np.sum(p * (logp - logm), axis=-1)
    kl_qm = np.sum(q * (logq - logm), axis=-1)
    return _x86_reduce_leading(0.5 * (kl_pm + kl_qm), reduction, np)


# ─────────────────────────────────────────────────────────────────────────────
# EBM + diffusion losses (P7) — score_matching / denoising_score_matching /
# implicit_score_matching / contrastive_divergence / persistent_cd /
# ddpm_noise_pred / vlb / load_balance. All are pre-computed-tensor losses that
# COMPOSE on the device reduce + elementwise lanes (no new kernel): the
# FLOP-heavy diff/square and the reductions run on the AVX-512 / gfx1151 binary +
# reduce kernels (via _creal + _dev_reduce_*), with the cheap structure (argmax /
# one-hot / scalar scale, the noise draw is the caller's) on the host. f32.
# compiler_path="x86_ebm_loss_compiled" / "rocm_ebm_loss_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_EBM_LOSS_OPS = (
    "tessera.loss.score_matching", "tessera.loss.denoising_score_matching",
    "tessera.loss.implicit_score_matching", "tessera.loss.contrastive_divergence",
    "tessera.loss.persistent_cd", "tessera.loss.ddpm_noise_pred",
    "tessera.loss.vlb", "tessera.loss.load_balance_loss",
)


def _dev_reduce_axis(x: Any, kind: str, axis: int, target: str, np: Any) -> Any:
    """Sum/mean over one axis on the device reduce kernel."""
    op = "tessera.sum" if kind == "sum" else "tessera.mean"
    fn = _x86_reduce if target == "x86" else _rocm_reduce
    return np.asarray(fn(np.ascontiguousarray(x, np.float32), op, axis, False,
                         np), np.float32)


def _dev_reduce_all(loss: Any, reduction: str, target: str, np: Any) -> Any:
    """Apply none/mean/sum over ALL elements on the device reduce kernel."""
    if reduction == "none":
        return np.ascontiguousarray(loss, np.float32)
    flat = np.ascontiguousarray(loss, np.float32).reshape(-1)
    if target == "x86":
        return _x86_reduce_scalar(flat, 0 if reduction == "sum" else 2, np)
    r = _dev_reduce_axis(flat.reshape(1, -1), "sum" if reduction == "sum"
                         else "mean", 1, target, np)
    return np.float32(np.asarray(r).reshape(()))


def _ebm_loss_compute(op_name: str, operands: list, kwargs: dict, target: str,
                      np: Any) -> Any:
    red = str(kwargs.get("reduction", "mean"))
    if red not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {red}")
    ops = [np.ascontiguousarray(o, np.float32) for o in operands]

    def sub(a: Any, b: Any) -> Any:
        return _creal("sub", target, np, a, b)

    def mul(a: Any, b: Any) -> Any:
        return _creal("mul", target, np, a, b)

    if op_name == "tessera.loss.ddpm_noise_pred":          # mse(pred, true)
        d = sub(ops[0], ops[1])
        return _dev_reduce_all(mul(d, d), red, target, np)

    if op_name == "tessera.loss.score_matching":           # ½·mse(score, target)
        d = sub(ops[0], ops[1])
        out = _dev_reduce_all(mul(d, d), red, target, np)
        return (np.float32(0.5) * np.asarray(out, np.float32)).astype(np.float32)

    if op_name in ("tessera.loss.contrastive_divergence",
                   "tessera.loss.persistent_cd"):          # reduce(E⁺ − E⁻)
        return _dev_reduce_all(sub(ops[0], ops[1]), red, target, np)

    if op_name == "tessera.loss.vlb":                      # reduce(terms)
        return _dev_reduce_all(ops[0], red, target, np)

    if op_name == "tessera.loss.implicit_score_matching":
        # per-sample ½‖s‖² + div, then reduce.
        sq = mul(ops[0], ops[0])
        sumsq = _dev_reduce_axis(sq, "sum", -1, target, np)
        persample = (np.float32(0.5) * sumsq + ops[1]).astype(np.float32)
        return _dev_reduce_all(persample, red, target, np)

    if op_name == "tessera.loss.denoising_score_matching":
        # target = -(ỹ − y)/σ²; per-sample ½‖s − target‖² (sum over D); reduce.
        sigma = float(kwargs.get("sigma", 0.0))
        if sigma <= 0.0:
            raise ValueError(
                f"denoising_score_matching requires sigma > 0; got {sigma}")
        s, yc, yn = ops[0], ops[1], ops[2]
        tgt = (np.float32(-1.0) / np.float32(sigma * sigma)
               * np.asarray(sub(yn, yc), np.float32)).astype(np.float32)
        d = sub(s, tgt)
        persample = (np.float32(0.5)
                     * _dev_reduce_axis(mul(d, d), "sum", -1, target, np))
        return _dev_reduce_all(persample.astype(np.float32), red, target, np)

    if op_name == "tessera.loss.load_balance_loss":
        # Switch-Transformer aux: E·Σ_e f_e·P_e (f = routed fraction, P = mean
        # prob). argmax / one-hot on host; the token-axis means + Σ on device.
        p = ops[0]
        n_experts = int(p.shape[-1])
        assignment = kwargs.get("assignment")
        if assignment is not None:
            idx = np.asarray(assignment, np.int64)
        else:
            idx = np.argmax(p, axis=-1)
        one_hot = np.eye(n_experts, dtype=np.float32)[idx]
        f = _dev_reduce_axis(one_hot, "mean", -2, target, np)
        P = _dev_reduce_axis(p, "mean", -2, target, np)
        aux = (np.float32(n_experts)
               * _dev_reduce_axis(mul(f, P), "sum", -1, target, np))
        return _dev_reduce_all(aux.astype(np.float32), red, target, np)

    raise ValueError(f"ebm_loss executor: unknown op {op_name!r}")


def _execute_ebm_loss(artifact: RuntimeArtifact, args: Any, target: str,
                      path: str) -> Any:
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _EBM_LOSS_OPS:
        raise ValueError(
            f"{path} executor handles one of {_EBM_LOSS_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    operand_names = [str(n) for n in ops[0].get("operands", [])]
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    return _ebm_loss_compute(op_name, operands, ops[0].get("kwargs") or {},
                             target, np)


