# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED reduce lane (2026-06-25) — row reduction sum/mean/max/min over
# the last axis (the ROCm analog of the x86 AVX-512 reduction lane). An arbitrary
# reduced axis is folded to [outer, inner] by transposing the reduced axes to the
# end (matching _apple_gpu_dispatch_reduce). ``compiler_path =
# "rocm_reduce_compiled"``. f16/bf16/f32 storage, f32 reduce.
# ─────────────────────────────────────────────────────────────────────────────
_REDUCE_BLOCKDIM = 256  # must match BD in GenerateROCMReduceKernel.cpp
_rocm_reduce_hsaco_cache: dict[tuple[str, str], bytes] = {}

#: op_name -> reduce kind.
_ROCM_REDUCE_OPS = {
    "tessera.sum": "sum", "tessera.mean": "mean",
    "tessera.max": "max", "tessera.amax": "max",
    "tessera.min": "min", "tessera.amin": "min",
    "tessera.prod": "prod",
}


def _build_compiled_reduce_hsaco(kind: str, dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.reduce"() {{name = "rd", kind = "{kind}", '
        f'dtype = "{dtype}"}} : () -> ()\n}}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-reduce-kernel", directive, _rocm_reduce_hsaco_cache,
        (chip, kind, dtype))


def _execute_rocm_compiled_reduce(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` reduce lane: run the COMPILER-GENERATED row-reduction
    kernel for sum / mean / max / min. An arbitrary ``axis`` (default: reduce all)
    is folded to a [outer, inner] last-axis reduction by transposing the reduced
    axes to the end; ``keepdims`` supported. f16/bf16/f32 storage, f32 reduce."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_REDUCE_OPS:
        raise ValueError(
            "rocm_reduce_compiled executor handles exactly one of "
            f"{tuple(_ROCM_REDUCE_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _ROCM_REDUCE_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    keepdims = bool(kwargs.get("keepdims", False))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    n = x.ndim
    if n == 0:
        return np.array(x, copy=True)

    store: Any
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(f"rocm reduce lane handles f16/bf16/f32; got {x.dtype}")

    axis = kwargs.get("axis", None)
    if axis is None:
        axes = tuple(range(n))
    elif isinstance(axis, int):
        axes = (axis if axis >= 0 else n + axis,)
    else:
        axes = tuple(a if a >= 0 else n + a for a in axis)
    kept = [i for i in range(n) if i not in axes]
    perm = kept + list(axes)
    xt = np.ascontiguousarray(np.transpose(x, perm), dtype=store)
    inner = 1
    for a in axes:
        inner *= int(x.shape[a])
    outer = int(xt.size // inner) if inner else 0
    if inner <= 0:
        raise ValueError("rocm reduce: empty reduction axis")
    kept_shape = tuple(int(x.shape[i]) for i in kept)

    hsaco = _build_compiled_reduce_hsaco(kind, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm reduce: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm reduce: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"rd") != 0:
        raise RuntimeError("rocm reduce: kernel symbol 'rd' not found")

    xc = xt.reshape(-1)
    o = np.zeros(max(outer, 1), dtype=store)
    nin = outer * inner
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(dx), esz * nin) != 0:
        raise RuntimeError("rocm reduce: hipMalloc failed")
    if hip.hipMalloc(ctypes.byref(do), esz * max(outer, 1)) != 0:
        raise RuntimeError("rocm reduce: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * nin, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, nin) + _mr(do, max(outer, 1))
                   + [ctypes.c_int64(outer), ctypes.c_int64(inner)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, max(outer, 1), 1, 1, _REDUCE_BLOCKDIM,
                                   1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm reduce: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * max(outer, 1), 2)
    for dev in (dx, do):
        hip.hipFree(dev)

    res = o.reshape(kept_shape)
    if keepdims:
        full = [1 if i in axes else int(x.shape[i]) for i in range(n)]
        res = res.reshape(full)
    return res


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED arg-reduce lane (2026-06-27) — argmax/argmin (CUB ArgMax pattern)
# warp-shuffle reduction carrying the (value,index) pair; first-occurrence
# tie-break. ``compiler_path = "rocm_argreduce_compiled"``. f16/bf16/f32 input,
# i32 index output. ONE hsaco per (chip, kind, dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_argreduce_hsaco_cache: dict[tuple[str, str, str], bytes] = {}
_ROCM_ARGREDUCE_OPS = {"tessera.argmax": "argmax", "tessera.argmin": "argmin"}


def _build_compiled_argreduce_hsaco(kind: str, dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.argreduce"() {{name = "ar", kind = "{kind}", '
        f'dtype = "{dtype}"}} : () -> ()\n}}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-argreduce-kernel", directive, _rocm_argreduce_hsaco_cache,
        (chip, kind, dtype))


def _execute_rocm_compiled_argreduce(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` arg-reduce lane: run the COMPILER-GENERATED
    warp-shuffle argmax/argmin kernel along a single axis (numpy first-occurrence
    tie-break). f16/bf16/f32 input, i32 index output."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_ARGREDUCE_OPS:
        raise ValueError(
            "rocm_argreduce_compiled executor handles exactly one of "
            f"{tuple(_ROCM_ARGREDUCE_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _ROCM_ARGREDUCE_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("argreduce requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    n = x.ndim
    if n == 0:
        return np.array(0, dtype=np.int32)

    store: Any
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(
                f"rocm argreduce lane handles f16/bf16/f32; got {x.dtype}")

    axis = kwargs.get("axis", None)
    if axis is None:
        axes = tuple(range(n))           # flatten → global arg index
    elif isinstance(axis, int):
        axes = (axis if axis >= 0 else n + axis,)
    else:
        raise ValueError("argreduce supports a single int axis or None")
    kept = [i for i in range(n) if i not in axes]
    perm = kept + list(axes)
    xt = np.ascontiguousarray(np.transpose(x, perm), dtype=store)
    inner = 1
    for a in axes:
        inner *= int(x.shape[a])
    outer = int(xt.size // inner) if inner else 0
    if inner <= 0:
        raise ValueError("rocm argreduce: empty reduction axis")
    kept_shape = tuple(int(x.shape[i]) for i in kept)

    hsaco = _build_compiled_argreduce_hsaco(kind, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm argreduce: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm argreduce: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"ar") != 0:
        raise RuntimeError("rocm argreduce: kernel symbol 'ar' not found")

    xc = xt.reshape(-1)
    o = np.zeros(max(outer, 1), dtype=np.int32)
    nin = outer * inner
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(dx), esz * nin) != 0 or \
       hip.hipMalloc(ctypes.byref(do), 4 * max(outer, 1)) != 0:
        raise RuntimeError("rocm argreduce: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * nin, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, nin) + _mr(do, max(outer, 1))
                   + [ctypes.c_int64(outer), ctypes.c_int64(inner)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, max(outer, 1), 1, 1, _REDUCE_BLOCKDIM,
                                   1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm argreduce: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, 4 * max(outer, 1), 2)
    for dev in (dx, do):
        hip.hipFree(dev)
    return o.reshape(kept_shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED scan lane (2026-06-27) — cumsum/cumprod/cummax/cummin (CUB
# BlockScan technique). Inclusive prefix scan along one axis; output same shape.
# ``compiler_path = "rocm_scan_compiled"``. f16/bf16/f32. ONE hsaco per
# (chip, kind, dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_scan_hsaco_cache: dict[tuple[str, str, str], bytes] = {}
_ROCM_SCAN_OPS = {
    "tessera.cumsum": "cumsum", "tessera.cumprod": "cumprod",
    "tessera.cummax": "cummax", "tessera.cummin": "cummin",
}


def _build_compiled_scan_hsaco(kind: str, dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.scan"() {{name = "sc", kind = "{kind}", '
        f'dtype = "{dtype}"}} : () -> ()\n}}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-scan-kernel", directive, _rocm_scan_hsaco_cache,
        (chip, kind, dtype))


def _execute_rocm_compiled_scan(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` scan lane: run the COMPILER-GENERATED block-scan
    kernel (cumsum/cumprod/cummax/cummin) along one axis. Output same shape;
    axis=None flattens to 1-D (numpy semantics). f16/bf16/f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_SCAN_OPS:
        raise ValueError(
            "rocm_scan_compiled executor handles exactly one of "
            f"{tuple(_ROCM_SCAN_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _ROCM_SCAN_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("scan requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    n = x.ndim

    store: Any
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(f"rocm scan lane handles f16/bf16/f32; got {x.dtype}")

    axis = kwargs.get("axis", None)
    flatten = axis is None or n <= 1
    if flatten:
        flat = np.ascontiguousarray(x, dtype=store).reshape(1, -1)
        inner = int(flat.shape[1])
        outer = 1
        kept_then_axis: tuple[int, ...] = ()
        inv: list[int] = []
    else:
        assert axis is not None
        a = int(axis) if axis >= 0 else n + int(axis)
        perm = [i for i in range(n) if i != a] + [a]
        inv = [int(perm.index(i)) for i in range(n)]
        flat = np.ascontiguousarray(np.transpose(x, perm), dtype=store)
        inner = int(x.shape[a])
        outer = int(flat.size // inner)
        kept_then_axis = tuple(int(x.shape[i]) for i in perm)
    if inner <= 0:
        return np.array(x, copy=True)

    hsaco = _build_compiled_scan_hsaco(kind, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm scan: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm scan: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"sc") != 0:
        raise RuntimeError("rocm scan: kernel symbol 'sc' not found")

    xc = np.ascontiguousarray(flat, dtype=store).reshape(-1)
    o = np.zeros(outer * inner, dtype=store)
    nelem = outer * inner
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(dx), esz * nelem) != 0 or \
       hip.hipMalloc(ctypes.byref(do), esz * nelem) != 0:
        raise RuntimeError("rocm scan: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * nelem, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, nelem) + _mr(do, nelem)
                   + [ctypes.c_int64(outer), ctypes.c_int64(inner)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, max(outer, 1), 1, 1, _REDUCE_BLOCKDIM,
                                   1, 1, 0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm scan: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * nelem, 2)
    for dev in (dx, do):
        hip.hipFree(dev)
    if flatten:
        return o.reshape(-1)             # numpy flattens for axis=None
    return np.transpose(o.reshape(kept_then_axis), inv)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED elementwise activation lane (2026-06-25) — standalone gelu /
# silu / relu (the same activations the GEMM fused epilogue applies in-register).
# ``compiler_path = "rocm_activation_compiled"`` builds the COMPILER-GENERATED
# flat elementwise kernel (generate-rocm-activation-kernel → hsaco; no WMMA) and
# launches it via HIP. f32/f16/bf16, f32 compute. ONE hsaco per (chip, kind,
# dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_GRID_BLOCKDIM = 256  # matches BD in the elementwise/rope generators
_rocm_act_hsaco_cache: dict[tuple[str, str, str], bytes] = {}
_rocm_rope_hsaco_cache: dict[tuple[str, str], bytes] = {}

#: op_name → activation kind.
_ROCM_ACT_OPS: dict[str, str] = {
    "tessera.gelu": "gelu", "tessera.silu": "silu", "tessera.relu": "relu",
}


def _build_rocm_elementwise_hsaco(pass_name: str, directive: str,
                                  cache: dict, key: tuple) -> bytes:
    """Shared in-process build for the plain gpu→ROCDL elementwise/rope kernels
    (no WMMA, no lower-tessera-target-to-rocdl). Cached by `key`."""
    cached = cache.get(key)
    if cached is not None:
        return cached
    opt = _tessera_opt_path()
    if opt is None:
        raise _RocmCompiledUnavailable("tessera-opt not built — no compiled lane")
    chip = _rocm_chip()
    pipeline = (
        "builtin.module("
        f"{pass_name},"
        "gpu.module(convert-scf-to-cf,convert-gpu-to-rocdl,"
        "reconcile-unrealized-casts),"
        f"rocdl-attach-target{{chip={chip}}},"
        "gpu-module-to-binary)"
    )
    import subprocess
    r = subprocess.run([str(opt), "-", f"--pass-pipeline={pipeline}"],
                       input=directive, capture_output=True, text=True)
    if r.returncode != 0 or "gpu.binary" not in r.stdout:
        raise _RocmCompiledUnavailable(
            f"tessera-opt did not serialize {pass_name} in-process "
            f"(rc={r.returncode}): {r.stderr[:400]}")
    hsaco = _extract_hsaco_blob(r.stdout)
    if hsaco[:4] != b"\x7fELF":
        raise _RocmCompiledUnavailable(f"{pass_name}: gpu.binary not an ELF hsaco")
    cache[key] = hsaco
    return hsaco


def _build_compiled_activation_hsaco(kind: str, dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.activation"() {{name = "a", kind = "{kind}", '
        f'dtype = "{dtype}"}} : () -> ()\n}}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-activation-kernel", directive,
        _rocm_act_hsaco_cache, (chip, kind, dtype))


def _execute_rocm_compiled_activation(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="rocm"`` activation lane: run the COMPILER-GENERATED flat
    elementwise kernel for a standalone gelu / silu / relu over any-shape input
    (one thread per element). f32/f16/bf16 storage, f32 compute."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_ACT_OPS:
        raise ValueError(
            "rocm_activation_compiled executor handles exactly one of "
            f"{tuple(_ROCM_ACT_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind = _ROCM_ACT_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("activation requires one operand")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    n = int(np.prod(x.shape)) if x.ndim else 1
    if n <= 0:
        return np.array(x, copy=True)

    store: Any
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(
                f"rocm activation lane handles f32/f16/bf16; got {x.dtype}")

    hsaco = _build_compiled_activation_hsaco(kind, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm activation: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm activation: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"a") != 0:
        raise RuntimeError("rocm activation: kernel symbol 'a' not found")

    xc = np.ascontiguousarray(x, dtype=store).reshape(-1)
    o = np.zeros(n, dtype=store)
    dx, do = ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (dx, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm activation: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = _mr(dx, n) + _mr(do, n) + [ctypes.c_int64(n)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (dx, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm activation: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (dx, do):
        hip.hipFree(dev)
    return o.reshape(x.shape)


