# A flat elementwise kernel applying a pointwise logical op (and/or/xor/not) over
# any-shape i8 bool inputs, producing a bool result. ``compiler_path =
# "rocm_logical_compiled"``. Inputs normalized to bool via != 0 (numpy
# semantics). ``not`` is unary; and/or/xor binary. ONE hsaco per (chip, kind).
# ─────────────────────────────────────────────────────────────────────────────
_rocm_logical_hsaco_cache: dict[tuple[str, str], bytes] = {}

#: op_name → (logical kernel kind, operand count).
_ROCM_LOGICAL_OPS: dict[str, tuple[str, int]] = {
    "tessera.logical_and": ("and", 2), "tessera.logical_or": ("or", 2),
    "tessera.logical_xor": ("xor", 2), "tessera.logical_not": ("not", 1),
}


def _build_compiled_logical_hsaco(kind: str) -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.logical"() {{name = "l", kind = "{kind}"}} '
        ': () -> ()\n}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-logical-kernel", directive, _rocm_logical_hsaco_cache,
        (chip, kind))


def _execute_rocm_compiled_logical(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` logical lane: run the COMPILER-GENERATED flat
    elementwise logical kernel (and/or/xor/not) over any-shape inputs, producing
    a numpy ``bool_`` result. Inputs are normalized to bool (``!= 0``); ``not``
    is unary, the rest binary."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_LOGICAL_OPS:
        raise ValueError(
            "rocm_logical_compiled executor handles exactly one of "
            f"{tuple(_ROCM_LOGICAL_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind, nin = _ROCM_LOGICAL_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < nin:
        raise ValueError(f"logical {kind} requires {nin} operand(s)")
    values = _bind_launch_args(args, arg_names)
    a = _as_numpy(values[operand_names[0]])
    inputs = [a]
    if nin == 2:
        bb = _as_numpy(values[operand_names[1]])
        if a.shape != bb.shape:
            raise ValueError(
                f"rocm logical lane requires matching operand shapes; got "
                f"a{a.shape} b{bb.shape}")
        inputs.append(bb)
    n = int(np.prod(a.shape)) if a.ndim else 1
    if n <= 0:
        return np.zeros(a.shape, dtype=np.bool_)

    hsaco = _build_compiled_logical_hsaco(kind)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm logical: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm logical: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"l") != 0:
        raise RuntimeError("rocm logical: kernel symbol 'l' not found")

    # i8 bool storage (1 byte/element); normalize numpy inputs to 0/1 bytes.
    devs: list[Any] = []
    launch_args: list[Any] = []

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    for arr_in in inputs:
        host = (np.ascontiguousarray(arr_in).reshape(-1) != 0).astype(np.uint8)
        dev = ctypes.c_void_p()
        if hip.hipMalloc(ctypes.byref(dev), n) != 0:
            for d in devs:
                hip.hipFree(d)
            raise RuntimeError("rocm logical: hipMalloc failed")
        hip.hipMemcpy(dev, host.ctypes.data_as(ctypes.c_void_p), n, 1)
        devs.append(dev)
        launch_args += _mr(dev, n)

    o = np.zeros(n, dtype=np.uint8)
    do = ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(do), n) != 0:
        for d in devs:
            hip.hipFree(d)
        raise RuntimeError("rocm logical: hipMalloc failed")
    devs.append(do)
    launch_args += _mr(do, n) + [ctypes.c_int64(n)]

    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for d in devs:
            hip.hipFree(d)
        raise RuntimeError(f"rocm logical: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, n, 2)
    for d in devs:
        hip.hipFree(d)
    return o.reshape(a.shape).astype(np.bool_)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED bitwise lane (2026-06-26) — S2 bitwise family
# A flat elementwise kernel applying a pointwise bitwise op (and/or/xor/not) over
# any-shape i32 inputs, acting on the full integer bit pattern (no
# normalization). ``compiler_path = "rocm_bitwise_compiled"``. ``not`` is unary
# (~a = a ^ -1); and/or/xor binary. ONE hsaco per (chip, kind).
# ─────────────────────────────────────────────────────────────────────────────
_rocm_bitwise_hsaco_cache: dict[tuple[str, str], bytes] = {}

#: op_name → (bitwise kernel kind, operand count).
_ROCM_BITWISE_OPS: dict[str, tuple[str, int]] = {
    "tessera.bitwise_and": ("and", 2), "tessera.bitwise_or": ("or", 2),
    "tessera.bitwise_xor": ("xor", 2), "tessera.bitwise_not": ("not", 1),
    "tessera.popcount": ("popcount", 1),  # math.ctpop (RDNA v_bcnt); unary
}


def _build_compiled_bitwise_hsaco(kind: str) -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.bitwise"() {{name = "w", kind = "{kind}"}} '
        ': () -> ()\n}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-bitwise-kernel", directive, _rocm_bitwise_hsaco_cache,
        (chip, kind))


def _execute_rocm_compiled_bitwise(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` bitwise lane: run the COMPILER-GENERATED flat
    elementwise bitwise kernel (and/or/xor/not) over any-shape i32 inputs, acting
    on the full integer bit pattern. ``not`` is unary, the rest binary."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_BITWISE_OPS:
        raise ValueError(
            "rocm_bitwise_compiled executor handles exactly one of "
            f"{tuple(_ROCM_BITWISE_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    kind, nin = _ROCM_BITWISE_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < nin:
        raise ValueError(f"bitwise {kind} requires {nin} operand(s)")
    values = _bind_launch_args(args, arg_names)
    a = _as_numpy(values[operand_names[0]])
    inputs = [a]
    if nin == 2:
        bb = _as_numpy(values[operand_names[1]])
        if a.shape != bb.shape:
            raise ValueError(
                f"rocm bitwise lane requires matching operand shapes; got "
                f"a{a.shape} b{bb.shape}")
        inputs.append(bb)
    n = int(np.prod(a.shape)) if a.ndim else 1
    if n <= 0:
        return np.zeros(a.shape, dtype=np.int32)

    hsaco = _build_compiled_bitwise_hsaco(kind)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm bitwise: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm bitwise: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"w") != 0:
        raise RuntimeError("rocm bitwise: kernel symbol 'w' not found")

    devs: list[Any] = []
    launch_args: list[Any] = []

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    for arr_in in inputs:
        host = np.ascontiguousarray(arr_in, dtype=np.int32).reshape(-1)
        dev = ctypes.c_void_p()
        if hip.hipMalloc(ctypes.byref(dev), 4 * n) != 0:
            for d in devs:
                hip.hipFree(d)
            raise RuntimeError("rocm bitwise: hipMalloc failed")
        hip.hipMemcpy(dev, host.ctypes.data_as(ctypes.c_void_p), 4 * n, 1)
        devs.append(dev)
        launch_args += _mr(dev, n)

    o = np.zeros(n, dtype=np.int32)
    do = ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(do), 4 * n) != 0:
        for d in devs:
            hip.hipFree(d)
        raise RuntimeError("rocm bitwise: hipMalloc failed")
    devs.append(do)
    launch_args += _mr(do, n) + [ctypes.c_int64(n)]

    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for d in devs:
            hip.hipFree(d)
        raise RuntimeError(f"rocm bitwise: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, 4 * n, 2)
    for d in devs:
        hip.hipFree(d)
    return o.reshape(a.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED silu_mul lane (2026-06-25) — SwiGLU gate-multiply
# silu_mul(a, b) = silu(a)·b, a flat 2-operand elementwise kernel (sibling of the
# activation lane). ``compiler_path = "rocm_silu_mul_compiled"``. f32/f16/bf16,
# f32 compute. ONE hsaco per (chip, dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_silu_mul_hsaco_cache: dict[tuple[str, str], bytes] = {}


def _build_compiled_silu_mul_hsaco(dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.silu_mul"() {{name = "sm", dtype = "{dtype}"}} '
        ': () -> ()\n}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-silu-mul-kernel", directive,
        _rocm_silu_mul_hsaco_cache, (chip, dtype))


def _execute_rocm_compiled_silu_mul(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` silu_mul lane: run the COMPILER-GENERATED flat
    2-operand elementwise SwiGLU gate-multiply silu(a)·b over any-shape inputs
    (one thread per element). f32/f16/bf16 storage, f32 compute."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name != "tessera.silu_mul":
        raise ValueError(
            "rocm_silu_mul_compiled executor handles exactly one "
            f"tessera.silu_mul op; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("silu_mul requires two operands (a, b)")
    values = _bind_launch_args(args, arg_names)
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    if a.shape != b.shape:
        raise ValueError(
            f"silu_mul requires matching operand shapes; got a{a.shape} "
            f"b{b.shape}")
    n = int(np.prod(a.shape)) if a.ndim else 1
    if n <= 0:
        return np.array(a, copy=True)

    store: Any
    if a.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif a.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and a.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(
                f"rocm silu_mul lane handles f32/f16/bf16; got {a.dtype}")

    hsaco = _build_compiled_silu_mul_hsaco(dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm silu_mul: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm silu_mul: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"sm") != 0:
        raise RuntimeError("rocm silu_mul: kernel symbol 'sm' not found")

    ac = np.ascontiguousarray(a, dtype=store).reshape(-1)
    bc = np.ascontiguousarray(b, dtype=store).reshape(-1)
    o = np.zeros(n, dtype=store)
    da, db, do = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (da, db, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm silu_mul: hipMalloc failed")
    hip.hipMemcpy(da, ac.ctypes.data_as(ctypes.c_void_p), esz * n, 1)
    hip.hipMemcpy(db, bc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = _mr(da, n) + _mr(db, n) + _mr(do, n) + [ctypes.c_int64(n)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (da, db, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm silu_mul: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (da, db, do):
        hip.hipFree(dev)
    return o.reshape(a.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED pointwise-loss lane — mse / mae / huber / smooth_l1 / log_cosh.
# The per-element loss runs on the COMPILER-GENERATED gpu kernel
# (generate-rocm-pointwise-loss-kernel); the reduction (none/mean/sum) is a host
# epilogue on the GPU-computed array. The CPU analog is the x86_loss lane.
# ``compiler_path = "rocm_loss_compiled"``. ONE hsaco per (chip, dtype, kind).
# ─────────────────────────────────────────────────────────────────────────────
#: op_name -> (loss kind, param-kwarg name or None). Matches the x86 lane and
#: GenerateROCMPointwiseLossKernel.cpp.
_ROCM_POINTWISE_LOSS_OPS = {
    "tessera.mse_loss": (0, None),
    "tessera.mae_loss": (1, None),
    "tessera.huber_loss": (2, "delta"),
    "tessera.smooth_l1_loss": (3, "beta"),
    "tessera.log_cosh_loss": (4, None),
}
_rocm_pointwise_loss_hsaco_cache: dict[tuple[str, str, int], bytes] = {}


def _build_compiled_pointwise_loss_hsaco(kind: int, param: float,
                                         dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.pointwise_loss"() {{name = "pl", dtype = "{dtype}", '
        f'kind = {int(kind)} : i64, param = {float(param):e} : f32}} '
        ': () -> ()\n}\n')
    # param only affects huber/smooth_l1; bake it into the cache key for those.
    key = (chip, dtype, int(kind)) if kind not in (2, 3) else \
        (chip, f"{dtype}:{float(param):e}", int(kind))
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-pointwise-loss-kernel", directive,
        _rocm_pointwise_loss_hsaco_cache, key)


def _execute_rocm_compiled_pointwise_loss(artifact: RuntimeArtifact,
                                          args: Any) -> Any:
    """The ``target="rocm"`` pointwise-loss lane: run the COMPILER-GENERATED
    per-element regression loss (mse/mae/huber/smooth_l1/log_cosh) over
    (pred, target) on gfx1151, then apply the none/mean/sum reduction. f32/f16/
    bf16 storage, f32 compute."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_POINTWISE_LOSS_OPS:
        raise ValueError(
            "rocm_loss_compiled executor handles exactly one of "
            f"{tuple(_ROCM_POINTWISE_LOSS_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    kind, param_kw = _ROCM_POINTWISE_LOSS_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("loss requires two operands (pred, target)")
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    param = float(kwargs.get(param_kw, 1.0)) if param_kw else 1.0
    values = _bind_launch_args(args, arg_names)
    a = _as_numpy(values[operand_names[0]])
    b = _as_numpy(values[operand_names[1]])
    try:
        bshape = np.broadcast_shapes(a.shape, b.shape)
    except ValueError as exc:
        raise ValueError(
            f"loss pred{a.shape} and target{b.shape} do not broadcast") from exc
    a = np.broadcast_to(a, bshape)
    b = np.broadcast_to(b, bshape)
    n = int(np.prod(bshape)) if bshape else 1
    if n <= 0:
        return np.array(a, copy=True)

    store: Any
    if a.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif a.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and a.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(f"rocm loss lane handles f32/f16/bf16; got {a.dtype}")

    hsaco = _build_compiled_pointwise_loss_hsaco(kind, param, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm loss: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm loss: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"pl") != 0:
        raise RuntimeError("rocm loss: kernel symbol 'pl' not found")

    ac = np.ascontiguousarray(a, dtype=store).reshape(-1)
    bc = np.ascontiguousarray(b, dtype=store).reshape(-1)
    o = np.zeros(n, dtype=store)
    da, db, do = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (da, db, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm loss: hipMalloc failed")
    hip.hipMemcpy(da, ac.ctypes.data_as(ctypes.c_void_p), esz * n, 1)
    hip.hipMemcpy(db, bc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = _mr(da, n) + _mr(db, n) + _mr(do, n) + [ctypes.c_int64(n)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (da, db, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm loss: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (da, db, do):
        hip.hipFree(dev)
    per = o.reshape(bshape).astype(np.float32)
    if reduction == "none":
        return per
    return np.float32(per.sum() if reduction == "sum" else per.mean())


def _rocm_launch_nary_elementwise(hsaco: bytes, sym: bytes,
                                  inputs_flat: list, n: int, store: Any,
                                  esz: int, tag: str, np: Any) -> Any:
    """Malloc/copy/launch/copy-back/free for a flat n-element gpu kernel taking
    K input memrefs + 1 output memref + N. Returns the output as a flat
    ``store``-dtype array. Shared by the ROCm loss lanes."""
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable(f"rocm {tag}: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable(f"rocm {tag}: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, sym) != 0:
        raise RuntimeError(f"rocm {tag}: kernel symbol not found")
    devs = []
    for arr in inputs_flat:
        d = ctypes.c_void_p()
        if hip.hipMalloc(ctypes.byref(d), esz * n) != 0:
            raise RuntimeError(f"rocm {tag}: hipMalloc failed")
        hip.hipMemcpy(d, arr.ctypes.data_as(ctypes.c_void_p), esz * n, 1)
        devs.append(d)
    do = ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(do), esz * n) != 0:
        raise RuntimeError(f"rocm {tag}: hipMalloc failed")

    def _mr(p):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(n), ctypes.c_int64(1)]

    launch_args = []
    for d in devs:
        launch_args += _mr(d)
    launch_args += _mr(do) + [ctypes.c_int64(n)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    o = np.zeros(n, dtype=store)
    if rc != 0:
        for d in devs + [do]:
            hip.hipFree(d)
        raise RuntimeError(f"rocm {tag}: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for d in devs + [do]:
        hip.hipFree(d)
    return o


def _rocm_loss_store(a: Any, np: Any) -> tuple:
    if a.dtype == np.float32:
        return "f32", np.float32, 4
    if a.dtype == np.float16:
        return "f16", np.float16, 2
    bf16 = _bfloat16_dtype()
    if bf16 is not None and a.dtype == bf16:
        return "bf16", bf16, 2
    raise ValueError(f"rocm loss lane handles f32/f16/bf16; got {a.dtype}")


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED binary-loss lane — bce / asymmetric_bce (ROCm mirror of the x86
# binary-loss lane). ``compiler_path = "rocm_binary_loss_compiled"``.
# ─────────────────────────────────────────────────────────────────────────────
_ROCM_BINARY_LOSS_OPS = {
    "tessera.binary_cross_entropy_loss": (0, None),
    "tessera.asymmetric_bce": (1, ("pos_weight", "neg_weight")),
}
_rocm_binary_loss_hsaco_cache: dict[tuple, bytes] = {}


def _build_compiled_binary_loss_hsaco(kind: int, pw: float, nw: float,
                                      dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.binary_loss"() {{name = "bl", dtype = "{dtype}", '
        f'kind = {int(kind)} : i64, pos_weight = {float(pw):e} : f32, '
        f'neg_weight = {float(nw):e} : f32}} : () -> ()\n}}\n')
    key = (chip, dtype, int(kind), float(pw), float(nw))
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-binary-loss-kernel", directive,
        _rocm_binary_loss_hsaco_cache, key)


def _execute_rocm_compiled_binary_loss(artifact: RuntimeArtifact,
                                       args: Any) -> Any:
    """The ``target="rocm"`` binary-loss lane: bce / asymmetric_bce over
    (logits, targets) on gfx1151 + reduction. f32/f16/bf16."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_BINARY_LOSS_OPS:
        raise ValueError(
            "rocm_binary_loss_compiled executor handles exactly one of "
            f"{tuple(_ROCM_BINARY_LOSS_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    kind, weight_kws = _ROCM_BINARY_LOSS_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("binary loss requires two operands (logits, targets)")
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    pw = float(kwargs.get(weight_kws[0], 1.0)) if weight_kws else 1.0
    nw = float(kwargs.get(weight_kws[1], 1.0)) if weight_kws else 1.0
    values = _bind_launch_args(args, arg_names)
    z = _as_numpy(values[operand_names[0]])
    t = _as_numpy(values[operand_names[1]])
    try:
        bshape = np.broadcast_shapes(z.shape, t.shape)
    except ValueError as exc:
        raise ValueError(
            f"binary loss logits{z.shape} targets{t.shape} do not "
            f"broadcast") from exc
    z = np.broadcast_to(z, bshape)
    t = np.broadcast_to(t, bshape)
    n = int(np.prod(bshape)) if bshape else 1
    if n <= 0:
        return np.array(z, copy=True)
    dtype_tag, store, esz = _rocm_loss_store(z, np)
    hsaco = _build_compiled_binary_loss_hsaco(kind, pw, nw, dtype_tag)
    zc = np.ascontiguousarray(z, dtype=store).reshape(-1)
    tc = np.ascontiguousarray(t, dtype=store).reshape(-1)
    o = _rocm_launch_nary_elementwise(hsaco, b"bl", [zc, tc], n, store, esz,
                                      "binary_loss", np)
    per = o.reshape(bshape).astype(np.float32)
    if reduction == "none":
        return per
    return np.float32(per.sum() if reduction == "sum" else per.mean())


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED rl policy-loss lane — ppo / cispo / grpo + normalize_group_
# advantages (ROCm mirror of the x86 rl-loss lane). The surrogate runs on the
# policy-loss kernel; normalize runs on the rocm norm (layer_norm) lane over the
# group axis. KL/entropy/mask add-ons diagnose out. ``compiler_path =
# "rocm_rl_loss_compiled"``.
# ─────────────────────────────────────────────────────────────────────────────
_ROCM_POLICY_OPS = {
    "tessera.ppo_policy_loss": (0, "clip_epsilon", 0.2),
    "tessera.grpo_policy_loss": (0, "clip_epsilon", 0.2),
    "tessera.cispo_policy_loss": (1, "epsilon_high", 5.0),
}
_rocm_policy_loss_hsaco_cache: dict[tuple, bytes] = {}


def _build_compiled_policy_loss_hsaco(kind: int, clip: float,
                                      dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.policy_loss"() {{name = "pol", dtype = "{dtype}", '
        f'kind = {int(kind)} : i64, clip = {float(clip):e} : f32}} '
        ': () -> ()\n}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-policy-loss-kernel", directive,
        _rocm_policy_loss_hsaco_cache, (chip, dtype, int(kind), float(clip)))


def _rocm_group_normalize(r: Any, group_axis: int, eps: float, np: Any) -> Any:
    """(r − mean)/sqrt(var + eps) over ``group_axis`` via the ROCm layer_norm
    lane (transpose-to-last → norm kernel → transpose-back)."""
    r = np.ascontiguousarray(r, np.float32)
    nd = r.ndim
    ax = int(group_axis) if group_axis >= 0 else nd + int(group_axis)
    if ax < 0 or ax >= nd:
        raise ValueError("normalize_group_advantages: group_axis out of range")
    perm = [i for i in range(nd) if i != ax] + [ax]
    rt = np.ascontiguousarray(np.transpose(r, perm))
    art = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_norm_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": "tessera.layer_norm", "result": "o",
                 "operands": ["x"], "kwargs": {"eps": float(eps)}}]})
    out = np.asarray(_execute_rocm_compiled_norm(art, (rt,)), np.float32)
    inv = [perm.index(i) for i in range(nd)]
    return np.ascontiguousarray(np.transpose(out, inv))


def _execute_rocm_compiled_rl_loss(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` RL policy-loss lane: ppo / cispo / grpo core
    surrogate (policy-loss kernel) + normalize_group_advantages (norm lane).
    KL/entropy/mask add-ons get a stable diagnostic. f32/f16/bf16."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    handled = ("tessera.ppo_policy_loss", "tessera.cispo_policy_loss",
               "tessera.grpo_policy_loss", "tessera.normalize_group_advantages")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"rocm_rl_loss_compiled executor handles one of {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]

    if op_name == "tessera.normalize_group_advantages":
        if len(operands) != 1:
            raise ValueError(
                "rocm normalize_group_advantages lane takes one operand "
                "(rewards); masked normalization is not in the fused lane")
        return _rocm_group_normalize(
            operands[0], int(kwargs.get("group_axis", 1)),
            float(kwargs.get("eps", 1e-8)), np)

    if float(kwargs.get("kl_coef", 0.0)) or float(kwargs.get("entropy_coef", 0.0)):
        raise ValueError(
            f"rocm rl-loss lane handles the core {op_name} surrogate only; the "
            "KL-penalty / entropy-bonus terms are unsupported")
    if len(operands) < 3:
        raise ValueError(f"{op_name} needs (logp_new, logp_old, advantages)")
    kind, clip_kw, clip_default = _ROCM_POLICY_OPS[op_name]
    clip = float(kwargs.get(clip_kw, clip_default))
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"rl-loss reduction must be none/mean/sum; got {reduction}")
    ln = operands[0]
    lo = operands[1]
    adv = operands[2]
    if not (ln.shape == lo.shape == adv.shape):
        raise ValueError(
            f"rl-loss requires matching shapes; got logp_new{ln.shape} "
            f"logp_old{lo.shape} advantages{adv.shape}")
    n = int(np.prod(ln.shape)) if ln.ndim else 1
    if n <= 0:
        return np.array(ln, copy=True)
    dtype_tag, store, esz = _rocm_loss_store(ln, np)
    hsaco = _build_compiled_policy_loss_hsaco(kind, clip, dtype_tag)
    flats = [np.ascontiguousarray(x, dtype=store).reshape(-1)
             for x in (ln, lo, adv)]
    o = _rocm_launch_nary_elementwise(hsaco, b"pol", flats, n, store, esz,
                                      "policy_loss", np)
    per = o.reshape(ln.shape).astype(np.float32)
    if reduction == "none":
        return per
    return np.float32(per.sum() if reduction == "sum" else per.mean())


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED fpquant lane — quantize/dequantize fp8 / fp6 / fp4 + nvfp4 (ROCm
# mirror of the x86 fpquant/nvfp4 lanes). Grid-snap on the COMPILER-GENERATED
# fpquant kernel; per-tensor / per-block scale is host structure.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_fpquant_hsaco_cache: dict[tuple, bytes] = {}
_FP_NO_CLAMP_ROCM = -126
_ROCM_FPQUANT_OPS = {
    "tessera.quantize_fp8": (True, {"e4m3": (448.0, 3, -6),
                                    "e5m2": (57344.0, 2, -14)}, "e4m3"),
    "tessera.dequantize_fp8": (False, {"e4m3": (448.0, 3, -6),
                                       "e5m2": (57344.0, 2, -14)}, "e4m3"),
    "tessera.quantize_fp6": (True, {"e2m3": (7.5, 3, _FP_NO_CLAMP_ROCM),
                                    "e3m2": (28.0, 2, _FP_NO_CLAMP_ROCM)}, "e3m2"),
    "tessera.dequantize_fp6": (False, {"e2m3": (7.5, 3, _FP_NO_CLAMP_ROCM),
                                       "e3m2": (28.0, 2, _FP_NO_CLAMP_ROCM)},
                               "e3m2"),
    "tessera.quantize_fp4": (True, {"e2m1": (6.0, 1, _FP_NO_CLAMP_ROCM)}, "e2m1"),
    "tessera.dequantize_fp4": (False, {"e2m1": (6.0, 1, _FP_NO_CLAMP_ROCM)},
                               "e2m1"),
}


def _rocm_fpgrid(x: Any, max_normal: float, mantissa_bits: int, min_exp: int,
                 np: Any) -> Any:
    """Snap an array to a low-precision float grid on the ROCm fpquant kernel
    (no scaling — caller pre-scales). Shape-preserving, f32."""
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.fpquant"() {{name = "fq", dtype = "f32", '
        f'max_normal = {float(max_normal):e} : f32, '
        f'mantissa_bits = {int(mantissa_bits)} : i64, '
        f'min_exp = {int(min_exp)} : i64}} : () -> ()\n}}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-fpquant-kernel", directive, _rocm_fpquant_hsaco_cache,
        (chip, float(max_normal), int(mantissa_bits), int(min_exp)))
    flat = np.ascontiguousarray(x, np.float32).reshape(-1)
    n = int(flat.size)
    if n <= 0:
        return np.array(x, copy=True)
    o = _rocm_launch_nary_elementwise(hsaco, b"fq", [flat], n, np.float32, 4,
                                      "fpquant", np)
    return o.reshape(np.shape(x))


def _execute_rocm_compiled_fpquant(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` low-precision-float quantize lane: quantize/
    dequantize fp8 / fp6 / fp4 on gfx1151. quantize snaps to the format grid on
    the fpquant kernel (per-tensor symmetric scale); dequantize is the fp32
    passthrough."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_FPQUANT_OPS:
        raise ValueError(
            "rocm_fpquant_compiled executor handles exactly one of "
            f"{tuple(_ROCM_FPQUANT_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    is_quant, fmt_map, default_fmt = _ROCM_FPQUANT_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("quantize op requires one operand")
    kwargs = op.get("kwargs") or {}
    fmt = str(kwargs.get("format", default_fmt))
    if fmt not in fmt_map:
        raise ValueError(
            f"{op_name}: format must be one of {tuple(fmt_map)}; got {fmt!r}")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"rocm fpquant lane handles f32 only; got {x.dtype}")
    if not is_quant:
        return np.ascontiguousarray(x, np.float32)
    max_normal, mantissa_bits, min_exp = fmt_map[fmt]
    scale_kw = kwargs.get("scale")
    if scale_kw is None:
        amax = float(np.max(np.abs(x))) if x.size else 0.0
        scale = max(amax / max_normal, 1e-12)
    else:
        scale = float(scale_kw)
    scaled = np.clip(np.ascontiguousarray(x, np.float32) / np.float32(scale),
                     -max_normal, max_normal).astype(np.float32)
    out = _rocm_fpgrid(scaled, max_normal, mantissa_bits, min_exp, np)
    return (out * np.float32(scale)).astype(np.float32)


def _execute_rocm_compiled_intquant(artifact: RuntimeArtifact, args: Any) -> Any:
    def round_exec(x: Any) -> Any:
        import numpy as np
        return _rocm_unary_t(x, "round", np)

    return _execute_intquant_composite(
        artifact, args, "rocm", round_exec, _rocm_binary_exec)


_POOLING_OPS = (
    "tessera.max_pool", "tessera.avg_pool", "tessera.min_pool",
    "tessera.adaptive_pool",
)


def _pool_pair(v: Any) -> tuple[int, int]:
    if isinstance(v, (tuple, list)):
        return int(v[0]), int(v[1])
    return int(v), int(v)


def _pool2d_compiled(
    x: Any,
    kernel_size: Any,
    stride: Any,
    padding: Any,
    reduce_op: str,
    reduce_exec: Any,
    np: Any,
) -> Any:
    x_arr = np.ascontiguousarray(_as_numpy(x), dtype=np.float32)
    if x_arr.ndim != 4:
        raise ValueError(f"pool expects NCHW rank-4 input; got {x_arr.shape}")
    kh, kw = _pool_pair(kernel_size)
    sh, sw = _pool_pair(stride if stride is not None else kernel_size)
    ph, pw = _pool_pair(padding)
    pad_value = -np.inf if reduce_op == "tessera.max" else (
        np.inf if reduce_op == "tessera.min" else 0.0)
    padded = np.pad(
        x_arr, ((0, 0), (0, 0), (ph, ph), (pw, pw)),
        constant_values=pad_value)
    out_h = (x_arr.shape[2] + 2 * ph - kh) // sh + 1
    out_w = (x_arr.shape[3] + 2 * pw - kw) // sw + 1
    if out_h <= 0 or out_w <= 0:
        raise ValueError("pool output spatial dimensions must be positive")
    rows = []
    for i in range(out_h):
        for j in range(out_w):
            window = padded[:, :, i * sh:i * sh + kh, j * sw:j * sw + kw]
            rows.append(window.reshape(x_arr.shape[0], x_arr.shape[1], kh * kw))
    mat = np.stack(rows, axis=2).reshape(-1, kh * kw)
    red = np.asarray(reduce_exec(mat, reduce_op, axis=1, keepdims=False), np.float32)
    return red.reshape(x_arr.shape[0], x_arr.shape[1], out_h, out_w)


def _adaptive_pool2d_compiled(
    x: Any,
    output_size: Any,
    reduce_op: str,
    reduce_exec: Any,
    np: Any,
) -> Any:
    x_arr = np.ascontiguousarray(_as_numpy(x), dtype=np.float32)
    if x_arr.ndim != 4:
        raise ValueError(f"adaptive_pool expects NCHW rank-4 input; got {x_arr.shape}")
    out_h, out_w = _pool_pair(output_size)
    out = np.zeros((x_arr.shape[0], x_arr.shape[1], out_h, out_w), dtype=np.float32)
    for i in range(out_h):
        h0 = int(np.floor(i * x_arr.shape[2] / out_h))
        h1 = int(np.ceil((i + 1) * x_arr.shape[2] / out_h))
        for j in range(out_w):
            w0 = int(np.floor(j * x_arr.shape[3] / out_w))
            w1 = int(np.ceil((j + 1) * x_arr.shape[3] / out_w))
            window = x_arr[:, :, h0:h1, w0:w1]
            mat = window.reshape(x_arr.shape[0], x_arr.shape[1], -1).reshape(-1, window.shape[2] * window.shape[3])
            red = np.asarray(reduce_exec(mat, reduce_op, axis=1, keepdims=False), np.float32)
            out[:, :, i, j] = red.reshape(x_arr.shape[0], x_arr.shape[1])
    return out


def _execute_pooling_composite(
    artifact: RuntimeArtifact,
    args: Any,
    target: str,
    reduce_exec: Any,
) -> Any:
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _POOLING_OPS:
        raise ValueError(
            f"{target}_pooling_compiled executor handles one of {_POOLING_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("pooling op requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = values[operand_names[0]]
    if op_name == "tessera.max_pool":
        red = "tessera.max"
    elif op_name == "tessera.min_pool":
        red = "tessera.min"
    else:
        red = "tessera.mean"
    if op_name == "tessera.adaptive_pool":
        reducer = kwargs.get("reducer", "mean")
        if reducer in ("max", "amax"):
            red = "tessera.max"
        elif reducer in ("min", "amin"):
            red = "tessera.min"
        elif reducer not in ("mean", "avg", None):
            raise ValueError("compiled adaptive_pool supports reducer mean/max/min")
        return _adaptive_pool2d_compiled(
            x, kwargs["output_size"], red, reduce_exec, np)
    return _pool2d_compiled(
        x,
        kwargs["kernel_size"],
        kwargs.get("stride"),
        kwargs.get("padding", 0),
        red,
        reduce_exec,
        np,
    )


def _execute_x86_compiled_pooling(artifact: RuntimeArtifact, args: Any) -> Any:
    import numpy as np
    def reduce_exec(x: Any, op_name: str, axis: Any, keepdims: bool) -> Any:
        return _x86_reduce(x, op_name, axis, keepdims, np)
    return _execute_pooling_composite(artifact, args, "x86", reduce_exec)


def _execute_rocm_compiled_pooling(artifact: RuntimeArtifact, args: Any) -> Any:
    import numpy as np
    def reduce_exec(x: Any, op_name: str, axis: Any, keepdims: bool) -> Any:
        return _rocm_reduce(x, op_name, axis, keepdims, np)
    return _execute_pooling_composite(artifact, args, "rocm", reduce_exec)


_IMAGE_AFFINE_OPS = ("tessera.image_normalize",)


def _execute_image_affine_composite(
    artifact: RuntimeArtifact,
    args: Any,
    target: str,
    binary_exec: Any,
) -> Any:
    import numpy as np
    from . import _image_ops as _imgops

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _IMAGE_AFFINE_OPS:
        raise ValueError(
            f"{target}_image_affine_compiled executor handles image_normalize; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    operand_names = [str(n) for n in op.get("operands", [])]
    values = _bind_launch_args(args, arg_names)
    x = np.ascontiguousarray(_as_numpy(values[operand_names[0]]), dtype=np.float32)
    nchw, restore = _imgops.img_canon(x, str(kwargs.get("layout", "nchw")))
    c = int(nchw.shape[1])
    mean_a = np.asarray(kwargs["mean"], dtype=np.float32).reshape(-1)
    std_a = np.asarray(kwargs["std"], dtype=np.float32).reshape(-1)
    if mean_a.size not in (1, c) or std_a.size not in (1, c):
        raise ValueError(
            f"image_normalize: mean/std must be scalar or per-channel "
            f"(C={c}); got mean={mean_a.size}, std={std_a.size}.")
    if np.any(std_a == 0):
        raise ValueError("image_normalize: std must be nonzero.")
    m = mean_a.reshape(1, -1, 1, 1) if mean_a.size == c else mean_a.reshape(1, 1, 1, 1)
    s = std_a.reshape(1, -1, 1, 1) if std_a.size == c else std_a.reshape(1, 1, 1, 1)
    mb = np.broadcast_to(m, nchw.shape).astype(np.float32)
    sb = np.broadcast_to(s, nchw.shape).astype(np.float32)
    centered = np.asarray(binary_exec("tessera.sub", np.ascontiguousarray(nchw, np.float32), mb), np.float32)
    out = np.asarray(binary_exec("tessera.div", centered, sb), np.float32)
    return restore(out)


def _execute_x86_compiled_image_affine(artifact: RuntimeArtifact, args: Any) -> Any:
    return _execute_image_affine_composite(
        artifact, args, "x86", _x86_binary_exec)


def _execute_rocm_compiled_image_affine(artifact: RuntimeArtifact, args: Any) -> Any:
    return _execute_image_affine_composite(
        artifact, args, "rocm", _rocm_binary_exec)


_METRIC_LOSS_OPS = (
    "tessera.wasserstein_distance",
    "tessera.cosine_embedding_loss",
    "tessera.contrastive_loss",
    "tessera.triplet_loss",
    "tessera.nt_xent_loss",
    "tessera.info_nce_loss",
    "tessera.seq2seq_loss",
)


def _loss_reduce(v: Any, reduction: str, reduce_exec: Any, np: Any) -> Any:
    arr = np.asarray(v, np.float32)
    if reduction == "none":
        return arr
    if reduction == "sum":
        return np.float32(np.asarray(
            reduce_exec(arr, "tessera.sum", axis=None, keepdims=False)))
    if reduction == "mean":
        return np.float32(np.asarray(
            reduce_exec(arr, "tessera.mean", axis=None, keepdims=False)))
    raise ValueError(f"unknown reduction {reduction!r}")


def _loss_log_softmax(logits: Any, unary_exec: Any, reduce_exec: Any, np: Any) -> Any:
    z = np.asarray(logits, np.float32)
    m = np.asarray(reduce_exec(z, "tessera.max", axis=-1, keepdims=True), np.float32)
    shifted = (z - m).astype(np.float32)
    e = np.asarray(unary_exec(shifted, "exp"), np.float32)
    s = np.asarray(reduce_exec(e, "tessera.sum", axis=-1, keepdims=True), np.float32)
    return (shifted - np.asarray(unary_exec(s, "log"), np.float32)).astype(np.float32)


def _execute_metric_loss_composite(
    artifact: RuntimeArtifact,
    args: Any,
    target: str,
    unary_exec: Any,
    reduce_exec: Any,
) -> Any:
    """Metric/contrastive loss composite lane.

    Reductions and exp/log are backend-native. Sorts, label masks, and compact
    matrix assembly stay on host, matching the existing host-structure/device-
    FLOP split used by attention and normalization composites.
    """
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _METRIC_LOSS_OPS:
        raise ValueError(
            f"{target}_metric_loss_compiled executor handles one of "
            f"{_METRIC_LOSS_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    values = _bind_launch_args(args, arg_names)
    names = [str(n) for n in op.get("operands", [])]

    def arr(i: int, dtype: Any = np.float32) -> Any:
        return np.ascontiguousarray(_as_numpy(values[names[i]]), dtype=dtype)

    def row_sum(x: Any) -> Any:
        return np.asarray(reduce_exec(x, "tessera.sum", axis=-1, keepdims=False),
                          np.float32)

    def row_mean(x: Any) -> Any:
        return np.asarray(reduce_exec(x, "tessera.mean", axis=-1, keepdims=False),
                          np.float32)

    if op_name == "tessera.wasserstein_distance":
        x = np.sort(arr(0), axis=-1)
        y = np.sort(arr(1), axis=-1)
        per = row_mean(np.abs(x - y).astype(np.float32))
        return _loss_reduce(per, reduction, reduce_exec, np)

    if op_name == "tessera.cosine_embedding_loss":
        a, b = arr(0), arr(1)
        t = np.asarray(_as_numpy(values[names[2]]), np.float32)
        dot = row_sum((a * b).astype(np.float32))
        na = np.asarray(unary_exec(row_sum((a * a).astype(np.float32)), "sqrt"),
                        np.float32)
        nb = np.asarray(unary_exec(row_sum((b * b).astype(np.float32)), "sqrt"),
                        np.float32)
        cos = dot / (na * nb + np.float32(1e-12))
        margin = np.float32(kwargs.get("margin", 0.0))
        per = np.where(t > 0, 1.0 - cos, np.maximum(0.0, cos - margin))
        return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)

    if op_name == "tessera.contrastive_loss":
        a, b = arr(0), arr(1)
        t = np.asarray(_as_numpy(values[names[2]]), np.float32)
        diff = (a - b).astype(np.float32)
        dist = np.asarray(unary_exec(row_sum((diff * diff).astype(np.float32)),
                                     "sqrt"), np.float32)
        margin = np.float32(kwargs.get("margin", 1.0))
        per = t * dist * dist + (1.0 - t) * np.maximum(0.0, margin - dist) ** 2
        return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)

    if op_name == "tessera.triplet_loss":
        a, p, n = arr(0), arr(1), arr(2)
        pos = np.asarray(unary_exec(row_sum(((a - p) ** 2).astype(np.float32)),
                                    "sqrt"), np.float32)
        neg = np.asarray(unary_exec(row_sum(((a - n) ** 2).astype(np.float32)),
                                    "sqrt"), np.float32)
        per = np.maximum(0.0, pos - neg + np.float32(kwargs.get("margin", 1.0)))
        return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)

    if op_name == "tessera.info_nce_loss":
        q, p, neg = arr(0), arr(1), arr(2)
        pos = row_sum((q * p).astype(np.float32))[:, None]
        neg_logits = np.einsum("bd,bkd->bk", q, neg).astype(np.float32)
        logits = np.concatenate([pos, neg_logits], axis=-1) / np.float32(
            kwargs.get("temperature", 0.1))
        logp = _loss_log_softmax(logits, unary_exec, reduce_exec, np)
        per = -logp[:, 0]
        return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)

    if op_name == "tessera.nt_xent_loss":
        z = arr(0)
        labels = np.asarray(_as_numpy(values[names[1]]))
        norm = np.asarray(unary_exec(row_sum((z * z).astype(np.float32)), "sqrt"),
                          np.float32)[:, None]
        zn = z / (norm + np.float32(1e-12))
        logits = (zn @ zn.T).astype(np.float32) / np.float32(
            kwargs.get("temperature", 0.5))
        np.fill_diagonal(logits, -np.inf)
        positives = labels[:, None] == labels[None, :]
        np.fill_diagonal(positives, False)
        logp = _loss_log_softmax(logits, unary_exec, reduce_exec, np)
        denom = np.maximum(positives.sum(axis=-1), 1).astype(np.float32)
        per = -np.sum(np.where(positives, logp, 0.0), axis=-1) / denom
        return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)

    logits = arr(0)
    targets = np.asarray(_as_numpy(values[names[1]]), np.int64)
    logp = _loss_log_softmax(logits, unary_exec, reduce_exec, np)
    flat = logp.reshape(-1, logp.shape[-1])
    per = -flat[np.arange(flat.shape[0]), targets.reshape(-1)].reshape(targets.shape)
    if len(names) > 2:
        mask = np.asarray(_as_numpy(values[names[2]]), np.float32)
        per = per * mask
        if reduction == "mean":
            denom = max(float(np.sum(mask)), 1.0)
            return np.float32(np.sum(per) / denom)
    return _loss_reduce(per.astype(np.float32), reduction, reduce_exec, np)


def _execute_x86_compiled_metric_loss(artifact: RuntimeArtifact, args: Any) -> Any:
    import numpy as np

    def unary_exec(x: Any, kind: str) -> Any:
        if kind == "sqrt":
            art = RuntimeArtifact(metadata={
                "target": "x86", "compiler_path": "x86_unary_compiled",
                "arg_names": ["x"], "output_name": "o",
                "ops": [{"op_name": "tessera.sqrt", "result": "o",
                         "operands": ["x"], "kwargs": {}}]})
            return _execute_x86_compiled_unary(art, (x,))
        return _x86_unary_t(x, 0 if kind == "exp" else 1, np)

    def reduce_exec(x: Any, op_name: str, axis: Any, keepdims: bool) -> Any:
        return _x86_reduce(x, op_name, axis, keepdims, np)

    return _execute_metric_loss_composite(
        artifact, args, "x86", unary_exec, reduce_exec)


def _execute_rocm_compiled_metric_loss(artifact: RuntimeArtifact, args: Any) -> Any:
    import numpy as np

    def unary_exec(x: Any, kind: str) -> Any:
        return _rocm_unary_t(x, kind, np)

    def reduce_exec(x: Any, op_name: str, axis: Any, keepdims: bool) -> Any:
        return _rocm_reduce(x, op_name, axis, keepdims, np)

    return _execute_metric_loss_composite(
        artifact, args, "rocm", unary_exec, reduce_exec)


