def _execute_structured_compute_composite(
    artifact: RuntimeArtifact,
    args: Any,
    target: str,
) -> Any:
    """Structured single-GPU primitive lane.

    These ops are dominated by dynamic programming, image/layout indexing, or
    small structured loops. They intentionally reuse Tessera's public primitive
    implementations instead of claiming a new fused backend kernel. The runtime
    row still proves that the compiler artifact reaches an executable backend
    path with target-specific dispatch and direct compare fixtures.
    """
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    op_records = list(metadata.get("ops") or [])
    op_name = str(op_records[0].get("op_name", "")) if len(op_records) == 1 else ""
    if len(op_records) != 1 or op_name not in _STRUCTURED_COMPUTE_OPS:
        raise ValueError(
            f"{target}_structured_compute_compiled executor handles one of "
            f"{_STRUCTURED_COMPUTE_OPS}; "
            f"got {[o.get('op_name') for o in op_records]!r}")
    op = op_records[0]
    kwargs = dict(op.get("kwargs") or {})
    values = _bind_launch_args(args, arg_names)
    names = [str(n) for n in op.get("operands", [])]
    operands = [values[n] for n in names]

    from tessera import losses, ops
    from tessera.nn import functional as F

    if op_name == "tessera.ctc_loss":
        return losses.ctc_loss(*operands, **kwargs)
    if op_name == "tessera.center_crop":
        return ops.center_crop(*operands, **kwargs)
    if op_name == "tessera.image_resize":
        return ops.image_resize(*operands, **kwargs)
    if op_name == "tessera.interpolate":
        return ops.interpolate(*operands, **kwargs)
    if op_name == "tessera.patchify":
        return ops.patchify(*operands, **kwargs)
    if op_name == "tessera.pixel_shuffle":
        return ops.pixel_shuffle(*operands, **kwargs)
    if op_name == "tessera.pixel_unshuffle":
        return ops.pixel_unshuffle(*operands, **kwargs)
    if op_name == "tessera.conv1d":
        return F.conv1d(*operands, **kwargs)
    if op_name == "tessera.conv_transpose":
        return F.conv_transpose(*operands, **kwargs)
    if op_name == "tessera.lora_linear":
        return F.lora_linear(*operands, **kwargs)
    if op_name == "tessera.simple_rnn_cell":
        return F.simple_rnn_cell(*operands, **kwargs)
    if op_name == "tessera.gru_cell":
        return F.gru_cell(*operands, **kwargs)
    if op_name == "tessera.lstm_cell":
        # Canonical op contract (tessera.ops.lstm_cell): (4H,In)/(4H,H) weights
        # via W_ih.T/W_hh.T, packed concat([h_t, c_t]) output — NOT F.lstm_cell
        # (which takes transposed weights and returns a tuple).
        return ops.lstm_cell(*operands, **kwargs)
    if op_name == "tessera.cross_attention":
        return ops.cross_attention(*operands, **kwargs)
    if op_name == "tessera.perceiver_resampler":
        return ops.perceiver_resampler(*operands, **kwargs)
    if op_name == "tessera.bidirectional_scan":
        return F.bidirectional_scan(*operands, **kwargs)
    if op_name == "tessera.arange":
        return ops.arange(*operands, **kwargs)
    if op_name == "tessera.cast":
        return ops.cast(*operands, **kwargs)
    if op_name == "tessera.masked_fill":
        return ops.masked_fill(*operands, **kwargs)
    if op_name == "tessera.mor_partition":
        return ops.mor_partition(*operands, **kwargs)
    if op_name == "tessera.mor_router":
        return ops.mor_router(*operands, **kwargs)
    if op_name == "tessera.mor_scatter":
        return ops.mor_scatter(*operands, **kwargs)
    if op_name == "tessera.pack":
        return ops.pack(*operands, **kwargs)
    if op_name == "tessera.rearrange":
        return ops.rearrange(*operands, **kwargs)
    if op_name == "tessera.rope_merge":
        return ops.rope_merge(*operands, **kwargs)
    if op_name == "tessera.rope_split":
        return ops.rope_split(*operands, **kwargs)
    if op_name == "tessera.tile_view":
        return ops.tile_view(*operands, **kwargs)
    if op_name == "tessera.transpose":
        return ops.transpose(*operands, **kwargs)
    if op_name == "tessera.unpack":
        return ops.unpack(*operands, **kwargs)
    if op_name == "tessera.attn_compressed_blocks":
        return ops.attn_compressed_blocks(*operands, **kwargs)
    if op_name == "tessera.attn_local_window_2d":
        return ops.attn_local_window_2d(*operands, **kwargs)
    if op_name == "tessera.attn_top_k_blocks":
        if "scores" not in kwargs and len(operands) >= 4:
            kwargs["scores"] = operands[3]
            operands = operands[:3]
        return ops.attn_top_k_blocks(*operands, **kwargs)
    if op_name == "tessera.linear_attn_state":
        return ops.linear_attn_state(*operands, **kwargs)
    if op_name == "tessera.lookahead_sparse_attention":
        return ops.lookahead_sparse_attention(*operands, **kwargs)
    if op_name == "tessera.power_attn":
        return ops.power_attn(*operands, **kwargs)
    if op_name == "tessera.edm_loss_weight":
        from tessera.compiler import diffusion_schedule as D
        return D.edm_loss_weight(*operands, **kwargs)
    if op_name == "tessera.edm_precondition":
        from tessera.compiler import diffusion_schedule as D
        return D.edm_precondition(*operands, **kwargs)
    if op_name == "tessera.factorized_pos_emb":
        return ops.factorized_pos_emb(*operands, **kwargs)
    if op_name == "tessera.masked_scatter":
        return ops.masked_scatter(*operands, **kwargs)
    if op_name == "tessera.memory_read":
        from tessera import memory
        return memory.memory_read(*operands, **kwargs)
    if op_name == "tessera.mrope_2d":
        return ops.mrope_2d(*operands, **kwargs)
    if op_name == "tessera.online_softmax_state":
        return ops.online_softmax_state(*operands, **kwargs)
    if op_name == "tessera.spectral_norm":
        return F.spectral_norm(*operands, **kwargs)
    return ops.depthwise_conv1d(*operands, **kwargs)


def _execute_x86_structured_compute_compiled(
    artifact: RuntimeArtifact,
    args: Any,
) -> Any:
    return _execute_structured_compute_composite(artifact, args, "x86")


def _execute_rocm_structured_compute_compiled(
    artifact: RuntimeArtifact,
    args: Any,
) -> Any:
    return _execute_structured_compute_composite(artifact, args, "rocm")


def _execute_apple_gpu_structured_compute_compiled(
    artifact: RuntimeArtifact,
    args: Any,
) -> Any:
    """Apple GPU structured-compute lane — the conv family (conv1d /
    conv_transpose / depthwise_conv1d) reach an executable apple_gpu path via
    runtime.launch() and match the reference primitive. Parity with the x86 /
    ROCm structured-compute lanes: host-structured shape/control bookkeeping,
    direct execute/compare evidence, not a bespoke fused Metal kernel."""
    return _execute_structured_compute_composite(artifact, args, "apple_gpu")


#: op_name -> (loss kind, param kwarg or None). Mirrors _X86_LOSS_OPS: the ROCm
#: mirror is rocm_loss_compiled. The Apple GPU lane composes the per-element loss
#: on the GPU binary/unary opcode lanes where a clean opcode exists (mse = r·r,
#: mae = |r|) and host-side for the piecewise/transcendental middle (huber /
#: smooth_l1 / log_cosh); the none/mean/sum reduction runs on the MPSGraph reduce
#: lane. All GPU dispatchers fall back to numpy when Metal is unavailable.
_APPLE_GPU_LOSS_OPS = {
    "tessera.mse_loss": (0, None),
    "tessera.mae_loss": (1, None),
    "tessera.huber_loss": (2, "delta"),
    "tessera.smooth_l1_loss": (3, "beta"),
    "tessera.log_cosh_loss": (4, None),
}


def _execute_apple_gpu_compiled_loss(artifact: RuntimeArtifact,
                                     args: Any) -> Any:
    """The ``target="apple_gpu"`` pointwise-regression loss lane: mse / mae /
    huber / smooth_l1 / log_cosh over (pred, target). Residual ``r = pred -
    target`` on the GPU binary lane; mse (``r·r``) and mae (``|r|``) compose on
    the GPU mul/abs opcodes; huber / smooth_l1 / log_cosh apply their piecewise/
    transcendental transform host-side (matches tessera.losses exactly in f32);
    the none/mean/sum reduction runs on the MPSGraph reduce lane. Parity with
    x86_loss_compiled / rocm_loss_compiled. f32."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _APPLE_GPU_LOSS_OPS:
        raise ValueError(
            "apple_gpu_loss_compiled executor handles exactly one of "
            f"{tuple(_APPLE_GPU_LOSS_OPS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    kind, param_kw = _APPLE_GPU_LOSS_OPS[op_name]
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("loss requires two operands (pred, target)")
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    param = float(kwargs.get(param_kw, 1.0)) if param_kw else 0.0
    values = _bind_launch_args(args, arg_names)
    pred = _as_numpy(values[operand_names[0]])
    target = _as_numpy(values[operand_names[1]])
    if pred.dtype != np.float32:
        raise ValueError(f"apple_gpu loss lane handles f32 only; got {pred.dtype}")
    try:
        bshape = np.broadcast_shapes(pred.shape, target.shape)
    except ValueError as exc:
        raise ValueError(
            f"loss pred{pred.shape} and target{target.shape} do not "
            f"broadcast") from exc
    pred = np.ascontiguousarray(np.broadcast_to(pred, bshape), np.float32)
    target = np.ascontiguousarray(np.broadcast_to(target, bshape), np.float32)

    # Residual on the GPU binary lane (pred - target).
    r = np.asarray(
        _apple_gpu_dispatch_mpsgraph_binary("tessera.sub", [pred, target], {}, np),
        np.float32)
    if kind == 0:      # mse: r·r on the GPU mul lane
        per = np.asarray(
            _apple_gpu_dispatch_mpsgraph_binary("tessera.mul", [r, r], {}, np),
            np.float32)
    elif kind == 1:    # mae: |r| on the GPU unary abs lane
        per = np.asarray(_apple_gpu_dispatch_unary("tessera.abs", [r], np),
                         np.float32)
    elif kind == 2:    # huber (host piecewise; matches tessera.losses.huber_loss)
        ar = np.abs(r)
        d = param
        per = np.where(ar <= d, 0.5 * r * r, d * (ar - 0.5 * d)).astype(np.float32)
    elif kind == 3:    # smooth_l1 (host piecewise)
        ar = np.abs(r)
        b = param
        per = np.where(ar < b, 0.5 * r * r / b, ar - 0.5 * b).astype(np.float32)
    else:              # log_cosh: r + log1p(exp(-2r)) - log2 (host, stable)
        per = (r + np.log1p(np.exp(-2.0 * r)) - np.float32(np.log(2.0))).astype(
            np.float32)

    if reduction == "none":
        return per.reshape(bshape)
    # none/mean/sum reduction on the MPSGraph reduce lane (op 0 = sum, 1 = mean).
    key = "tessera.mean" if reduction == "mean" else "tessera.reduce"
    return np.asarray(
        _apple_gpu_dispatch_reduce(key, [per], {"axis": None}, np), np.float32)


#: op_name -> (reference module, callable name). The Apple GPU loss-family lane
#: (binary-CE / class-axis / RL-policy / EBM-diffusion). Mirrors the x86
#: binary_loss / class_loss / rl_loss / ebm_loss lanes and the ROCm equivalents:
#: the per-sample loss composes through the standalone reference (host structure
#: — gather/one-hot/clip/softplus, some in f64), and the none/mean/sum reduction
#: runs on the MPSGraph reduce lane. Direct execute/compare vs tessera.losses /
#: tessera.rl, not a bespoke fused Metal kernel.
_APPLE_GPU_LOSS_FAMILY_REFS = {
    # binary-cross-entropy
    "tessera.binary_cross_entropy_loss": ("losses", "binary_cross_entropy_loss"),
    # class-axis
    "tessera.cross_entropy_loss": ("losses", "cross_entropy_loss"),
    "tessera.kl_divergence": ("losses", "kl_divergence"),
    "tessera.js_divergence": ("losses", "js_divergence"),
    "tessera.z_loss": ("losses", "z_loss"),
    # RL policy
    "tessera.ppo_policy_loss": ("rl", "ppo_policy_loss"),
    "tessera.cispo_policy_loss": ("rl", "cispo_policy_loss"),
    "tessera.grpo_policy_loss": ("rl", "grpo_policy_loss"),
    # EBM / diffusion
    "tessera.score_matching_loss": ("losses", "score_matching_loss"),
    "tessera.denoising_score_matching_loss":
        ("losses", "denoising_score_matching_loss"),
    "tessera.implicit_score_matching_loss":
        ("losses", "implicit_score_matching_loss"),
    "tessera.contrastive_divergence_loss": ("losses", "contrastive_divergence_loss"),
    "tessera.persistent_cd_loss": ("losses", "persistent_cd_loss"),
    "tessera.ddpm_noise_pred_loss": ("losses", "ddpm_noise_pred_loss"),
    "tessera.vlb_loss": ("losses", "vlb_loss"),
    "tessera.load_balance_loss": ("losses", "load_balance_loss"),
}


def _execute_apple_gpu_compiled_loss_family(artifact: RuntimeArtifact,
                                            args: Any) -> Any:
    """The ``target="apple_gpu"`` loss-family lane: binary-CE / class-axis (ce /
    kl / js / z_loss) / RL policy (ppo / cispo / grpo) / EBM-diffusion. The
    per-sample loss composes through the standalone reference (host structure);
    the none/mean/sum reduction runs on the MPSGraph reduce lane — the same
    "host structure + GPU reduction" model as rocm_*_loss_compiled. A masked
    mean/sum is a weighted reduction the reference owns. f32; matches
    tessera.losses / tessera.rl."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _APPLE_GPU_LOSS_FAMILY_REFS:
        raise ValueError(
            "apple_gpu_loss_family_compiled executor handles one of "
            f"{tuple(_APPLE_GPU_LOSS_FAMILY_REFS)}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    names = [str(n) for n in op.get("operands", [])]
    kwargs = dict(op.get("kwargs") or {})
    values = _bind_launch_args(args, arg_names)
    operands = [values[n] for n in names]

    from tessera import losses, rl
    mod_name, fn_name = _APPLE_GPU_LOSS_FAMILY_REFS[op_name]
    ref_fn = getattr({"losses": losses, "rl": rl}[mod_name], fn_name)

    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    # A masked mean/sum is a weighted reduction (not a plain GPU reduce); the
    # reference owns it end-to-end (Decision #21: never silently wrong).
    if kwargs.get("mask") is not None and reduction != "none":
        return ref_fn(*operands, **kwargs)

    per = np.ascontiguousarray(
        np.asarray(ref_fn(*operands, **{**kwargs, "reduction": "none"}), np.float32))
    if reduction == "none":
        return per
    key = "tessera.mean" if reduction == "mean" else "tessera.reduce"
    return np.asarray(
        _apple_gpu_dispatch_reduce(key, [per], {"axis": None}, np), np.float32)


def _execute_rocm_compiled_nvfp4(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` nvfp4 lane: block-scaled fp4 (E2M1 codes + per-block
    fp8-E4M3 scale) on the fpquant kernel + host block structure. quantize
    returns the dequantized fp32; dequantize is the passthrough."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    _OPS = ("tessera.quantize_nvfp4", "tessera.dequantize_nvfp4")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _OPS:
        raise ValueError(
            f"rocm_nvfp4_compiled executor handles one of {_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("nvfp4 op requires one operand")
    kwargs = op.get("kwargs") or {}
    bs = int(kwargs.get("block_size", 16))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    if x.dtype != np.float32:
        raise ValueError(f"rocm nvfp4 lane handles f32 only; got {x.dtype}")
    if op_name == "tessera.dequantize_nvfp4":
        return np.ascontiguousarray(x, np.float32)
    if bs <= 0 or x.ndim < 1 or int(x.shape[-1]) % bs != 0:
        raise ValueError(
            f"nvfp4 last dim must be divisible by block_size {bs}")
    x = np.ascontiguousarray(x, np.float32)
    n = int(x.shape[-1])
    nb = n // bs
    blocks = x.reshape(*x.shape[:-1], nb, bs)
    amax = np.abs(blocks).max(axis=-1)
    raw = np.maximum(amax / np.float32(6.0), np.float32(1e-30))
    scale = _rocm_fpgrid(raw, 448.0, 3, -6, np)            # fp8 e4m3 scale
    scale = np.where(scale == 0.0, np.float32(1.0), scale).astype(np.float32)
    sf = scale[..., None]
    codes = _rocm_fpgrid(blocks / sf, 6.0, 1, 0, np)       # fp4 e2m1 (clamp 0)
    return (codes * sf).reshape(*x.shape[:-1], n).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm class-axis loss lane — cross_entropy / kl / js / focal /
# label_smoothed_cross_entropy / z_loss (ROCm mirror of the x86 class-loss lane).
# exp/log on the rocm unary lane; class-axis structure on the host.
# ─────────────────────────────────────────────────────────────────────────────
def _rocm_unary_t(x: Any, kind: str, np: Any) -> Any:
    """Elementwise exp/log on the ROCm unary lane (tessera.exp / tessera.log)."""
    art = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_unary_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": f"tessera.{kind}", "result": "o",
                 "operands": ["x"]}]})
    return np.asarray(_execute_rocm_compiled_unary(
        art, (np.ascontiguousarray(x, np.float32),)), np.float32)


def _rocm_log_softmax(z: Any, np: Any) -> Any:
    m = np.max(z, axis=-1, keepdims=True)
    shifted = (z - m).astype(np.float32)
    e = _rocm_unary_t(shifted, "exp", np)
    s = e.sum(axis=-1, keepdims=True).astype(np.float32)
    return (shifted - _rocm_unary_t(s, "log", np)).astype(np.float32)


_ROCM_CLASS_LOSS_OPS = (
    "tessera.cross_entropy_loss", "tessera.kl_divergence",
    "tessera.js_divergence", "tessera.focal_loss",
    "tessera.label_smoothed_cross_entropy", "tessera.z_loss",
)


def _execute_rocm_compiled_class_loss(artifact: RuntimeArtifact,
                                      args: Any) -> Any:
    """The ``target="rocm"`` class-axis loss lane: cross_entropy / kl / js /
    focal / label_smoothed_cross_entropy / z_loss. exp/log on the rocm unary
    lane (gfx1151); class-axis max/sum/gather/one-hot on the host."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_CLASS_LOSS_OPS:
        raise ValueError(
            f"rocm_class_loss_compiled executor handles one of "
            f"{_ROCM_CLASS_LOSS_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    reduction = str(kwargs.get("reduction", "mean"))
    if reduction not in ("none", "mean", "sum"):
        raise ValueError(f"loss reduction must be none/mean/sum; got {reduction}")
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]

    def _red(loss):
        if reduction == "none":
            return loss.astype(np.float32)
        return np.float32(loss.sum() if reduction == "sum" else loss.mean())

    def _gather(logp, targets):
        flat = logp.reshape(-1, logp.shape[-1])
        idx = targets.reshape(-1).astype(np.int64)
        return flat[np.arange(idx.size), idx].reshape(targets.shape)

    if op_name == "tessera.cross_entropy_loss":
        logits = operands[0].astype(np.float32)
        targets = operands[1]
        logp = _rocm_log_softmax(logits, np)
        if targets.dtype.kind in "iu":
            loss = -_gather(logp, targets)
        else:
            loss = -np.sum(targets.astype(np.float32) * logp, axis=-1)
        return _red(loss)

    if op_name == "tessera.label_smoothed_cross_entropy":
        logits = operands[0].astype(np.float32)
        targets = operands[1].astype(np.int64)
        c = int(logits.shape[-1])
        smooth = float(kwargs.get("smoothing", 0.1))
        soft = np.full(targets.shape + (c,), smooth / max(1, c - 1), np.float32)
        np.put_along_axis(soft, targets[..., None], 1.0 - smooth, axis=-1)
        loss = -np.sum(soft * _rocm_log_softmax(logits, np), axis=-1)
        return _red(loss)

    if op_name == "tessera.focal_loss":
        logits = operands[0].astype(np.float32)
        targets = operands[1]
        gamma = float(kwargs.get("gamma", 2.0))
        alpha = kwargs.get("alpha")
        probs = _rocm_unary_t(_rocm_log_softmax(logits, np), "exp", np)
        pt = _gather(probs, targets)
        logpt = _rocm_unary_t(np.maximum(pt, 1e-12).astype(np.float32), "log", np)
        loss = -((1.0 - pt) ** gamma) * logpt
        if alpha is not None:
            loss = float(alpha) * loss
        return _red(loss)

    if op_name == "tessera.z_loss":
        z = operands[0].astype(np.float32)
        m = np.max(z, axis=-1, keepdims=True)
        e = _rocm_unary_t((z - m).astype(np.float32), "exp", np)
        s = e.sum(axis=-1, keepdims=True).astype(np.float32)
        lse = (m + _rocm_unary_t(s, "log", np)).squeeze(axis=-1)
        return _red(lse * lse)

    if op_name == "tessera.kl_divergence":
        p_log = operands[0].astype(np.float32)
        q = operands[1].astype(np.float32)
        p = _rocm_unary_t(p_log, "exp", np)
        logq = _rocm_unary_t(np.maximum(q, 1e-12).astype(np.float32), "log", np)
        return _red(np.sum(p * (p_log - logq), axis=-1))

    # tessera.js_divergence
    p = operands[0].astype(np.float32)
    q = operands[1].astype(np.float32)
    mid = (0.5 * (p + q)).astype(np.float32)
    logp = _rocm_unary_t(np.maximum(p, 1e-12).astype(np.float32), "log", np)
    logq = _rocm_unary_t(np.maximum(q, 1e-12).astype(np.float32), "log", np)
    logm = _rocm_unary_t(np.maximum(mid, 1e-12).astype(np.float32), "log", np)
    kl_pm = np.sum(p * (logp - logm), axis=-1)
    kl_qm = np.sum(q * (logq - logm), axis=-1)
    return _red(0.5 * (kl_pm + kl_qm))


# ─────────────────────────────────────────────────────────────────────────────
# ROCm reduce/stable-reduce FOUNDATION — the reduction + stable_reduction ops
# beyond the base sum/mean/max/min/amax/amin (warp-shuffle reduce kernel) and
# softmax. var/std/count_nonzero and logsumexp/log_softmax compose the
# warp-shuffle reduce kernel + the unary exp/log lane (the same compose pattern
# as the class-loss lane); prod is a new reduce-kernel combine (rocm_reduce_
# compiled); softmax_safe/sigmoid_safe alias the stable softmax / sigmoid lanes.
# ─────────────────────────────────────────────────────────────────────────────
def _rocm_reduce(x: Any, op_name: str, axis: Any, keepdims: bool,
                 np: Any) -> Any:
    """Row-reduction (sum/mean/max/min/prod) over ``axis`` on the warp-shuffle
    reduce kernel, via the rocm_reduce_compiled lane."""
    art = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_reduce_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": op_name, "result": "o", "operands": ["x"],
                 "kwargs": {"axis": axis, "keepdims": keepdims}}]})
    return np.asarray(_execute_rocm_compiled_reduce(
        art, (np.ascontiguousarray(x, np.float32),)), np.float32)


_ROCM_STAT_REDUCE_OPS = ("tessera.var", "tessera.std", "tessera.count_nonzero")


def _execute_rocm_compiled_stat_reduce(artifact: RuntimeArtifact,
                                       args: Any) -> Any:
    """The ``target="rocm"`` statistical-reduction lane: var / std /
    count_nonzero over an axis, composed from the warp-shuffle reduce kernel.
    var = mean(x²) − mean(x)²; std = sqrt(var); count_nonzero = sum(x != 0)."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_STAT_REDUCE_OPS:
        raise ValueError(
            f"rocm_stat_reduce_compiled executor handles one of "
            f"{_ROCM_STAT_REDUCE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("stat reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = kwargs.get("axis", None)
    keepdims = bool(kwargs.get("keepdims", False))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]]).astype(np.float32)

    if op_name == "tessera.count_nonzero":
        mask = (x != 0.0).astype(np.float32)
        out = _rocm_reduce(mask, "tessera.sum", axis, keepdims, np)
        return np.rint(out).astype(np.int64)

    mean = _rocm_reduce(x, "tessera.mean", axis, True, np)
    m2 = _rocm_reduce(x * x, "tessera.mean", axis, True, np)
    var = np.maximum(m2 - mean * mean, np.float32(0.0))
    if op_name == "tessera.std":
        var = _rocm_unary_t(var, "sqrt", np)
    if not keepdims:
        if axis is None:
            var = var.reshape(())
        else:
            axes = (axis,) if isinstance(axis, int) else tuple(axis)
            var = np.squeeze(var, axis=tuple(a if a >= 0 else x.ndim + a
                                             for a in axes))
    return var.astype(np.float32)


_ROCM_STABLE_REDUCE_OPS = ("tessera.logsumexp", "tessera.log_softmax",
                           "tessera.softmax_safe", "tessera.sigmoid_safe")


def _execute_rocm_compiled_stable_reduce(artifact: RuntimeArtifact,
                                         args: Any) -> Any:
    """The ``target="rocm"`` stable-reduction lane: logsumexp / log_softmax /
    softmax_safe / sigmoid_safe. logsumexp/log_softmax compose the warp-shuffle
    reduce (max/sum) + the unary exp/log lane (max-shifted, overflow-safe);
    softmax_safe routes to the stable softmax lane, sigmoid_safe to sigmoid."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_STABLE_REDUCE_OPS:
        raise ValueError(
            f"rocm_stable_reduce_compiled executor handles one of "
            f"{_ROCM_STABLE_REDUCE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("stable reduce requires one operand")
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]]).astype(np.float32)

    if op_name == "tessera.softmax_safe":
        return _execute_rocm_compiled_softmax(
            RuntimeArtifact(metadata={
                "target": "rocm", "compiler_path": "rocm_softmax_compiled",
                "arg_names": ["x"], "output_name": "o",
                "ops": [{"op_name": "tessera.softmax", "result": "o",
                         "operands": ["x"], "kwargs": kwargs}]}), (x,))
    if op_name == "tessera.sigmoid_safe":
        return _rocm_unary_t(x, "sigmoid", np)

    axis = kwargs.get("axis", -1)
    keepdims = bool(kwargs.get("keepdims", False))
    m = _rocm_reduce(x, "tessera.max", axis, True, np)
    e = _rocm_unary_t((x - m).astype(np.float32), "exp", np)
    s = _rocm_reduce(e, "tessera.sum", axis, True, np)
    lse_keep = (m + _rocm_unary_t(s, "log", np)).astype(np.float32)
    if op_name == "tessera.log_softmax":
        return (x - lse_keep).astype(np.float32)
    # tessera.logsumexp
    if keepdims:
        return lse_keep
    if axis is None:
        return lse_keep.reshape(())
    axes = (axis,) if isinstance(axis, int) else tuple(axis)
    return np.squeeze(lse_keep, axis=tuple(a if a >= 0 else x.ndim + a
                                           for a in axes)).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm spectral (FFT) lane — fft / ifft / rfft / irfft (Spectral PR4). The
# COMPILER-GENERATED one-thread-per-bin DFT kernel (generate-rocm-dft-kernel)
# does the transform for ANY length on gfx1151; r2c/c2r pack/unpack + the
# SpectralPlan scale wrap it (radix-2/Bluestein perf is a follow-up — the plan
# still records the strategy). complex64/f32. compiler_path="rocm_fft_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_rocm_dft_hsaco_cache: dict[tuple[str, bool], bytes] = {}


def _rocm_dft_rows(rows: Any, inverse: bool, np: Any) -> Any:
    """Unnormalized DFT of complex64 rows [batch, n] on the gfx1151 DFT kernel.
    Returns complex64 [batch, n]."""
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.dft"() {{name = "dt", '
        f'inverse = {"true" if inverse else "false"}}} : () -> ()\n}}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-dft-kernel", directive, _rocm_dft_hsaco_cache,
        (chip, bool(inverse)))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm dft: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm dft: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"dt") != 0:
        raise RuntimeError("rocm dft: kernel symbol 'dt' not found")

    rows = np.ascontiguousarray(rows, np.complex64)
    batch, n = int(rows.shape[0]), int(rows.shape[1])
    L = 2 * batch * n
    inb = np.ascontiguousarray(rows.view(np.float32).reshape(-1))
    out = np.zeros(L, dtype=np.float32)
    din, dout = ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (din, dout):
        if hip.hipMalloc(ctypes.byref(dev), 4 * L) != 0:
            raise RuntimeError("rocm dft: hipMalloc failed")
    hip.hipMemcpy(din, inb.ctypes.data_as(ctypes.c_void_p), 4 * L, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(din, L) + _mr(dout, L)
                   + [ctypes.c_int64(batch), ctypes.c_int64(n)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    total = batch * n
    gx = (total + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (din, dout):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm dft: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), dout, 4 * L, 2)
    for dev in (din, dout):
        hip.hipFree(dev)
    return out.view(np.complex64).reshape(batch, n)


_ROCM_FFT_OPS = ("tessera.fft", "tessera.ifft", "tessera.rfft", "tessera.irfft")


def _execute_rocm_compiled_fft(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` spectral lane: fft / ifft / rfft / irfft over any
    axis length, on the gfx1151 DFT kernel + r2c/c2r pack-unpack. The
    SpectralPlan owns normalization. complex64/f32."""
    import numpy as np

    from .compiler.spectral_plan import plan_fft

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_FFT_OPS:
        raise ValueError(
            f"rocm_fft_compiled executor handles one of {_ROCM_FFT_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 1:
        raise ValueError("fft requires one operand")
    kwargs = op.get("kwargs") or {}
    axis = int(kwargs.get("axis", -1))
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    nd = x.ndim
    if nd < 1:
        raise ValueError("fft operand must have rank >= 1")
    ax = axis if axis >= 0 else nd + axis

    inverse = op_name == "tessera.ifft"
    if op_name == "tessera.irfft":
        m = int(x.shape[ax])
        n = int(kwargs.get("n") or 2 * (m - 1))
    else:
        n = int(x.shape[ax])
    mode = {"tessera.rfft": "r2c", "tessera.irfft": "c2r"}.get(op_name, "c2c")
    plan = plan_fft(n, axis=ax, mode=mode,
                    inverse=inverse or op_name == "tessera.irfft")

    xm = np.moveaxis(x, ax, -1)
    lead = xm.shape[:-1]

    if op_name in ("tessera.fft", "tessera.ifft"):
        out = _rocm_dft_rows(xm.reshape(-1, n).astype(np.complex64),
                             plan.inverse, np)
        if plan.scale != 1.0:
            out = out * np.complex64(plan.scale)
        return np.moveaxis(out.reshape(*lead, n), -1, ax).astype(np.complex64)

    if op_name == "tessera.rfft":
        full = _rocm_dft_rows(xm.reshape(-1, n).astype(np.complex64), False, np)
        half = full[:, : n // 2 + 1]
        return np.moveaxis(half.reshape(*lead, n // 2 + 1), -1, ax).astype(
            np.complex64)

    rows = xm.reshape(-1, m).astype(np.complex64)
    batch = rows.shape[0]
    full = np.zeros((batch, n), np.complex64)
    full[:, :m] = rows[:, :m]
    if n - m > 0:
        full[:, m:n] = np.conj(rows[:, 1:n - n // 2])[:, ::-1]
    out = _rocm_dft_rows(full, True, np).real * np.float32(1.0 / n)
    return np.moveaxis(out.reshape(*lead, n), -1, ax).astype(np.float32)


def _rocm_fftexec(sub_op: str, x: Any, sub_kwargs: dict) -> Any:
    art = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_fft_compiled",
        "arg_names": ["x"], "output_name": "o",
        "ops": [{"op_name": sub_op, "result": "o", "operands": ["x"],
                 "kwargs": sub_kwargs}]})
    return _execute_rocm_compiled_fft(art, (x,))


def _execute_rocm_compiled_spectral(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` composite spectral lane: dct / stft / istft /
    spectral_conv / spectral_filter, composing the gfx1151 FFT (DFT) lane."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _SPECTRAL_COMPOSITE_OPS:
        raise ValueError(
            f"rocm_spectral_compiled executor handles one of "
            f"{_SPECTRAL_COMPOSITE_OPS}; got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[str(n)]) for n in op.get("operands", [])]
    return _spectral_composite(op_name, operands, op.get("kwargs") or {},
                               _rocm_fftexec, np)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED sparse lane (Sparse PR) — genuinely sparse kernels: spmm (CSR
# row-wise) + sddmm (sampled dense-dense). compiler_path="rocm_sparse_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_rocm_spmm_hsaco_cache: dict[tuple[str], bytes] = {}
_rocm_sddmm_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_sparse_launch(hsaco: bytes, sym: bytes, buffers: list,
                        scalars: list, grid_total: int) -> None:
    """Launch a sparse kernel: ``buffers`` = list of (device_ptr, elem_count)
    memref args; ``scalars`` = trailing index args; grid sized to grid_total."""
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm sparse: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm sparse: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, sym) != 0:
        raise RuntimeError(f"rocm sparse: kernel symbol {sym!r} not found")

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args: list = []
    for dev, size in buffers:
        launch_args += _mr(dev, size)
    launch_args += [ctypes.c_int64(s) for s in scalars]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (grid_total + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        raise RuntimeError(f"rocm sparse: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()


def _rocm_sparse_launch_custom(hsaco: bytes, sym: bytes, buffers: list,
                               scalars: list, grid_x: int,
                               block_x: int) -> None:
    """Launch a generated sparse kernel with explicit grid/block geometry."""
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm sparse: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm sparse: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, sym) != 0:
        raise RuntimeError(f"rocm sparse: kernel symbol {sym!r} not found")

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args: list = []
    for dev, size in buffers:
        launch_args += _mr(dev, size)
    launch_args += [ctypes.c_int64(s) for s in scalars]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, grid_x, 1, 1, block_x, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        raise RuntimeError(f"rocm sparse: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()


def _rocm_dev_in(hip: Any, host: Any, nbytes: int) -> Any:
    d = ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(d), nbytes) != 0:
        raise RuntimeError("rocm sparse: hipMalloc failed")
    hip.hipMemcpy(d, host.ctypes.data_as(ctypes.c_void_p), nbytes, 1)
    return d


_rocm_block_sparse_attn_hsaco_cache: dict[tuple[str, bool], bytes] = {}
_rocm_block_sparse_topk_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_block_sparse_attn_hsaco(*, tiled: bool = True) -> bytes:
    chip = _rocm_chip()
    op = "block_sparse_attention_tiled" if tiled else "block_sparse_attention"
    name = "bsat" if tiled else "bsa"
    directive = (
        'module {\n'
        f'  "tessera_rocm.{op}"() {{name = "{name}"}} : () -> ()\n'
        '}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-block-sparse-attn-kernel", directive,
        _rocm_block_sparse_attn_hsaco_cache, (chip, bool(tiled)))


def _rocm_block_sparse_topk_hsaco() -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        '  "tessera_rocm.block_sparse_topk_select"() {name = "btopk"} : () -> ()\n'
        '}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-block-sparse-topk-kernel", directive,
        _rocm_block_sparse_topk_hsaco_cache, (chip,))


def _rocm_block_sparse_topk_select_native(scores: Any, np: Any, *,
                                          top_k: int, block_size: int,
                                          causal: bool = True,
                                          force_local_block: bool = True,
                                          q_positions: Any = None) -> Any:
    sc = np.ascontiguousarray(np.asarray(scores, dtype=np.float32))
    if sc.ndim != 4:
        raise ValueError("block sparse top-k scores must be (B,Hkv,Sq,num_blocks)")
    B, Hkv, Sq, Nb = map(int, sc.shape)
    if not (1 <= int(top_k) <= Nb):
        raise ValueError(f"top_k={top_k} must be in [1, num_blocks={Nb}]")
    qpos = (np.arange(Sq, dtype=np.int64) if q_positions is None
            else np.asarray(q_positions, dtype=np.int64).reshape(-1))
    if qpos.shape[0] != Sq:
        raise ValueError(f"q_positions length {qpos.shape[0]} must equal Sq={Sq}")

    hsaco = _rocm_block_sparse_topk_hsaco()
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm block_sparse_topk: hipInit failed")
    out = np.zeros((B, Hkv, Sq, int(top_k)), dtype=np.int64)
    devs: list[Any] = []
    try:
        d_s = _rocm_dev_in(hip, sc.reshape(-1), 4 * sc.size); devs.append(d_s)
        d_qp = _rocm_dev_in(hip, qpos.reshape(-1), 8 * qpos.size); devs.append(d_qp)
        d_o = _rocm_dev_in(hip, out.reshape(-1), 8 * out.size); devs.append(d_o)
        _rocm_sparse_launch(
            hsaco, b"btopk",
            [(d_s, sc.size), (d_qp, qpos.size), (d_o, out.size)],
            [B, Hkv, Sq, Nb, int(top_k), int(block_size),
             1 if causal else 0, 1 if force_local_block else 0],
            B * Hkv * Sq)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_o, 8 * out.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)
    return out


def _rocm_selected_block_attention_native(Q: Any, K: Any, V: Any,
                                          selected_block_ids: Any, np: Any, *,
                                          block_size: int, causal: bool = True,
                                          q_positions: Any = None,
                                          scale: Any = None,
                                          tiled: bool = True) -> Any:
    """Run DK2 selected-block sparse attention on ROCm.

    The runtime pre-scales Q so the generated kernel can keep an integer-only
    ABI while preserving stdlib attention numerics.
    """
    if scale is not None:
        sc = float(scale)
    else:
        sc = None
    q = np.ascontiguousarray(_as_numpy(Q), dtype=np.float32)
    k = np.ascontiguousarray(_as_numpy(K), dtype=np.float32)
    v = np.ascontiguousarray(_as_numpy(V), dtype=np.float32)
    sel = np.ascontiguousarray(np.asarray(selected_block_ids, dtype=np.int64))
    if q.ndim != 4 or k.ndim != 4 or v.ndim != 4:
        raise ValueError("selected-block attention expects rank-4 Q/K/V")
    B, Hq, Sq, D = map(int, q.shape)
    Bk, Hkv, Sk, Dk = map(int, k.shape)
    Bv, Hkv_v, Sk_v, Dv = map(int, v.shape)
    if (B, Hkv, Sk) != (Bv, Hkv_v, Sk_v) or B != Bk or D != Dk:
        raise ValueError(f"Q/K/V shape mismatch: Q={q.shape} K={k.shape} V={v.shape}")
    if Hkv == 0 or Hq % Hkv:
        raise ValueError(f"GQA requires Hq % Hkv == 0; got Hq={Hq}, Hkv={Hkv}")
    if block_size <= 0:
        raise ValueError("block_size must be > 0")
    if sel.ndim != 4 or sel.shape[:3] != (B, Hkv, Sq):
        raise ValueError(
            f"selected_block_ids must be (B,Hkv,Sq,Ksel); got {sel.shape}")
    Ksel = int(sel.shape[3])
    num_blocks = (Sk + int(block_size) - 1) // int(block_size)
    if np.any(sel < 0) or np.any(sel >= num_blocks):
        raise ValueError(
            f"selected_block_ids entries must be in [0, num_blocks={num_blocks})")
    qpos = (np.arange(Sq, dtype=np.int64) if q_positions is None
            else np.asarray(q_positions, dtype=np.int64).reshape(-1))
    if qpos.shape[0] != Sq:
        raise ValueError(f"q_positions length {qpos.shape[0]} must equal Sq={Sq}")
    q_scale = np.float32((1.0 / np.sqrt(D)) if sc is None else sc)
    q = np.ascontiguousarray(q * q_scale, dtype=np.float32)

    use_tiled = bool(tiled) and Dv <= 256
    hsaco = _rocm_block_sparse_attn_hsaco(tiled=use_tiled)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm block_sparse_attention: hipInit failed")
    out = np.zeros((B, Hq, Sq, Dv), dtype=np.float32)
    devs: list[Any] = []
    try:
        d_q = _rocm_dev_in(hip, q.reshape(-1), 4 * q.size); devs.append(d_q)
        d_k = _rocm_dev_in(hip, k.reshape(-1), 4 * k.size); devs.append(d_k)
        d_v = _rocm_dev_in(hip, v.reshape(-1), 4 * v.size); devs.append(d_v)
        d_sel = _rocm_dev_in(hip, sel.reshape(-1), 8 * sel.size); devs.append(d_sel)
        d_qpos = _rocm_dev_in(hip, qpos.reshape(-1), 8 * qpos.size); devs.append(d_qpos)
        d_o = _rocm_dev_in(hip, out.reshape(-1), 4 * out.size); devs.append(d_o)
        buffers = [(d_q, q.size), (d_k, k.size), (d_v, v.size), (d_sel, sel.size),
                   (d_qpos, qpos.size), (d_o, out.size)]
        scalars = [B, Hq, Hkv, Sq, Sk, D, Dv, int(block_size), Ksel,
                   1 if causal else 0]
        if use_tiled:
            _rocm_sparse_launch_custom(hsaco, b"bsat", buffers, scalars,
                                       B * Hq * Sq, max(1, Dv))
        else:
            _rocm_sparse_launch(hsaco, b"bsa", buffers, scalars, out.size)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_o, 4 * out.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)
    return out


def _dsa_selected_block_ids(Q: Any, K: Any, np: Any, *, top_k_blocks: int,
                            block_size: int, causal: bool,
                            q_positions: Any = None) -> Any:
    from .stdlib import attention as _attn

    q = np.asarray(Q)
    k = np.asarray(K)
    pad = (-int(k.shape[2])) % int(block_size)
    if pad:
        k = np.concatenate(
            [k, np.zeros(k.shape[:2] + (pad, k.shape[3]), dtype=k.dtype)],
            axis=2)
    scores = _attn.dsa_block_index(q, k, block_size=block_size)
    keep = _attn.dsa_select_blocks(
        scores, top_k=min(int(top_k_blocks), scores.shape[-1]),
        block_size=block_size, causal=causal, q_positions=q_positions)
    B, Hkv, Sq, nb = keep.shape
    ksel = min(nb, int(top_k_blocks) + (1 if causal else 0))
    sel = np.zeros((B, Hkv, Sq, ksel), dtype=np.int64)
    for b in range(B):
        for h in range(Hkv):
            for s in range(Sq):
                ids = np.flatnonzero(keep[b, h, s])
                if ids.size == 0:
                    ids = np.array([min(nb - 1, int((q_positions[s] if q_positions is not None else s) // block_size))])
                ids = ids[:ksel]
                sel[b, h, s, :ids.size] = ids
                if ids.size < ksel:
                    fillers = [blk for blk in range(nb) if blk not in set(ids.tolist())]
                    fill = np.asarray(fillers[:ksel - ids.size], dtype=np.int64)
                    sel[b, h, s, ids.size:ids.size + fill.size] = fill
                    if ids.size + fill.size < ksel:
                        sel[b, h, s, ids.size + fill.size:] = ids[-1]
    return sel


def _deepseek_sparse_attention_rocm(
    Q: Any,
    K: Any,
    V: Any,
    gate_logits: Any,
    np: Any,
    *,
    window_size: int,
    block_size: int,
    top_k: int,
    causal: bool,
) -> tuple[Any, str]:
    """DeepSeek/NSA ROCm lane.

    The public op is a three-branch composition.  Off hardware we deliberately
    call the reference op so unsupported hosts remain exact.  On ROCm hardware
    the selected-block top-k branch uses the DK2 GPU-resident top-k selector and
    selected-block sparse-attention kernel; sliding and compressed branches stay
    reference compositions until a fused NSA branch kernel lands.
    """
    from . import ops as _ops

    q = np.asarray(Q)
    k = np.asarray(K)
    v = np.asarray(V)
    if q.ndim != 4 or k.ndim != 4 or v.ndim != 4:
        raise ValueError("deepseek_sparse_attention expects rank-4 Q/K/V")
    if q.shape[:2] != k.shape[:2] or q.shape[:2] != v.shape[:2]:
        raise ValueError(
            "rocm deepseek_sparse_attention currently requires equal Q/K/V "
            f"batch/head dims; got Q{q.shape} K{k.shape} V{v.shape}")
    if int(k.shape[2]) % int(block_size) != 0:
        raise ValueError(
            f"K sequence length {k.shape[2]} must be divisible by block_size={block_size}")

    try:
        K_c, V_c = _ops.compress_blocks(k, v, block_size=block_size)
        scores = np.matmul(q.astype(np.float32), np.swapaxes(
            np.asarray(K_c, dtype=np.float32), -1, -2))
        selected = _rocm_block_sparse_topk_select_native(
            scores, np, top_k=top_k, block_size=block_size, causal=causal,
            force_local_block=False)
        branch_topk = _rocm_selected_block_attention_native(
            # NSA applies causal masking at block-selection time only.  Unlike
            # MSA, the selected top-k blocks then attend over all tokens inside
            # each selected block, including same-block future tokens.
            q, k, v, selected, np, block_size=block_size, causal=False,
            tiled=True)
    except _RocmCompiledUnavailable:
        return (
            _ops.deepseek_sparse_attention(
                q, k, v, gate_logits,
                window_size=window_size, block_size=block_size, top_k=top_k,
                causal=causal),
            "reference_cpu",
        )

    branch_sliding = _ops.attn_sliding_window(
        q, k, v, window_size=window_size, causal=causal)
    branch_compressed = _ops.attn_compressed_blocks(q, K_c, V_c)
    if gate_logits is None:
        weights = np.full(branch_sliding.shape[:-1] + (3,), 1.0 / 3.0,
                          dtype=np.float64)
    else:
        logits = np.asarray(gate_logits, dtype=np.float64)
        e = np.exp(logits - logits.max(axis=-1, keepdims=True))
        weights = e / e.sum(axis=-1, keepdims=True)
    out = (
        np.asarray(branch_sliding) * weights[..., 0:1]
        + np.asarray(branch_compressed) * weights[..., 1:2]
        + np.asarray(branch_topk) * weights[..., 2:3]
    )
    return out.astype(np.result_type(q, k, v), copy=False), "native_gpu"


def _execute_rocm_compiled_sparse_attention(artifact: RuntimeArtifact,
                                            args: Any) -> Any:
    """DK2 ROCm selected-block sparse attention lane.

    Handles MSA's explicit `selected_block_ids` ABI plus DSA selected-block
    normalization. Hardware-free runs fall back to stdlib references and report
    `reference_cpu`; ROCm hardware runs report `native_gpu`.
    """
    import numpy as np

    from .stdlib import attention as _attn

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    handled = (
        "tessera.msa_sparse_attention",
        "tessera.dsa_block_sparse_attention",
        "tessera.deepseek_sparse_attention",
    )
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"rocm_sparse_attn_compiled executor handles {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    names = [str(n) for n in op.get("operands", [])]
    if len(names) < 3:
        raise ValueError("sparse attention requires Q, K, V operands")
    values = _bind_launch_args(args, arg_names)
    Q, K, V = (_as_numpy(values[names[0]]), _as_numpy(values[names[1]]),
               _as_numpy(values[names[2]]))
    block_size_arg = kwargs.get("block_size")
    if block_size_arg is None:
        raise ValueError("sparse attention requires block_size")
    block_size = int(block_size_arg)
    causal = bool(kwargs.get("causal", True))
    q_positions = kwargs.get("q_positions")
    scale = kwargs.get("scale")
    attention_strategy = str(kwargs.get("attention_strategy", "tiled"))
    use_tiled = attention_strategy != "scalar"
    if op_name == "tessera.deepseek_sparse_attention":
        top_k_arg = kwargs.get("top_k")
        window_size_arg = kwargs.get("window_size")
        if top_k_arg is None or window_size_arg is None:
            raise ValueError("deepseek_sparse_attention requires window_size and top_k")
        gate_logits = None
        if len(names) >= 4:
            gate_logits = values[names[3]]
        elif kwargs.get("gate_logits") is not None:
            gate_logits = kwargs.get("gate_logits")
        return _deepseek_sparse_attention_rocm(
            Q, K, V, gate_logits, np, window_size=int(window_size_arg),
            block_size=block_size, top_k=int(top_k_arg), causal=causal)

    if op_name == "tessera.msa_sparse_attention":
        top_k_arg = kwargs.get("top_k")
        if top_k_arg is None:
            raise ValueError("msa_sparse_attention requires top_k")
        top_k = int(top_k_arg)
        selected = kwargs.get("selected_block_ids")
        if selected is None and len(names) >= 4:
            selected = values[names[3]]
        if selected is None:
            scores = _attn.msa_index_scores(Q, K, block_size=block_size, scale=scale)
            force_local = bool(kwargs.get("force_local_block", True))
            selection_strategy = str(kwargs.get("selection_strategy", "auto"))
            can_try_gpu_select = (
                selection_strategy == "gpu" or
                (selection_strategy == "auto" and _rocm_wmma_runtime_available())
            )
            if can_try_gpu_select:
                try:
                    selected = _rocm_block_sparse_topk_select_native(
                        scores, np, top_k=top_k, block_size=block_size,
                        causal=causal, force_local_block=force_local,
                        q_positions=q_positions)
                except _RocmCompiledUnavailable:
                    if selection_strategy == "gpu":
                        raise
                    selected = None
            if selected is None:
                selected = _attn.msa_select_blocks(
                    scores, top_k=top_k, block_size=block_size,
                    force_local_block=force_local,
                    causal=causal, q_positions=q_positions)
        try:
            return (
                _rocm_selected_block_attention_native(
                    Q, K, V, selected, np, block_size=block_size, causal=causal,
                    q_positions=q_positions, scale=scale, tiled=use_tiled),
                "native_gpu",
            )
        except _RocmCompiledUnavailable:
            return (
                _attn.msa_sparse_attention(
                    Q, K, V, block_size=block_size, top_k=top_k,
                    force_local_block=bool(kwargs.get("force_local_block", True)),
                    causal=causal, scale=scale, q_positions=q_positions,
                    selected_block_ids=selected),
                "reference_cpu",
            )

    top_k_blocks_arg = kwargs.get("top_k_blocks")
    if top_k_blocks_arg is None:
        raise ValueError("dsa_block_sparse_attention requires top_k_blocks")
    top_k_blocks = int(top_k_blocks_arg)
    selected = kwargs.get("selected_block_ids")
    if selected is None and len(names) >= 4:
        selected = values[names[3]]
    if selected is None:
        selected = _dsa_selected_block_ids(
            Q, K, np, top_k_blocks=top_k_blocks, block_size=block_size,
            causal=causal, q_positions=q_positions)
    try:
        return (
            _rocm_selected_block_attention_native(
                Q, K, V, selected, np, block_size=block_size, causal=causal,
                q_positions=q_positions, scale=scale, tiled=use_tiled),
            "native_gpu",
        )
    except _RocmCompiledUnavailable:
        return (
            _attn.dsa_block_sparse_attention(
                Q, K, V, top_k_blocks=top_k_blocks, block_size=block_size,
                causal=causal, scale=scale, q_positions=q_positions),
            "reference_cpu",
        )


def _rocm_spmm_csr(indptr: Any, indices: Any, values: Any, B: Any,
                   m: int, n: int, np: Any) -> Any:
    """C[m,n] = A_csr @ B[K,n] on the gfx1151 row-wise SpMM kernel. f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.spmm"() {name = "sp"} '
                 ': () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-spmm-kernel", directive, _rocm_spmm_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm spmm: hipInit failed")
    ip = np.ascontiguousarray(indptr, np.int32)
    ix = np.ascontiguousarray(indices, np.int32)
    vv = np.ascontiguousarray(values, np.float32)
    bc = np.ascontiguousarray(B, np.float32).reshape(-1)
    out = np.zeros(m * n, np.float32)
    d_ip = _rocm_dev_in(hip, ip, 4 * ip.size)
    d_ix = _rocm_dev_in(hip, ix, 4 * ix.size)
    d_vv = _rocm_dev_in(hip, vv, 4 * vv.size)
    d_bc = _rocm_dev_in(hip, bc, 4 * bc.size)
    d_out = _rocm_dev_in(hip, out, 4 * out.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"sp",
            [(d_ip, ip.size), (d_ix, ix.size), (d_vv, vv.size),
             (d_bc, bc.size), (d_out, out.size)],
            [m, n], m * n)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_out,
                      4 * out.size, 2)
    finally:
        for d in (d_ip, d_ix, d_vv, d_bc, d_out):
            hip.hipFree(d)
    return out.reshape(m, n)


def _rocm_sddmm(A: Any, B: Any, mask: Any, np: Any) -> Any:
    """OUT[M,N] = (A[M,K] @ B[K,N]) ⊙ mask on the gfx1151 sampled kernel. f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.sddmm"() {name = "sd"} '
                 ': () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-sddmm-kernel", directive, _rocm_sddmm_hsaco_cache,
        (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm sddmm: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    bt = np.ascontiguousarray(np.asarray(B, np.float32).T)
    mk = np.ascontiguousarray(mask, np.float32).reshape(-1)
    m, k = int(a.shape[0]), int(a.shape[1])
    n = int(bt.shape[0])
    out = np.zeros(m * n, np.float32)
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_bt = _rocm_dev_in(hip, bt.reshape(-1), 4 * bt.size)
    d_mk = _rocm_dev_in(hip, mk, 4 * mk.size)
    d_out = _rocm_dev_in(hip, out, 4 * out.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"sd",
            [(d_a, a.size), (d_bt, bt.size), (d_mk, mk.size),
             (d_out, out.size)],
            [m, n, k], m * n)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_out,
                      4 * out.size, 2)
    finally:
        for d in (d_a, d_bt, d_mk, d_out):
            hip.hipFree(d)
    return out.reshape(m, n)


def _execute_rocm_compiled_sparse(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` sparse lane: spmm_csr / spmm_coo / sddmm / bsmm on
    the COMPILER-GENERATED gfx1151 sparse kernels (CSR SpMM + sampled SDDMM) +
    the ROCm matmul lane for bsmm. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _SPARSE_OPS:
        raise ValueError(
            f"rocm_sparse_compiled executor handles one of {_SPARSE_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands = [values[str(n)] for n in op.get("operands", [])]

    def _spmm(indptr, indices, vals, b, m, n):
        return _rocm_spmm_csr(indptr, indices, vals, b, m, n, np)

    def _bsmm(x, w):
        bf16 = _bfloat16_dtype()
        if bf16 is None:
            raise _RocmCompiledUnavailable("rocm bsmm needs bf16 (ml_dtypes)")
        return _rocm_wmma_gemm_2d(np.asarray(x, bf16), np.asarray(w, bf16))

    return _sparse_compute(
        op_name, operands, _spmm,
        lambda a, b, mk: _rocm_sddmm(a, b, mk, np), _bsmm, np)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED state-space lane — Mamba2 selective scan (one thread per (b,d)).
# compiler_path="rocm_selective_ssm_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_rocm_ssm_hsaco_cache: dict[tuple[str, str], bytes] = {}


def _rocm_selective_ssm(x: Any, A: Any, B: Any, C: Any, delta: Any,
                        gate: Any, state: Any, np: Any) -> Any:
    """y[B,S,D] = Mamba2 selective scan on the gfx1151 kernel. x/A/B/C/delta + y
    storage is f32/f16/bf16 (the state + exp + accumulate stay f32 in-kernel).

    All dtypes run the exact sequential per-(b,d) scan here — the chunked-parallel
    SSD form is x86-only: ROCm's only batched GEMM is WMMA (f16/bf16 inputs), so a
    chunked f32 path would have to cast the C·B / state-update contractions to
    f16, overflowing (→inf/NaN) on valid f32 inputs whose magnitude exceeds the
    fp16 range. Keeping f32 (and low-precision) on this scan stays finite + exact.
    """
    store = _ssm_store_dtype(x, np)
    esz = 4 if store == np.float32 else 2                       # bytes/element
    dtag = ("f16" if store == np.float16
            else "f32" if store == np.float32 else "bf16")
    chip = _rocm_chip()
    dattr = "" if dtag == "f32" else f', dtype = "{dtag}"'
    directive = ('module {\n  "tessera_rocm.selective_ssm"() {name = "ss"'
                 f'{dattr}}} : () -> ()\n}}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-selective-ssm-kernel", directive, _rocm_ssm_hsaco_cache,
        (chip, dtag))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm ssm: hipInit failed")
    x, a2d, Bc, Cc, dl, h, bsz, s, d, n = _ssm_prepare(
        x, A, B, C, delta, state, np, store=store)
    y = np.zeros(bsz * s * d, store)
    d_x = _rocm_dev_in(hip, x.reshape(-1), esz * x.size)
    d_a = _rocm_dev_in(hip, a2d.reshape(-1), esz * a2d.size)
    d_b = _rocm_dev_in(hip, Bc.reshape(-1), esz * Bc.size)
    d_c = _rocm_dev_in(hip, Cc.reshape(-1), esz * Cc.size)
    d_dl = _rocm_dev_in(hip, dl.reshape(-1), esz * dl.size)
    d_h = _rocm_dev_in(hip, h.reshape(-1), 4 * h.size)         # h is f32 scratch
    d_y = _rocm_dev_in(hip, y, esz * y.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"ss",
            [(d_x, x.size), (d_a, a2d.size), (d_b, Bc.size), (d_c, Cc.size),
             (d_dl, dl.size), (d_h, h.size), (d_y, y.size)],
            [bsz, s, d, n], bsz * d)
        hip.hipMemcpy(y.ctypes.data_as(ctypes.c_void_p), d_y, esz * y.size, 2)
    finally:
        for dev in (d_x, d_a, d_b, d_c, d_dl, d_h, d_y):
            hip.hipFree(dev)
    out = y.reshape(bsz, s, d)
    if gate is not None:
        out = out * np.ascontiguousarray(gate, store)
    return out


_rocm_ssm_bwd_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_selective_ssm_bwd(x, A, B, C, delta, dout, gate, state, np):
    """Reverse-mode adjoint of selective_ssm on the gfx1151 backward kernel
    (one thread per (b,d), atomic cross-channel reductions). Returns
    (dx, dA, dB, dC, ddelta) — matches autodiff.vjp.vjp_selective_ssm. f32."""
    (xa, a2d, Bc, Cc, dl, dy, bsz, s, d, n, a1d, h_traj,
     dx, dA2d, dBg, dCg, dd) = _ssm_bwd_prepare(
        x, A, B, C, delta, dout, gate, state, np)
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.selective_ssm_bwd"() {name = "ssb"} '
                 ': () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-selective-ssm-bwd-kernel", directive,
        _rocm_ssm_bwd_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm ssm_bwd: hipInit failed")
    dh = np.zeros((bsz, d, n), np.float32)
    # dx/dA2d/dB/dC/ddelta must be zero on device — the kernel accumulates into
    # them (atomics for the cross-channel reductions). _rocm_dev_in copies the
    # zeroed host arrays up.
    d_x = _rocm_dev_in(hip, xa.reshape(-1), 4 * xa.size)
    d_a = _rocm_dev_in(hip, a2d.reshape(-1), 4 * a2d.size)
    d_b = _rocm_dev_in(hip, Bc.reshape(-1), 4 * Bc.size)
    d_c = _rocm_dev_in(hip, Cc.reshape(-1), 4 * Cc.size)
    d_dl = _rocm_dev_in(hip, dl.reshape(-1), 4 * dl.size)
    d_dy = _rocm_dev_in(hip, dy.reshape(-1), 4 * dy.size)
    d_ht = _rocm_dev_in(hip, h_traj.reshape(-1), 4 * h_traj.size)
    d_dh = _rocm_dev_in(hip, dh.reshape(-1), 4 * dh.size)
    d_dx = _rocm_dev_in(hip, dx.reshape(-1), 4 * dx.size)
    d_dA = _rocm_dev_in(hip, dA2d.reshape(-1), 4 * dA2d.size)
    d_dB = _rocm_dev_in(hip, dBg.reshape(-1), 4 * dBg.size)
    d_dC = _rocm_dev_in(hip, dCg.reshape(-1), 4 * dCg.size)
    d_dd = _rocm_dev_in(hip, dd.reshape(-1), 4 * dd.size)
    devs = (d_x, d_a, d_b, d_c, d_dl, d_dy, d_ht, d_dh,
            d_dx, d_dA, d_dB, d_dC, d_dd)
    try:
        _rocm_sparse_launch(
            hsaco, b"ssb",
            [(d_x, xa.size), (d_a, a2d.size), (d_b, Bc.size), (d_c, Cc.size),
             (d_dl, dl.size), (d_dy, dy.size), (d_ht, h_traj.size),
             (d_dh, dh.size), (d_dx, dx.size), (d_dA, dA2d.size),
             (d_dB, dBg.size), (d_dC, dCg.size), (d_dd, dd.size)],
            [bsz, s, d, n], bsz * d)
        cv = ctypes.c_void_p
        for host, dev in ((dx, d_dx), (dA2d, d_dA), (dBg, d_dB),
                          (dCg, d_dC), (dd, d_dd)):
            hip.hipMemcpy(host.ctypes.data_as(cv), dev, 4 * host.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)
    dA = dA2d.sum(axis=1) if a1d else dA2d
    return dx, dA, dBg, dCg, dd


_rocm_moe_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_moe(x: Any, experts: Any, route: Any, scores: Any, np: Any) -> Any:
    """MoE compute — routed per-token expert GEMVs (top-1) on the gfx1151 kernel.
    f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.moe"() {name = "mo"} : () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-moe-kernel", directive, _rocm_moe_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm moe: hipInit failed")
    tk, ex, r, lead, in_dim, out_dim = _moe_prepare(x, experts, route, scores, np)
    t = int(tk.shape[0])
    out = np.zeros(t * out_dim, np.float32)
    d_x = _rocm_dev_in(hip, tk.reshape(-1), 4 * tk.size)
    d_e = _rocm_dev_in(hip, ex.reshape(-1), 4 * ex.size)
    d_r = _rocm_dev_in(hip, r, 4 * r.size)
    d_o = _rocm_dev_in(hip, out, 4 * out.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"mo",
            [(d_x, tk.size), (d_e, ex.size), (d_r, r.size), (d_o, out.size)],
            [t, in_dim, out_dim], t * out_dim)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_o, 4 * out.size, 2)
    finally:
        for d in (d_x, d_e, d_r, d_o):
            hip.hipFree(d)
    return out.reshape(lead + (out_dim,))


def _execute_rocm_compiled_moe(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` moe-compute lane: routed per-token expert GEMVs
    (top-1) on the COMPILER-GENERATED gfx1151 kernel. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name != "tessera.moe":
        raise ValueError(
            "rocm_moe_compiled executor handles tessera.moe; "
            f"got {[o.get('op_name') for o in ops]!r}")
    values = _bind_launch_args(args, arg_names)
    x, experts, route, scores = _moe_bind(ops[0], values)
    return _rocm_moe(x, experts, route, scores, np)


_rocm_opt_hsaco_cache: dict[tuple[str, str], bytes] = {}
_OPTIMIZER_KIND_STR = {0: "sgd", 1: "momentum", 2: "adam", 3: "adamw", 4: "lion",
                       5: "nesterov"}


def _rocm_optimizer_kernel(kind: int, p: Any, g: Any, m: Any, v: Any, n: int,
                           lr: float, b1: float, b2: float, eps: float,
                           wd: float, b1c: float, b2c: float) -> tuple:
    """One fused optimizer step over a flat parameter array on the gfx1151
    kernel (kind StrAttr-selected). Returns (p_out, m_out, v_out). f32."""
    import numpy as np
    chip = _rocm_chip()
    kstr = _OPTIMIZER_KIND_STR[kind]
    directive = ('module {\n  "tessera_rocm.optimizer"() {name = "op", '
                 f'kind = "{kstr}"}} : () -> ()\n}}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-optimizer-kernel", directive, _rocm_opt_hsaco_cache,
        (chip, kstr))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm optimizer: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm optimizer: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"op") != 0:
        raise RuntimeError("rocm optimizer: kernel symbol 'op' not found")
    pf = np.ascontiguousarray(p, np.float32).reshape(-1)
    gf = np.ascontiguousarray(g, np.float32).reshape(-1)
    mf = np.ascontiguousarray(m, np.float32).reshape(-1)
    vf = np.ascontiguousarray(v, np.float32).reshape(-1)
    p_out = np.zeros(n, np.float32)
    m_out = np.zeros(n, np.float32)
    v_out = np.zeros(n, np.float32)
    d_p = _rocm_dev_in(hip, pf, 4 * n)
    d_g = _rocm_dev_in(hip, gf, 4 * n)
    d_m = _rocm_dev_in(hip, mf, 4 * n)
    d_v = _rocm_dev_in(hip, vf, 4 * n)
    d_po = _rocm_dev_in(hip, p_out, 4 * n)
    d_mo = _rocm_dev_in(hip, m_out, 4 * n)
    d_vo = _rocm_dev_in(hip, v_out, 4 * n)

    def _mr(dev):
        return [ctypes.c_void_p(dev.value), ctypes.c_void_p(dev.value),
                ctypes.c_int64(0), ctypes.c_int64(n), ctypes.c_int64(1)]

    launch_args: list = []
    for dev in (d_p, d_g, d_m, d_v, d_po, d_mo, d_vo):
        launch_args += _mr(dev)
    launch_args.append(ctypes.c_int64(n))
    launch_args += [ctypes.c_float(x) for x in
                    (lr, b1, b2, eps, wd, b1c, b2c)]
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    try:
        rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                       0, None, arr, None)
        if rc != 0:
            raise RuntimeError(f"rocm optimizer: launch failed rc={rc}")
        hip.hipDeviceSynchronize()
        for host, dev in ((p_out, d_po), (m_out, d_mo), (v_out, d_vo)):
            hip.hipMemcpy(host.ctypes.data_as(ctypes.c_void_p), dev, 4 * n, 2)
    finally:
        for dev in (d_p, d_g, d_m, d_v, d_po, d_mo, d_vo):
            hip.hipFree(dev)
    return p_out, m_out, v_out


def _execute_rocm_compiled_optimizer(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` optimizer lane: sgd / momentum / adam / adamw / lion
    per-parameter update on the COMPILER-GENERATED gfx1151 kernel. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
