# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED linalg lane — Cholesky factorization + triangular solve.
# compiler_path="rocm_linalg_compiled".
# ─────────────────────────────────────────────────────────────────────────────
_rocm_chol_hsaco_cache: dict[tuple[str], bytes] = {}
_rocm_tri_hsaco_cache: dict[tuple[str, bool], bytes] = {}


def _rocm_cholesky(A: Any, np: Any) -> Any:
    """L[..,n,n] lower s.t. A=L·Lᵀ on the gfx1151 batched Cholesky kernel. f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.cholesky"() {name = "ch"} '
                 ': () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-cholesky-kernel", directive, _rocm_chol_hsaco_cache,
        (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm cholesky: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    n = int(a.shape[-1])
    batch = int(a.size // (n * n))
    out = np.zeros(a.size, np.float32)
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_l = _rocm_dev_in(hip, out, 4 * out.size)
    try:
        _rocm_sparse_launch(hsaco, b"ch", [(d_a, a.size), (d_l, out.size)],
                            [batch, n], batch)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_l, 4 * out.size, 2)
    finally:
        for d in (d_a, d_l):
            hip.hipFree(d)
    return out.reshape(a.shape)


def _rocm_tri_solve_raw(A: Any, B: Any, lower: bool, np: Any) -> Any:
    """A[..,n,n] · X = B[..,n,m] on the gfx1151 triangular-solve kernel. f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.tri_solve"() {name = "ts", '
                 f'lower = {"true" if lower else "false"}}} : () -> ()\n}}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-tri-solve-kernel", directive, _rocm_tri_hsaco_cache,
        (chip, bool(lower)))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm tri_solve: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    bb = np.ascontiguousarray(B, np.float32)
    n = int(a.shape[-1])
    m = int(bb.shape[-1])
    batch = int(a.size // (n * n))
    out = np.zeros(bb.size, np.float32)
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_b = _rocm_dev_in(hip, bb.reshape(-1), 4 * bb.size)
    d_x = _rocm_dev_in(hip, out, 4 * out.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"ts",
            [(d_a, a.size), (d_b, bb.size), (d_x, out.size)],
            [batch, n, m], batch * m)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_x, 4 * out.size, 2)
    finally:
        for d in (d_a, d_b, d_x):
            hip.hipFree(d)
    return out.reshape(bb.shape)


_rocm_lu_hsaco_cache: dict[tuple[str], bytes] = {}
_rocm_qr_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_lu(A: Any, np: Any) -> tuple:
    """getrf — A[..,n,n] → (packed LU[..,n,n], pivots[..,n] int32) on gfx1151."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.lu"() {name = "lu"} : () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-lu-kernel", directive, _rocm_lu_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm lu: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    n = int(a.shape[-1])
    batch = int(a.size // (n * n))
    lu = np.zeros(a.size, np.float32)
    piv = np.zeros(batch * n, np.int32)
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_lu = _rocm_dev_in(hip, lu, 4 * lu.size)
    d_pv = _rocm_dev_in(hip, piv, 4 * piv.size)
    try:
        _rocm_sparse_launch(hsaco, b"lu",
                            [(d_a, a.size), (d_lu, lu.size), (d_pv, piv.size)],
                            [batch, n], batch)
        hip.hipMemcpy(lu.ctypes.data_as(ctypes.c_void_p), d_lu, 4 * lu.size, 2)
        hip.hipMemcpy(piv.ctypes.data_as(ctypes.c_void_p), d_pv, 4 * piv.size, 2)
    finally:
        for d in (d_a, d_lu, d_pv):
            hip.hipFree(d)
    return lu.reshape(a.shape), piv.reshape(a.shape[:-1])


def _rocm_qr(A: Any, np: Any) -> tuple:
    """Householder QR — A[..,m,n] → reduced (Q[..,m,k], R[..,k,n]) on gfx1151."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.qr"() {name = "qr"} : () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-qr-kernel", directive, _rocm_qr_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm qr: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    m, n = int(a.shape[-2]), int(a.shape[-1])
    k = min(m, n)
    batch = int(a.size // (m * n))
    q = np.zeros(batch * m * m, np.float32)
    r = np.zeros(batch * m * n, np.float32)
    vscratch = np.zeros(batch * m, np.float32)
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_q = _rocm_dev_in(hip, q, 4 * q.size)
    d_r = _rocm_dev_in(hip, r, 4 * r.size)
    d_v = _rocm_dev_in(hip, vscratch, 4 * vscratch.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"qr",
            [(d_a, a.size), (d_q, q.size), (d_r, r.size), (d_v, vscratch.size)],
            [batch, m, n], batch)
        hip.hipMemcpy(q.ctypes.data_as(ctypes.c_void_p), d_q, 4 * q.size, 2)
        hip.hipMemcpy(r.ctypes.data_as(ctypes.c_void_p), d_r, 4 * r.size, 2)
    finally:
        for d in (d_a, d_q, d_r, d_v):
            hip.hipFree(d)
    qf = q.reshape(a.shape[:-2] + (m, m))[..., :, :k]
    rf = r.reshape(a.shape[:-2] + (m, n))[..., :k, :]
    return np.ascontiguousarray(qf), np.ascontiguousarray(rf)


_rocm_svd_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_svd_mn(A: Any, np: Any) -> tuple:
    """One-sided Jacobi SVD for m≥n — A[..,m,n] → (U[..,m,n], S[..,n],
    Vh[..,n,n]) on the gfx1151 kernel. f32."""
    chip = _rocm_chip()
    directive = ('module {\n  "tessera_rocm.svd"() {name = "sv"} : () -> ()\n}\n')
    hsaco = _build_rocm_elementwise_hsaco(
        "generate-rocm-svd-kernel", directive, _rocm_svd_hsaco_cache, (chip,))
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm svd: hipInit failed")
    a = np.ascontiguousarray(A, np.float32)
    m, n = int(a.shape[-2]), int(a.shape[-1])
    batch = int(a.size // (m * n))
    u = np.zeros(batch * m * n, np.float32)
    s = np.zeros(batch * n, np.float32)
    vt = np.zeros(batch * n * n, np.float32)
    uc = np.zeros(batch * n * m, np.float32)   # column-major working scratch
    vc = np.zeros(batch * n * n, np.float32)   # V scratch
    d_a = _rocm_dev_in(hip, a.reshape(-1), 4 * a.size)
    d_u = _rocm_dev_in(hip, u, 4 * u.size)
    d_s = _rocm_dev_in(hip, s, 4 * s.size)
    d_vt = _rocm_dev_in(hip, vt, 4 * vt.size)
    d_uc = _rocm_dev_in(hip, uc, 4 * uc.size)
    d_vc = _rocm_dev_in(hip, vc, 4 * vc.size)
    try:
        _rocm_sparse_launch(
            hsaco, b"sv",
            [(d_a, a.size), (d_u, u.size), (d_s, s.size), (d_vt, vt.size),
             (d_uc, uc.size), (d_vc, vc.size)],
            [batch, m, n], batch)
        hip.hipMemcpy(u.ctypes.data_as(ctypes.c_void_p), d_u, 4 * u.size, 2)
        hip.hipMemcpy(s.ctypes.data_as(ctypes.c_void_p), d_s, 4 * s.size, 2)
        hip.hipMemcpy(vt.ctypes.data_as(ctypes.c_void_p), d_vt, 4 * vt.size, 2)
    finally:
        for d in (d_a, d_u, d_s, d_vt, d_uc, d_vc):
            hip.hipFree(d)
    return (u.reshape(a.shape[:-2] + (m, n)), s.reshape(a.shape[:-2] + (n,)),
            vt.reshape(a.shape[:-2] + (n, n)))


def _execute_rocm_compiled_linalg(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` linalg lane: cholesky / tri_solve / cholesky_solve on
    the COMPILER-GENERATED gfx1151 Cholesky + triangular-solve kernels. f32."""
    import numpy as np
    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _LINALG_OPS:
        raise ValueError(
            f"rocm_linalg_compiled executor handles one of {_LINALG_OPS}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    values = _bind_launch_args(args, arg_names)
    operands: list = [values[str(n)] for n in op.get("operands", [])]
    if op_name == "tessera.tri_solve":
        operands = operands[:2] + [op.get("kwargs") or {}]
    return _linalg_compute(op_name, operands,
                           lambda a: _rocm_cholesky(a, np),
                           lambda a, b, lo: _rocm_tri_solve_raw(a, b, lo, np),
                           lambda a: _rocm_lu(a, np),
                           lambda a: _rocm_qr(a, np),
                           lambda a: _rocm_svd_mn(a, np), np)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED alibi lane (2026-06-25) — ALiBi positional-bias generator
# bias[h,i,j] = slope[h]·(j−i), shape [H, S, S], a flat elementwise kernel
# (sibling of the rope lane). ``compiler_path = "rocm_alibi_compiled"``. Slopes
# default to the 2^(-8(k+1)/H) ramp; f32/f16/bf16 output. ONE hsaco per
# (chip, dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_alibi_hsaco_cache: dict[tuple[str, str], bytes] = {}


def _build_compiled_alibi_hsaco(dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.alibi"() {{name = "ab", dtype = "{dtype}"}} '
        ': () -> ()\n}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-alibi-kernel", directive,
        _rocm_alibi_hsaco_cache, (chip, dtype))


def _execute_rocm_compiled_alibi(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` alibi lane: run the COMPILER-GENERATED ALiBi
    positional-bias generator — bias[h,i,j] = slope[h]·(j−i), shape [H, S, S]
    (one thread per element). ``num_heads`` / ``seq_len`` from kwargs; the
    optional ``slopes`` operand overrides the default 2^(-8(k+1)/H) ramp.
    f32/f16/bf16 output."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) != "tessera.alibi":
        raise ValueError(
            "rocm_alibi_compiled executor handles exactly one tessera.alibi op; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    operand_names = [str(n) for n in op.get("operands", [])]
    values = _bind_launch_args(args, arg_names) if arg_names else {}

    h_val = kwargs.get("num_heads")
    s_val = kwargs.get("seq_len")
    if h_val is None or s_val is None:
        raise ValueError("alibi requires num_heads and seq_len")
    hh = int(h_val)
    ss = int(s_val)
    if hh <= 0 or ss <= 0:
        raise ValueError(f"alibi needs positive num_heads/seq_len; got {hh}/{ss}")

    if operand_names:
        slopes = np.ascontiguousarray(
            _as_numpy(values[operand_names[0]]), dtype=np.float32).reshape(-1)
        if slopes.size != hh:
            raise ValueError(
                f"alibi slopes must have length num_heads={hh}; got {slopes.size}")
    else:
        k = np.arange(1, hh + 1, dtype=np.float32)
        slopes = (2.0 ** (-8.0 * k / hh)).astype(np.float32)

    dtype_tag = str(kwargs.get("dtype", "f32"))
    store: Any  # numpy dtype varies per branch (f32 / f16 / bf16)
    if dtype_tag in ("f32", "float32"):
        store, esz = np.float32, 4
        dtype_tag = "f32"
    elif dtype_tag in ("f16", "float16"):
        store, esz = np.float16, 2
        dtype_tag = "f16"
    elif dtype_tag in ("bf16", "bfloat16"):
        bf16 = _bfloat16_dtype()
        if bf16 is None:
            raise ValueError("alibi bf16 output needs ml_dtypes")
        store, esz = bf16, 2
        dtype_tag = "bf16"
    else:
        raise ValueError(f"alibi dtype must be f32/f16/bf16; got {dtype_tag}")

    hsaco = _build_compiled_alibi_hsaco(dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm alibi: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm alibi: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"ab") != 0:
        raise RuntimeError("rocm alibi: kernel symbol 'ab' not found")

    n = hh * ss * ss
    o = np.zeros(n, dtype=store)
    dslopes, do = ctypes.c_void_p(), ctypes.c_void_p()
    if hip.hipMalloc(ctypes.byref(dslopes), 4 * hh) != 0:
        raise RuntimeError("rocm alibi: hipMalloc failed")
    if hip.hipMalloc(ctypes.byref(do), esz * n) != 0:
        raise RuntimeError("rocm alibi: hipMalloc failed")
    hip.hipMemcpy(dslopes, slopes.ctypes.data_as(ctypes.c_void_p), 4 * hh, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dslopes, hh) + _mr(do, n)
                   + [ctypes.c_int64(hh), ctypes.c_int64(ss)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    gx = (n + _GRID_BLOCKDIM - 1) // _GRID_BLOCKDIM
    rc = hip.hipModuleLaunchKernel(fn, gx, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (dslopes, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm alibi: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (dslopes, do):
        hip.hipFree(dev)
    return o.reshape(hh, ss, ss)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED rope lane (2026-06-25) — rotary position embedding (interleaved
# pairs). ``compiler_path = "rocm_rope_compiled"``. One workgroup per row; X and
# Theta are both [M, D] (D even). f32/f16/bf16, f32 cos/sin.
# ─────────────────────────────────────────────────────────────────────────────
def _build_compiled_rope_hsaco(dtype: str = "f32") -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        f'  "tessera_rocm.rope"() {{name = "r", dtype = "{dtype}"}} : () -> ()\n'
        '}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-rope-kernel", directive,
        _rocm_rope_hsaco_cache, (chip, dtype))


def _execute_rocm_compiled_rope(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` rope lane: run the COMPILER-GENERATED interleaved-
    pair rotary-position-embedding kernel. Operands X, Theta are both ``[..., D]``
    (D even, same shape); one workgroup per row. f32/f16/bf16."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    if len(ops) != 1 or str(ops[0].get("op_name", "")) != "tessera.rope":
        raise ValueError(
            "rocm_rope_compiled executor handles exactly one tessera.rope op; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    if len(operand_names) < 2:
        raise ValueError("rope requires two operands (x, theta)")
    values = _bind_launch_args(args, arg_names)
    x = _as_numpy(values[operand_names[0]])
    theta = _as_numpy(values[operand_names[1]])
    if x.ndim < 1 or int(x.shape[-1]) % 2 != 0:
        raise ValueError(
            f"rope needs an even innermost dim; got x{x.shape}")
    if theta.shape != x.shape:
        raise ValueError(
            f"rope requires theta to match x shape; got x{x.shape} "
            f"theta{theta.shape}")
    d = int(x.shape[-1])
    m = int(np.prod(x.shape[:-1])) if x.ndim > 1 else 1

    store: Any
    if x.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif x.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(f"rocm rope lane handles f32/f16/bf16; got {x.dtype}")
    # The angle table may be kept in fp32 even when x is half precision — a common
    # setup (nn.RotaryEmbedding defaults its theta table to fp32) the reference
    # path already handles. The device copy below casts theta to x's storage dtype
    # (np.ascontiguousarray(theta, dtype=store)), so mixed float storage is fine;
    # only reject a non-floating theta, which would silently produce wrong angles.
    _bf16 = _bfloat16_dtype()
    _theta_floats = (np.float32, np.float16) + ((_bf16,) if _bf16 is not None else ())
    if theta.dtype not in _theta_floats:
        raise ValueError(
            "rope theta must be a floating dtype (f32/f16/bf16); got "
            f"{theta.dtype} (the angle table is cast to x's storage dtype)")

    hsaco = _build_compiled_rope_hsaco(dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm rope: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm rope: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"r") != 0:
        raise RuntimeError("rocm rope: kernel symbol 'r' not found")

    xc = np.ascontiguousarray(x, dtype=store).reshape(-1)
    tc = np.ascontiguousarray(theta, dtype=store).reshape(-1)
    n = m * d
    o = np.zeros(n, dtype=store)
    dx, dt, do = ctypes.c_void_p(), ctypes.c_void_p(), ctypes.c_void_p()
    for dev in (dx, dt, do):
        if hip.hipMalloc(ctypes.byref(dev), esz * n) != 0:
            raise RuntimeError("rocm rope: hipMalloc failed")
    hip.hipMemcpy(dx, xc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)
    hip.hipMemcpy(dt, tc.ctypes.data_as(ctypes.c_void_p), esz * n, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dx, n) + _mr(dt, n) + _mr(do, n)
                   + [ctypes.c_int64(m), ctypes.c_int64(d)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, m, 1, 1, _GRID_BLOCKDIM, 1, 1,
                                   0, None, arr, None)
    if rc != 0:
        for dev in (dx, dt, do):
            hip.hipFree(dev)
        raise RuntimeError(f"rocm rope: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), do, esz * n, 2)
    for dev in (dx, dt, do):
        hip.hipFree(dev)
    return o.reshape(x.shape)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED exotic-attention compositions (2026-06-25) — gated_attention,
# mla_decode, mla_decode_fused, all built by COMPOSING already-compiled lanes:
# the WMMA flash_attn kernel + the WMMA GEMM kernel (for MLA's latent
# projections) + an elementwise gate. ``compiler_path = "rocm_exotic_attn_compiled"``.
# This is the attention analog of the matmul-family lane — no new MLIR pass.
# The hybrid_attention policy wrapper delegates to the already-compiled
# linear/delta lanes where possible, and DeepSeek sparse attention now lives in
# the DK2 rocm_sparse_attn_compiled lane.
# ─────────────────────────────────────────────────────────────────────────────
def _rocm_flash_attn(q: Any, k: Any, v: Any, *, scale: Any = None,
                     causal: bool = True, attn_bias: Any = None) -> Any:
    """Run the COMPILER-GENERATED WMMA flash_attn forward on Q/K/V via the
    flash_attn executor (constructs a minimal sub-artifact). Returns the f32
    attention output shaped like Q. An optional ``attn_bias`` (additive, shape
    broadcastable to Q.lead+(Sq,Sk)) routes through the bias kernel variant:
    ``O = softmax(scale·Q@K^T + attn_bias)·V``."""
    kw: dict[str, Any] = {"causal": bool(causal)}
    if scale is not None:
        kw["scale"] = float(scale)
    arg_names = ["q", "k", "v"]
    operands = ["q", "k", "v"]
    call_args: tuple[Any, ...] = (q, k, v)
    if attn_bias is not None:
        arg_names = ["q", "k", "v", "attn_bias"]
        operands = ["q", "k", "v", "attn_bias"]
        call_args = (q, k, v, attn_bias)
    sub = RuntimeArtifact(metadata={
        "target": "rocm", "compiler_path": "rocm_flash_attn_compiled",
        "executable": True, "execution_kind": "native_gpu",
        "arg_names": arg_names, "output_name": "o",
        "ops": [{"op_name": "tessera.flash_attn", "result": "o",
                 "operands": operands, "kwargs": kw}],
    })
    return _execute_rocm_compiled_flash_attn(sub, call_args)


def _rocm_project_last(x: Any, w: Any, store: Any) -> Any:
    """y = x[...,Dl] @ w[Dl, D] on the WMMA GEMM kernel, returned in `store`
    dtype (so the flash lane can consume it). Used for MLA latent projections."""
    import numpy as np
    dl, d = w.shape
    y = _rocm_wmma_gemm_2d(x.reshape(-1, dl), w).reshape(*x.shape[:-1], d)
    return np.ascontiguousarray(y, dtype=store)


_rocm_mla_absorb_decode_hsaco_cache: dict[tuple[str], bytes] = {}


def _rocm_mla_absorb_decode_hsaco() -> bytes:
    chip = _rocm_chip()
    directive = (
        'module {\n'
        '  "tessera_rocm.mla_absorb_decode"() {name = "mla"} : () -> ()\n'
        '}\n')
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-mla-absorb-decode-kernel", directive,
        _rocm_mla_absorb_decode_hsaco_cache, (chip,))


def _rocm_mla_decode_step_native(x_t: Any, latent_cache: Any, rope_cache: Any,
                                 weights: Any, np: Any, *,
                                 absorb: bool = True, scale: Any = None) -> Any:
    """DK1 ROCm absorbed-latent decode proof for stdlib.attention.mla_decode_step.

    The wrapper matches the stdlib cache side effects: append c/rope for x_t,
    read the full cache, project/rotate/scales Q on the host, then launch a
    ROCm kernel that computes attention directly from latent c + Wuk/Wuv.
    """
    if not absorb:
        raise _RocmCompiledUnavailable("rocm MLA decode_step native requires absorb=True")

    from .stdlib import attention as _attn

    hsaco = _rocm_mla_absorb_decode_hsaco()
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm MLA absorb decode: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm MLA absorb decode: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"mla") != 0:
        raise RuntimeError("rocm MLA absorb decode: kernel symbol 'mla' not found")

    xa = np.ascontiguousarray(_as_numpy(x_t), dtype=np.float32)
    if xa.ndim != 2:
        raise ValueError(f"mla_decode_step x_t must be rank-2; got {xa.shape}")
    kv_start = int(latent_cache.current_seq)
    c_new, kr_new = _attn.compress_latent(xa, weights)
    latent_cache.append(c_new)
    rope_cache.append(kr_new)
    c_all = np.ascontiguousarray(latent_cache.read(0, latent_cache.current_seq),
                                 dtype=np.float32)
    kr_all = np.ascontiguousarray(rope_cache.read(0, rope_cache.current_seq),
                                  dtype=np.float32)

    Hh = int(weights.num_heads)
    Dn = int(weights.d_nope)
    Dr = int(weights.d_rope)
    Dc = int(weights.d_c)
    Dv = int(weights.d_v)
    Sq = int(xa.shape[0])
    T = int(c_all.shape[0])
    if kr_all.shape != (T, Dr):
        raise ValueError(f"rope cache must be ({T}, {Dr}); got {kr_all.shape}")

    w_q = np.asarray(weights.w_q, dtype=np.float32)
    q = np.matmul(xa, w_q).reshape(Sq, Hh, Dn + Dr)
    q_nope = np.ascontiguousarray(q[..., :Dn], dtype=np.float32)
    q_pos = kv_start + np.arange(Sq)
    q_rope = _attn.apply_rope(q[..., Dn:].transpose(1, 0, 2), q_pos)
    q_rope = np.ascontiguousarray(q_rope.transpose(1, 0, 2), dtype=np.float32)
    sc = float(scale) if scale is not None else float(1.0 / np.sqrt(Dn + Dr))
    q_nope *= np.float32(sc)
    q_rope *= np.float32(sc)

    wuk = np.ascontiguousarray(
        np.asarray(weights.w_uk, dtype=np.float32).reshape(Dc, Hh, Dn))
    wuv = np.ascontiguousarray(
        np.asarray(weights.w_uv, dtype=np.float32).reshape(Dc, Hh, Dv))
    out = np.zeros((Sq, Hh, Dv), dtype=np.float32)

    devs: list[Any] = []
    try:
        d_qn = _rocm_dev_in(hip, q_nope.reshape(-1), 4 * q_nope.size); devs.append(d_qn)
        d_qr = _rocm_dev_in(hip, q_rope.reshape(-1), 4 * q_rope.size); devs.append(d_qr)
        d_c = _rocm_dev_in(hip, c_all.reshape(-1), 4 * c_all.size); devs.append(d_c)
        d_kr = _rocm_dev_in(hip, kr_all.reshape(-1), 4 * kr_all.size); devs.append(d_kr)
        d_wuk = _rocm_dev_in(hip, wuk.reshape(-1), 4 * wuk.size); devs.append(d_wuk)
        d_wuv = _rocm_dev_in(hip, wuv.reshape(-1), 4 * wuv.size); devs.append(d_wuv)
        d_o = _rocm_dev_in(hip, out.reshape(-1), 4 * out.size); devs.append(d_o)
        _rocm_sparse_launch(
            hsaco, b"mla",
            [(d_qn, q_nope.size), (d_qr, q_rope.size), (d_c, c_all.size),
             (d_kr, kr_all.size), (d_wuk, wuk.size), (d_wuv, wuv.size),
             (d_o, out.size)],
            [Sq, T, Hh, Dn, Dr, Dc, Dv, kv_start],
            Sq * Hh * Dv)
        hip.hipMemcpy(out.ctypes.data_as(ctypes.c_void_p), d_o,
                      4 * out.size, 2)
    finally:
        for dev in devs:
            hip.hipFree(dev)
    return out.reshape(Sq, Hh * Dv)


def _rocm_hybrid_attention_composed(
    Q: Any,
    K: Any,
    V: Any,
    np: Any,
    kwargs: dict[str, Any],
) -> tuple[Any, str]:
    """ROCm hybrid_attention policy wrapper.

    hybrid_attention is a named dispatch policy over already-proven lanes, not a
    separate math kernel.  Route the policies that map cleanly to ROCm compiled
    lanes, and fall back to the public reference when the selected slot is an
    MLA softmax/weight path or ROCm is unavailable.
    """
    from . import ops as _ops

    def _ref() -> tuple[Any, str]:
        return _ops.hybrid_attention(Q, K, V, **kwargs), "reference_cpu"

    if kwargs.get("return_state") or kwargs.get("state") is not None:
        return _ref()
    pattern = str(kwargs.get("pattern", "auto")).lower()
    layer_index = int(kwargs.get("layer_index", 0))
    causal = bool(kwargs.get("causal", True))

    def _artifact(path: str, op_name: str, names: list[str],
                  op_kwargs: dict[str, Any]) -> RuntimeArtifact:
        return RuntimeArtifact(metadata={
            "target": "rocm",
            "compiler_path": path,
            "executable": True,
            "execution_kind": "native_gpu",
            "arg_names": names,
            "output_name": "o",
            "ops": [{
                "op_name": op_name,
                "result": "o",
                "operands": names,
                "kwargs": op_kwargs,
            }],
        })

    def _linear_lightning_or_ref() -> tuple[Any, str]:
        art = _artifact(
            "rocm_linear_attn_compiled", "tessera.lightning_attention",
            ["Q", "K", "V"], {"causal": causal, "decay": kwargs.get("decay")})
        try:
            return _execute_rocm_compiled_linear_attn(art, (Q, K, V)), "native_gpu"
        except ValueError as exc:
            if "rocm linear_attn lane handles f16/bf16 storage" in str(exc):
                return _ref()
            raise

    try:
        if pattern in ("lightning", "auto"):
            return _linear_lightning_or_ref()
        if pattern in ("ling_1_7_mla_lightning", "ling2_5", "ling_2_5"):
            if layer_index % 8 == 7:
                return _ref()
            return _linear_lightning_or_ref()
        if pattern in ("gated_deltanet", "delta", "kimi_kda_mla", "kimi_linear", "kimi"):
            if pattern in ("kimi_kda_mla", "kimi_linear", "kimi") and layer_index % 2 == 1:
                return _ref()
            op_name = (
                "tessera.kimi_delta_attention"
                if pattern in ("kimi_kda_mla", "kimi_linear", "kimi")
                else "tessera.gated_deltanet"
            )
            names = ["Q", "K", "V"]
            operands: list[Any] = [Q, K, V]
            op_kwargs: dict[str, Any] = {"causal": causal}
            for key, name in (("gate", "gate"), ("beta", "beta"), ("decay", "decay")):
                val = kwargs.get(key)
                present = val is not None
                op_kwargs[f"has_{key}"] = present
                if present:
                    names.append(name)
                    operands.append(val)
            art = _artifact("rocm_deltanet_compiled", op_name, names, op_kwargs)
            return _execute_rocm_compiled_deltanet(art, tuple(operands)), "native_gpu"
    except _RocmCompiledUnavailable:
        return _ref()

    return _ref()


def _execute_rocm_compiled_exotic_attention(artifact: RuntimeArtifact,
                                            args: Any) -> Any:
    """The ``target="rocm"`` exotic-attention composition lane: gated_attention
    (flash × sigmoid-gate), mla_decode (latent K/V projections + flash), and
    mla_decode_fused (down/up projections + flash). All on the COMPILER-GENERATED
    WMMA flash_attn + GEMM kernels. f16/bf16 storage, f32 softmax+accumulate."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    handled = ("tessera.gated_attention", "tessera.hybrid_attention",
               "tessera.mla_decode", "tessera.mla_decode_fused",
               "tessera.mla_decode_step")
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in handled:
        raise ValueError(
            f"rocm_exotic_attn_compiled executor handles one of {handled}; "
            f"got {[o.get('op_name') for o in ops]!r}")
    op = ops[0]
    operand_names = [str(n) for n in op.get("operands", [])]
    kwargs = op.get("kwargs") or {}
    values = _bind_launch_args(args, arg_names)
    if op_name == "tessera.mla_decode_step":
        if len(operand_names) != 4:
            raise ValueError(
                "mla_decode_step takes (x_t, latent_cache, rope_cache, weights)")
        from .stdlib import attention as _attn
        try:
            out = _rocm_mla_decode_step_native(
                values[operand_names[0]], values[operand_names[1]],
                values[operand_names[2]], values[operand_names[3]], np,
                absorb=bool(kwargs.get("absorb", True)),
                scale=kwargs.get("scale"))
            return out, "native_gpu"
        except _RocmCompiledUnavailable:
            try:
                out = _attn.mla_decode_step(
                    values[operand_names[0]], values[operand_names[1]],
                    values[operand_names[2]], values[operand_names[3]],
                    absorb=bool(kwargs.get("absorb", True)),
                    scale=kwargs.get("scale"))
                return out, "reference_cpu"
            except KeyError as exc:
                raise ValueError(
                    f"missing mla_decode_step argument {exc.args[0]!r}") from exc

    operands = [_as_numpy(values[n]) for n in operand_names]
    if op_name == "tessera.hybrid_attention":
        if len(operands) != 3:
            raise ValueError("hybrid_attention takes (Q, K, V)")
        return _rocm_hybrid_attention_composed(
            operands[0], operands[1], operands[2], np, dict(kwargs))

    scale = kwargs.get("scale")
    causal = bool(kwargs.get("causal", True))

    def _store_of(x):
        if x.dtype == np.float16:
            return np.float16
        bf16 = _bfloat16_dtype()
        if bf16 is not None and x.dtype == bf16:
            return bf16
        raise ValueError(
            f"rocm exotic-attention lane needs f16/bf16 Q/K/V; got {x.dtype}")

    if op_name == "tessera.gated_attention":
        if len(operands) != 4:
            raise ValueError("gated_attention takes (Q, K, V, gate)")
        q, k, v, gate = operands
        attn = _rocm_flash_attn(q, k, v, scale=scale, causal=causal)
        g = np.asarray(gate).astype(np.float32)
        act = str(kwargs.get("gate_activation", "sigmoid"))
        if act == "sigmoid":
            g = (1.0 / (1.0 + np.exp(-g))).astype(np.float32)
        elif act not in ("identity", "none"):
            raise ValueError(
                "gate_activation must be 'sigmoid', 'identity', or 'none'")
        return attn * np.broadcast_to(g, attn.shape)

    if op_name == "tessera.mla_decode":
        if len(operands) not in (3, 5):
            raise ValueError(
                "mla_decode takes (Q, K_latent, V_latent[, W_k, W_v])")
        q = operands[0]
        store = _store_of(q)
        k = operands[1]
        v = operands[2]
        if len(operands) == 5:
            w_k, w_v = operands[3], operands[4]
            if w_k.ndim != 2 or w_v.ndim != 2:
                raise ValueError("mla_decode W_k/W_v must be rank-2")
            k = _rocm_project_last(k, w_k, store)
            v = _rocm_project_last(v, w_v, store)
        return _rocm_flash_attn(q, k, v, scale=scale, causal=causal)

    # tessera.mla_decode_fused — (x, w_dkv, w_uk, w_uv, q): c=x@w_dkv; K=c@w_uk;
    # V=c@w_uv; flash_attn(q, K, V). All four matmuls on the WMMA GEMM kernel.
    if len(operands) != 5:
        raise ValueError("mla_decode_fused takes (x, w_dkv, w_uk, w_uv, q)")
    x, w_dkv, w_uk, w_uv, q = operands
    store = _store_of(q)
    for w in (w_dkv, w_uk, w_uv):
        if w.ndim != 2:
            raise ValueError("mla_decode_fused weights must be rank-2")
    c = _rocm_project_last(x, w_dkv, store)            # x @ w_dkv
    k = _rocm_project_last(c, w_uk, store)             # c @ w_uk
    v = _rocm_project_last(c, w_uv, store)             # c @ w_uv
    return _rocm_flash_attn(q, k, v, scale=scale, causal=causal)


# ─────────────────────────────────────────────────────────────────────────────
# ROCm COMPILED DeltaNet scan lane (2026-06-25) — the gated/delta linear-
# attention recurrence (gated_deltanet / kimi_delta_attention /
# modified_delta_attention) as a causal sequential-scan kernel. The first
# RECURRENT compiled ROCm kernel (no existing lane composes it). One workgroup
# per (b,h), one thread per value-column; LDS state. ``compiler_path =
# "rocm_deltanet_compiled"``. f16/bf16/f32 storage, f32 compute. ONE hsaco per
# (chip, d_qk, d_v, flags, dtype), cached.
# ─────────────────────────────────────────────────────────────────────────────
_rocm_deltanet_hsaco_cache: dict[tuple, bytes] = {}


def _build_compiled_deltanet_hsaco(d_qk: int, d_v: int, erase: bool,
                                   modified: bool, has_gate: bool,
                                   has_beta: bool, has_decay: bool,
                                   dtype: str = "f32") -> bytes:
    chip = _rocm_chip()

    def _b(v: bool) -> str:
        return "true" if v else "false"

    directive = (
        'module {\n'
        f'  "tessera_rocm.deltanet"() {{name = "dn", d_qk = {d_qk} : i64, '
        f'd_v = {d_v} : i64, erase = {_b(erase)}, modified = {_b(modified)}, '
        f'has_gate = {_b(has_gate)}, has_beta = {_b(has_beta)}, '
        f'has_decay = {_b(has_decay)}, dtype = "{dtype}"}} : () -> ()\n}}\n')
    key = (chip, d_qk, d_v, erase, modified, has_gate, has_beta, has_decay,
           dtype)
    return _build_rocm_elementwise_hsaco(
        "generate-rocm-deltanet-kernel", directive, _rocm_deltanet_hsaco_cache,
        key)


#: op_name -> modified flag (only modified_delta_attention bounds the delta).
_ROCM_DELTANET_OPS = {
    "tessera.gated_deltanet": False,
    "tessera.kimi_delta_attention": False,
    "tessera.modified_delta_attention": True,
}


def _execute_rocm_compiled_deltanet(artifact: RuntimeArtifact, args: Any) -> Any:
    """The ``target="rocm"`` DeltaNet lane: run the COMPILER-GENERATED causal
    sequential-scan kernel for the gated/delta linear-attention recurrence.
    Operands [Q, K, V, gate?, beta?, decay?] (optionals in that order, presence
    via has_gate/has_beta/has_decay kwargs); ``erase`` kwarg; ``modified`` from
    the op name. Q/K [B,H,S,Dqk], V [B,H,S,Dv]; f16/bf16/f32 storage, f32
    compute. Causal-only (state=None, no state out)."""
    import numpy as np

    metadata = artifact.metadata or {}
    arg_names = list(metadata.get("arg_names") or [])
    ops = list(metadata.get("ops") or [])
    op_name = str(ops[0].get("op_name", "")) if len(ops) == 1 else ""
    if len(ops) != 1 or op_name not in _ROCM_DELTANET_OPS:
        raise ValueError(
            "rocm_deltanet_compiled executor handles exactly one of "
            f"{tuple(_ROCM_DELTANET_OPS)}; got {[o.get('op_name') for o in ops]!r}")
    modified = _ROCM_DELTANET_OPS[op_name]
    op = ops[0]
    kwargs = op.get("kwargs") or {}
    if not bool(kwargs.get("causal", True)):
        raise ValueError("rocm deltanet lane is causal-only")
    erase = bool(kwargs.get("erase", False))
    has_gate = bool(kwargs.get("has_gate", False))
    has_beta = bool(kwargs.get("has_beta", False))
    has_decay = bool(kwargs.get("has_decay", False))
    operand_names = [str(n) for n in op.get("operands", [])]
    values = _bind_launch_args(args, arg_names)
    operands = [_as_numpy(values[n]) for n in operand_names]
    need = 3 + has_gate + has_beta + has_decay
    if len(operands) != need:
        raise ValueError(
            f"deltanet expects {need} operands (Q,K,V + present optionals); "
            f"got {len(operands)}")
    q, k, v = operands[0], operands[1], operands[2]
    if q.ndim != 4 or k.ndim != 4 or v.ndim != 4:
        raise ValueError("deltanet expects rank-4 (B,H,S,D) Q/K/V")
    ptr = 3
    gate = operands[ptr] if has_gate else None
    ptr += 1 if has_gate else 0
    beta = operands[ptr] if has_beta else None
    ptr += 1 if has_beta else 0
    decay = operands[ptr] if has_decay else None

    B, H, S, d_qk = (int(x) for x in q.shape)
    d_v = int(v.shape[-1])
    if k.shape != q.shape or v.shape[:3] != q.shape[:3]:
        raise ValueError(
            f"deltanet K must match Q and V must share B,H,S; got Q{q.shape} "
            f"K{k.shape} V{v.shape}")
    bh = B * H

    store: Any  # numpy dtype varies per branch (f32 / f16 / bf16)
    if q.dtype == np.float32:
        dtype_tag, store, esz = "f32", np.float32, 4
    elif q.dtype == np.float16:
        dtype_tag, store, esz = "f16", np.float16, 2
    else:
        bf16 = _bfloat16_dtype()
        if bf16 is not None and q.dtype == bf16:
            dtype_tag, store, esz = "bf16", bf16, 2
        else:
            raise ValueError(f"rocm deltanet lane handles f16/bf16/f32; got {q.dtype}")

    hsaco = _build_compiled_deltanet_hsaco(
        d_qk, d_v, erase, modified, has_gate, has_beta, has_decay, dtype_tag)
    hip = _load_hip_for_launch()
    if hip is None:
        raise _RocmCompiledUnavailable("libamdhip64.so not loadable")
    if hip.hipInit(0) != 0:
        raise _RocmCompiledUnavailable("rocm deltanet: hipInit failed")
    mod = ctypes.c_void_p()
    if hip.hipModuleLoadData(ctypes.byref(mod), hsaco) != 0:
        raise _RocmCompiledUnavailable("rocm deltanet: no usable AMD GPU")
    fn = ctypes.c_void_p()
    if hip.hipModuleGetFunction(ctypes.byref(fn), mod, b"dn") != 0:
        raise RuntimeError("rocm deltanet: kernel symbol 'dn' not found")

    qc = np.ascontiguousarray(q, dtype=store).reshape(-1)
    kc = np.ascontiguousarray(k, dtype=store).reshape(-1)
    vc = np.ascontiguousarray(v, dtype=store).reshape(-1)
    n_qk, n_v, n_sc = bh * S * d_qk, bh * S * d_v, bh * S
    o = np.zeros(n_v, dtype=store)
    # storage-dtype gate (or len-1 dummy); f32 beta/decay (or len-1 dummy).
    gate_c = (np.ascontiguousarray(gate, dtype=store).reshape(-1)
              if has_gate else np.zeros(1, dtype=store))
    beta_c = (np.ascontiguousarray(beta, dtype=np.float32).reshape(-1)
              if has_beta else np.zeros(1, np.float32))
    decay_c = (np.ascontiguousarray(decay, dtype=np.float32).reshape(-1)
               if has_decay else np.zeros(1, np.float32))

    dQ, dK, dV, dO, dG = (ctypes.c_void_p() for _ in range(5))
    dBeta, dDecay = ctypes.c_void_p(), ctypes.c_void_p()
    allocs = [(dQ, esz * n_qk), (dK, esz * n_qk), (dV, esz * n_v),
              (dO, esz * n_v), (dG, esz * gate_c.size),
              (dBeta, 4 * beta_c.size), (dDecay, 4 * decay_c.size)]
    for dev, size in allocs:
        if hip.hipMalloc(ctypes.byref(dev), size) != 0:
            raise RuntimeError("rocm deltanet: hipMalloc failed")
    hip.hipMemcpy(dQ, qc.ctypes.data_as(ctypes.c_void_p), esz * n_qk, 1)
    hip.hipMemcpy(dK, kc.ctypes.data_as(ctypes.c_void_p), esz * n_qk, 1)
    hip.hipMemcpy(dV, vc.ctypes.data_as(ctypes.c_void_p), esz * n_v, 1)
    hip.hipMemcpy(dG, gate_c.ctypes.data_as(ctypes.c_void_p),
                  esz * gate_c.size, 1)
    hip.hipMemcpy(dBeta, beta_c.ctypes.data_as(ctypes.c_void_p),
                  4 * beta_c.size, 1)
    hip.hipMemcpy(dDecay, decay_c.ctypes.data_as(ctypes.c_void_p),
                  4 * decay_c.size, 1)

    def _mr(p, size):
        return [ctypes.c_void_p(p.value), ctypes.c_void_p(p.value),
                ctypes.c_int64(0), ctypes.c_int64(size), ctypes.c_int64(1)]

    launch_args = (_mr(dQ, n_qk) + _mr(dK, n_qk) + _mr(dV, n_v) + _mr(dO, n_v)
                   + _mr(dG, gate_c.size) + _mr(dBeta, beta_c.size)
                   + _mr(dDecay, decay_c.size) + [ctypes.c_int64(S)])
    arr = (ctypes.c_void_p * len(launch_args))()
    for i, val in enumerate(launch_args):
        arr[i] = ctypes.cast(ctypes.byref(val), ctypes.c_void_p)
    rc = hip.hipModuleLaunchKernel(fn, bh, 1, 1, d_v, 1, 1, 0, None, arr, None)
    devs = [dQ, dK, dV, dO, dG, dBeta, dDecay]
    if rc != 0:
        for dev in devs:
            hip.hipFree(dev)
        raise RuntimeError(f"rocm deltanet: kernel launch failed rc={rc}")
    hip.hipDeviceSynchronize()
    hip.hipMemcpy(o.ctypes.data_as(ctypes.c_void_p), dO, esz * n_v, 2)
    for dev in devs:
        hip.hipFree(dev)
    return o.reshape(B, H, S, d_v)


