def _apple_gpu_dispatch_topk(op_name: str, operands: list[Any], kwargs: dict,
                             np: Any) -> Any:
    """Hard top-k (k>1) per row via the MPSGraph TopK lane. Returns
    ``(values, indices)`` descending — the eager ``top_k`` semantics. Arbitrary
    ``axis`` is folded to the last axis; non-float inputs / unavailable Metal
    fall back to numpy argsort. ``segmented_topk_gpu``."""
    x = np.asarray(operands[0])
    k = kwargs.get("k")
    if k is None and len(operands) > 1:
        k = int(np.asarray(operands[1]).item())
    if k is None:
        raise ValueError("top_k requires a 'k' argument")
    k = int(k)
    axis = int(kwargs.get("axis", -1))

    xm = np.moveaxis(x, axis, -1)
    lead = xm.shape[:-1]
    cols = int(xm.shape[-1])
    rows = int(np.prod(lead)) if lead else 1
    sym = _apple_gpu_mpsgraph_topk_f32()
    can_gpu = (sym is not None and x.dtype == np.float32 and 1 <= k <= cols)
    if not can_gpu:
        idx2 = np.argsort(np.ascontiguousarray(xm.reshape(rows, cols)),
                          axis=-1)[:, ::-1][:, :k]
        vals2 = np.take_along_axis(xm.reshape(rows, cols), idx2, axis=-1)
    else:
        x2 = np.ascontiguousarray(xm.reshape(rows, cols), dtype=np.float32)
        vals2 = np.zeros((rows, k), np.float32)
        idx2 = np.zeros((rows, k), np.int32)
        fp = lambda a: a.ctypes.data_as(ctypes.POINTER(ctypes.c_float))
        ip = lambda a: a.ctypes.data_as(ctypes.POINTER(ctypes.c_int32))
        sym(fp(x2), fp(vals2), ip(idx2), rows, cols, k)

    out_shape = (*lead, k)
    vals = np.moveaxis(vals2.reshape(out_shape), -1, axis) if lead else vals2.reshape(k)
    idx = np.moveaxis(idx2.reshape(out_shape), -1, axis) if lead else idx2.reshape(k)
    return vals, idx.astype(np.int64)


def _apple_gpu_dispatch_reduce(op_name: str, operands: list[Any], kwargs: dict,
                               np: Any) -> Any:
    """Reductions / scans via the MPSGraph lane. Arbitrary axis/keepdims are
    folded to a [rows, cols] last-axis reduction by transposing the reduced
    axes to the end. f16/bf16 upcast to f32 (fp32 reduction numerics). Falls
    back to numpy for non-float dtypes or when Metal is unavailable."""
    x = np.asarray(operands[0])
    kind, op = _APPLE_GPU_REDUCE_OPS[op_name]
    axis = kwargs.get("axis", -1 if kind == "scan" else None)
    keepdims = bool(kwargs.get("keepdims", False))
    ddof = int(kwargs.get("ddof", 0))
    out_dtype = x.dtype
    bf16 = _bfloat16_dtype()
    is_float = (x.dtype in (np.float32, np.float16)
                or (bf16 is not None and x.dtype == bf16))
    fp = lambda a: a.ctypes.data_as(ctypes.POINTER(ctypes.c_float))

    def _ref() -> Any:
        if kind == "reduce":
            f = {0: np.sum, 1: np.mean, 2: np.amax, 3: np.amin, 4: np.prod}.get(op)
            if f is not None:
                return f(x, axis=axis, keepdims=keepdims)
            if op == 5:
                return np.var(x, axis=axis, keepdims=keepdims, ddof=ddof)
            if op == 7:  # logsumexp = log(Σ exp(x − max)) + max  (stable)
                m = np.max(x, axis=axis, keepdims=True)
                r = np.log(np.sum(np.exp(x - m), axis=axis, keepdims=True)) + m
                return r if keepdims else np.squeeze(
                    r, axis=(tuple(range(x.ndim)) if axis is None else axis))
            return np.std(x, axis=axis, keepdims=keepdims, ddof=ddof)
        if kind == "arg":
            r = (np.argmax if op == 0 else np.argmin)(x, axis=axis)
            return np.expand_dims(r, axis) if (keepdims and axis is not None) else r
        scan_fn = {0: np.cumsum, 1: np.cumprod,
                   2: np.maximum.accumulate, 3: np.minimum.accumulate}[op]
        return scan_fn(x, axis=axis)

    if not is_float or x.ndim == 0:
        return _ref()
    xf = np.ascontiguousarray(x.astype(np.float32))
    n = x.ndim

    if kind == "scan":
        ax = axis if axis is not None else -1
        ax = ax if ax >= 0 else n + ax
        perm = [i for i in range(n) if i != ax] + [ax]
        inv = list(np.argsort(perm))
        xt = np.ascontiguousarray(np.transpose(xf, perm))
        inner = int(xt.shape[-1])
        outer = int(xt.size // inner) if inner else 0
        sym = _apple_gpu_mpsgraph_scan_f32()
        if sym is None:
            return _ref()
        out = np.empty((outer, inner), np.float32)
        sym(ctypes.c_int32(op), fp(xt.reshape(outer, inner)), fp(out),
            ctypes.c_int32(outer), ctypes.c_int32(inner))
        res = np.transpose(out.reshape(xt.shape), inv)
        return res.astype(out_dtype)

    # reduce / arg: normalize the reduced axes.
    if axis is None:
        axes = tuple(range(n))
    elif isinstance(axis, int):
        axes = (axis if axis >= 0 else n + axis,)
    else:
        axes = tuple(a if a >= 0 else n + a for a in axis)
    if kind == "arg" and len(axes) != 1 and axis is not None:
        return _ref()
    kept = [i for i in range(n) if i not in axes]
    perm = kept + list(axes)
    xt = np.ascontiguousarray(np.transpose(xf, perm))
    inner = 1
    for a in axes:
        inner *= int(x.shape[a])
    outer = int(xt.size // inner) if inner else 0
    kept_shape = tuple(int(x.shape[i]) for i in kept)

    if kind == "reduce":
        sym = _apple_gpu_mpsgraph_reduce_f32()
        if sym is None:
            return _ref()
        out = np.empty(max(outer, 1), np.float32)
        sym(ctypes.c_int32(op), fp(xt.reshape(outer, inner)), fp(out),
            ctypes.c_int32(outer), ctypes.c_int32(inner))
        if op in (5, 6) and ddof != 0 and inner > ddof:
            factor = inner / (inner - ddof)
            out = out * (factor if op == 5 else np.sqrt(factor))
        res = out.reshape(kept_shape) if kept_shape else out.reshape(())
        if keepdims:
            full = [int(s) for s in x.shape]
            for a in axes:
                full[a] = 1
            res = res.reshape(full)
        return res.astype(out_dtype)

    # arg
    sym = _apple_gpu_mpsgraph_argreduce_f32()
    if sym is None:
        return _ref()
    out = np.empty(max(outer, 1), np.int32)
    sym(ctypes.c_int32(op),
        fp(np.ascontiguousarray(xt.reshape(outer, inner))),
        out.ctypes.data_as(ctypes.POINTER(ctypes.c_int32)),
        ctypes.c_int32(outer), ctypes.c_int32(inner))
    res = out.astype(np.int64)
    res = res.reshape(kept_shape) if kept_shape else res.reshape(())
    if keepdims and axis is not None:
        full = [int(s) for s in x.shape]
        for a in axes:
            full[a] = 1
        res = res.reshape(full)
    return res


def apple_gpu_kv_cache_read(cache: Any, start: int, end: "int | None" = None
                            ) -> "tuple[Any, Any, str]":
    """Device-resident KV-cache slice read on the apple_gpu lane.

    Reads ``[start, end)`` from ``cache`` and places K/V in shared (unified-memory)
    ``DeviceTensor`` buffers, returning zero-copy device-resident views — the GPU
    sees the same bytes the attention kernel consumes, with no host round-trip
    (the residency model ``cache.ResidentLatentKVCache`` uses).

    Returns ``(k_view, v_view, execution_mode)`` where ``execution_mode`` is
    ``"metal_runtime"`` only when the DeviceTensor ABI is live on this machine,
    else ``"reference"`` (host read). Provenance-honest: a host fallback never
    claims native execution.
    """
    import numpy as _np
    k_host, v_host = cache.read(start, end)
    k_host = _np.ascontiguousarray(k_host, dtype=_np.float32)
    v_host = _np.ascontiguousarray(v_host, dtype=_np.float32)
    if DeviceTensor.is_metal():
        k_dev = DeviceTensor.from_numpy(k_host)
        v_dev = DeviceTensor.from_numpy(v_host)
        if k_dev is not None and v_dev is not None:
            # Zero-copy device-resident views over the shared Metal buffers.
            return k_dev.numpy(), v_dev.numpy(), "metal_runtime"
    return k_host, v_host, "reference"


